impl RuntimeSnapshot {
    fn from_runtime(runtime: &RuntimeWorld) -> Self {
        let content_handles = runtime.world.actors[..runtime.world.actor_count]
            .iter()
            .map(|actor| ("actor", actor.id))
            .chain(
                runtime.world.items[..runtime.world.item_count]
                    .iter()
                    .map(|item| ("item", item.id)),
            )
            .chain(
                runtime.world.locations[..runtime.world.location_count]
                    .iter()
                    .map(|location| ("location", location.id)),
            )
            .collect::<Vec<_>>();
        Self {
            version: 4,
            worldpack_bundle_hash: active_content().manifest.bundle_hash.clone(),
            content_context: content_registry().content_reference_context(content_handles),
            rules_profile: active_content().manifest.rules_profile.clone(),
            active_rules_variants: active_content().manifest.active_rules_variants.clone(),
            active_rules_extensions: active_content().manifest.active_rules_extensions.clone(),

            world_version: runtime.world.version,
            tick: runtime.world.tick,
            next_event_seq: runtime.world.next_event_seq,
            canonical_identities: runtime.canonical_identities.clone(),
            command_receipts: runtime.command_receipts.clone(),
            world_actors: runtime.world.actors[..runtime.world.actor_count].to_vec(),
            world_items: runtime.world.items[..runtime.world.item_count].to_vec(),
            world_locations: runtime.world.locations[..runtime.world.location_count].to_vec(),
            world_exits: runtime.world.exits[..runtime.world.exit_count].to_vec(),
            world_evolution_tracks: runtime.world.evolution_tracks
                [..runtime.world.evolution_track_count]
                .to_vec(),
            world_combat_encounters: runtime.world.combat_encounters
                [..runtime.world.combat_encounter_count]
                .to_vec(),
            actor_meta: runtime.actors.clone(),
            item_meta: runtime.items.clone(),
            location_names: runtime.locations.clone(),
            location_meta: runtime.location_meta.clone(),
            content: runtime.content.clone(),
            branches: runtime.branches.clone(),
            clocks: runtime.clocks.clone(),
            tags: runtime.tags.clone(),
            jobs: runtime.jobs.clone(),
            room_sheets: runtime.room_sheets.clone(),
            generated_pathways: runtime.generated_pathways.clone(),
            community_art_generations: runtime.community_art_generations.clone(),
            journeys: runtime.journeys.clone(),
            character_identities: runtime.character_identities.clone(),
            callings: runtime.callings.clone(),
            skills: runtime.skills.clone(),
            charm_slots: runtime.charm_slots.clone(),
            equipped_charms: runtime.equipped_charms.clone(),
            prepared_spells: runtime.prepared_spells.clone(),
            npc_cooperation: runtime.npc_cooperation.clone(),
            item_provenance: runtime.item_provenance.clone(),
            materialization_receipts: runtime.materialization_receipts.clone(),
            ledger_marks: runtime.ledger_marks.clone(),
            advancement_spends: runtime.advancement_spends.clone(),
            bonds: runtime.bonds.clone(),
            resident_memories: runtime.resident_memories.clone(),
            search_memories: runtime.search_memories.clone(),
            resident_continuities: BTreeMap::new(),
            actor_autonomy: runtime.actor_autonomy.clone(),
            deeds: runtime.deeds.clone(),
            deed_ids_by_actor: runtime.deed_ids_by_actor.clone(),
            actor_practices: runtime.actor_practices.clone(),
            transfer_offers: runtime.transfer_offers.clone(),
            gift_auto_accepts: runtime.gift_auto_accepts.clone(),
            actor_safety: runtime.actor_safety.clone(),
            world_simulation: runtime.world_simulation.clone(),
            rpg_claims: runtime.rpg_claims.clone(),
            orb_balances: runtime.orb_balances.clone(),
            orb_reward_claims: runtime.orb_reward_claims.clone(),
            listen_attempt_claims: runtime.listen_attempt_claims.clone(),
            event_log: runtime.event_log.clone(),
            recent_room_lines: runtime.recent_room_lines.clone(),
            next_actor_id: runtime.next_actor_id,
            next_content_id: runtime.next_content_id,
            next_seed: runtime.next_seed,
        }
    }

    fn into_runtime(self) -> io::Result<RuntimeWorld> {
        let compatibility =
            persisted_worldpack_replay_compatibility(&self.worldpack_bundle_hash, "snapshot")?;
        if compatibility == WorldpackReplayCompatibility::DeclaredMigration {
            warn!(
                "loading snapshot through declared worldpack migration: {} -> {}",
                self.worldpack_bundle_hash,
                active_content().manifest.bundle_hash
            );
        }
        validate_persisted_content_context_for_replay(
            &self.content_context,
            "snapshot",
            compatibility == WorldpackReplayCompatibility::DeclaredMigration,
        )?;
        if !self.rules_profile.is_empty()
            && self.rules_profile != active_content().manifest.rules_profile
        {
            return Err(snapshot_error(format!(
                "snapshot rules profile {} does not match active rules profile {}",
                self.rules_profile,
                active_content().manifest.rules_profile
            )));
        }
        if self.active_rules_variants != active_content().manifest.active_rules_variants {
            return Err(snapshot_error(format!(
                "snapshot rules variants {:?} do not match active variants {:?}",
                self.active_rules_variants,
                active_content().manifest.active_rules_variants
            )));
        }
        if self.active_rules_extensions != active_content().manifest.active_rules_extensions {
            return Err(snapshot_error(format!(
                "snapshot rules extensions {:?} do not match active extensions {:?}",
                self.active_rules_extensions,
                active_content().manifest.active_rules_extensions
            )));
        }

        if self.world_actors.len() > CW_MAX_ACTORS {
            return Err(snapshot_error("too many actors in snapshot"));
        }
        if self.world_items.len() > CW_MAX_ITEMS {
            return Err(snapshot_error("too many items in snapshot"));
        }
        if self.world_locations.len() > CW_MAX_LOCATIONS {
            return Err(snapshot_error("too many locations in snapshot"));
        }
        if self.world_exits.len() > CW_MAX_EXITS {
            return Err(snapshot_error("too many exits in snapshot"));
        }
        if self.world_evolution_tracks.len() > CW_MAX_EVOLUTION_TRACKS {
            return Err(snapshot_error("too many evolution tracks in snapshot"));
        }
        if self.world_combat_encounters.len() > CW_MAX_COMBAT_ENCOUNTERS {
            return Err(snapshot_error("too many combat encounters in snapshot"));
        }
        for encounter in &self.world_combat_encounters {
            if encounter.id == 0 || encounter.location_id == 0 {
                return Err(snapshot_error("combat encounter has no id or location"));
            }
            if encounter.participant_count > CW_MAX_COMBAT_PARTICIPANTS {
                return Err(snapshot_error(
                    "too many combat participants in snapshot encounter",
                ));
            }
            if !matches!(
                encounter.status,
                CW_COMBAT_ENCOUNTER_ACTIVE | CW_COMBAT_ENCOUNTER_RESOLVED
            ) {
                return Err(snapshot_error("invalid combat encounter status"));
            }
            if encounter.participant_count < 2
                || usize::from(encounter.current_index) >= encounter.participant_count
            {
                return Err(snapshot_error("invalid combat encounter turn state"));
            }
            let mut participant_ids = BTreeSet::new();
            for participant in &encounter.participants[..encounter.participant_count] {
                if participant.actor_id == 0
                    || !matches!(participant.side, 1 | 2)
                    || !participant_ids.insert(participant.actor_id)
                {
                    return Err(snapshot_error("invalid combat participant state"));
                }
            }
        }

        let mut world = CwWorld {
            version: self.world_version,
            tick: self.tick,
            next_event_seq: self.next_event_seq,
            actor_count: self.world_actors.len(),
            item_count: self.world_items.len(),
            location_count: self.world_locations.len(),
            exit_count: self.world_exits.len(),
            evolution_track_count: self.world_evolution_tracks.len(),
            combat_encounter_count: self.world_combat_encounters.len(),
            ..CwWorld::default()
        };

        if world.version == 0 {
            unsafe {
                cw_world_init(&mut world);
            }
            world.actor_count = self.world_actors.len();
            world.item_count = self.world_items.len();
            world.location_count = self.world_locations.len();
            world.exit_count = self.world_exits.len();
            world.evolution_track_count = self.world_evolution_tracks.len();
            world.combat_encounter_count = self.world_combat_encounters.len();
            world.tick = self.tick;
            world.next_event_seq = self.next_event_seq;
        }
        world.version = CW_KERNEL_VERSION;

        for (idx, actor) in self.world_actors.into_iter().enumerate() {
            world.actors[idx] = actor;
        }
        for (idx, item) in self.world_items.into_iter().enumerate() {
            world.items[idx] = item;
        }
        for (idx, location) in self.world_locations.into_iter().enumerate() {
            world.locations[idx] = location;
        }
        for (idx, exit) in self.world_exits.into_iter().enumerate() {
            world.exits[idx] = exit;
        }
        for (idx, track) in self.world_evolution_tracks.into_iter().enumerate() {
            world.evolution_tracks[idx] = track;
        }
        for (idx, encounter) in self.world_combat_encounters.into_iter().enumerate() {
            world.combat_encounters[idx] = encounter;
        }

        let max_seq = self
            .event_log
            .iter()
            .map(|event| event.seq)
            .max()
            .unwrap_or(0);
        if world.next_event_seq <= max_seq {
            world.next_event_seq = max_seq + 1;
        }
        if world.next_event_seq == 0 {
            world.next_event_seq = 1;
        }

        Ok(RuntimeWorld {
            world,
            canonical_identities: self.canonical_identities,
            command_receipts: self.command_receipts,
            actors: self.actor_meta,
            items: self.item_meta,
            locations: self.location_names,
            location_meta: self.location_meta,
            content: self.content,
            branches: self.branches,
            clocks: self.clocks,
            tags: self.tags,
            jobs: self.jobs,
            room_sheets: self.room_sheets,
            generated_pathways: self.generated_pathways,
            community_art_generations: self.community_art_generations,
            journeys: self.journeys,
            character_identities: self.character_identities,
            callings: self.callings,
            skills: self.skills,
            charm_slots: self.charm_slots,
            equipped_charms: self.equipped_charms,
            prepared_spells: self.prepared_spells,
            npc_cooperation: self.npc_cooperation,
            item_provenance: self.item_provenance,
            materialization_receipts: self.materialization_receipts,
            ledger_marks: self.ledger_marks,
            advancement_spends: self.advancement_spends,
            bonds: self.bonds,
            resident_memories: self.resident_memories,
            search_memories: self.search_memories,
            resident_continuities: self.resident_continuities,
            actor_autonomy: self.actor_autonomy,
            deeds: self.deeds,
            deed_ids_by_actor: self.deed_ids_by_actor,
            actor_practices: self.actor_practices,
            transfer_offers: self.transfer_offers,
            gift_auto_accepts: self.gift_auto_accepts,
            actor_safety: self.actor_safety,
            world_simulation: self.world_simulation,
            rpg_claims: self.rpg_claims,
            orb_balances: self.orb_balances,
            orb_reward_claims: self.orb_reward_claims,
            listen_attempt_claims: self.listen_attempt_claims,
            presence_states: BTreeMap::new(),
            event_log: self.event_log,
            recent_room_lines: self.recent_room_lines,
            next_actor_id: self.next_actor_id,
            next_content_id: self.next_content_id,
            next_seed: self.next_seed,
        })
        .map(|mut runtime| {
            runtime.backfill_recent_room_lines();
            runtime.ensure_seed_topology();
            runtime.ensure_seed_rpg_projection();
            runtime.backfill_generated_avatar_flavor();
            runtime.backfill_listen_attempt_claims_from_events();
            runtime.refresh_all_resident_continuities();
            runtime.ensure_actor_autonomy();
            runtime.rebuild_deed_index();
            runtime.ensure_world_simulation();
            let mint_seed = runtime.next_seed;
            runtime.ensure_canonical_identities(mint_seed);
            runtime.refresh_all_canonical_events();
            runtime
        })
    }
}

