    fn push_projected_event(&mut self, event: EventView) {
        if event.type_name == "message.created" && event.content.is_some() {
            if let Some(location_id) = event.location_id {
                let room_lines = self.recent_room_lines.entry(location_id).or_default();
                room_lines.push(event.clone());
                if room_lines.len() > RECENT_ROOM_LINE_CAPACITY {
                    room_lines.drain(0..room_lines.len() - RECENT_ROOM_LINE_CAPACITY);
                }
            }
        }
        self.event_log.push(event);
        if self.event_log.len() > 512 {
            let excess = self.event_log.len() - 512;
            self.event_log.drain(0..excess);
        }
    }

    fn backfill_recent_room_lines(&mut self) {
        if !self.recent_room_lines.is_empty() {
            return;
        }
        for event in &self.event_log {
            if event.type_name != "message.created" || event.content.is_none() {
                continue;
            }
            let Some(location_id) = event.location_id else {
                continue;
            };
            let room_lines = self.recent_room_lines.entry(location_id).or_default();
            room_lines.push(event.clone());
            if room_lines.len() > RECENT_ROOM_LINE_CAPACITY {
                room_lines.drain(0..room_lines.len() - RECENT_ROOM_LINE_CAPACITY);
            }
        }
    }

    fn load_snapshot(path: &Path) -> io::Result<Self> {
        let bytes = fs::read(path)?;
        let snapshot: RuntimeSnapshot = serde_json::from_slice(&bytes)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        snapshot.into_runtime()
    }

    fn save_snapshot(&self, path: &Path) -> io::Result<()> {
        if let Some(parent) = path.parent() {
            if !parent.as_os_str().is_empty() {
                fs::create_dir_all(parent)?;
            }
        }

        let tmp = path.with_extension("json.tmp");
        let snapshot = RuntimeSnapshot::from_runtime(self);
        let bytes = serde_json::to_vec_pretty(&snapshot)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        fs::write(&tmp, bytes)?;
        fs::rename(tmp, path)?;
        Ok(())
    }

    fn load_resident_continuity_snapshot(&mut self, path: &Path) -> io::Result<usize> {
        let bytes = fs::read(path)?;
        let snapshot: ResidentContinuitySnapshot = serde_json::from_slice(&bytes)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        if snapshot.version != 1 {
            return Err(snapshot_error(
                "unsupported resident continuity snapshot version",
            ));
        }
        let compatibility = persisted_worldpack_replay_compatibility(
            &snapshot.worldpack_bundle_hash,
            "resident continuity",
        )?;
        if compatibility == WorldpackReplayCompatibility::DeclaredMigration {
            warn!(
                "loading resident continuity through declared worldpack migration: {} -> {}",
                snapshot.worldpack_bundle_hash,
                active_content().manifest.bundle_hash
            );
        }
        Ok(self.apply_resident_continuity_snapshot(snapshot))
    }

    fn apply_resident_continuity_snapshot(
        &mut self,
        snapshot: ResidentContinuitySnapshot,
    ) -> usize {
        let mut applied = 0;
        for (resident_id, continuity) in snapshot.residents {
            let Some(resident) = self.actor_by_id(resident_id) else {
                continue;
            };
            if !Self::actor_is_active_avatar(resident) {
                continue;
            }
            let current_seq = self
                .resident_continuities
                .get(&resident_id)
                .map(|current| current.last_observed_event_seq)
                .unwrap_or(0);
            if continuity.last_observed_event_seq >= current_seq {
                self.resident_continuities.insert(resident_id, continuity);
                applied += 1;
            }
        }
        self.refresh_all_resident_continuities();
        applied
    }

    fn save_resident_continuity_snapshot(&self, path: &Path) -> io::Result<()> {
        if let Some(parent) = path.parent() {
            if !parent.as_os_str().is_empty() {
                fs::create_dir_all(parent)?;
            }
        }

        let tmp = path.with_extension("json.tmp");
        let snapshot = ResidentContinuitySnapshot::from_runtime(self);
        let bytes = serde_json::to_vec_pretty(&snapshot)
            .map_err(|error| io::Error::new(io::ErrorKind::InvalidData, error))?;
        fs::write(&tmp, bytes)?;
        fs::rename(tmp, path)?;
        Ok(())
    }

    fn next_seed_value(&self) -> u64 {
        self.next_seed
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407)
    }

    fn next_content_id_value(&self) -> u64 {
        self.next_content_id + 1
    }

    fn expire_branch_for_actor(&mut self, actor_id: u64) -> Option<EventView> {
        let branch = self.branches.remove(&actor_id)?;
        Some(self.append_branch_lifecycle_event("branch.expired", &branch))
    }

    fn expire_stale_branches(&mut self) -> Vec<EventView> {
        let expired_actor_ids: Vec<u64> = self
            .branches
            .iter()
            .filter_map(|(actor_id, branch)| (!self.branch_is_active(branch)).then_some(*actor_id))
            .collect();
        expired_actor_ids
            .into_iter()
            .filter_map(|actor_id| self.expire_branch_for_actor(actor_id))
            .collect()
    }

    fn apply_journal_record(&mut self, record: &JournalRecord) -> (u32, Vec<EventView>) {
        self.expire_transfer_offers();
        for (actor_id, meta) in &record.actor_meta_upserts {
            self.actors.insert(*actor_id, meta.clone());
            self.next_actor_id = self.next_actor_id.max(*actor_id + 1);
        }
        for (content_id, body) in &record.content_upserts {
            self.content.insert(*content_id, body.clone());
            self.next_content_id = self.next_content_id.max(*content_id);
        }

        self.next_seed = record.seed;
        let action = self.action_with_skill_bonus(record.action);
        let advances_world_tick = record.advances_world_tick();
        let authoritative_contribution_clock_ids = record
            .projection_mutations
            .iter()
            .filter_map(|mutation| match mutation {
                ProjectionMutation::ResolveJobContribution { intent } => {
                    Some(intent.strategy.clock_id.clone())
                }
                _ => None,
            })
            .collect::<BTreeSet<_>>();
        self.prepare_projection_mutations(&record.projection_mutations);
        let projection_only_blocked_by_combat = advances_world_tick
            && action.kind == CW_ACTION_NONE
            && self
                .active_combat_encounter_for_actor(action.actor_id)
                .is_some();
        let (status, mut events) = if action.kind == CW_ACTION_NONE
            && !record.projection_mutations.is_empty()
            && !projection_only_blocked_by_combat
        {
            if advances_world_tick {
                self.world.tick = self.world.tick.saturating_add(1);
            }
            (CW_OK, Vec::new())
        } else {
            self.apply_action_with_seed(action, record.seed, advances_world_tick)
        };
        if status == CW_OK {
            if advances_world_tick {
                self.decay_search_memories();
            }
            let listen_context = self.listen_context_for_action(&action, &events);
            let was_repeat_listen = listen_context
                .map(|(actor_id, location_id)| {
                    self.listen_attempt_claimed_at(actor_id, location_id)
                })
                .unwrap_or(false);
            for (actor_id, branch) in &record.branch_upserts {
                self.branches.insert(*actor_id, branch.clone());
                events.push(self.append_branch_lifecycle_event("branch.opened", branch));
            }
            for actor_id in &record.branch_resolutions {
                if let Some(branch) = self.branches.remove(actor_id) {
                    events.push(self.append_branch_lifecycle_event("branch.resolved", &branch));
                }
            }
            events.extend(self.apply_actor_creation_rpg_projection(
                &action,
                &events,
                record.initial_calling.as_deref(),
                record.initial_skill.as_deref(),
                record.initial_character_profile_id.as_deref(),
                record.initial_species_id.as_deref(),
                record.initial_origin_id.as_deref(),
                record.initial_physical_description.as_deref(),
            ));
            if action.kind == CW_ACTION_RULES_STUDY {
                if let Some(check) = events.iter().find(|event| {
                    event.type_name == "ability_check.rolled"
                        && event.actor_id == Some(action.actor_id)
                }) {
                    let understood = check.success
                        && check
                            .total
                            .zip(check.dc)
                            .is_some_and(|(total, dc)| total >= dc);
                    events.push(
                        self.append_async_job_event(
                            "study.resolved",
                            action.actor_id,
                            None,
                            Some(
                                if understood {
                                    "The authored signs yielded one understood truth."
                                } else {
                                    "The authored signs remain unresolved."
                                }
                                .to_string(),
                            ),
                        ),
                    );
                }
            }
            events.extend(self.expire_stale_branches());
            let committed_events = events.clone();
            events.extend(self.apply_projection_mutations(
                &action,
                &committed_events,
                &record.projection_mutations,
            ));
            events.extend(self.apply_class_readiness_projection(record, &action, &events));
            let committed_events = events.clone();
            events.extend(self.apply_bounded_magic_projection(&action, &committed_events));
            let committed_events = events.clone();
            events.extend(self.apply_influence_projection(&action, &committed_events));
            self.reinforce_search_memories_from_events(&events);
            let committed_events = events.clone();
            events.extend(self.apply_event_lifecycle_hooks(
                &action,
                &committed_events,
                &authoritative_contribution_clock_ids,
            ));
            let committed_events = events.clone();
            events.extend(self.apply_defend_project_preparation(&action, &committed_events));
            let committed_events = events.clone();
            events.extend(self.apply_attack_project_danger(&action, &committed_events));
            let committed_events = events.clone();
            events.extend(self.apply_combat_outcome_projection(&action, &committed_events));
            events.extend(self.apply_progress_contribution_ledger_projection(&events));
            events.extend(self.apply_frontier_return_ledger_projection(&action, &events));
            events.extend(self.apply_frontier_travel_since_rest_projection(&events));
            events.extend(self.apply_gift_bond_projection(&events));
            events.extend(self.apply_resident_feature_bond_projection(&events));
            events.extend(self.apply_resident_witness_ledger_projection(&events));
            self.record_listen_attempt(&action, &events);
            let discovery_settlement_reason =
                record
                    .projection_mutations
                    .iter()
                    .find_map(|mutation| match mutation {
                        ProjectionMutation::SettleVisitLedgerAfterDiscovery { reason } => {
                            Some(reason.as_str())
                        }
                        _ => None,
                    });
            events.extend(self.apply_listen_rpg_projection(
                &action,
                &events,
                was_repeat_listen,
                discovery_settlement_reason,
                &authoritative_contribution_clock_ids,
            ));
            let committed_events = events.clone();
            events
                .extend(self.apply_first_tale_public_trace_projection(&action, &committed_events));
            let committed_events = events.clone();
            events.extend(self.clear_job_resolved_tags_from_events(&committed_events));
            self.apply_automatic_orb_rewards(&action, &events);
            for delta in &record.orb_deltas {
                self.apply_orb_delta(delta.actor_id, delta.delta);
            }
            if action.kind != CW_ACTION_SAY {
                self.clear_resident_pending_action(action.actor_id);
            }
            self.reconcile_card_zones();
            let delivery_evidence = self.update_item_provenance(&events);
            let logistics_events = self.apply_actor_causal_logistics(delivery_evidence);
            let public_beat_available = logistics_events
                .iter()
                .all(|event| !event.type_name.starts_with("world."));
            events.extend(logistics_events);
            self.project_qualifying_deeds(&events);
            self.apply_resident_memory_projection(&action, &events);
            if advances_world_tick {
                let committed_events = events.clone();
                events.extend(self.apply_player_tick_frontier_resets(&action, &committed_events));
                let committed_events = events.clone();
                events.extend(self.apply_played_time_world_simulation(
                    &action,
                    record.seed,
                    &committed_events,
                    public_beat_available,
                ));
            }
            self.record_autonomous_action(record);
            if record.source_world_tick.is_some() {
                for event in &mut events {
                    event.apply_async_causality(record);
                }
                for event in &events {
                    if let Some(logged) = self
                        .event_log
                        .iter_mut()
                        .rev()
                        .find(|logged| logged.seq == event.seq)
                    {
                        logged.apply_async_causality(record);
                    }
                }
            }
        }
        self.ensure_canonical_identities(record.seed);
        if status == CW_OK {
            self.bump_entity_versions_for_events(&events);
        }
        self.refresh_canonical_events(&mut events);
        (status, events)
    }

    fn apply_projection_mutations(
        &mut self,
        action: &CwAction,
        committed_events: &[EventView],
        mutations: &[ProjectionMutation],
    ) -> Vec<EventView> {
        let mut events = Vec::new();
        for mutation in mutations {
            match mutation {
                ProjectionMutation::CreateTransferOffer { offer } => {
                    self.transfer_offers
                        .entry(offer.id.clone())
                        .or_insert_with(|| offer.clone());
                }
                ProjectionMutation::ResolveTransferOffer {
                    offer_id,
                    status,
                    resolved_by_actor_id,
                } => {
                    if let Some(offer) = self.transfer_offers.get_mut(offer_id) {
                        if offer.status == TransferOfferStatus::Pending || offer.status == *status {
                            offer.status = *status;
                            offer.resolved_by_actor_id = Some(*resolved_by_actor_id);
                        }
                    }
                }
                ProjectionMutation::SetActorSafety {
                    actor_id,
                    target_actor_id,
                    control,
                    enabled,
                } => {
                    let safety = self.actor_safety.entry(*actor_id).or_default();
                    let ids = match control {
                        ActorSafetyControl::Mute => &mut safety.muted_actor_ids,
                        ActorSafetyControl::Block => &mut safety.blocked_actor_ids,
                    };
                    if *enabled {
                        ids.insert(*target_actor_id);
                    } else {
                        ids.remove(target_actor_id);
                    }
                    if *control == ActorSafetyControl::Block && *enabled {
                        for offer in self.transfer_offers.values_mut() {
                            let participants_match = (offer.offered_by_actor_id == *actor_id
                                && offer.offered_to_actor_id == *target_actor_id)
                                || (offer.offered_by_actor_id == *target_actor_id
                                    && offer.offered_to_actor_id == *actor_id);
                            if participants_match && offer.status == TransferOfferStatus::Pending {
                                offer.status = TransferOfferStatus::Invalidated;
                                offer.resolved_by_actor_id = Some(*actor_id);
                            }
                        }
                        for policy in self.gift_auto_accepts.values_mut() {
                            let participants_match = (policy.recipient_actor_id == *actor_id
                                && policy.offered_by_actor_id == *target_actor_id)
                                || (policy.recipient_actor_id == *target_actor_id
                                    && policy.offered_by_actor_id == *actor_id);
                            if participants_match {
                                policy.consumed = true;
                            }
                        }
                    }
                }
                ProjectionMutation::SetGiftAutoAccept { policy } => {
                    self.gift_auto_accepts
                        .insert(policy.id.clone(), policy.clone());
                }
                ProjectionMutation::ConsumeGiftAutoAccept { policy_id } => {
                    if let Some(policy) = self.gift_auto_accepts.get_mut(policy_id) {
                        policy.consumed = true;
                    }
                }
                ProjectionMutation::ShuffleHand { reason } => {
                    events.push(self.append_hand_shuffled_event(action.actor_id, reason));
                }
                ProjectionMutation::ChatStatus {
                    target_actor_id,
                    status,
                    reason,
                } => {
                    events.push(self.append_async_job_event(
                        &format!("chat.{status}"),
                        action.actor_id,
                        Some(*target_actor_id),
                        Some(reason.clone()),
                    ));
                }
                ProjectionMutation::RefreshAvatarIdentity {
                    actor_id,
                    physical_description,
                } => {
                    if !physical_description.trim().is_empty() {
                        if let Some(identity) = self.character_identities.get_mut(actor_id) {
                            identity.physical_description =
                                compact_whitespace(physical_description);
                        }
                    }
                    events.push(self.append_async_job_event(
                        "avatar.refined",
                        *actor_id,
                        None,
                        None,
                    ));
                }
                ProjectionMutation::FundCommunityArt {
                    subject_kind,
                    subject_id,
                    level,
                    required_orbs,
                    contributor_actor_id,
                    intent_id,
                    amount,
                    history_through_seq,
                } => {
                    let key = community_art_generation_key(subject_kind, *subject_id, *level);
                    let funding_reason = {
                        let generation =
                            self.community_art_generations
                                .entry(key)
                                .or_insert_with(|| CommunityArtGenerationState {
                                    subject_kind: subject_kind.clone(),
                                    subject_id: *subject_id,
                                    level: *level,
                                    required_orbs: (*required_orbs).max(1),
                                    funded_orbs: 0,
                                    contributions: BTreeMap::new(),
                                    funding_intent_ids: BTreeSet::new(),
                                    status: "funding".to_string(),
                                    history_through_seq: *history_through_seq,
                                });
                        if !intent_id.is_empty()
                            && !generation.funding_intent_ids.insert(intent_id.clone())
                        {
                            continue;
                        }
                        let accepted = (*amount).max(0).min(
                            generation
                                .required_orbs
                                .saturating_sub(generation.funded_orbs),
                        );
                        if accepted > 0 {
                            generation.funded_orbs += accepted;
                            *generation
                                .contributions
                                .entry(*contributor_actor_id)
                                .or_insert(0) += accepted;
                            generation.history_through_seq =
                                generation.history_through_seq.max(*history_through_seq);
                            if generation.funded_orbs >= generation.required_orbs {
                                generation.status = "funded".to_string();
                            }
                        }
                        format!(
                            "{}:{}:level:{}:{}/{}",
                            subject_kind,
                            subject_id,
                            level,
                            generation.funded_orbs,
                            generation.required_orbs
                        )
                    };
                    events.push(self.append_async_job_event(
                        "community_art.funded",
                        *contributor_actor_id,
                        None,
                        Some(funding_reason),
                    ));
                }
                ProjectionMutation::SetCommunityArtStatus {
                    subject_kind,
                    subject_id,
                    level,
                    status,
                } => {
                    let key = community_art_generation_key(subject_kind, *subject_id, *level);
                    let Some(generation) = self.community_art_generations.get_mut(&key) else {
                        continue;
                    };
                    generation.status = status.clone();
                    events.push(self.append_async_job_event(
                        &format!("community_art.{status}"),
                        action.actor_id,
                        None,
                        Some(format!("{}:{}:level:{}", subject_kind, subject_id, level)),
                    ));
                }
                ProjectionMutation::RefinePathway { pathway } => {
                    let mut refined = pathway.clone();
                    if let Some(current) = self.generated_pathways.get(&pathway.id) {
                        refined
                            .revealed_edges
                            .extend(current.revealed_edges.clone());
                        refined.familiar |= current.familiar;
                    }
                    for waypoint in &refined.waypoints {
                        self.locations.insert(waypoint.id, waypoint.name.clone());
                        self.location_meta
                            .insert(waypoint.id, waypoint.meta.clone());
                    }
                    self.generated_pathways
                        .insert(refined.id.clone(), refined.clone());
                    events.push(self.append_async_job_event(
                        "pathway.refined",
                        refined.created_by_actor_id,
                        None,
                        Some(refined.id),
                    ));
                }
                ProjectionMutation::UpdateResidentContinuity {
                    resident_id,
                    proposal,
                    reason,
                } => {
                    self.apply_resident_intent_projection(*resident_id, proposal, reason);
                }
                ProjectionMutation::PlaceResident {
                    actor_id,
                    location_id,
                    reason: _,
                } => {
                    let valid_actor = self
                        .actor_by_id(*actor_id)
                        .is_some_and(Self::actor_is_active_avatar);
                    if valid_actor {
                        if let Some(event) =
                            self.place_actor_location(*actor_id, *location_id, true)
                        {
                            events.push(event);
                        }
                    }
                }
                ProjectionMutation::RendezvousActor {
                    actor_id,
                    location_id,
                    invite_id: _,
                } => {
                    if self.actor_by_id(*actor_id).is_some() {
                        if let Some(event) =
                            self.place_actor_location(*actor_id, *location_id, true)
                        {
                            events.push(event);
                        }
                    }
                }
                ProjectionMutation::JourneyTransition {
                    pathway,
                    journey,
                    reveal_edges,
                    narration,
                    event_type,
                } => {
                    let mut next_pathway = self
                        .generated_pathways
                        .get(&pathway.id)
                        .cloned()
                        .unwrap_or_else(|| pathway.clone());
                    for (from_location_id, to_location_id) in reveal_edges {
                        next_pathway
                            .revealed_edges
                            .insert(pathway_edge_key(*from_location_id, *to_location_id));
                    }
                    self.generated_pathways
                        .insert(next_pathway.id.clone(), next_pathway.clone());
                    self.ensure_generated_pathway_project(&next_pathway);
                    if let Some(journey) = journey {
                        self.journeys.insert(action.actor_id, journey.clone());
                    } else {
                        self.journeys.remove(&action.actor_id);
                    }
                    let journey_destination = journey
                        .as_ref()
                        .map(|journey| journey.destination_location_id)
                        .or_else(|| {
                            (event_type == "journey.completed")
                                .then_some(action.destination_location_id)
                        });
                    events.push(self.append_journey_event(
                        event_type,
                        action.actor_id,
                        narration,
                        journey_destination,
                    ));
                }
                ProjectionMutation::UpgradePathwayIfReady {
                    pathway_id,
                    progress_clock_id,
                } => {
                    let ready = self
                        .clocks
                        .get(progress_clock_id)
                        .is_some_and(|clock| clock.filled >= clock.segments);
                    let should_upgrade = ready
                        && self
                            .generated_pathways
                            .get(pathway_id)
                            .is_some_and(|pathway| !pathway.familiar);
                    if !should_upgrade {
                        continue;
                    }
                    if let Some(pathway) = self.generated_pathways.get_mut(pathway_id) {
                        pathway.familiar = true;
                    }
                    if let Some(clock) = self
                        .clocks
                        .get_mut(&generated_pathway_danger_clock_id(pathway_id))
                    {
                        clock.status = "quiet".to_string();
                    }
                    events.extend(self.set_job_status_events(
                        &generated_pathway_job_id(pathway_id),
                        "completed",
                        action.actor_id,
                        "pathway_familiarized",
                    ));
                    events.push(self.append_journey_event(
                        "pathway.familiarized",
                        action.actor_id,
                        "Travelers have made the whole way familiar; its lasting landscape can now take shape.",
                        None,
                    ));
                }
                ProjectionMutation::SearchFeature {
                    location_id,
                    feature_key,
                    feature_name,
                    content,
                    reason,
                } => {
                    let already_searched =
                        self.feature_search_claimed(action.actor_id, *location_id, feature_key);
                    let event = self.append_feature_search_event(
                        action.actor_id,
                        *location_id,
                        feature_name,
                        content,
                        reason,
                    );
                    events.push(event.clone());
                    let tag = RpgTagState {
                        id: feature_search_tag_id(action.actor_id, *location_id, feature_key),
                        scope: "actor".to_string(),
                        scope_id: action.actor_id,
                        label: format!("searched {feature_name}"),
                        kind: "memory".to_string(),
                        active: true,
                        source_event_seq: Some(event.seq),
                        expires: None,
                    };
                    if !already_searched {
                        if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                            events.push(tag_event);
                        }
                    }
                    if !already_searched {
                        if let Some(ledger_event) = self.mark_visit_ledger(
                            action.actor_id,
                            "feature",
                            "You recorded a room detail.",
                            event.seq,
                            &format!("feature_search:{location_id}:{feature_key}"),
                        ) {
                            events.push(ledger_event);
                        }
                    }
                    if !self.room_feature_search_claimed(*location_id, feature_key) {
                        let room_tag = RpgTagState {
                            id: room_feature_search_tag_id(*location_id, feature_key),
                            scope: "room".to_string(),
                            scope_id: *location_id,
                            label: format!("searched {feature_name}"),
                            kind: "discovery".to_string(),
                            active: true,
                            source_event_seq: Some(event.seq),
                            expires: None,
                        };
                        if let Some(tag_event) = self.set_rpg_tag(room_tag, action.actor_id, reason)
                        {
                            events.push(tag_event);
                        }
                    }
                }
                ProjectionMutation::SearchLocation {
                    location_id,
                    content,
                    reason,
                } => {
                    let already_searched =
                        self.location_search_claimed(action.actor_id, *location_id);
                    let event = self.append_location_search_event(
                        action.actor_id,
                        *location_id,
                        content,
                        reason,
                    );
                    events.push(event.clone());
                    let tag = RpgTagState {
                        id: location_search_tag_id(action.actor_id, *location_id),
                        scope: "actor".to_string(),
                        scope_id: action.actor_id,
                        label: "searched location".to_string(),
                        kind: "memory".to_string(),
                        active: true,
                        source_event_seq: Some(event.seq),
                        expires: None,
                    };
                    if !already_searched {
                        if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                            events.push(tag_event);
                        }
                    }
                    if !already_searched {
                        if let Some(ledger_event) = self.mark_visit_ledger(
                            action.actor_id,
                            "location",
                            "You noticed what this place keeps.",
                            event.seq,
                            &format!("location_search:{location_id}"),
                        ) {
                            events.push(ledger_event);
                        }
                    }
                    if !self.room_location_search_claimed(*location_id) {
                        let room_tag = RpgTagState {
                            id: room_location_search_tag_id(*location_id),
                            scope: "room".to_string(),
                            scope_id: *location_id,
                            label: "searched location".to_string(),
                            kind: "discovery".to_string(),
                            active: true,
                            source_event_seq: Some(event.seq),
                            expires: None,
                        };
                        if let Some(tag_event) = self.set_rpg_tag(room_tag, action.actor_id, reason)
                        {
                            events.push(tag_event);
                        }
                    }
                }
                ProjectionMutation::DiscoverSeedExit {
                    from_location_id,
                    to_location_id,
                    reason,
                } => {
                    let Some(exit) = self
                        .seed_exit_by_locations(*from_location_id, *to_location_id)
                        .cloned()
                    else {
                        continue;
                    };
                    if self.seed_exit_discovered(*from_location_id, *to_location_id) {
                        continue;
                    }
                    self.ensure_exit(exit.from_location_id, exit.to_location_id, exit.flags);
                    let reverse_exit = self
                        .seed_exit_by_locations(*to_location_id, *from_location_id)
                        .cloned();
                    if let Some(reverse) = reverse_exit.as_ref() {
                        self.ensure_exit(
                            reverse.from_location_id,
                            reverse.to_location_id,
                            reverse.flags,
                        );
                    }
                    let destination = self
                        .location_name(*to_location_id)
                        .unwrap_or_else(|| format!("Location {}", to_location_id));
                    let content = format!("A way to {destination} becomes clear.");
                    let event = self.append_exit_discovered_event(
                        action.actor_id,
                        *from_location_id,
                        *to_location_id,
                        content,
                    );
                    events.push(event.clone());

                    let mut discovered_exits = vec![exit];
                    if let Some(reverse) = reverse_exit {
                        discovered_exits.push(reverse);
                    }
                    let witness_actor_ids = self.search_witness_actor_ids(*from_location_id);
                    for discovered_exit in discovered_exits {
                        let tag_destination = self
                            .location_name(discovered_exit.to_location_id)
                            .unwrap_or_else(|| {
                                format!("Location {}", discovered_exit.to_location_id)
                            });
                        self.remember_search_discovery_for_actor_ids(
                            &witness_actor_ids,
                            discovered_exit.from_location_id,
                            SEARCH_MEMORY_KIND_SEED_EXIT,
                            discovered_exit.to_location_id,
                            &seed_exit_search_memory_subject_key(
                                discovered_exit.from_location_id,
                                discovered_exit.to_location_id,
                            ),
                        );
                        let tag = RpgTagState {
                            id: seed_exit_discovered_tag_id(
                                discovered_exit.from_location_id,
                                discovered_exit.to_location_id,
                            ),
                            scope: "room".to_string(),
                            scope_id: discovered_exit.from_location_id,
                            label: format!("path to {tag_destination}"),
                            kind: "discovery".to_string(),
                            active: true,
                            source_event_seq: Some(event.seq),
                            expires: None,
                        };
                        if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                            events.push(tag_event);
                        }
                    }
                }
                ProjectionMutation::DiscoverHiddenExit {
                    hidden_exit_id,
                    reason,
                } => {
                    let Some(hidden_exit) = self.hidden_exit_by_id(hidden_exit_id) else {
                        continue;
                    };
                    if self.hidden_exit_discovered(hidden_exit) {
                        continue;
                    }
                    self.ensure_exit(hidden_exit.from_location_id, hidden_exit.to_location_id, 0);
                    self.ensure_exit(hidden_exit.to_location_id, hidden_exit.from_location_id, 0);
                    let event = self.append_exit_discovered_event(
                        action.actor_id,
                        hidden_exit.from_location_id,
                        hidden_exit.to_location_id,
                        hidden_exit.discovery_text.clone(),
                    );
                    events.push(event.clone());
                    self.remember_search_discovery_for_witnesses(
                        hidden_exit.from_location_id,
                        SEARCH_MEMORY_KIND_HIDDEN_EXIT,
                        hidden_exit.to_location_id,
                        hidden_exit.id.clone(),
                    );
                    let destination = self
                        .location_name(hidden_exit.to_location_id)
                        .unwrap_or_else(|| format!("Location {}", hidden_exit.to_location_id));
                    let tag = RpgTagState {
                        id: hidden_exit_discovered_tag_id(&hidden_exit.id),
                        scope: "room".to_string(),
                        scope_id: hidden_exit.from_location_id,
                        label: format!("entrance to {destination}"),
                        kind: "discovery".to_string(),
                        active: true,
                        source_event_seq: Some(event.seq),
                        expires: None,
                    };
                    if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                        events.push(tag_event);
                    }
                }
                ProjectionMutation::DiscoverAvatar {
                    actor_id,
                    location_id,
                    reason,
                } => {
                    let Some(target) = self.actor_by_id(*actor_id) else {
                        continue;
                    };
                    if target.location_id != *location_id || self.avatar_discovered(*actor_id) {
                        continue;
                    }
                    let target_name = self
                        .actor_name(*actor_id)
                        .unwrap_or_else(|| format!("Avatar {}", actor_id));
                    let content = format!("{target_name} steps out of the room's hidden edge.");
                    let event = self.append_avatar_discovered_event(
                        action.actor_id,
                        *actor_id,
                        *location_id,
                        content,
                    );
                    events.push(event.clone());
                    self.remember_search_discovery_for_witnesses(
                        *location_id,
                        SEARCH_MEMORY_KIND_AVATAR,
                        *actor_id,
                        actor_id.to_string(),
                    );
                    let tag = RpgTagState {
                        id: avatar_discovered_tag_id(*actor_id),
                        scope: "actor".to_string(),
                        scope_id: *actor_id,
                        label: format!("discovered {target_name}"),
                        kind: "discovery".to_string(),
                        active: true,
                        source_event_seq: Some(event.seq),
                        expires: None,
                    };
                    if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                        events.push(tag_event);
                    }
                }
                ProjectionMutation::RememberSearchItem {
                    item_id,
                    location_id,
                    reason,
                } => {
                    let Some(item_name) = self.item_name(*item_id) else {
                        continue;
                    };
                    self.remember_search_discovery_for_witnesses(
                        *location_id,
                        SEARCH_MEMORY_KIND_ITEM,
                        *item_id,
                        item_id.to_string(),
                    );
                    let tag = RpgTagState {
                        id: search_item_found_tag_id(*item_id),
                        scope: "item".to_string(),
                        scope_id: *item_id,
                        label: format!("found {item_name}"),
                        kind: "discovery".to_string(),
                        active: true,
                        source_event_seq: events.last().map(|event| event.seq),
                        expires: None,
                    };
                    if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                        events.push(tag_event);
                    }
                }
                ProjectionMutation::UseFeature {
                    item_id,
                    location_id,
                    feature_key,
                    content,
                    reason,
                } => {
                    let event = self.append_feature_use_event(
                        action.actor_id,
                        *location_id,
                        *item_id,
                        content,
                        reason,
                    );
                    events.push(event.clone());
                    if feature_key.is_empty() {
                        continue;
                    }
                    let item_name = self
                        .item_name(*item_id)
                        .unwrap_or_else(|| format!("Item {item_id}"));
                    let tag = RpgTagState {
                        id: feature_use_tag_id(
                            action.actor_id,
                            *location_id,
                            feature_key,
                            *item_id,
                        ),
                        scope: "actor".to_string(),
                        scope_id: action.actor_id,
                        label: format!("used {item_name}"),
                        kind: "memory".to_string(),
                        active: true,
                        source_event_seq: Some(event.seq),
                        expires: None,
                    };
                    if let Some(tag_event) = self.set_rpg_tag(tag, action.actor_id, reason) {
                        events.push(tag_event);
                    }
                    if let Some(ledger_event) = self.mark_visit_ledger(
                        action.actor_id,
                        "feature",
                        "You made a held item matter in the room.",
                        event.seq,
                        &format!("feature_use:{location_id}:{feature_key}:{item_id}"),
                    ) {
                        events.push(ledger_event);
                    }
                }
                ProjectionMutation::AdvanceClock {
                    clock_id,
                    amount,
                    reason,
                } => events.extend(self.advance_clock(clock_id, *amount, action.actor_id, reason)),
                ProjectionMutation::ResolveJobContribution { intent } => {
                    let mut contribution_sources = committed_events.to_vec();
                    contribution_sources.extend(events.clone());
                    events.extend(self.resolve_job_contribution(
                        action,
                        &contribution_sources,
                        intent,
                    ));
                }
                ProjectionMutation::SetTag { tag, reason } => {
                    if let Some(event) = self.set_rpg_tag(tag.clone(), action.actor_id, reason) {
                        events.push(event);
                    }
                }
                ProjectionMutation::ClearTag { tag_id, reason } => {
                    if let Some(event) = self.clear_rpg_tag(tag_id, action.actor_id, reason) {
                        events.push(event);
                    }
                }
                ProjectionMutation::SetJobStatus {
                    job_id,
                    status,
                    reason,
                } => {
                    events.extend(self.set_job_status_events(
                        job_id,
                        status,
                        action.actor_id,
                        reason,
                    ));
                }
                ProjectionMutation::LegacyAcceptQuest { .. } => {
                    // The pre-worldpack prototype required explicit quest acceptance.
                    // Mounted jobs are active by construction now, so replay only needs
                    // to preserve this retired record's tick and causality.
                }
                ProjectionMutation::BankVisitLedger { reason } => {
                    if let Some(event) = self.bank_visit_ledger(action.actor_id, reason) {
                        events.push(event);
                    }
                }
                ProjectionMutation::SettleVisitLedgerAfterDiscovery { .. } => {
                    // Discovery settlement runs after the current action's marks
                    // have been projected. Keeping this as an explicit journal
                    // mutation preserves the historical order for older records.
                }
                ProjectionMutation::MarkVisitLedger {
                    category,
                    label,
                    source_event_seq,
                    reason,
                } => {
                    if let Some(event) = self.mark_visit_ledger(
                        action.actor_id,
                        category,
                        label,
                        *source_event_seq,
                        reason,
                    ) {
                        events.push(event);
                    }
                }
                ProjectionMutation::ChooseClass {
                    profile_id,
                    class_id,
                    calling,
                    starting_skill_id,
                    actor_meta,
                    reason,
                } => {
                    events.extend(self.choose_character_class(
                        action.actor_id,
                        profile_id,
                        class_id,
                        calling,
                        starting_skill_id,
                        actor_meta,
                        reason,
                    ));
                }
                ProjectionMutation::ReviseCalling {
                    statement,
                    cost,
                    reason,
                } => {
                    events.extend(self.revise_calling(action.actor_id, statement, *cost, reason));
                }
                ProjectionMutation::CreateBond {
                    target_actor_id,
                    statement,
                    cost,
                    reason,
                } => {
                    events.extend(self.create_bond(
                        action.actor_id,
                        *target_actor_id,
                        statement,
                        *cost,
                        reason,
                    ));
                }
                ProjectionMutation::ReviseBond {
                    target_actor_id,
                    statement,
                    cost,
                    reason,
                } => {
                    events.extend(self.revise_bond(
                        action.actor_id,
                        *target_actor_id,
                        statement,
                        *cost,
                        reason,
                    ));
                }
                ProjectionMutation::TrainSkill {
                    skill_id,
                    cost,
                    reason,
                } => {
                    events.extend(self.train_skill(action.actor_id, skill_id, *cost, reason));
                }
                ProjectionMutation::UnlockCharmSlot { cost, reason } => {
                    events.extend(self.unlock_charm_slot(action.actor_id, *cost, reason));
                }
                ProjectionMutation::UnlockCharmSlotForCharm {
                    item_id,
                    cost,
                    reason,
                } => {
                    events.extend(self.unlock_charm_slot_for_charm(
                        action.actor_id,
                        *item_id,
                        *cost,
                        reason,
                    ));
                }
                ProjectionMutation::SetCharmEquipped {
                    item_id,
                    equipped,
                    reason,
                } => {
                    events.extend(self.set_charm_equipped(
                        action.actor_id,
                        *item_id,
                        *equipped,
                        reason,
                    ));
                }
                ProjectionMutation::SetSpellPrepared {
                    item_id,
                    prepared,
                    reason,
                } => {
                    events.extend(self.set_spell_prepared(
                        action.actor_id,
                        *item_id,
                        *prepared,
                        reason,
                    ));
                }
                ProjectionMutation::SetItemEquipped {
                    item_id,
                    equipped,
                    reason,
                } => {
                    events.extend(self.set_item_equipped(
                        action.actor_id,
                        *item_id,
                        *equipped,
                        reason,
                    ));
                }
                ProjectionMutation::SetItemContained {
                    item_id,
                    container_item_id,
                    reason,
                } => {
                    events.extend(self.set_item_contained(
                        action.actor_id,
                        *item_id,
                        *container_item_id,
                        reason,
                    ));
                }
                ProjectionMutation::MaterializeItem {
                    receipt,
                    item,
                    meta,
                    reason,
                } => {
                    events.extend(self.materialize_item(
                        receipt.clone(),
                        *item,
                        meta.clone(),
                        reason,
                    ));
                }
                ProjectionMutation::UnmaterializeItem { receipt_id, reason } => {
                    events.extend(self.unmaterialize_item(action.actor_id, receipt_id, reason));
                }
                ProjectionMutation::DeepenBond {
                    target_actor_id,
                    claim_key,
                    event_reason,
                    ledger_reason,
                } => {
                    let source_event_seq = self.world.next_event_seq;
                    events.extend(self.deepen_bond_from_event(
                        action.actor_id,
                        *target_actor_id,
                        source_event_seq,
                        claim_key.clone(),
                        event_reason,
                        ledger_reason,
                    ));
                }
                ProjectionMutation::ResolveBond {
                    target_actor_id,
                    reason,
                } => {
                    events.extend(self.resolve_bond(action.actor_id, *target_actor_id, reason));
                }
            }
        }
        events
    }

    fn apply_event_lifecycle_hooks(
        &mut self,
        action: &CwAction,
        events: &[EventView],
        excluded_clock_ids: &BTreeSet<String>,
    ) -> Vec<EventView> {
        let mut projected = Vec::new();
        for event in events {
            if !event.success {
                continue;
            }
            if event.type_name == "actor.moved" && event.actor_id == Some(action.actor_id) {
                if let Some(destination_location_id) = event.destination_location_id {
                    projected.extend(self.apply_lifecycle_hooks_excluding_clocks(
                        "on_enter",
                        "room",
                        &destination_location_id.to_string(),
                        action.actor_id,
                        event.seq,
                        excluded_clock_ids,
                    ));
                }
            } else if event.type_name == "item.used" && event.actor_id == Some(action.actor_id) {
                if let Some(item_id) = event.item_id {
                    projected.extend(self.apply_lifecycle_hooks_excluding_clocks(
                        "on_use",
                        "item",
                        &item_id.to_string(),
                        action.actor_id,
                        event.seq,
                        excluded_clock_ids,
                    ));
                }
            } else if event.type_name == "item.given" && event.actor_id == Some(action.actor_id) {
                if let Some(target_actor_id) = event.target_actor_id {
                    projected.extend(self.apply_lifecycle_hooks_excluding_clocks(
                        "on_give",
                        "actor",
                        &target_actor_id.to_string(),
                        action.actor_id,
                        event.seq,
                        excluded_clock_ids,
                    ));
                }
            }
        }
        projected
    }

    fn apply_lifecycle_hooks_excluding_clocks(
        &mut self,
        hook_name: &str,
        target_kind: &str,
        target_id: &str,
        actor_id: u64,
        source_event_seq: u64,
        excluded_clock_ids: &BTreeSet<String>,
    ) -> Vec<EventView> {
        let mut projected = Vec::new();
        for hook in lifecycle_hooks_for(hook_name, target_kind, target_id) {
            let effects = hook
                .effects
                .iter()
                .filter(|effect| {
                    !matches!(
                        effect,
                        EffectDescriptor::AdvanceClock { clock_id, .. }
                            if excluded_clock_ids.contains(clock_id)
                    )
                })
                .cloned()
                .collect::<Vec<_>>();
            if effects.is_empty() {
                continue;
            }
            if let Some(claim_key) =
                lifecycle_hook_claim_key(hook, actor_id, target_kind, target_id, source_event_seq)
            {
                if !self.rpg_claims.insert(claim_key) {
                    continue;
                }
            }
            projected.extend(self.apply_lifecycle_effects(
                hook_name,
                actor_id,
                source_event_seq,
                &effects,
            ));
        }
        projected
    }

    fn apply_lifecycle_effects(
        &mut self,
        hook_name: &str,
        actor_id: u64,
        source_event_seq: u64,
        effects: &[EffectDescriptor],
    ) -> Vec<EventView> {
        if effects.is_empty() || self.validate_runtime_effects(effects).is_err() {
            return Vec::new();
        }
        let mut events = Vec::new();
        for effect in effects {
            match effect {
                EffectDescriptor::AdvanceClock {
                    clock_id,
                    amount,
                    reason,
                } => events.extend(self.advance_clock(
                    clock_id,
                    *amount,
                    actor_id,
                    reason.as_deref().unwrap_or(hook_name),
                )),
                EffectDescriptor::SetTag {
                    tag_id,
                    scope,
                    scope_id,
                    label,
                    kind,
                    expires,
                    reason,
                } => {
                    let tag = RpgTagState {
                        id: tag_id.clone(),
                        scope: scope.clone(),
                        scope_id: *scope_id,
                        label: label.clone(),
                        kind: kind.clone(),
                        active: true,
                        source_event_seq: Some(source_event_seq),
                        expires: expires.clone(),
                    };
                    if let Some(event) =
                        self.set_rpg_tag(tag, actor_id, reason.as_deref().unwrap_or(hook_name))
                    {
                        events.push(event);
                    }
                }
                EffectDescriptor::ClearTag { tag_id, reason } => {
                    if let Some(event) =
                        self.clear_rpg_tag(tag_id, actor_id, reason.as_deref().unwrap_or(hook_name))
                    {
                        events.push(event);
                    }
                }
                EffectDescriptor::SetJobStatus {
                    job_id,
                    status,
                    reason,
                } => {
                    events.extend(self.set_job_status_events(
                        job_id,
                        status,
                        actor_id,
                        reason.as_deref().unwrap_or(hook_name),
                    ));
                }
            }
        }
        events
    }

    fn apply_actor_creation_rpg_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
        initial_calling: Option<&str>,
        initial_skill: Option<&str>,
        initial_character_profile_id: Option<&str>,
        initial_species_id: Option<&str>,
        initial_origin_id: Option<&str>,
        initial_physical_description: Option<&str>,
    ) -> Vec<EventView> {
        if action.kind != CW_ACTION_CREATE_ACTOR || self.callings.contains_key(&action.actor_id) {
            return Vec::new();
        }
        let Some(actor) = self.actor_by_id(action.actor_id) else {
            return Vec::new();
        };
        if !Self::actor_is_active_avatar(actor) {
            return Vec::new();
        }
        if let (Some(profile_id), Some(species_id), Some(origin_id)) = (
            initial_character_profile_id,
            initial_species_id,
            initial_origin_id,
        ) {
            self.character_identities
                .entry(action.actor_id)
                .or_insert_with(|| AvatarIdentityState {
                    actor_id: action.actor_id,
                    profile_id: profile_id.to_string(),
                    species_id: species_id.to_string(),
                    origin_id: origin_id.to_string(),
                    physical_description: initial_physical_description
                        .map(compact_whitespace)
                        .unwrap_or_default(),
                    class_id: None,
                    class_selection_ready: false,
                    qualifying_world_actions: 0,
                    class_source_event_seq: None,
                });
        }
        let source_event_seq = events
            .iter()
            .find(|event| event.actor_id == Some(action.actor_id))
            .map(|event| event.seq);
        let calling = CallingState {
            actor_id: action.actor_id,
            statement: initial_calling
                .and_then(normalize_calling_statement)
                .unwrap_or_else(|| default_calling_statement().to_string()),
            source_event_seq,
        };
        self.callings.insert(action.actor_id, calling.clone());
        let reason = initial_calling
            .and_then(normalize_calling_statement)
            .map(|_| "chosen_calling")
            .unwrap_or("avatar_created");
        let mut projection_events =
            vec![self.append_calling_event("calling.set", &calling, reason)];
        if let Some(skill_id) = initial_skill.filter(|skill_id| skill_label(skill_id).is_some()) {
            let id = skill_state_id(action.actor_id, skill_id);
            if !self.skills.contains_key(&id) {
                let skill = SkillState {
                    actor_id: action.actor_id,
                    skill_id: skill_id.to_string(),
                    label: skill_label(skill_id).unwrap_or("Knack").to_string(),
                    rank: 1,
                    updated_event_seq: Some(self.world.next_event_seq),
                };
                self.skills.insert(id, skill.clone());
                projection_events.push(self.append_skill_event(
                    "skill.stepped",
                    &skill,
                    "character_creation",
                ));
            }
        }
        projection_events
    }

    fn apply_class_readiness_projection(
        &mut self,
        record: &JournalRecord,
        action: &CwAction,
        committed_events: &[EventView],
    ) -> Vec<EventView> {
        if action.actor_id == 0
            || action.kind == CW_ACTION_CREATE_ACTOR
            || !matches!(
                record.origin,
                JournalOrigin::PlayerCard | JournalOrigin::Speech
            )
        {
            return Vec::new();
        }
        if action.kind == CW_ACTION_NONE
            && !record.projection_mutations.is_empty()
            && record
                .projection_mutations
                .iter()
                .all(|mutation| matches!(mutation, ProjectionMutation::ShuffleHand { .. }))
        {
            return Vec::new();
        }
        let shared_world_contribution = committed_events.iter().any(|event| {
            event.type_name == "job.contribution.resolved"
                && event.actor_id == Some(action.actor_id)
                && event
                    .content
                    .as_deref()
                    .and_then(|content| serde_json::from_str::<JobContributionTrace>(content).ok())
                    .is_some_and(|trace| trace.total_progress > 0)
        });
        if !shared_world_contribution {
            return Vec::new();
        }
        let became_ready = {
            let Some(identity) = self.character_identities.get_mut(&action.actor_id) else {
                return Vec::new();
            };
            if identity.class_id.is_some() || identity.class_selection_ready {
                return Vec::new();
            }
            identity.qualifying_world_actions = identity.qualifying_world_actions.saturating_add(1);
            identity.class_selection_ready = identity.qualifying_world_actions >= 1;
            identity.class_selection_ready
        };
        became_ready
            .then(|| {
                self.append_async_job_event(
                    "class.selection_ready",
                    action.actor_id,
                    None,
                    Some(
                        "Your contribution changed the shared world. Optional campaign rules are now available."
                            .to_string(),
                    ),
                )
            })
            .into_iter()
            .collect()
    }

    fn choose_character_class(
        &mut self,
        actor_id: u64,
        profile_id: &str,
        class_id: &str,
        calling_statement: &str,
        starting_skill_id: &str,
        actor_meta: &ActorMeta,
        reason: &str,
    ) -> Vec<EventView> {
        let valid_identity = self
            .character_identities
            .get(&actor_id)
            .is_some_and(|identity| {
                identity.profile_id == profile_id
                    && identity.class_id.is_none()
                    && identity.class_selection_ready
            });
        if !valid_identity {
            return Vec::new();
        }
        let Some(actor_index) = self.world.actors[..self.world.actor_count]
            .iter()
            .position(|actor| actor.id == actor_id && Self::actor_is_active_avatar(*actor))
        else {
            return Vec::new();
        };
        self.world.actors[actor_index].stats.level = 1;
        self.actors.insert(actor_id, actor_meta.clone());
        if let Some(identity) = self.character_identities.get_mut(&actor_id) {
            identity.class_id = Some(class_id.to_string());
            identity.class_selection_ready = false;
        }

        let mut events = Vec::new();
        let class_event = self.append_async_job_event(
            "class.chosen",
            actor_id,
            None,
            Some(format!("{class_id}:{reason}")),
        );
        if let Some(identity) = self.character_identities.get_mut(&actor_id) {
            identity.class_source_event_seq = Some(class_event.seq);
        }
        events.push(class_event);

        let calling = CallingState {
            actor_id,
            statement: normalize_calling_statement(calling_statement)
                .unwrap_or_else(|| default_calling_statement().to_string()),
            source_event_seq: events.first().map(|event| event.seq),
        };
        self.callings.insert(actor_id, calling.clone());
        events.push(self.append_calling_event("calling.set", &calling, "class_chosen"));

        if let Some(label) = skill_label(starting_skill_id) {
            let id = skill_state_id(actor_id, starting_skill_id);
            if !self.skills.contains_key(&id) {
                let skill = SkillState {
                    actor_id,
                    skill_id: starting_skill_id.to_string(),
                    label: label.to_string(),
                    rank: 1,
                    updated_event_seq: Some(self.world.next_event_seq),
                };
                self.skills.insert(id, skill.clone());
                events.push(self.append_skill_event("skill.stepped", &skill, "class_chosen"));
            }
        }
        events
    }

    fn apply_progress_contribution_ledger_projection(
        &mut self,
        events: &[EventView],
    ) -> Vec<EventView> {
        let mut projected = Vec::new();
        for event in events {
            if event.type_name != "clock.updated" || event.clock_kind.as_deref() != Some("progress")
            {
                continue;
            }
            let legacy_work_or_help = matches!(
                event.content.as_deref(),
                Some(
                    "work"
                        | "prepared_work"
                        | "informed_work"
                        | "help"
                        | "prepared_help"
                        | "informed_help"
                )
            );
            let authoritative_work_or_help = event
                .caused_by_event_seq
                .and_then(|cause_seq| events.iter().find(|candidate| candidate.seq == cause_seq))
                .filter(|candidate| candidate.type_name == "job.contribution.resolved")
                .and_then(|candidate| candidate.content.as_deref())
                .and_then(|content| serde_json::from_str::<JobContributionTrace>(content).ok())
                .is_some_and(|trace| matches!(trace.action_kind.as_str(), "work" | "help"));
            if !legacy_work_or_help && !authoritative_work_or_help {
                continue;
            }
            let Some(actor_id) = event.actor_id else {
                continue;
            };
            let Some(clock_id) = event.clock_id.as_deref() else {
                continue;
            };
            if let Some(event) = self.mark_visit_ledger(
                actor_id,
                "helped",
                "You helped move a shared project forward.",
                event.seq,
                &format!("clock:{clock_id}:helped"),
            ) {
                projected.push(event);
            }
        }
        projected
    }

    fn apply_frontier_return_ledger_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
    ) -> Vec<EventView> {
        if !matches!(action.kind, CW_ACTION_FLEE | CW_ACTION_COMBAT_ESCAPE) {
            return Vec::new();
        }
        let mut projected = Vec::new();
        for event in events {
            if event.type_name != "combat.flee.success"
                || !event.success
                || event.actor_id != Some(action.actor_id)
            {
                continue;
            }
            let Some(from_location_id) = event.location_id else {
                continue;
            };
            let to_location_id = event
                .destination_location_id
                .unwrap_or(action.destination_location_id);
            if !self.location_is_frontier(from_location_id)
                || self.location_is_frontier(to_location_id)
            {
                continue;
            }
            if let Some(event) = self.mark_visit_ledger(
                action.actor_id,
                "frontier_return",
                "You dared the frontier and returned.",
                event.seq,
                &format!("flee:{from_location_id}:{to_location_id}:frontier_return"),
            ) {
                projected.push(event);
            }
        }
        projected
    }

    fn apply_frontier_travel_since_rest_projection(
        &mut self,
        events: &[EventView],
    ) -> Vec<EventView> {
        let mut projected = Vec::new();
        for event in events {
            if event.type_name != "actor.moved" || !event.success {
                continue;
            }
            let Some(actor_id) = event.actor_id else {
                continue;
            };
            let Some(actor) = self.actor_by_id(actor_id) else {
                continue;
            };
            if !Self::actor_is_active_avatar(actor) {
                continue;
            }
            let from_location_id = event.location_id.unwrap_or(0);
            let to_location_id = event.destination_location_id.unwrap_or(0);
            if !self.location_is_frontier(from_location_id)
                && !self.location_is_frontier(to_location_id)
            {
                continue;
            }
            let tag = RpgTagState {
                id: frontier_travel_since_rest_tag_id(actor_id, event.seq),
                scope: "actor".to_string(),
                scope_id: actor_id,
                label: "frontier travel".to_string(),
                kind: "memory".to_string(),
                active: true,
                source_event_seq: Some(event.seq),
                expires: Some("after_rest".to_string()),
            };
            if let Some(event) = self.set_rpg_tag(tag, actor_id, "frontier_travel") {
                projected.push(event);
            }
        }
        projected
    }

    fn deepen_bond_from_event(
        &mut self,
        actor_id: u64,
        target_actor_id: u64,
        source_event_seq: u64,
        claim_key: String,
        event_reason: &str,
        ledger_reason: &str,
    ) -> Vec<EventView> {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return Vec::new();
        };
        let Some(target) = self.actor_by_id(target_actor_id) else {
            return Vec::new();
        };
        if !Self::actor_is_active_avatar(actor)
            || !Self::actor_is_active_avatar(target)
            || actor.id == target.id
        {
            return Vec::new();
        }
        if !self.rpg_claims.insert(claim_key) {
            return Vec::new();
        }

        let target_name = self
            .actor_name(target_actor_id)
            .unwrap_or_else(|| format!("Resident {target_actor_id}"));
        let id = bond_id(actor_id, target_actor_id);
        let bond = {
            let bond = self.bonds.entry(id.clone()).or_insert_with(|| BondState {
                id,
                actor_id,
                target_actor_id,
                statement: default_bond_statement(&target_name),
                strength: 0,
                status: "active".to_string(),
                source_event_seq: Some(source_event_seq),
                updated_event_seq: None,
            });
            bond.strength = bond.strength.saturating_add(1).min(3);
            bond.status = "active".to_string();
            bond.updated_event_seq = Some(source_event_seq);
            bond.clone()
        };

        let mut projected = vec![self.append_bond_event("bond.deepened", &bond, event_reason)];
        if let Some(ledger_event) = self.mark_visit_ledger(
            actor_id,
            "bond",
            &format!("You grew closer to {target_name}."),
            source_event_seq,
            ledger_reason,
        ) {
            projected.push(ledger_event);
        }
        projected
    }

    fn apply_gift_bond_projection(&mut self, events: &[EventView]) -> Vec<EventView> {
        let mut projected = Vec::new();
        for event in events {
            if event.type_name != "item.given" || !event.success {
                continue;
            }
            let (Some(actor_id), Some(target_actor_id), Some(item_id)) =
                (event.actor_id, event.target_actor_id, event.item_id)
            else {
                continue;
            };
            projected.extend(self.deepen_bond_from_event(
                actor_id,
                target_actor_id,
                event.seq,
                gift_bond_claim_key(actor_id, target_actor_id, item_id),
                "resident_gift",
                &format!("gift:{actor_id}:{target_actor_id}:{item_id}:bond"),
            ));
        }
        projected
    }

    fn apply_resident_feature_bond_projection(&mut self, events: &[EventView]) -> Vec<EventView> {
        let mut projected = Vec::new();
        for event in events {
            if event.type_name != "item.used" || !event.success {
                continue;
            }
            let Some(actor_id) = event.actor_id else {
                continue;
            };
            let Some(target) = FEATURE_BOND_TARGETS.iter().find(|target| {
                event.location_id == Some(target.location_id)
                    && event.item_id == Some(target.item_id)
            }) else {
                continue;
            };
            projected.extend(self.deepen_bond_from_event(
                actor_id,
                target.target_actor_id,
                event.seq,
                feature_bond_claim_key(actor_id, target),
                target.reason,
                &format!(
                    "feature_use:{actor_id}:{}:{}:{}:{}:bond",
                    target.target_actor_id, target.location_id, target.feature_key, target.item_id
                ),
            ));
        }
        projected
    }

    fn apply_resident_witness_ledger_projection(&mut self, events: &[EventView]) -> Vec<EventView> {
        let evolved_item_pairs = events
            .iter()
            .filter(|event| event.type_name == "avatar.evolved" && event.success)
            .filter_map(|event| Some((event.target_actor_id?, event.item_id.unwrap_or(0))))
            .collect::<BTreeSet<_>>();
        let mut projected = Vec::new();
        for event in events {
            let Some((location_id, label, reason)) =
                self.resident_witness_ledger_context(event, &evolved_item_pairs)
            else {
                continue;
            };
            let witness_actor_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
                .iter()
                .filter(|actor| {
                    Self::actor_is_active_avatar(**actor) && actor.location_id == location_id
                })
                .map(|actor| actor.id)
                .collect();
            for actor_id in witness_actor_ids {
                if let Some(event) =
                    self.mark_visit_ledger(actor_id, "witness", &label, event.seq, &reason)
                {
                    projected.push(event);
                }
            }
        }
        projected
    }

    fn resident_witness_ledger_context(
        &self,
        event: &EventView,
        evolved_item_pairs: &BTreeSet<(u64, u64)>,
    ) -> Option<(u64, String, String)> {
        match event.type_name.as_str() {
            "item.picked_up" => {
                let resident_id = event.actor_id?;
                let resident = self.actor_by_id(resident_id)?;
                if !Self::actor_is_active_avatar(resident) {
                    return None;
                }
                let item_id = event.item_id?;
                if evolved_item_pairs.contains(&(resident_id, item_id))
                    || !self.resident_item_claim_is_witnessable(resident, item_id)
                {
                    return None;
                }
                let location_id = event.location_id.or(Some(resident.location_id))?;
                let resident_name = self
                    .actor_name(resident_id)
                    .unwrap_or_else(|| format!("Resident {resident_id}"));
                let item_name = self
                    .item_name(item_id)
                    .unwrap_or_else(|| format!("Item {item_id}"));
                Some((
                    location_id,
                    format!("noticed {resident_name} tuck away {item_name}."),
                    format!(
                        "witness:resident_item_claimed:{resident_id}:{item_id}:{}",
                        event.seq
                    ),
                ))
            }
            "avatar.evolved" => {
                let source_actor_id = event.actor_id?;
                let source = self.actor_by_id(source_actor_id)?;
                if !Self::actor_is_active_avatar(source) {
                    return None;
                }
                let resident_id = event.target_actor_id?;
                let resident = self.actor_by_id(resident_id)?;
                if !Self::actor_is_active_avatar(resident) {
                    return None;
                }
                let location_id = event.location_id.or(Some(resident.location_id))?;
                let resident_name = self
                    .actor_name(resident_id)
                    .unwrap_or_else(|| format!("Resident {resident_id}"));
                Some((
                    location_id,
                    format!("watched {resident_name} find a new shape."),
                    format!(
                        "witness:resident_evolved:{resident_id}:{}:{}",
                        event.item_id.unwrap_or(0),
                        event.seq
                    ),
                ))
            }
            _ => None,
        }
    }

    fn resident_item_claim_is_witnessable(&self, resident: CwActor, item_id: u64) -> bool {
        evolution_item_matches_resident(item_id, resident.id)
            || self
                .resident_personal_desire_for_item(resident.id, item_id)
                .is_some()
            || self
                .resident_personal_attachment_for_item(resident.id, item_id)
                .is_some()
            || self
                .resident_feature_use_match_for_item(resident, item_id)
                .is_some()
            || self.item_by_id(item_id).is_some_and(|item| {
                item.kind == CW_ITEM_POTION && self.resident_healing_target(resident).is_some()
            })
    }

    fn apply_listen_rpg_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
        was_repeat_listen: bool,
        settlement_reason: Option<&str>,
        excluded_clock_ids: &BTreeSet<String>,
    ) -> Vec<EventView> {
        if !action_is_discovery_check(action) {
            return Vec::new();
        }
        let Some(listen_event) = events.iter().find(|event| {
            event.type_name == "ability_check.rolled" && event.actor_id == Some(action.actor_id)
        }) else {
            return Vec::new();
        };
        let Some(location_id) = listen_event.location_id else {
            return Vec::new();
        };

        let mut projected = Vec::new();
        let discovery_mode = if action.kind == CW_ACTION_RULES_STUDY {
            "study"
        } else {
            "search"
        };
        let listen_succeeded = listen_event.success
            && listen_event
                .total
                .zip(listen_event.dc)
                .map(|(total, dc)| total >= dc)
                .unwrap_or(false);
        if settlement_reason.is_none() {
            if let Some(event) = self.bank_visit_ledger(action.actor_id, discovery_mode) {
                projected.push(event);
            }
        }
        if listen_succeeded {
            projected.extend(self.apply_listen_ledger_projection(
                action.actor_id,
                location_id,
                listen_event.seq,
            ));
            projected.extend(self.apply_lifecycle_hooks_excluding_clocks(
                if action.kind == CW_ACTION_RULES_STUDY {
                    "on_study"
                } else {
                    "on_listen"
                },
                "room",
                &location_id.to_string(),
                action.actor_id,
                listen_event.seq,
                excluded_clock_ids,
            ));
            if let Some(reason) = settlement_reason {
                if let Some(event) = self.bank_visit_ledger(action.actor_id, reason) {
                    projected.push(event);
                }
            }
        }

        if was_repeat_listen && self.location_is_frontier(location_id) {
            let tag = RpgTagState {
                id: tired_tag_id(action.actor_id),
                scope: "actor".to_string(),
                scope_id: action.actor_id,
                label: "tired".to_string(),
                kind: "condition".to_string(),
                active: true,
                source_event_seq: Some(listen_event.seq),
                expires: Some("after_rest".to_string()),
            };
            if let Some(event) = self.set_rpg_tag(tag, action.actor_id, "repeat_listen") {
                projected.push(event);
            }
        }

        projected
    }

    fn apply_first_tale_public_trace_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
    ) -> Vec<EventView> {
        if !action_is_discovery_check(action)
            || self.first_tale_trace_event_seq(action.actor_id).is_some()
            || !self.listen_attempt_claimed_at(action.actor_id, COSY_COTTAGE_LOCATION_ID)
        {
            return Vec::new();
        }
        let Some(check) = events.iter().find(|event| {
            event.type_name == "ability_check.rolled"
                && event.actor_id == Some(action.actor_id)
                && event.location_id == Some(RAIN_SOFT_GARDEN_LOCATION_ID)
        }) else {
            return Vec::new();
        };
        if !check.success
            || !check
                .total
                .zip(check.dc)
                .is_some_and(|(total, dc)| total >= dc)
        {
            return Vec::new();
        }

        let mut trace = self.append_async_job_event(
            "first_tale.public_trace",
            action.actor_id,
            None,
            Some(
                "marked the first uncovered stone so the next visitor can trust the washed path"
                    .to_string(),
            ),
        );
        trace.caused_by_event_seq = Some(check.seq);
        self.replace_projected_event(&trace);
        self.rpg_claims
            .insert(first_tale_trace_claim_key(action.actor_id, trace.seq));
        vec![trace]
    }

    fn apply_bounded_magic_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
    ) -> Vec<EventView> {
        if action.kind != CW_ACTION_RULES_MAGIC {
            return Vec::new();
        }
        let Some(event) = events.iter().find(|event| {
            event.type_name == "magic.spell_cast"
                && event.success
                && event.actor_id == Some(action.actor_id)
                && event.item_id == Some(action.item_id)
        }) else {
            return Vec::new();
        };
        let Some(meta) = self.items.get(&action.item_id) else {
            return Vec::new();
        };
        if meta
            .mechanics
            .as_ref()
            .and_then(|mechanics| mechanics.magic_effect.as_deref())
            != Some("cosyworld.magic/steady-light")
        {
            return Vec::new();
        }
        let target_actor_id = event.target_actor_id.unwrap_or(action.actor_id);
        self.set_rpg_tag(
            RpgTagState {
                id: format!("spell:steady-light:{target_actor_id}"),
                scope: "actor".to_string(),
                scope_id: target_actor_id,
                label: "steady light".to_string(),
                kind: "boon".to_string(),
                active: true,
                source_event_seq: Some(event.seq),
                expires: Some("after_rest".to_string()),
            },
            action.actor_id,
            "cosyworld.magic/steady-light",
        )
        .into_iter()
        .collect()
    }

    fn apply_influence_projection(
        &mut self,
        action: &CwAction,
        events: &[EventView],
    ) -> Vec<EventView> {
        if action.kind != CW_ACTION_RULES_INFLUENCE {
            return Vec::new();
        }
        let Some(target) = self.actor_by_id(action.target_actor_id) else {
            return Vec::new();
        };
        if !Self::actor_is_active_avatar(target) {
            return Vec::new();
        }
        let Some(check) = events.iter().find(|event| {
            event.type_name == "ability_check.rolled" && event.actor_id == Some(action.actor_id)
        }) else {
            return Vec::new();
        };
        let succeeded = check
            .total
            .zip(check.dc)
            .is_some_and(|(total, dc)| total >= dc);
        let outcome = if succeeded { "cooperates" } else { "declines" };
        let attitude = if succeeded { "cooperative" } else { "cautious" };
        let key = format!("{}:{}", action.actor_id, action.target_actor_id);
        let attempts = self
            .npc_cooperation
            .get(&key)
            .map(|state| state.attempts.saturating_add(1))
            .unwrap_or(1);
        self.npc_cooperation.insert(
            key,
            NpcCooperationState {
                actor_id: action.actor_id,
                target_actor_id: action.target_actor_id,
                desired_cooperation: "share one useful local lead".to_string(),
                attitude: attitude.to_string(),
                outcome: outcome.to_string(),
                attempts,
                source_event_seq: check.seq,
            },
        );
        let target_name = self
            .actor_name(action.target_actor_id)
            .unwrap_or_else(|| format!("Resident {}", action.target_actor_id));
        vec![self.append_async_job_event(
            "influence.committed",
            action.actor_id,
            Some(action.target_actor_id),
            Some(format!(
                "{target_name} {outcome}: the authored request was to share one useful local lead."
            )),
        )]
    }

    fn apply_listen_ledger_projection(
        &mut self,
        actor_id: u64,
        location_id: u64,
        source_event_seq: u64,
    ) -> Vec<EventView> {
        let mut events = Vec::new();
        if let Some(event) = self.mark_visit_ledger(
            actor_id,
            "learned_truth",
            "You learned a true thing by listening.",
            source_event_seq,
            &format!("listen:{location_id}:learned_truth"),
        ) {
            events.push(event);
        }
        if self
            .callings
            .get(&actor_id)
            .map(|calling| calling_matches_listen(&calling.statement))
            .unwrap_or(false)
        {
            if let Some(event) = self.mark_visit_ledger(
                actor_id,
                "calling",
                "You followed what draws you by listening closely.",
                source_event_seq,
                &format!("listen:{location_id}:calling"),
            ) {
                events.push(event);
            }
        }
        events
    }

    fn listen_context_for_action(
        &self,
        action: &CwAction,
        events: &[EventView],
    ) -> Option<(u64, u64)> {
        if !action_is_discovery_check(action) {
            return None;
        }
        let location_id = events
            .iter()
            .find(|event| {
                event.type_name == "ability_check.rolled" && event.actor_id == Some(action.actor_id)
            })
            .and_then(|event| event.location_id)
            .or_else(|| {
                self.actor_by_id(action.actor_id)
                    .map(|actor| actor.location_id)
            })?;
        Some((action.actor_id, location_id))
    }

    fn advance_clock(
        &mut self,
        clock_id: &str,
        amount: u8,
        actor_id: u64,
        reason: &str,
    ) -> Vec<EventView> {
        if amount == 0 {
            return Vec::new();
        }
        let next_seq = self.world.next_event_seq;
        let Some(clock) = self.clocks.get_mut(clock_id) else {
            return Vec::new();
        };
        let before = clock.filled;
        let after = before.saturating_add(amount).min(clock.segments);
        if after == before {
            return Vec::new();
        }
        let crossed_fill = before < clock.segments && after >= clock.segments;
        clock.filled = after;
        clock.status = if clock.filled >= clock.segments {
            "filled".to_string()
        } else {
            "active".to_string()
        };
        clock.updated_event_seq = Some(next_seq);
        if crossed_fill && clock.completion.is_none() {
            clock.completion = Some(ClockCompletionMemory {
                actor_id,
                event_seq: next_seq,
                text: clock.presentation.completion_memory.clone(),
            });
        }
        let clock = clock.clone();
        let update_event = self.append_clock_event(
            "clock.updated",
            actor_id,
            &clock,
            i16::from(after.saturating_sub(before)),
            reason,
        );
        let mut events = vec![update_event.clone()];
        let crossed_thresholds = self
            .jobs
            .values()
            .flat_map(|job| job.narrated_thresholds.iter())
            .filter(|threshold| {
                threshold.clock_id == clock.id
                    && before < threshold.filled
                    && after >= threshold.filled
            })
            .cloned()
            .collect::<Vec<_>>();
        for threshold in crossed_thresholds {
            let mut event =
                self.append_clock_event("clock.threshold", actor_id, &clock, 0, &threshold.text);
            event.caused_by_event_seq = Some(update_event.seq);
            self.replace_projected_event(&event);
            events.push(event);
        }
        if crossed_fill && !clock.on_fill.is_empty() {
            let claim_key = clock_fill_claim_key(&clock.id, update_event.seq);
            if self.rpg_claims.insert(claim_key) {
                let mut fill_events = self.apply_clock_fill_effects(
                    &clock.id,
                    actor_id,
                    update_event.seq,
                    &clock.on_fill,
                );
                self.link_events_to_cause(&mut fill_events, update_event.seq);
                events.extend(fill_events);
            }
        }
        events
    }

    fn record_clock_contribution(
        &mut self,
        actor_id: u64,
        trace: &JobContributionTrace,
        contribution_event_seq: u64,
        clock_event: &EventView,
    ) {
        let progress = clock_event
            .clock_delta
            .and_then(|delta| u8::try_from(delta).ok())
            .unwrap_or_default();
        if progress == 0 {
            return;
        }
        self.push_clock_contribution_memory(
            &trace.clock_id,
            ClockContributionMemory {
                actor_id,
                strategy_id: trace.strategy_id.clone(),
                strategy_label: trace.strategy_label.clone(),
                target_label: trace.target.label.clone(),
                progress,
                contribution_event_seq,
                clock_event_seq: clock_event.seq,
            },
        );
    }

    fn push_clock_contribution_memory(
        &mut self,
        clock_id: &str,
        contribution: ClockContributionMemory,
    ) {
        let Some(clock) = self.clocks.get_mut(clock_id) else {
            return;
        };
        if clock
            .recent_contributions
            .iter()
            .any(|entry| entry.contribution_event_seq == contribution.contribution_event_seq)
        {
            return;
        }
        clock.recent_contributions.push(contribution);
        clock
            .recent_contributions
            .sort_by_key(|entry| entry.contribution_event_seq);
        if clock.recent_contributions.len() > MAX_RECENT_CLOCK_CONTRIBUTIONS {
            let discard = clock
                .recent_contributions
                .len()
                .saturating_sub(MAX_RECENT_CLOCK_CONTRIBUTIONS);
            clock.recent_contributions.drain(..discard);
        }
    }

    fn replace_projected_event(&mut self, replacement: &EventView) {
        if let Some(event) = self
            .event_log
            .iter_mut()
            .rev()
            .find(|event| event.seq == replacement.seq)
        {
            *event = replacement.clone();
        }
    }

    fn link_events_to_cause(&mut self, events: &mut [EventView], cause_event_seq: u64) {
        for event in events {
            if event.caused_by_event_seq.is_none() {
                event.caused_by_event_seq = Some(cause_event_seq);
                self.replace_projected_event(event);
            }
        }
    }

    fn apply_clock_fill_effects(
        &mut self,
        clock_id: &str,
        actor_id: u64,
        source_event_seq: u64,
        effects: &[EffectDescriptor],
    ) -> Vec<EventView> {
        if effects.is_empty() {
            return Vec::new();
        }
        if let Err(error) = self.validate_clock_fill_effects(effects) {
            return self
                .clocks
                .get(clock_id)
                .cloned()
                .map(|clock| {
                    vec![self.append_clock_event(
                        "clock.fill_effect_rejected",
                        actor_id,
                        &clock,
                        0,
                        &error,
                    )]
                })
                .unwrap_or_default();
        }

        let mut events = Vec::new();
        for effect in effects {
            match effect {
                EffectDescriptor::AdvanceClock {
                    clock_id,
                    amount,
                    reason,
                } => events.extend(self.advance_clock(
                    clock_id,
                    *amount,
                    actor_id,
                    reason.as_deref().unwrap_or("clock_fill_effect"),
                )),
                EffectDescriptor::SetTag {
                    tag_id,
                    scope,
                    scope_id,
                    label,
                    kind,
                    expires,
                    reason,
                } => {
                    let tag = RpgTagState {
                        id: tag_id.clone(),
                        scope: scope.clone(),
                        scope_id: *scope_id,
                        label: label.clone(),
                        kind: kind.clone(),
                        active: true,
                        source_event_seq: Some(source_event_seq),
                        expires: expires.clone(),
                    };
                    if let Some(event) =
                        self.set_rpg_tag(tag, actor_id, reason.as_deref().unwrap_or("clock_fill"))
                    {
                        events.push(event);
                    }
                }
                EffectDescriptor::ClearTag { tag_id, reason } => {
                    if let Some(event) = self.clear_rpg_tag(
                        tag_id,
                        actor_id,
                        reason.as_deref().unwrap_or("clock_fill"),
                    ) {
                        events.push(event);
                    }
                }
                EffectDescriptor::SetJobStatus {
                    job_id,
                    status,
                    reason,
                } => {
                    events.extend(self.set_job_status_events(
                        job_id,
                        status,
                        actor_id,
                        reason.as_deref().unwrap_or("clock_fill"),
                    ));
                }
            }
        }
        events
    }

    fn contribution_claim_key(
        actor_id: u64,
        job_id: &str,
        strategy: &JobContributionStrategy,
        target: &ResolvedContributionTarget,
    ) -> Option<String> {
        let stem = format!(
            "job_contribution:{job_id}:{}:{}:{}",
            strategy.id, target.kind, target.id
        );
        match strategy.claim_policy {
            ContributionClaimPolicy::Repeatable => None,
            ContributionClaimPolicy::OncePerActor => Some(format!(
                "job_contribution:{job_id}:{}:actor:{actor_id}",
                strategy.id
            )),
            ContributionClaimPolicy::OncePerTarget => Some(stem),
            ContributionClaimPolicy::OncePerActorTarget => Some(format!("{stem}:actor:{actor_id}")),
        }
    }

    fn resolve_job_contribution(
        &mut self,
        action: &CwAction,
        committed_events: &[EventView],
        intent: &JobContributionIntent,
    ) -> Vec<EventView> {
        let Some(job) = self.jobs.get(&intent.job_id).cloned() else {
            return Vec::new();
        };
        let Some(current_strategy) = job
            .contribution_strategies
            .iter()
            .find(|strategy| strategy.id == intent.strategy.id)
        else {
            return Vec::new();
        };
        if current_strategy.version != intent.strategy.version
            || current_strategy.action_kind != intent.strategy.action_kind
            || current_strategy.clock_id != intent.strategy.clock_id
            || self.job_status(&job) != "active"
        {
            return Vec::new();
        }
        let Some(clock) = self.clocks.get(&intent.strategy.clock_id) else {
            return Vec::new();
        };
        if clock.filled >= clock.segments {
            return Vec::new();
        }

        let claim_key = Self::contribution_claim_key(
            action.actor_id,
            &intent.job_id,
            &intent.strategy,
            &intent.target,
        );
        if claim_key
            .as_ref()
            .is_some_and(|claim_key| self.rpg_claims.contains(claim_key))
        {
            return Vec::new();
        }

        let (resolution, outcome, resolved, source_event_seqs) =
            match &intent.strategy.resolution {
                ContributionResolutionPolicy::Certain => ("certain", "certain", true, Vec::new()),
                ContributionResolutionPolicy::SrdCheck { ability, dc } => {
                    let check = committed_events.iter().find(|event| {
                        event.type_name == "ability_check.rolled"
                            && event.actor_id == Some(action.actor_id)
                            && action.ability == ability_from_string(ability)
                            && event.dc == Some(*dc as i16)
                    });
                    let Some(check) = check else {
                        return Vec::new();
                    };
                    let succeeded = check.success
                        && check
                            .total
                            .zip(check.dc)
                            .is_some_and(|(total, dc)| total >= dc);
                    (
                        "srd_check",
                        if succeeded { "success" } else { "failure" },
                        succeeded,
                        vec![check.seq],
                    )
                }
                ContributionResolutionPolicy::ExistingKernelOutcome { event_type } => {
                    let outcome_event =
                        committed_events.iter().find(|event| {
                            event.type_name == *event_type
                                && event.actor_id == Some(action.actor_id)
                                && match intent.target.kind.as_str() {
                                    "item" => intent
                                        .target
                                        .id
                                        .parse::<u64>()
                                        .ok()
                                        .is_some_and(|item_id| event.item_id == Some(item_id)),
                                    "actor" => intent.target.id.parse::<u64>().ok().is_some_and(
                                        |actor_id| {
                                            event.target_actor_id == Some(actor_id)
                                                || event.actor_id == Some(actor_id)
                                        },
                                    ),
                                    _ => true,
                                }
                        });
                    let Some(outcome_event) = outcome_event else {
                        return Vec::new();
                    };
                    (
                        "existing_kernel_outcome",
                        if outcome_event.success {
                            "success"
                        } else {
                            "failure"
                        },
                        outcome_event.success,
                        vec![outcome_event.seq],
                    )
                }
            };

        if let Some(claim_key) = claim_key.as_ref() {
            if !self.rpg_claims.insert(claim_key.clone()) {
                return Vec::new();
            }
        }
        let prepared_bonus_progress = if self
            .actor_by_id(action.actor_id)
            .is_some_and(|actor| self.prepared_tag_active(action.actor_id, actor.location_id))
        {
            intent.strategy.prepared_bonus_progress
        } else {
            0
        };
        let success_progress = if resolved {
            intent.strategy.success_progress
        } else {
            0
        };
        let total_progress = intent
            .strategy
            .baseline_progress
            .saturating_add(success_progress)
            .saturating_add(prepared_bonus_progress);
        let trace = JobContributionTrace {
            schema_version: JOB_CONTRIBUTION_SCHEMA_VERSION,
            job_id: intent.job_id.clone(),
            strategy_id: intent.strategy.id.clone(),
            strategy_label: intent.strategy.strategy_label.clone(),
            narration_key: intent.strategy.narration_key.clone(),
            action_kind: intent.strategy.action_kind.clone(),
            rules_action: intent.strategy.rules_action.clone(),
            operation: intent.strategy.operation.clone(),
            target: intent.target.clone(),
            resolution: resolution.to_string(),
            outcome: outcome.to_string(),
            baseline_progress: intent.strategy.baseline_progress,
            success_progress,
            prepared_bonus_progress,
            total_progress,
            clock_id: intent.strategy.clock_id.clone(),
            claim_key: claim_key.clone(),
            source_event_seqs: source_event_seqs.clone(),
            rules_profile: intent.strategy.rules_profile.clone(),
            rules_pack_id: intent.strategy.rules_pack_id.clone(),
            rules_pack_version: intent.strategy.rules_pack_version.clone(),
            pack_id: intent.strategy.pack_id.clone(),
            pack_version: intent.strategy.pack_version.clone(),
        };
        let target_actor_id = (intent.target.kind == "actor")
            .then(|| intent.target.id.parse::<u64>().ok())
            .flatten();
        let mut contribution_event = self.append_async_job_event(
            "job.contribution.resolved",
            action.actor_id,
            target_actor_id,
            serde_json::to_string(&trace).ok(),
        );
        contribution_event.clock_id = Some(intent.strategy.clock_id.clone());
        contribution_event.caused_by_event_seq = source_event_seqs.last().copied();
        self.replace_projected_event(&contribution_event);
        if total_progress > 0
            && intent.job_id == FIRST_TALE_JOB_ID
            && self.first_tale_trace_event_seq(action.actor_id).is_none()
        {
            self.rpg_claims.insert(first_tale_trace_claim_key(
                action.actor_id,
                contribution_event.seq,
            ));
        }

        let mut events = vec![contribution_event.clone()];
        if total_progress > 0 {
            let mut progress_events = self.advance_clock(
                &intent.strategy.clock_id,
                total_progress,
                action.actor_id,
                &format!("job_contribution:{}:{}", intent.job_id, intent.strategy.id),
            );
            self.link_events_to_cause(&mut progress_events, contribution_event.seq);
            if let Some(clock_event) = progress_events
                .iter()
                .find(|event| event.type_name == "clock.updated")
                .cloned()
            {
                self.record_clock_contribution(
                    action.actor_id,
                    &trace,
                    contribution_event.seq,
                    &clock_event,
                );
            }
            events.extend(progress_events);
        }
        let authored_effects = if resolved {
            &intent.strategy.on_success
        } else {
            &intent.strategy.on_failure
        };
        let mut consequence_events = self.apply_contribution_effects(
            action.actor_id,
            contribution_event.seq,
            authored_effects,
        );
        self.link_events_to_cause(&mut consequence_events, contribution_event.seq);
        events.extend(consequence_events);
        events
    }

    fn apply_contribution_effects(
        &mut self,
        actor_id: u64,
        source_event_seq: u64,
        effects: &[EffectDescriptor],
    ) -> Vec<EventView> {
        if effects.is_empty() || self.validate_runtime_effects(effects).is_err() {
            return Vec::new();
        }
        let mut events = Vec::new();
        for effect in effects {
            match effect {
                EffectDescriptor::AdvanceClock {
                    clock_id,
                    amount,
                    reason,
                } => events.extend(self.advance_clock(
                    clock_id,
                    *amount,
                    actor_id,
                    reason.as_deref().unwrap_or("job_contribution"),
                )),
                EffectDescriptor::SetTag {
                    tag_id,
                    scope,
                    scope_id,
                    label,
                    kind,
                    expires,
                    reason,
                } => {
                    let tag = RpgTagState {
                        id: tag_id.clone(),
                        scope: scope.clone(),
                        scope_id: *scope_id,
                        label: label.clone(),
                        kind: kind.clone(),
                        active: true,
                        source_event_seq: Some(source_event_seq),
                        expires: expires.clone(),
                    };
                    if let Some(event) = self.set_rpg_tag(
                        tag,
                        actor_id,
                        reason.as_deref().unwrap_or("job_contribution"),
                    ) {
                        events.push(event);
                    }
                }
                EffectDescriptor::ClearTag { tag_id, reason } => {
                    if let Some(event) = self.clear_rpg_tag(
                        tag_id,
                        actor_id,
                        reason.as_deref().unwrap_or("job_contribution"),
                    ) {
                        events.push(event);
                    }
                }
                EffectDescriptor::SetJobStatus {
                    job_id,
                    status,
                    reason,
                } => events.extend(self.set_job_status_events(
                    job_id,
                    status,
                    actor_id,
                    reason.as_deref().unwrap_or("job_contribution"),
                )),
            }
        }
        events
    }

    fn validate_clock_fill_effects(&self, effects: &[EffectDescriptor]) -> Result<(), String> {
        self.validate_runtime_effects(effects)
    }

    fn validate_runtime_effects(&self, effects: &[EffectDescriptor]) -> Result<(), String> {
        for effect in effects {
            match effect {
                EffectDescriptor::AdvanceClock {
                    clock_id, amount, ..
                } => {
                    let Some(clock) = self.clocks.get(clock_id) else {
                        return Err(format!("missing clock {clock_id}"));
                    };
                    if *amount == 0 || *amount > clock.segments.max(1) {
                        return Err(format!("invalid clock amount {amount} for {clock_id}"));
                    }
                }
                EffectDescriptor::SetTag {
                    tag_id,
                    scope,
                    scope_id,
                    label,
                    kind,
                    ..
                } => {
                    if tag_id.trim().is_empty() || label.trim().is_empty() {
                        return Err("tag id and label are required".to_string());
                    }
                    if !tag_scope_is_allowed(scope) || !tag_kind_is_allowed(kind) {
                        return Err(format!("invalid tag {scope}/{kind}"));
                    }
                    if scope == "actor" && self.actor_by_id(*scope_id).is_none() {
                        return Err(format!("missing actor {scope_id}"));
                    }
                    if scope == "room" && self.location_name(*scope_id).is_none() {
                        return Err(format!("missing room {scope_id}"));
                    }
                }
                EffectDescriptor::ClearTag { tag_id, .. } => {
                    if !self.tags.contains_key(tag_id) {
                        return Err(format!("missing tag {tag_id}"));
                    }
                }
                EffectDescriptor::SetJobStatus { job_id, status, .. } => {
                    let Some(job) = self.jobs.get(job_id) else {
                        return Err(format!("missing job {job_id}"));
                    };
                    let next = normalize_job_status(status)
                        .ok_or_else(|| format!("invalid job status {status}"))?;
                    let current = job.status.trim();
                    if matches!(current, "completed" | "failed") && current != next {
                        return Err(format!("illegal job status transition {current}->{next}"));
                    }
                }
            }
        }
        Ok(())
    }

    fn set_rpg_tag(
        &mut self,
        mut tag: RpgTagState,
        actor_id: u64,
        reason: &str,
    ) -> Option<EventView> {
        if self
            .tags
            .get(&tag.id)
            .map(|existing| existing.active)
            .unwrap_or(false)
        {
            return None;
        }
        tag.active = true;
        self.tags.insert(tag.id.clone(), tag.clone());
        Some(self.append_tag_event("tag.applied", actor_id, &tag, reason))
    }

    fn clear_rpg_tag(&mut self, tag_id: &str, actor_id: u64, reason: &str) -> Option<EventView> {
        let tag = self.tags.get_mut(tag_id)?;
        if !tag.active {
            return None;
        }
        tag.active = false;
        let tag = tag.clone();
        Some(self.append_tag_event("tag.cleared", actor_id, &tag, reason))
    }

    fn set_job_status_events(
        &mut self,
        job_id: &str,
        status: &str,
        actor_id: u64,
        reason: &str,
    ) -> Vec<EventView> {
        self.set_job_status(job_id, status, actor_id, reason)
            .into_iter()
            .collect()
    }

    fn clear_job_resolved_tags_from_events(&mut self, events: &[EventView]) -> Vec<EventView> {
        let mut resolved_jobs = Vec::new();
        for event in events {
            if event.type_name != "job.updated" {
                continue;
            }
            let Some(content) = event.content.as_deref() else {
                continue;
            };
            let Some(status) = job_status_from_event_content(content) else {
                continue;
            };
            let Some(job_id) = job_id_from_event_content(content) else {
                continue;
            };
            if matches!(status, "completed" | "failed") {
                resolved_jobs.push((job_id, event.actor_id.unwrap_or(0)));
            }
        }
        let mut cleared = Vec::new();
        for (job_id, actor_id) in resolved_jobs {
            cleared.extend(self.clear_job_resolved_tags(&job_id, actor_id, "job_resolved"));
        }
        cleared
    }

    fn clear_job_resolved_tags(
        &mut self,
        job_id: &str,
        actor_id: u64,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(job) = self.jobs.get(job_id).cloned() else {
            return Vec::new();
        };
        let tag_ids: Vec<String> = self
            .tags
            .values()
            .filter(|tag| tag.active && tag.expires.as_deref() == Some("when_job_resolves"))
            .filter(|tag| match tag.scope.as_str() {
                "room" => job.location_ids.contains(&tag.scope_id),
                "actor" => job.location_ids.iter().any(|location_id| {
                    tag.id
                        == project_preparation_spent_tag_id(
                            tag.scope_id,
                            *location_id,
                            &job.progress_clock_id,
                        )
                }),
                _ => false,
            })
            .map(|tag| tag.id.clone())
            .collect();
        tag_ids
            .into_iter()
            .filter_map(|tag_id| self.clear_rpg_tag(&tag_id, actor_id, reason))
            .collect()
    }

    fn set_job_status(
        &mut self,
        job_id: &str,
        status: &str,
        actor_id: u64,
        reason: &str,
    ) -> Option<EventView> {
        let normalized = normalize_job_status(status)?;
        let job = self.jobs.get_mut(job_id)?;
        if job.status == normalized {
            return None;
        }
        if matches!(job.status.as_str(), "completed" | "failed") && job.status != normalized {
            return None;
        }
        job.status = normalized.to_string();
        let job = job.clone();
        Some(self.append_job_event("job.updated", actor_id, &job, reason))
    }

    fn mark_visit_ledger(
        &mut self,
        actor_id: u64,
        category: &str,
        label: &str,
        source_event_seq: u64,
        reason: &str,
    ) -> Option<EventView> {
        let id = visit_ledger_mark_id(actor_id, category, reason);
        let claim_key = visit_ledger_claim_key(&id);
        if !self.rpg_claims.insert(claim_key) || self.ledger_marks.contains_key(&id) {
            return None;
        }
        let mark = VisitLedgerMarkState {
            id: id.clone(),
            actor_id,
            category: category.to_string(),
            label: label.to_string(),
            source_event_seq,
            banked: false,
        };
        self.ledger_marks.insert(id, mark.clone());
        Some(self.append_ledger_event("ledger.marked", &mark, reason))
    }

    fn bank_visit_ledger(&mut self, actor_id: u64, reason: &str) -> Option<EventView> {
        let mut mark_ids: Vec<_> = self
            .ledger_marks
            .values()
            .filter(|mark| mark.actor_id == actor_id && !mark.banked)
            .map(|mark| (mark.source_event_seq, mark.id.clone()))
            .collect();
        mark_ids.sort_by_key(|(source_event_seq, _)| *source_event_seq);
        if mark_ids.is_empty() {
            return None;
        }

        let mut categories = Vec::new();
        for (_, mark_id) in &mark_ids {
            if let Some(mark) = self.ledger_marks.get_mut(mark_id) {
                mark.banked = true;
                categories.push(mark.category.clone());
            }
        }
        Some(self.append_ledger_bank_event(actor_id, mark_ids.len(), &categories, reason))
    }

    fn revise_calling(
        &mut self,
        actor_id: u64,
        statement: &str,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        if cost == 0
            || self.advancement_points_available(actor_id) < usize::from(cost)
            || self
                .callings
                .get(&actor_id)
                .map(|calling| calling.statement == statement)
                .unwrap_or(false)
        {
            return Vec::new();
        }

        let spend_seq = self.world.next_event_seq;
        let spend = AdvancementSpendState {
            id: advancement_spend_id(actor_id, "calling_revision", spend_seq),
            actor_id,
            kind: "calling_revision".to_string(),
            label: "Purpose changed".to_string(),
            cost,
            source_event_seq: spend_seq,
        };
        if self.advancement_spends.contains_key(&spend.id) {
            return Vec::new();
        }
        self.advancement_spends
            .insert(spend.id.clone(), spend.clone());
        let mut events = vec![self.append_advancement_event("advancement.spent", &spend, reason)];

        let calling = CallingState {
            actor_id,
            statement: statement.to_string(),
            source_event_seq: Some(self.world.next_event_seq),
        };
        self.callings.insert(actor_id, calling.clone());
        events.push(self.append_calling_event("calling.revised", &calling, reason));
        events
    }

    fn create_bond(
        &mut self,
        actor_id: u64,
        target_actor_id: u64,
        statement: &str,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        let id = bond_id(actor_id, target_actor_id);
        if cost == 0
            || self.advancement_points_available(actor_id) < usize::from(cost)
            || self.active_bond(actor_id, target_actor_id).is_some()
        {
            return Vec::new();
        }

        let spend_seq = self.world.next_event_seq;
        let target_name = self
            .actor_name(target_actor_id)
            .unwrap_or_else(|| format!("Resident {target_actor_id}"));
        let spend = AdvancementSpendState {
            id: advancement_spend_id(actor_id, "bond_slot", spend_seq),
            actor_id,
            kind: "bond_slot".to_string(),
            label: format!("Friendship with {target_name}"),
            cost,
            source_event_seq: spend_seq,
        };
        if self.advancement_spends.contains_key(&spend.id) {
            return Vec::new();
        }
        self.advancement_spends
            .insert(spend.id.clone(), spend.clone());
        let mut events = vec![self.append_advancement_event("advancement.spent", &spend, reason)];

        let bond = BondState {
            id: id.clone(),
            actor_id,
            target_actor_id,
            statement: statement.to_string(),
            strength: 1,
            status: "active".to_string(),
            source_event_seq: Some(self.world.next_event_seq),
            updated_event_seq: Some(self.world.next_event_seq),
        };
        self.bonds.insert(id, bond.clone());
        events.push(self.append_bond_event("bond.created", &bond, reason));
        events
    }

    fn revise_bond(
        &mut self,
        actor_id: u64,
        target_actor_id: u64,
        statement: &str,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        let id = bond_id(actor_id, target_actor_id);
        if cost == 0 || self.advancement_points_available(actor_id) < usize::from(cost) {
            return Vec::new();
        }
        let Some(existing) = self.bonds.get(&id) else {
            return Vec::new();
        };
        if existing.status == "resolved"
            || existing.strength == 0
            || existing.statement == statement
        {
            return Vec::new();
        }

        let spend_seq = self.world.next_event_seq;
        let spend = AdvancementSpendState {
            id: advancement_spend_id(actor_id, "bond_revision", spend_seq),
            actor_id,
            kind: "bond_revision".to_string(),
            label: "Friendship changed".to_string(),
            cost,
            source_event_seq: spend_seq,
        };
        if self.advancement_spends.contains_key(&spend.id) {
            return Vec::new();
        }
        self.advancement_spends
            .insert(spend.id.clone(), spend.clone());
        let mut events = vec![self.append_advancement_event("advancement.spent", &spend, reason)];

        let Some(bond) = self.bonds.get_mut(&id) else {
            return events;
        };
        bond.statement = statement.to_string();
        bond.status = "active".to_string();
        bond.updated_event_seq = Some(self.world.next_event_seq);
        let bond = bond.clone();
        events.push(self.append_bond_event("bond.revised", &bond, reason));
        events
    }

    fn train_skill(
        &mut self,
        actor_id: u64,
        skill_id: &str,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(label) = skill_label(skill_id) else {
            return Vec::new();
        };
        let id = skill_state_id(actor_id, skill_id);
        let current_rank = self.skills.get(&id).map(|skill| skill.rank).unwrap_or(0);
        if cost == 0
            || current_rank >= MAX_SKILL_RANK
            || self.trained_since_rest_tag_active(actor_id)
            || self.advancement_points_available(actor_id) < usize::from(cost)
        {
            return Vec::new();
        }

        let spend_seq = self.world.next_event_seq;
        let spend = AdvancementSpendState {
            id: advancement_spend_id(actor_id, "skill_step", spend_seq),
            actor_id,
            kind: "skill_step".to_string(),
            label: format!("{label} skill step"),
            cost,
            source_event_seq: spend_seq,
        };
        if self.advancement_spends.contains_key(&spend.id) {
            return Vec::new();
        }
        self.advancement_spends
            .insert(spend.id.clone(), spend.clone());
        let mut events = vec![self.append_advancement_event("advancement.spent", &spend, reason)];

        let skill = SkillState {
            actor_id,
            skill_id: skill_id.to_string(),
            label: label.to_string(),
            rank: current_rank.saturating_add(1).min(MAX_SKILL_RANK),
            updated_event_seq: Some(self.world.next_event_seq),
        };
        self.skills.insert(id, skill.clone());
        events.push(self.append_skill_event("skill.stepped", &skill, reason));
        let tag = RpgTagState {
            id: trained_since_rest_tag_id(actor_id),
            scope: "actor".to_string(),
            scope_id: actor_id,
            label: "trained".to_string(),
            kind: "condition".to_string(),
            active: true,
            source_event_seq: Some(self.world.next_event_seq),
            expires: Some("after_rest".to_string()),
        };
        if let Some(event) = self.set_rpg_tag(tag, actor_id, reason) {
            events.push(event);
        }
        let tag = RpgTagState {
            id: tired_tag_id(actor_id),
            scope: "actor".to_string(),
            scope_id: actor_id,
            label: "tired".to_string(),
            kind: "condition".to_string(),
            active: true,
            source_event_seq: Some(self.world.next_event_seq),
            expires: Some("after_rest".to_string()),
        };
        if let Some(event) = self.set_rpg_tag(tag, actor_id, reason) {
            events.push(event);
        }
        events
    }

    fn unlock_charm_slot(&mut self, actor_id: u64, cost: u8, reason: &str) -> Vec<EventView> {
        self.unlock_charm_slot_with_demand(actor_id, None, cost, reason)
    }

    fn unlock_charm_slot_for_charm(
        &mut self,
        actor_id: u64,
        item_id: u64,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        if self
            .charm_slot_expansion_candidate(actor_id)
            .is_none_or(|candidate| candidate.id != item_id)
        {
            return Vec::new();
        }
        self.unlock_charm_slot_with_demand(actor_id, Some(item_id), cost, reason)
    }

    fn unlock_charm_slot_with_demand(
        &mut self,
        actor_id: u64,
        charm_item_id: Option<u64>,
        cost: u8,
        reason: &str,
    ) -> Vec<EventView> {
        let current_slots = self.charm_slot_count(actor_id);
        if cost == 0
            || current_slots >= MAX_CHARM_SLOTS
            || self.advancement_points_available(actor_id) < usize::from(cost)
        {
            return Vec::new();
        }
        let charm_name = charm_item_id.and_then(|item_id| self.item_name(item_id));
        let spend_seq = self.world.next_event_seq;
        let spend = AdvancementSpendState {
            id: advancement_spend_id(actor_id, "charm_slot", spend_seq),
            actor_id,
            kind: "charm_slot".to_string(),
            label: charm_name
                .as_ref()
                .map(|name| format!("Make room for {name}"))
                .unwrap_or_else(|| "Bracelet charm slot".to_string()),
            cost,
            source_event_seq: spend_seq,
        };
        if self.advancement_spends.contains_key(&spend.id) {
            return Vec::new();
        }
        self.advancement_spends
            .insert(spend.id.clone(), spend.clone());
        let mut events = vec![self.append_advancement_event("advancement.spent", &spend, reason)];
        let next_slots = current_slots.saturating_add(1).min(MAX_CHARM_SLOTS);
        self.charm_slots.insert(actor_id, next_slots);
        events.push(
            self.append_deck_event(
                "charm_slot.unlocked",
                actor_id,
                charm_item_id,
                charm_name
                    .map(|name| {
                        format!("bracelet_slots:{next_slots}:make_room_for:{name}:{reason}")
                    })
                    .unwrap_or_else(|| format!("bracelet_slots:{next_slots}:{reason}")),
            ),
        );
        events
    }

    fn set_charm_equipped(
        &mut self,
        actor_id: u64,
        item_id: u64,
        equipped: bool,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(item) = self.item_by_id(item_id) else {
            return Vec::new();
        };
        if item.holder_actor_id != actor_id || item.role != CW_ITEM_ROLE_SKILL_CHARM {
            return Vec::new();
        }
        let slots = usize::from(self.charm_slot_count(actor_id));
        let equipped_items = self.equipped_charms.entry(actor_id).or_default();
        let changed = if equipped {
            if equipped_items.contains(&item_id) || equipped_items.len() >= slots {
                false
            } else {
                equipped_items.insert(item_id)
            }
        } else {
            equipped_items.remove(&item_id)
        };
        if !changed {
            return Vec::new();
        }
        let zone = if equipped {
            CW_CARD_ZONE_EQUIPPED
        } else {
            CW_CARD_ZONE_CARRIED
        };
        if !self.set_item_zone(item_id, zone, 0) {
            let equipped_items = self.equipped_charms.entry(actor_id).or_default();
            if equipped {
                equipped_items.remove(&item_id);
            } else {
                equipped_items.insert(item_id);
            }
            return Vec::new();
        }
        vec![self.append_deck_event(
            if equipped {
                "skill_charm.equipped"
            } else {
                "skill_charm.unequipped"
            },
            actor_id,
            Some(item_id),
            reason.to_string(),
        )]
    }

    fn set_spell_prepared(
        &mut self,
        actor_id: u64,
        item_id: u64,
        prepared: bool,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(item) = self.item_by_id(item_id) else {
            return Vec::new();
        };
        if item.holder_actor_id != actor_id || item.role != CW_ITEM_ROLE_SPELL {
            return Vec::new();
        }
        let prepared_items = self.prepared_spells.entry(actor_id).or_default();
        let changed = if prepared {
            if prepared_items.contains(&item_id) || prepared_items.len() >= 3 {
                false
            } else {
                prepared_items.insert(item_id)
            }
        } else {
            prepared_items.remove(&item_id)
        };
        if !changed {
            return Vec::new();
        }
        let zone = if prepared {
            CW_CARD_ZONE_SPELL_DECK
        } else if item.charges == 0 {
            CW_CARD_ZONE_EXHAUSTED
        } else {
            CW_CARD_ZONE_CARRIED
        };
        if !self.set_item_zone(item_id, zone, 0) {
            let prepared_items = self.prepared_spells.entry(actor_id).or_default();
            if prepared {
                prepared_items.remove(&item_id);
            } else {
                prepared_items.insert(item_id);
            }
            return Vec::new();
        }
        vec![self.append_deck_event(
            if prepared {
                "spell.prepared"
            } else {
                "spell.unprepared"
            },
            actor_id,
            Some(item_id),
            reason.to_string(),
        )]
    }

    fn set_item_equipped(
        &mut self,
        actor_id: u64,
        item_id: u64,
        equipped: bool,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(item) = self.item_by_id(item_id) else {
            return Vec::new();
        };
        if item.holder_actor_id != actor_id
            || !matches!(item.role, CW_ITEM_ROLE_WEAPON | CW_ITEM_ROLE_CONTAINER)
            || item.container_item_id != 0
        {
            return Vec::new();
        }
        if equipped {
            if item.zone == CW_CARD_ZONE_EQUIPPED
                || self
                    .actor_held_items(actor_id)
                    .into_iter()
                    .any(|candidate| {
                        candidate.id != item.id
                            && candidate.role == item.role
                            && candidate.zone == CW_CARD_ZONE_EQUIPPED
                    })
            {
                return Vec::new();
            }
        } else if item.zone != CW_CARD_ZONE_EQUIPPED {
            return Vec::new();
        }
        let zone = if equipped {
            CW_CARD_ZONE_EQUIPPED
        } else {
            CW_CARD_ZONE_CARRIED
        };
        if !self.set_item_zone(item_id, zone, 0) {
            return Vec::new();
        }
        vec![self.append_deck_event(
            if equipped {
                "item.equipped"
            } else {
                "item.unequipped"
            },
            actor_id,
            Some(item_id),
            reason.to_string(),
        )]
    }

    fn set_item_contained(
        &mut self,
        actor_id: u64,
        item_id: u64,
        container_item_id: Option<u64>,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(item) = self.item_by_id(item_id) else {
            return Vec::new();
        };
        if item.holder_actor_id != actor_id {
            return Vec::new();
        }
        let mut events = Vec::new();
        let (zone, container_id, event_type) = if let Some(container_id) = container_item_id {
            let Some(container) = self.item_by_id(container_id) else {
                return Vec::new();
            };
            let Some(contract) = self.seed_item_contract_for_instance(container_id) else {
                return Vec::new();
            };
            let opening = contract
                .container_opening_size
                .as_deref()
                .and_then(item_size_from_str)
                .unwrap_or(0);
            let stores_empty_container = item.role == CW_ITEM_ROLE_CONTAINER
                && contract
                    .allowed_contents
                    .iter()
                    .any(|role| role == "container")
                && !self
                    .actor_held_items(actor_id)
                    .into_iter()
                    .any(|candidate| candidate.container_item_id == item.id);
            if item.id == container.id
                || container.role != CW_ITEM_ROLE_CONTAINER
                || container.holder_actor_id != actor_id
                || container.zone == CW_CARD_ZONE_CONTAINED
                || item.size_class > opening
                || !(stores_empty_container
                    || contract
                        .allowed_contents
                        .iter()
                        .any(|role| role == item_role(item.role)))
            {
                return Vec::new();
            }
            if item.role == CW_ITEM_ROLE_CONTAINER && item.zone == CW_CARD_ZONE_EQUIPPED {
                events.extend(self.set_item_equipped(actor_id, item_id, false, reason));
            }
            if item.role == CW_ITEM_ROLE_SKILL_CHARM && item.zone == CW_CARD_ZONE_EQUIPPED {
                events.extend(self.set_charm_equipped(actor_id, item_id, false, reason));
            } else if item.role == CW_ITEM_ROLE_SPELL && item.zone == CW_CARD_ZONE_SPELL_DECK {
                events.extend(self.set_spell_prepared(actor_id, item_id, false, reason));
            }
            (CW_CARD_ZONE_CONTAINED, container_id, "item.contained")
        } else {
            if item.zone != CW_CARD_ZONE_CONTAINED {
                return Vec::new();
            }
            (
                if item.charges == 0
                    && matches!(item.role, CW_ITEM_ROLE_CONSUMABLE | CW_ITEM_ROLE_SPELL)
                {
                    CW_CARD_ZONE_EXHAUSTED
                } else {
                    CW_CARD_ZONE_CARRIED
                },
                0,
                "item.uncontained",
            )
        };
        if !self.set_item_zone(item_id, zone, container_id) {
            return Vec::new();
        }
        events.push(self.append_deck_event(
            event_type,
            actor_id,
            Some(item_id),
            reason.to_string(),
        ));
        events
    }

    fn materialize_item(
        &mut self,
        receipt: MaterializationReceiptState,
        item: CwItem,
        meta: ItemMeta,
        reason: &str,
    ) -> Vec<EventView> {
        if self
            .materialization_receipts
            .get(&receipt.id)
            .is_some_and(|existing| existing.status == "materialized")
            || self.item_by_id(item.id).is_some()
            || self.world.item_count >= CW_MAX_ITEMS
        {
            return Vec::new();
        }
        self.world.items[self.world.item_count] = item;
        self.world.item_count += 1;
        self.items.insert(item.id, meta);
        self.materialization_receipts
            .insert(receipt.id.clone(), receipt.clone());
        self.item_provenance.insert(
            item.id,
            ItemProvenanceState {
                item_id: item.id,
                origin: format!("collection:{}", receipt.card_id),
                acquisition: "item.materialized".to_string(),
                previous_holder_actor_id: None,
                current_holder_actor_id: Some(receipt.actor_id),
                current_location_id: None,
                transfer_count: 0,
                source_event_seq: Some(receipt.source_event_seq),
                possession_journey: None,
            },
        );
        vec![self.append_deck_event(
            "item.materialized",
            receipt.actor_id,
            Some(item.id),
            reason.to_string(),
        )]
    }

    fn unmaterialize_item(
        &mut self,
        actor_id: u64,
        receipt_id: &str,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(receipt) = self.materialization_receipts.get(receipt_id).cloned() else {
            return Vec::new();
        };
        let Some(index) = self.world.items[..self.world.item_count]
            .iter()
            .position(|item| item.id == receipt.item_id)
        else {
            return Vec::new();
        };
        let item = self.world.items[index];
        if receipt.actor_id != actor_id
            || receipt.status != "materialized"
            || item.holder_actor_id != actor_id
            || item.zone != CW_CARD_ZONE_CARRIED
            || item.container_item_id != 0
        {
            return Vec::new();
        }
        let event = self.append_deck_event(
            "item.unmaterialized",
            actor_id,
            Some(item.id),
            reason.to_string(),
        );
        for slot in index..self.world.item_count.saturating_sub(1) {
            self.world.items[slot] = self.world.items[slot + 1];
        }
        self.world.item_count = self.world.item_count.saturating_sub(1);
        self.world.items[self.world.item_count] = CwItem::default();
        if let Some(receipt) = self.materialization_receipts.get_mut(receipt_id) {
            receipt.status = "collection".to_string();
            receipt.source_event_seq = event.seq;
        }
        if let Some(provenance) = self.item_provenance.get_mut(&item.id) {
            provenance.previous_holder_actor_id = Some(actor_id);
            provenance.current_holder_actor_id = None;
            provenance.current_location_id = None;
            provenance.acquisition = "item.unmaterialized".to_string();
            provenance.source_event_seq = Some(event.seq);
        }
        self.reconcile_card_zones();
        vec![event]
    }

    fn action_with_skill_bonus(&self, mut action: CwAction) -> CwAction {
        if matches!(
            action.kind,
            CW_ACTION_ABILITY_CHECK | CW_ACTION_RULES_SEARCH | CW_ACTION_RULES_STUDY
        ) {
            action.modifier = action
                .modifier
                .saturating_add(self.skill_bonus_for_ability(action.actor_id, action.ability));
            if action_is_listen_check(&action) && !self.listen_attempted_here(action.actor_id) {
                let natural_modifier = self
                    .actor_by_id(action.actor_id)
                    .map(|actor| ability_score_modifier(actor.stats.wisdom))
                    .unwrap_or(0);
                let welcome_bonus = WELCOMING_LISTEN_MIN_MODIFIER.saturating_sub(natural_modifier);
                action.modifier = action.modifier.max(welcome_bonus);
            }
        }
        action
    }

    fn skill_bonus_for_ability(&self, actor_id: u64, ability: u8) -> i16 {
        let Some(skill_id) = skill_id_for_ability(ability) else {
            return 0;
        };
        let legacy_training_bonus = self
            .skills
            .get(&skill_state_id(actor_id, skill_id))
            .map(|skill| skill_bonus_for_rank(skill.rank))
            .unwrap_or(0);
        let charm_bonus = self
            .equipped_charm_items(actor_id)
            .into_iter()
            .filter_map(|item| self.items.get(&item.id))
            .filter(|meta| meta.skill_id.as_deref() == Some(skill_id))
            .map(|meta| i16::from(meta.skill_bonus))
            .sum::<i16>();
        legacy_training_bonus.saturating_add(charm_bonus)
    }

    fn active_bond(&self, actor_id: u64, target_actor_id: u64) -> Option<&BondState> {
        self.bonds
            .get(&bond_id(actor_id, target_actor_id))
            .filter(|bond| bond.status != "resolved" && bond.strength > 0)
    }

    fn resolve_bond(
        &mut self,
        actor_id: u64,
        target_actor_id: u64,
        reason: &str,
    ) -> Vec<EventView> {
        let bond_id = bond_id(actor_id, target_actor_id);
        let Some(bond) = self.bonds.get_mut(&bond_id) else {
            return Vec::new();
        };
        if bond.status == "resolved" || bond.strength < BOND_SETTLE_MIN_STRENGTH {
            return Vec::new();
        }
        bond.status = "resolved".to_string();
        bond.updated_event_seq = Some(self.world.next_event_seq);
        let bond = bond.clone();
        let bond_event = self.append_bond_event("bond.resolved", &bond, reason);
        let mut events = vec![bond_event.clone()];
        let target_name = self
            .actor_name(target_actor_id)
            .unwrap_or_else(|| format!("Resident {target_actor_id}"));
        if let Some(event) = self.mark_visit_ledger(
            actor_id,
            "bond",
            &format!("You kept what mattered with {target_name}."),
            bond_event.seq,
            &format!("bond_resolved:{}", bond.id),
        ) {
            events.push(event);
        }
        events
    }

    fn apply_orb_delta(&mut self, actor_id: u64, delta: i32) {
        if actor_id == 0 || delta == 0 {
            return;
        }
        let current = self.orb_balances.get(&actor_id).copied().unwrap_or(0);
        self.orb_balances
            .insert(actor_id, current.saturating_add(delta).max(0));
    }

    fn orb_balance(&self, actor_id: u64) -> i32 {
        self.orb_balances.get(&actor_id).copied().unwrap_or(0)
    }

    fn apply_automatic_orb_rewards(&mut self, action: &CwAction, events: &[EventView]) {
        for reward in automatic_orb_rewards_for_action(action, events) {
            if self.orb_reward_claims.insert(reward.claim_key) {
                self.apply_orb_delta(reward.delta.actor_id, reward.delta.delta);
            }
        }
    }

    fn apply_action_with_seed(
        &mut self,
        action: CwAction,
        seed: u64,
        advances_world_tick: bool,
    ) -> (u32, Vec<EventView>) {
        let mut events = CwEventBuffer::default();
        let status = unsafe {
            cw_world_apply_with_tick(
                &mut self.world,
                &action,
                seed,
                u8::from(advances_world_tick),
                &mut events,
            )
        };
        let views = self.views_from_buffer(&events);
        self.event_log.extend(views.iter().cloned());
        if self.event_log.len() > 512 {
            let excess = self.event_log.len() - 512;
            self.event_log.drain(0..excess);
        }
        (status, views)
    }

    fn recompute_counters(&mut self) {
        let max_actor = self.world.actors[..self.world.actor_count]
            .iter()
            .map(|actor| actor.id)
            .chain(self.actors.keys().copied())
            .filter(|id| *id >= 5000)
            .max()
            .unwrap_or(4999);
        self.next_actor_id = self.next_actor_id.max(max_actor + 1).max(5000);

        let max_content = self.content.keys().copied().max().unwrap_or(9000);
        self.next_content_id = self.next_content_id.max(max_content).max(9000);
    }

    fn views_from_buffer(&self, buffer: &CwEventBuffer) -> Vec<EventView> {
        buffer.events[..buffer.count]
            .iter()
            .map(|event| self.event_view(event))
            .collect()
    }

    fn event_content(&self, event: &CwEvent) -> Option<String> {
        if event.success != 0 {
            match event.type_ {
                CW_EVENT_ITEM_TRADED => return self.trade_event_context(event),
                CW_EVENT_ITEM_PICKED_UP => return self.pickup_event_context(event),
                CW_EVENT_ITEM_DROPPED => return self.drop_event_context(event),
                CW_EVENT_ITEM_USED => return self.use_event_context(event),
                CW_EVENT_ITEM_GIVEN => return self.give_event_context(event),
                CW_EVENT_ACTOR_MOVED => return self.move_event_context(event),
                CW_EVENT_ITEM_FOUND => return self.search_found_event_context(event),
                CW_EVENT_ITEM_CRAFTED => return self.craft_event_context(event),
                CW_EVENT_ITEM_CREATED => return self.item_created_event_context(event),
                _ => {}
            }
        }
        self.content.get(&event.content_id).cloned()
    }

    fn recipe_name(&self, recipe_id: u64) -> Option<String> {
        self.recipe_by_id(recipe_id)
            .map(|recipe| recipe.name.clone())
    }

    fn search_found_event_context(&self, event: &CwEvent) -> Option<String> {
        let item_name = self.item_name(event.item_id)?;
        let location_name = self.location_name(event.location_id)?;
        Some(format!("{item_name} turned up in {location_name}."))
    }

    fn craft_event_context(&self, event: &CwEvent) -> Option<String> {
        let recipe_name = self
            .recipe_name(event.content_id)
            .unwrap_or_else(|| "Craft".to_string());
        let held_name = self.item_name(event.item_id)?;
        let floor_name = self.item_name(event.target_item_id)?;
        Some(format!("{recipe_name}: {held_name} met {floor_name}."))
    }

    fn item_created_event_context(&self, event: &CwEvent) -> Option<String> {
        let item_name = self.item_name(event.item_id)?;
        if let Some(location_name) = self.location_name(event.location_id) {
            Some(format!("{item_name} now waits in {location_name}."))
        } else if let Some(actor_name) = self.actor_name(event.target_actor_id) {
            Some(format!(
                "{item_name} now belongs in {actor_name}'s keeping."
            ))
        } else {
            Some(format!("{item_name} joined the world."))
        }
    }

    fn trade_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        let target = self.actor_by_id(event.target_actor_id)?;
        let mut parts = Vec::new();
        if Self::actor_is_active_avatar(actor) && event.target_item_id != 0 {
            parts.push(self.resident_gained_item_reason(actor, event.target_item_id));
        }
        if Self::actor_is_active_avatar(target) && event.item_id != 0 {
            parts.push(self.resident_gained_item_reason(target, event.item_id));
        }
        (!parts.is_empty()).then(|| format!("{}.", parts.join("; ")))
    }

    fn give_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        let target = self.actor_by_id(event.target_actor_id)?;
        if event.item_id == 0 || !Self::actor_is_active_avatar(target) {
            return None;
        }
        let item_name = self
            .item_name(event.item_id)
            .unwrap_or_else(|| format!("Item {}", event.item_id));
        let actor_name = self
            .actor_name(actor.id)
            .unwrap_or_else(|| format!("Actor {}", actor.id));
        let target_name = self
            .actor_name(target.id)
            .unwrap_or_else(|| format!("Resident {}", target.id));
        let reason = self.resident_gained_item_reason(target, event.item_id);
        let room_made = (event.target_item_id != 0)
            .then(|| {
                self.item_name(event.target_item_id)
                    .unwrap_or_else(|| format!("Item {}", event.target_item_id))
            })
            .map(|returned_name| {
                format!("; {target_name} handed {returned_name} back to make room")
            })
            .unwrap_or_default();
        Some(format!(
            "{actor_name} gave {item_name} to {target_name}{room_made}; {reason}."
        ))
    }

    fn pickup_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        if !Self::actor_is_active_avatar(actor) || event.item_id == 0 {
            return None;
        }
        Some(format!(
            "{}.",
            self.resident_gained_item_reason(actor, event.item_id)
        ))
    }

    fn drop_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        if !Self::actor_is_active_avatar(actor) || event.item_id == 0 {
            return None;
        }
        let actor_name = self
            .actor_name(actor.id)
            .unwrap_or_else(|| format!("Resident {}", actor.id));
        let item_name = self
            .item_name(event.item_id)
            .unwrap_or_else(|| format!("Item {}", event.item_id));
        if let Some(target_item_name) = self.resident_local_seek_item_name(actor, event.item_id) {
            return Some(format!(
                "{actor_name} made room for {target_item_name} by letting go of {item_name}."
            ));
        }
        Some(format!(
            "{actor_name} made room by letting go of {item_name}."
        ))
    }

    fn use_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        if !Self::actor_is_active_avatar(actor) || event.item_id == 0 || event.damage >= 0 {
            return None;
        }
        let actor_name = self
            .actor_name(actor.id)
            .unwrap_or_else(|| format!("Resident {}", actor.id));
        let item_name = self
            .item_name(event.item_id)
            .unwrap_or_else(|| format!("Item {}", event.item_id));
        if event.target_actor_id != 0 && event.target_actor_id != event.actor_id {
            let target_name = self
                .actor_name(event.target_actor_id)
                .unwrap_or_else(|| format!("Resident {}", event.target_actor_id));
            return Some(format!(
                "{actor_name} used {item_name} to help {target_name}."
            ));
        }
        Some(format!("{actor_name} used {item_name} to recover."))
    }

    fn move_event_context(&self, event: &CwEvent) -> Option<String> {
        let actor = self.actor_by_id(event.actor_id)?;
        if !Self::actor_is_active_avatar(actor) {
            return None;
        }
        let from_location_id = event.location_id;
        let to_location_id = event.destination_location_id;
        let memory = self.resident_memory_seek_target(actor)?;
        if self.next_unlocked_step_toward(from_location_id, memory.location_id)
            != Some(to_location_id)
        {
            return None;
        }
        let actor_name = self
            .actor_name(actor.id)
            .unwrap_or_else(|| format!("Resident {}", actor.id));
        let item_name = self
            .item_name(memory.subject_id)
            .unwrap_or_else(|| format!("Item {}", memory.subject_id));
        let location_name = self
            .location_name(memory.location_id)
            .unwrap_or_else(|| format!("Location {}", memory.location_id));
        Some(format!(
            "{actor_name} remembered {item_name} near {location_name}."
        ))
    }

    fn resident_gained_item_reason(&self, resident: CwActor, item_id: u64) -> String {
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let item_name = self
            .item_name(item_id)
            .unwrap_or_else(|| format!("Item {item_id}"));
        let item = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .find(|item| item.id == item_id);
        let healing_target = self.resident_healing_target(resident);
        if let Some(desire) = self.resident_personal_desire_for_item(resident.id, item_id) {
            format!(
                "{resident_name} wanted {item_name}: {}",
                desire.reason.trim_end_matches('.')
            )
        } else if self
            .resident_desired_item_ids(resident)
            .into_iter()
            .any(|desired_item_id| desired_item_id == item_id)
        {
            format!("{resident_name} wanted {item_name}")
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION)
            && healing_target.is_some_and(|target| target.id == resident.id)
        {
            format!("{resident_name} needed {item_name}")
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION) && healing_target.is_some() {
            let target = healing_target.expect("healing target checked");
            let target_name = self
                .actor_name(target.id)
                .unwrap_or_else(|| format!("Resident {}", target.id));
            format!("{resident_name} wanted {item_name} for {target_name}")
        } else if let Some(reason) = self.resident_item_recovery_reason(resident, item_id) {
            reason
        } else if let Some(candidate) = self.resident_feature_use_match_for_item(resident, item_id)
        {
            format!(
                "{resident_name} could use {item_name} with {}",
                candidate.feature_name
            )
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION) {
            format!("{resident_name} could use {item_name}")
        } else {
            format!("{resident_name} valued {item_name}")
        }
    }

    fn event_view(&self, event: &CwEvent) -> EventView {
        EventView {
            world_id: official_world_id(),
            world_epoch: official_world_epoch(),
            seq: event.seq,
            type_name: event_type_name(event.type_),
            success: event.success != 0,
            reason: event.reason,
            actor_id: opt_id(event.actor_id),
            actor_name: self.actor_name(event.actor_id),
            target_actor_id: opt_id(event.target_actor_id),
            target_actor_name: self.actor_name(event.target_actor_id),
            location_id: opt_id(event.location_id),
            location_name: self.location_name(event.location_id),
            destination_location_id: opt_id(event.destination_location_id),
            destination_location_name: self.location_name(event.destination_location_id),
            content_id: opt_id(event.content_id),
            content: self.event_content(event),
            item_id: opt_id(event.item_id),
            item_name: self.item_name(event.item_id),
            target_item_id: opt_id(event.target_item_id),
            target_item_name: self.item_name(event.target_item_id),
            raw_roll: opt_i16(event.raw_roll),
            modifier: opt_i16(event.modifier),
            total: opt_i16(event.total),
            dc: opt_i16(event.dc),
            damage: opt_i16(event.damage),
            current_hp: event_current_hp(event),
            clock_id: None,
            clock_scope: None,
            clock_scope_id: None,
            clock_kind: None,
            clock_label: None,
            clock_filled: None,
            clock_segments: None,
            clock_delta: None,
            tag_id: None,
            tag_scope: None,
            tag_scope_id: None,
            tag_kind: None,
            tag_label: None,
            caused_by_event_seq: None,
            source_world_tick: None,
            observed_through_seq: None,
            source_location_id: None,
            content_context: ContentReferenceContext::default(),
        }
    }

    fn actor_name(&self, actor_id: u64) -> Option<String> {
        self.actors.get(&actor_id).map(|meta| meta.name.clone())
    }

    fn item_name(&self, item_id: u64) -> Option<String> {
        self.items.get(&item_id).map(|meta| meta.name.clone())
    }

    fn seed_item_contract_for_instance(&self, item_id: u64) -> Option<&'static SeedItemContent> {
        active_content()
            .items
            .iter()
            .find(|seed| seed.id == item_id)
            .or_else(|| {
                let receipt = self
                    .materialization_receipts
                    .values()
                    .find(|receipt| receipt.item_id == item_id)?;
                let card = active_content()
                    .cards
                    .iter()
                    .find(|card| card.card_id == receipt.card_id && card.subject_kind == "item")?;
                active_content()
                    .items
                    .iter()
                    .find(|seed| seed.id == card.subject_id)
            })
    }

    fn location_name(&self, location_id: u64) -> Option<String> {
        self.locations.get(&location_id).cloned()
    }

    fn location_meta_for(&self, location_id: u64) -> LocationMeta {
        let name = self
            .location_name(location_id)
            .unwrap_or_else(|| "Unknown Location".to_string());
        self.location_meta
            .get(&location_id)
            .cloned()
            .unwrap_or_else(|| LocationMeta {
                title: name.clone(),
                description: format!("{name} has not settled its description yet."),
                persona: format!("{name} listens quietly until its persona is written."),
                memory: Vec::new(),
                biome: "unknown".to_string(),
                terrain: Vec::new(),
                image_url: None,
                art_prompt: None,
            })
    }

    fn actor_is_explorer(&self, actor_id: u64) -> bool {
        self.callings
            .get(&actor_id)
            .is_some_and(|calling| calling_statement_is_explorer(&calling.statement))
    }

    fn pathway_for_anchors(
        &self,
        from_location_id: u64,
        to_location_id: u64,
    ) -> Option<&GeneratedPathwayState> {
        self.generated_pathways
            .get(&generated_pathway_id(from_location_id, to_location_id))
    }

    fn generated_pathway_for_location(&self, location_id: u64) -> Option<&GeneratedPathwayState> {
        self.generated_pathways.values().find(|pathway| {
            pathway
                .waypoints
                .iter()
                .any(|waypoint| waypoint.id == location_id)
        })
    }

    fn generated_pathway_id_for_progress_clock(&self, clock_id: &str) -> Option<String> {
        self.generated_pathways
            .values()
            .find(|pathway| generated_pathway_progress_clock_id(&pathway.id) == clock_id)
            .map(|pathway| pathway.id.clone())
    }

    fn generated_location_is_revealed(&self, location_id: u64) -> bool {
        self.generated_pathways.values().any(|pathway| {
            pathway
                .waypoints
                .iter()
                .any(|waypoint| waypoint.id == location_id)
                && pathway.revealed_edges.iter().any(|edge| {
                    parse_pathway_edge_key(edge)
                        .is_some_and(|(left, right)| left == location_id || right == location_id)
                })
        })
    }

    fn pathway_distance(&self, from_location_id: u64, to_location_id: u64) -> u8 {
        active_content()
            .exits
            .iter()
            .find(|exit| {
                exit.from_location_id == from_location_id && exit.to_location_id == to_location_id
            })
            .map(|exit| exit.distance.max(1))
            .unwrap_or(1)
    }

    fn generated_pathway(
        &self,
        actor_id: u64,
        from_location_id: u64,
        to_location_id: u64,
        distance: u8,
    ) -> GeneratedPathwayState {
        let (origin_location_id, destination_location_id) =
            canonical_pathway_anchors(from_location_id, to_location_id);
        let origin_name = self
            .location_name(origin_location_id)
            .unwrap_or_else(|| "one known place".to_string());
        let destination_name = self
            .location_name(destination_location_id)
            .unwrap_or_else(|| "another known place".to_string());
        let origin_meta = self.location_meta_for(origin_location_id);
        let destination_meta = self.location_meta_for(destination_location_id);
        let pathway_id = generated_pathway_id(origin_location_id, destination_location_id);
        let seed = stable_pathway_hash(&pathway_id);
        let waypoint_count = usize::from(distance.saturating_sub(1));
        let names = [
            "Lantern Bend",
            "Mossy Verge",
            "Rain-Silver Crossing",
            "Foxglove Turn",
            "Quiet Rise",
            "Bramble Mile",
        ];
        let waypoints = (0..waypoint_count)
            .map(|index| {
                let landmark_name = names[(seed as usize + index) % names.len()].to_string();
                let id = generated_pathway_location_id(&pathway_id, index);
                let art_prompt = format!(
                    "cozy storybook landscape, {landmark_name}, a hidden waypoint along a newly explored pathway between {origin_name} and {destination_name}, stretch {step} of {distance}, {origin_biome} terrain meeting {destination_biome} terrain, {origin} meeting {destination}, no people, no text",
                    step = index + 1,
                    origin_biome = origin_meta.biome,
                    destination_biome = destination_meta.biome,
                    origin = origin_meta.description,
                    destination = destination_meta.description,
                );
                let terrain = interpolated_pathway_terrain(
                    &origin_meta,
                    &destination_meta,
                    index,
                    waypoint_count,
                );
                let terrain_phrase = terrain
                    .iter()
                    .take(3)
                    .cloned()
                    .collect::<Vec<_>>()
                    .join(", ");
                let description = format!(
                    "At {landmark_name}, {terrain_phrase} mark a half-known stretch between {origin_name} and {destination_name}; weather and footprints are still deciding what belongs."
                );
                GeneratedWaypointState {
                    id,
                    name: landmark_name.clone(),
                    meta: LocationMeta {
                        title: "Newly Found Path".to_string(),
                        description,
                        persona: format!(
                            "{landmark_name} is unfinished geography: alert, changeable, and eager to become familiar through footsteps."
                        ),
                        memory: vec![format!(
                            "An Explorer first drew this path between {origin_name} and {destination_name}."
                        )],
                        biome: format!("{} to {}", origin_meta.biome, destination_meta.biome),
                        terrain,
                        image_url: Some(format!("/assets/generated/pathways/{id}.svg")),
                        art_prompt: Some(art_prompt),
                    },
                }
            })
            .collect();
        GeneratedPathwayState {
            id: pathway_id,
            origin_location_id,
            destination_location_id,
            distance,
            created_by_actor_id: actor_id,
            waypoints,
            generation: GenerationProvenance {
                source: "deterministic_fallback".to_string(),
                feature: PATHWAY_CONTENT_FEATURE.to_string(),
                policy_mode: "fallback".to_string(),
                prompt_version: PATHWAY_CONTENT_PROMPT_VERSION.to_string(),
                provider: "none".to_string(),
                model: "none".to_string(),
                attempts: 0,
            },
            revealed_edges: BTreeSet::new(),
            art_eligible: distance >= 2,
            familiar: false,
        }
    }

    fn pathway_path(
        &self,
        pathway: &GeneratedPathwayState,
        from_location_id: u64,
        to_location_id: u64,
    ) -> Vec<u64> {
        let mut path = vec![pathway.origin_location_id];
        path.extend(pathway.waypoints.iter().map(|waypoint| waypoint.id));
        path.push(pathway.destination_location_id);
        if from_location_id == pathway.destination_location_id
            && to_location_id == pathway.origin_location_id
        {
            path.reverse();
        }
        path
    }

    #[cfg(test)]
    fn pathway_is_complete(&self, pathway: &GeneratedPathwayState) -> bool {
        let path = self.pathway_path(
            pathway,
            pathway.origin_location_id,
            pathway.destination_location_id,
        );
        path.windows(2).all(|edge| {
            pathway
                .revealed_edges
                .contains(&pathway_edge_key(edge[0], edge[1]))
        })
    }

    fn plan_journey_move(
        &self,
        actor_id: u64,
        requested_destination_id: u64,
    ) -> Result<Option<(CwAction, ProjectionMutation, JourneyNarrationPlan)>, String> {
        let actor = self
            .actor_by_id(actor_id)
            .ok_or_else(|| "The traveller is no longer here.".to_string())?;
        if let Some(current) = self.journeys.get(&actor_id).cloned() {
            let next_step = current.current_step + 1;
            let next_location_id = current
                .path
                .get(next_step)
                .copied()
                .ok_or_else(|| "This pathway has already arrived.".to_string())?;
            let pathway = self
                .generated_pathways
                .get(&current.pathway_id)
                .cloned()
                .ok_or_else(|| "The pathway has slipped out of the shared map.".to_string())?;
            let current_location_id = current.path[current.current_step];
            if requested_destination_id != next_location_id {
                let alternate_distance =
                    self.pathway_distance(actor.location_id, requested_destination_id);
                if alternate_distance > 1 {
                    return self
                        .plan_new_journey(actor, requested_destination_id, alternate_distance)
                        .map(Some);
                }
                let adjacent = self.world.exits[..self.world.exit_count]
                    .iter()
                    .any(|exit| {
                        exit.from_location_id == actor.location_id
                            && exit.to_location_id == requested_destination_id
                            && exit.flags & CW_EXIT_LOCKED == 0
                    });
                if !adjacent {
                    return Err("That place is not an open adjacent path.".to_string());
                }
                let previous_step = current.current_step.checked_sub(1);
                let backtracking = previous_step.is_some_and(|step| {
                    current.path.get(step).copied() == Some(requested_destination_id)
                        && pathway.revealed_edges.contains(&pathway_edge_key(
                            current_location_id,
                            requested_destination_id,
                        ))
                });
                let to_name = self
                    .location_name(requested_destination_id)
                    .or_else(|| {
                        pathway
                            .waypoints
                            .iter()
                            .find(|waypoint| waypoint.id == requested_destination_id)
                            .map(|waypoint| waypoint.name.clone())
                    })
                    .unwrap_or_else(|| "another open way".to_string());
                let mut next_journey = current.clone();
                if let Some(step) = previous_step.filter(|_| backtracking) {
                    next_journey.current_step = step;
                }
                let plan = JourneyNarrationPlan {
                    actor_name: self
                        .actor_name(actor_id)
                        .unwrap_or_else(|| "The traveller".to_string()),
                    from_name: self
                        .location_name(current_location_id)
                        .unwrap_or_else(|| "the path's edge".to_string()),
                    to_name: to_name.clone(),
                    destination_name: if backtracking {
                        current.destination_name.clone()
                    } else {
                        to_name
                    },
                    current_step: if backtracking {
                        next_journey.current_step
                    } else {
                        1
                    },
                    total_steps: if backtracking {
                        current.path.len().saturating_sub(1)
                    } else {
                        1
                    },
                    discovery: false,
                };
                return Ok(Some((
                    CwAction {
                        kind: CW_ACTION_MOVE,
                        actor_id,
                        destination_location_id: requested_destination_id,
                        ..CwAction::default()
                    },
                    ProjectionMutation::JourneyTransition {
                        pathway,
                        journey: backtracking.then_some(next_journey),
                        reveal_edges: Vec::new(),
                        narration: String::new(),
                        event_type: if backtracking {
                            "journey.backtracked".to_string()
                        } else {
                            "journey.paused".to_string()
                        },
                    },
                    plan,
                )));
            }
            if actor.location_id != current_location_id
                || !pathway
                    .revealed_edges
                    .contains(&pathway_edge_key(current_location_id, next_location_id))
            {
                return Err("Search this place before travelling onward.".to_string());
            }
            let mut next_journey = current.clone();
            next_journey.current_step = next_step;
            let completed = next_step + 1 >= current.path.len();
            let to_name = self
                .location_name(next_location_id)
                .or_else(|| {
                    pathway
                        .waypoints
                        .iter()
                        .find(|waypoint| waypoint.id == next_location_id)
                        .map(|waypoint| waypoint.name.clone())
                })
                .unwrap_or_else(|| current.destination_name.clone());
            let plan = JourneyNarrationPlan {
                actor_name: self
                    .actor_name(actor_id)
                    .unwrap_or_else(|| "The traveller".to_string()),
                from_name: self
                    .location_name(current_location_id)
                    .unwrap_or_else(|| "the path's edge".to_string()),
                to_name,
                destination_name: current.destination_name.clone(),
                current_step: next_step,
                total_steps: current.path.len().saturating_sub(1),
                discovery: false,
            };
            return Ok(Some((
                CwAction {
                    kind: CW_ACTION_MOVE,
                    actor_id,
                    destination_location_id: next_location_id,
                    ..CwAction::default()
                },
                ProjectionMutation::JourneyTransition {
                    pathway,
                    journey: (!completed).then_some(next_journey),
                    reveal_edges: Vec::new(),
                    narration: String::new(),
                    event_type: if completed {
                        "journey.completed".to_string()
                    } else {
                        "journey.progressed".to_string()
                    },
                },
                plan,
            )));
        }

        let distance = self.pathway_distance(actor.location_id, requested_destination_id);
        if distance <= 1 {
            return Ok(None);
        }
        self.plan_new_journey(actor, requested_destination_id, distance)
            .map(Some)
    }

    fn plan_new_journey(
        &self,
        actor: CwActor,
        requested_destination_id: u64,
        distance: u8,
    ) -> Result<(CwAction, ProjectionMutation, JourneyNarrationPlan), String> {
        let actor_id = actor.id;
        let explorer = self.actor_is_explorer(actor_id);
        let existing_pathway = self
            .pathway_for_anchors(actor.location_id, requested_destination_id)
            .cloned();
        let discovering_pathway = existing_pathway.is_none();
        let pathway = existing_pathway.unwrap_or_else(|| {
            self.generated_pathway(
                actor_id,
                actor.location_id,
                requested_destination_id,
                distance,
            )
        });
        let path = self.pathway_path(&pathway, actor.location_id, requested_destination_id);
        let first_edge = (path[0], path[1]);
        let next_journey = JourneyState {
            actor_id,
            pathway_id: pathway.id.clone(),
            origin_location_id: actor.location_id,
            destination_location_id: requested_destination_id,
            destination_name: self
                .location_name(requested_destination_id)
                .unwrap_or_else(|| "the far end of the path".to_string()),
            path: path.clone(),
            current_step: 0,
            explorer,
        };
        let next_location_id = path[1];
        let to_name = pathway
            .waypoints
            .iter()
            .find(|waypoint| waypoint.id == next_location_id)
            .map(|waypoint| waypoint.name.clone())
            .unwrap_or_else(|| next_journey.destination_name.clone());
        let plan = JourneyNarrationPlan {
            actor_name: self
                .actor_name(actor_id)
                .unwrap_or_else(|| "The traveller".to_string()),
            from_name: self
                .location_name(actor.location_id)
                .unwrap_or_else(|| "the known road".to_string()),
            to_name,
            destination_name: next_journey.destination_name.clone(),
            current_step: 1,
            total_steps: path.len().saturating_sub(1),
            discovery: discovering_pathway,
        };
        Ok((
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id,
                ..CwAction::default()
            },
            ProjectionMutation::JourneyTransition {
                pathway,
                journey: Some(next_journey),
                reveal_edges: vec![first_edge],
                narration: String::new(),
                event_type: "pathway.discovered".to_string(),
            },
            plan,
        ))
    }

    fn plan_pathway_search(
        &self,
        actor_id: u64,
    ) -> Result<(CwAction, ProjectionMutation, JourneyNarrationPlan), String> {
        let current = self
            .journeys
            .get(&actor_id)
            .cloned()
            .ok_or_else(|| "There is no unfinished journey here.".to_string())?;
        let next_step = current.current_step + 1;
        let next_location_id = current
            .path
            .get(next_step)
            .copied()
            .ok_or_else(|| "This pathway has already arrived.".to_string())?;
        let current_location_id = current.path[current.current_step];
        let pathway = self
            .generated_pathways
            .get(&current.pathway_id)
            .cloned()
            .ok_or_else(|| "The pathway has slipped out of the shared map.".to_string())?;
        if pathway
            .revealed_edges
            .contains(&pathway_edge_key(current_location_id, next_location_id))
        {
            return Err("The next stretch is already ready to travel.".to_string());
        }
        let to_name = self
            .location_name(next_location_id)
            .or_else(|| {
                pathway
                    .waypoints
                    .iter()
                    .find(|waypoint| waypoint.id == next_location_id)
                    .map(|waypoint| waypoint.name.clone())
            })
            .unwrap_or_else(|| current.destination_name.clone());
        let plan = JourneyNarrationPlan {
            actor_name: self
                .actor_name(actor_id)
                .unwrap_or_else(|| "The Explorer".to_string()),
            from_name: self
                .location_name(current_location_id)
                .unwrap_or_else(|| "the path's edge".to_string()),
            to_name,
            destination_name: current.destination_name.clone(),
            current_step: next_step,
            total_steps: current.path.len().saturating_sub(1),
            discovery: true,
        };
        Ok((
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id,
                ..CwAction::default()
            },
            ProjectionMutation::JourneyTransition {
                pathway,
                journey: Some(current),
                reveal_edges: vec![(current_location_id, next_location_id)],
                narration: String::new(),
                event_type: "pathway.discovered".to_string(),
            },
            plan,
        ))
    }

    fn actor_by_id(&self, actor_id: u64) -> Option<CwActor> {
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .find(|actor| actor.id == actor_id)
    }

    fn actor_is_active_avatar(actor: CwActor) -> bool {
        matches!(actor.kind, CW_ACTOR_HUMAN | CW_ACTOR_NPC) && actor.status == CW_ACTOR_ACTIVE
    }

    fn actor_control_mode(&self, actor_id: u64) -> ActorControlMode {
        self.actor_autonomy
            .get(&actor_id)
            .map(|autonomy| autonomy.control_mode)
            .unwrap_or_default()
    }

    fn actors_blocked(&self, left_actor_id: u64, right_actor_id: u64) -> bool {
        self.actor_safety
            .get(&left_actor_id)
            .is_some_and(|safety| safety.blocked_actor_ids.contains(&right_actor_id))
            || self
                .actor_safety
                .get(&right_actor_id)
                .is_some_and(|safety| safety.blocked_actor_ids.contains(&left_actor_id))
    }

    fn actor_muted(&self, actor_id: u64, target_actor_id: u64) -> bool {
        self.actor_safety
            .get(&actor_id)
            .is_some_and(|safety| safety.muted_actor_ids.contains(&target_actor_id))
    }

    fn transfer_offer_status(&self, offer: &TransferOfferState) -> TransferOfferStatus {
        if offer.status == TransferOfferStatus::Pending && self.world.tick >= offer.expires_tick {
            TransferOfferStatus::Expired
        } else {
            offer.status
        }
    }

    fn expire_transfer_offers(&mut self) {
        let tick = self.world.tick;
        for offer in self.transfer_offers.values_mut() {
            if offer.status == TransferOfferStatus::Pending && tick >= offer.expires_tick {
                offer.status = TransferOfferStatus::Expired;
            }
        }
    }

    fn matching_pending_transfer_offer(
        &self,
        kind: TransferOfferKind,
        offered_by_actor_id: u64,
        offered_to_actor_id: u64,
        offered_item_id: u64,
        requested_item_id: Option<u64>,
    ) -> Option<&TransferOfferState> {
        self.transfer_offers.values().find(|offer| {
            self.transfer_offer_status(offer) == TransferOfferStatus::Pending
                && offer.kind == kind
                && offer.offered_by_actor_id == offered_by_actor_id
                && offer.offered_to_actor_id == offered_to_actor_id
                && offer.offered_item_id == offered_item_id
                && offer.requested_item_id == requested_item_id
        })
    }

    fn new_transfer_offer(
        &self,
        kind: TransferOfferKind,
        offered_by_actor_id: u64,
        offered_to_actor_id: u64,
        offered_item_id: u64,
        requested_item_id: Option<u64>,
    ) -> TransferOfferState {
        let kind_label = match kind {
            TransferOfferKind::Gift => "gift",
            TransferOfferKind::Trade => "trade",
        };
        TransferOfferState {
            id: format!(
                "{kind_label}-{}-{}-{}-{}-{}-{}",
                offered_by_actor_id,
                offered_to_actor_id,
                offered_item_id,
                requested_item_id.unwrap_or_default(),
                self.world.next_event_seq,
                self.next_seed
            ),
            kind,
            offered_by_actor_id,
            offered_to_actor_id,
            offered_item_id,
            requested_item_id,
            created_tick: self.world.tick,
            expires_tick: self.world.tick.saturating_add(TRANSFER_OFFER_TTL_TICKS),
            status: TransferOfferStatus::Pending,
            resolved_by_actor_id: None,
        }
    }

    fn gift_auto_accept_policy(
        &self,
        recipient_actor_id: u64,
        offered_by_actor_id: u64,
        item_id: u64,
    ) -> Option<&GiftAutoAcceptPolicy> {
        self.gift_auto_accepts.values().find(|policy| {
            !policy.consumed
                && self.world.tick < policy.expires_tick
                && policy.recipient_actor_id == recipient_actor_id
                && policy.offered_by_actor_id == offered_by_actor_id
                && policy.item_id == item_id
                && !self.actors_blocked(recipient_actor_id, offered_by_actor_id)
        })
    }

    fn new_gift_auto_accept_policy(
        &self,
        recipient_actor_id: u64,
        offered_by_actor_id: u64,
        item_id: u64,
    ) -> GiftAutoAcceptPolicy {
        GiftAutoAcceptPolicy {
            id: format!(
                "gift-request-{recipient_actor_id}-{offered_by_actor_id}-{item_id}-{}-{}",
                self.world.next_event_seq, self.next_seed
            ),
            recipient_actor_id,
            offered_by_actor_id,
            item_id,
            created_tick: self.world.tick,
            expires_tick: self.world.tick.saturating_add(TRANSFER_OFFER_TTL_TICKS),
            consumed: false,
        }
    }

    fn actor_uses_inference(&self, actor_id: u64) -> bool {
        self.actor_control_mode(actor_id).uses_inference()
    }

    fn client_actor_can_submit(&self, actor_id: u64) -> bool {
        self.actor_by_id(actor_id)
            .is_some_and(Self::actor_is_active_avatar)
            && self.actor_control_mode(actor_id).is_direct_input()
    }

    fn actor_visible_in_projection(
        &self,
        actor: CwActor,
        client_actor_id: Option<u64>,
        active_direct_actor_ids: Option<&BTreeSet<u64>>,
    ) -> bool {
        if !self.actor_uses_inference(actor.id) {
            if Some(actor.id) == client_actor_id {
                return true;
            }
            return active_direct_actor_ids
                .map(|ids| ids.contains(&actor.id))
                .unwrap_or(true);
        }
        if self.avatar_hidden_until_discovered(actor) {
            return self.avatar_discovered(actor.id);
        }
        true
    }

    fn actor_held_items(&self, actor_id: u64) -> Vec<CwItem> {
        let mut items: Vec<_> = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .filter(|item| item.holder_actor_id == actor_id)
            .collect();
        items.sort_by_key(|item| item.id);
        items
    }

    fn default_spell_card(&self, actor_id: u64) -> Option<CwItem> {
        let prepared = self.prepared_spells.get(&actor_id)?;
        self.actor_held_items(actor_id).into_iter().find(|item| {
            item.role == CW_ITEM_ROLE_SPELL
                && item.zone == CW_CARD_ZONE_SPELL_DECK
                && item.charges > 0
                && prepared.contains(&item.id)
        })
    }

    fn equipped_weapon_item(&self, actor_id: u64) -> Option<CwItem> {
        self.actor_held_items(actor_id)
            .into_iter()
            .find(|item| item.role == CW_ITEM_ROLE_WEAPON && item.zone == CW_CARD_ZONE_EQUIPPED)
    }

    fn charm_slot_count(&self, actor_id: u64) -> u8 {
        self.charm_slots
            .get(&actor_id)
            .copied()
            .unwrap_or(BASE_CHARM_SLOTS)
            .clamp(BASE_CHARM_SLOTS, MAX_CHARM_SLOTS)
    }

    fn equipped_charm_items(&self, actor_id: u64) -> Vec<CwItem> {
        self.equipped_charms
            .get(&actor_id)
            .into_iter()
            .flat_map(|item_ids| item_ids.iter())
            .filter_map(|item_id| self.item_by_id(*item_id))
            .filter(|item| {
                item.holder_actor_id == actor_id
                    && item.role == CW_ITEM_ROLE_SKILL_CHARM
                    && item.zone == CW_CARD_ZONE_EQUIPPED
            })
            .take(usize::from(self.charm_slot_count(actor_id)))
            .collect()
    }

    fn charm_slot_expansion_candidate(&self, actor_id: u64) -> Option<CwItem> {
        let slots = self.charm_slot_count(actor_id);
        if slots >= MAX_CHARM_SLOTS
            || self.advancement_points_available(actor_id) < usize::from(CHARM_SLOT_COST)
        {
            return None;
        }
        let equipped = self.equipped_charm_items(actor_id);
        if equipped.len() != usize::from(slots) {
            return None;
        }
        let equipped_ids = equipped
            .into_iter()
            .map(|item| item.id)
            .collect::<BTreeSet<_>>();
        self.actor_held_items(actor_id).into_iter().find(|item| {
            item.role == CW_ITEM_ROLE_SKILL_CHARM
                && item.zone != CW_CARD_ZONE_EQUIPPED
                && !equipped_ids.contains(&item.id)
        })
    }

    fn deck_view(&self, actor_id: Option<u64>) -> DeckView {
        let Some(actor_id) = actor_id else {
            return DeckView {
                actor_id: None,
                carried_cards: Vec::new(),
                carried_weight_tenths: 0,
                base_carrying_capacity_tenths: 0,
                container_capacity_tenths: 0,
                carrying_capacity_tenths: 0,
                bracelet_slots: 0,
                equipped_charms: Vec::new(),
                available_charms: Vec::new(),
                charm_slot_expansion: None,
                spell_cards: Vec::new(),
                prepared_spell_cards: Vec::new(),
                exhausted_spell_cards: Vec::new(),
                exhausted_cards: Vec::new(),
                spell_deck_slots: 0,
                equipped_weapon: None,
                equipped_containers: Vec::new(),
                containers: Vec::new(),
                zone_counts: BTreeMap::new(),
                validation_errors: Vec::new(),
                bag_previews: Vec::new(),
            };
        };
        let carried = self.actor_held_items(actor_id);
        let charm_slot_expansion =
            self.charm_slot_expansion_candidate(actor_id).map(|charm| {
                let name = self
                    .item_name(charm.id)
                    .unwrap_or_else(|| format!("Item {}", charm.id));
                let description = self
                    .items
                    .get(&charm.id)
                    .map(|meta| meta.description.trim())
                    .filter(|description| !description.is_empty())
                    .unwrap_or("This charm could add another knack to your bracelet.");
                let advancement = self.advancement_points_available(actor_id);
                CharmSlotExpansionView {
                    charm: self.item_view(charm),
                    label: format!("Make room for {name}"),
                    explanation: format!(
                        "{description} Your Journal holds {advancement} earned advancement; spend {CHARM_SLOT_COST} to open one slot. The charm stays carried until you choose to wear it."
                    ),
                    advancement_cost: CHARM_SLOT_COST,
                }
            });
        let equipped_ids = self
            .equipped_charm_items(actor_id)
            .into_iter()
            .map(|item| item.id)
            .collect::<BTreeSet<_>>();
        let equipped_weapon = carried
            .iter()
            .copied()
            .find(|item| item.role == CW_ITEM_ROLE_WEAPON && item.zone == CW_CARD_ZONE_EQUIPPED)
            .map(|item| self.item_view(item));
        let equipped_containers = carried
            .iter()
            .copied()
            .filter(|item| {
                item.role == CW_ITEM_ROLE_CONTAINER && item.zone == CW_CARD_ZONE_EQUIPPED
            })
            .map(|item| self.item_view(item))
            .collect::<Vec<_>>();
        let containers = carried
            .iter()
            .copied()
            .filter(|item| item.role == CW_ITEM_ROLE_CONTAINER)
            .map(|container| {
                let contract = self.seed_item_contract_for_instance(container.id);
                ContainerDeckView {
                    container: self.item_view(container),
                    contents: carried
                        .iter()
                        .copied()
                        .filter(|item| item.container_item_id == container.id)
                        .map(|item| self.item_view(item))
                        .collect(),
                    opening_size: contract
                        .and_then(|seed| seed.container_opening_size.clone())
                        .unwrap_or_else(|| "none".to_string()),
                    allowed_contents: contract
                        .map(|seed| seed.allowed_contents.clone())
                        .unwrap_or_default(),
                    equipped: container.zone == CW_CARD_ZONE_EQUIPPED,
                    active_capacity_tenths: if container.zone == CW_CARD_ZONE_EQUIPPED {
                        container.container_capacity_tenths
                    } else {
                        0
                    },
                }
            })
            .collect::<Vec<_>>();
        let mut zone_counts = BTreeMap::new();
        for item in &carried {
            *zone_counts
                .entry(card_zone(item.zone, item.holder_actor_id, item.location_id).to_string())
                .or_insert(0) += 1;
        }
        let carried_weight = self.actor_carried_weight_tenths(actor_id);
        let carrying_capacity = self
            .actor_carrying_capacity_tenths(actor_id)
            .unwrap_or_default();
        let mut validation_errors = Vec::new();
        if carried_weight > carrying_capacity {
            let over = carried_weight.saturating_sub(carrying_capacity);
            let heaviest = carried
                .iter()
                .max_by_key(|item| effective_item_weight_tenths(**item))
                .and_then(|item| self.item_name(item.id))
                .unwrap_or_else(|| "a carried card".to_string());
            validation_errors.push(format!(
                "over capacity by {:.1} lb; {heaviest} is the heaviest carried card and only equipped, uncontained bags add capacity",
                over as f64 / 10.0
            ));
        }
        let bag_previews = carried
            .iter()
            .filter(|item| {
                item.role == CW_ITEM_ROLE_CONTAINER
                    && item.zone == CW_CARD_ZONE_CARRIED
                    && item.container_item_id == 0
            })
            .map(|item| {
                let preview_capacity =
                    carrying_capacity + u32::from(item.container_capacity_tenths);
                format!(
                    "equip {}: capacity becomes {:.1} lb and the carried deck would be {}",
                    self.item_name(item.id)
                        .unwrap_or_else(|| format!("Item {}", item.id)),
                    preview_capacity as f64 / 10.0,
                    if carried_weight <= preview_capacity {
                        "legal"
                    } else {
                        "overweight"
                    }
                )
            })
            .collect();
        DeckView {
            actor_id: Some(actor_id),
            carried_cards: carried
                .iter()
                .copied()
                .map(|item| self.item_view(item))
                .collect(),
            carried_weight_tenths: carried_weight,
            base_carrying_capacity_tenths: self
                .actor_base_carrying_capacity_tenths(actor_id)
                .unwrap_or_default(),
            container_capacity_tenths: self.actor_container_capacity_tenths(actor_id),
            carrying_capacity_tenths: carrying_capacity,
            bracelet_slots: self.charm_slot_count(actor_id),
            equipped_charms: carried
                .iter()
                .copied()
                .filter(|item| equipped_ids.contains(&item.id))
                .map(|item| self.item_view(item))
                .collect(),
            available_charms: carried
                .iter()
                .copied()
                .filter(|item| {
                    item.role == CW_ITEM_ROLE_SKILL_CHARM && !equipped_ids.contains(&item.id)
                })
                .map(|item| self.item_view(item))
                .collect(),
            charm_slot_expansion,
            spell_cards: carried
                .iter()
                .copied()
                .filter(|item| item.role == CW_ITEM_ROLE_SPELL)
                .map(|item| self.item_view(item))
                .collect(),
            prepared_spell_cards: carried
                .iter()
                .copied()
                .filter(|item| {
                    item.role == CW_ITEM_ROLE_SPELL
                        && item.charges > 0
                        && self
                            .prepared_spells
                            .get(&actor_id)
                            .is_some_and(|prepared| prepared.contains(&item.id))
                })
                .map(|item| self.item_view(item))
                .collect(),
            exhausted_spell_cards: carried
                .iter()
                .copied()
                .filter(|item| item.role == CW_ITEM_ROLE_SPELL && item.charges == 0)
                .map(|item| self.item_view(item))
                .collect(),
            exhausted_cards: carried
                .iter()
                .copied()
                .filter(|item| item.zone == CW_CARD_ZONE_EXHAUSTED)
                .map(|item| self.item_view(item))
                .collect(),
            spell_deck_slots: 3,
            equipped_weapon,
            equipped_containers,
            containers,
            zone_counts,
            validation_errors,
            bag_previews,
        }
    }

    fn loose_items_at_location(&self, location_id: u64) -> Vec<CwItem> {
        let mut items = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .filter(|item| {
                item.holder_actor_id == 0
                    && item.location_id == location_id
                    && !self.forgotten_search_item_at_location(*item, location_id)
            })
            .collect::<Vec<_>>();
        items.sort_by_key(|item| item.id);
        items
    }

    fn room_floor_empty(&self, location_id: u64) -> bool {
        self.loose_items_at_location(location_id).is_empty()
    }

    fn seed_exit_by_locations(
        &self,
        from_location_id: u64,
        to_location_id: u64,
    ) -> Option<&'static SeedExitContent> {
        active_content().exits.iter().find(|exit| {
            exit.from_location_id == from_location_id && exit.to_location_id == to_location_id
        })
    }

    fn seed_exit_discovered(&self, from_location_id: u64, to_location_id: u64) -> bool {
        self.search_discovery_remembered(
            SEARCH_MEMORY_KIND_SEED_EXIT,
            from_location_id,
            to_location_id,
            &seed_exit_search_memory_subject_key(from_location_id, to_location_id),
        )
    }

    fn seed_exit_candidate_for_search(&self, location_id: u64) -> Option<&'static SeedExitContent> {
        let mut candidates = active_content()
            .exits
            .iter()
            .filter(|exit| exit.from_location_id == location_id)
            .filter(|exit| !self.seed_exit_discovered(exit.from_location_id, exit.to_location_id))
            .collect::<Vec<_>>();
        candidates.sort_by_key(|exit| {
            (
                Reverse(search_reveal_chance_percent_for_subject(
                    "location",
                    exit.to_location_id,
                )),
                exit.to_location_id,
            )
        });
        candidates.first().copied()
    }

    fn hidden_search_item_for_location(&self, location_id: u64) -> Option<u64> {
        let mut hidden = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .filter(|item| {
                item.holder_actor_id == 0
                    && item.charges > 0
                    && (item.location_id == 0
                        || self.forgotten_search_item_at_location(*item, location_id))
                    && !self.search_item_remembered(item.id)
            })
            .collect::<Vec<_>>();
        hidden.sort_by_key(|item| {
            let home_rank = active_content()
                .items
                .iter()
                .find(|seed_item| seed_item.id == item.id)
                .map(|seed_item| {
                    if seed_item.location_id == location_id {
                        0
                    } else {
                        1
                    }
                })
                .unwrap_or(2);
            (
                home_rank,
                Reverse(search_reveal_chance_percent_for_subject("item", item.id)),
                item.id,
            )
        });
        hidden.first().map(|item| item.id)
    }

    fn hidden_exit_by_id(&self, hidden_exit_id: &str) -> Option<&'static SeedHiddenExitContent> {
        active_content()
            .hidden_exits
            .iter()
            .find(|hidden_exit| hidden_exit.id == hidden_exit_id)
    }

    fn hidden_exit_discovered(&self, hidden_exit: &SeedHiddenExitContent) -> bool {
        self.search_discovery_remembered(
            SEARCH_MEMORY_KIND_HIDDEN_EXIT,
            hidden_exit.from_location_id,
            hidden_exit.to_location_id,
            &hidden_exit.id,
        )
    }

    fn hidden_exit_between(
        &self,
        from_location_id: u64,
        to_location_id: u64,
    ) -> Option<&'static SeedHiddenExitContent> {
        active_content().hidden_exits.iter().find(|hidden_exit| {
            (hidden_exit.from_location_id == from_location_id
                && hidden_exit.to_location_id == to_location_id)
                || (hidden_exit.from_location_id == to_location_id
                    && hidden_exit.to_location_id == from_location_id)
        })
    }

    fn location_discovered_by_search(&self, location_id: u64) -> bool {
        active_content().exits.iter().any(|exit| {
            (exit.from_location_id == location_id || exit.to_location_id == location_id)
                && self.seed_exit_discovered(exit.from_location_id, exit.to_location_id)
        }) || active_content().hidden_exits.iter().any(|hidden_exit| {
            (hidden_exit.from_location_id == location_id
                || hidden_exit.to_location_id == location_id)
                && self.hidden_exit_discovered(hidden_exit)
        })
    }

    fn exit_discovered_for_projection(&self, from_location_id: u64, to_location_id: u64) -> bool {
        if self
            .seed_exit_by_locations(from_location_id, to_location_id)
            .is_some()
        {
            return self.seed_exit_discovered(from_location_id, to_location_id);
        }
        if let Some(hidden_exit) = self.hidden_exit_between(from_location_id, to_location_id) {
            return self.hidden_exit_discovered(hidden_exit);
        }
        true
    }

    fn hidden_exit_candidate_for_search(
        &self,
        location_id: u64,
        feature_key: &str,
    ) -> Option<&'static SeedHiddenExitContent> {
        active_content().hidden_exits.iter().find(|hidden_exit| {
            hidden_exit.from_location_id == location_id
                && hidden_exit.feature_key == feature_key
                && !self.hidden_exit_discovered(hidden_exit)
        })
    }

    fn default_hidden_exit_candidate(
        &self,
        location_id: u64,
    ) -> Option<&'static SeedHiddenExitContent> {
        active_content().hidden_exits.iter().find(|hidden_exit| {
            hidden_exit.from_location_id == location_id && !self.hidden_exit_discovered(hidden_exit)
        })
    }

    fn hidden_exit_reveal_chance_percent(&self, hidden_exit: &SeedHiddenExitContent) -> u8 {
        hidden_exit
            .reveal_chance_percent
            .min(search_reveal_chance_percent_for_subject(
                "location",
                hidden_exit.to_location_id,
            ))
    }

    #[cfg(test)]
    fn hidden_exit_search_succeeds(
        &self,
        seed: u64,
        actor_id: u64,
        hidden_exit: &SeedHiddenExitContent,
    ) -> bool {
        let candidate = SearchRevealCandidate::HiddenExit {
            hidden_exit_id: hidden_exit.id.clone(),
        };
        self.search_candidate_succeeds(seed, actor_id, &candidate)
    }

    fn avatar_discovered(&self, actor_id: u64) -> bool {
        self.search_memories.values().any(|memory| {
            memory.kind == SEARCH_MEMORY_KIND_AVATAR
                && memory.subject_id == actor_id
                && self.search_memory_active(memory)
        })
    }

    fn search_memory_active(&self, memory: &SearchMemoryState) -> bool {
        self.actor_by_id(memory.actor_id)
            .is_some_and(|actor| actor.status == CW_ACTOR_ACTIVE)
            && self
                .search_memory_effective_values(memory)
                .is_some_and(|(confidence, salience)| {
                    confidence >= SEARCH_MEMORY_MIN_CONFIDENCE && salience > 0
                })
    }

    fn search_memory_effective_values(&self, memory: &SearchMemoryState) -> Option<(u8, u8)> {
        let baseline = memory.last_used_tick.max(memory.found_tick);
        if baseline == 0 {
            return Some((memory.confidence, memory.salience));
        }
        let now = self.world.tick;
        let steps = now.saturating_sub(baseline) / SEARCH_MEMORY_TIME_DECAY_INTERVAL_TICKS;
        let confidence_loss = steps
            .saturating_mul(SEARCH_MEMORY_TIME_CONFIDENCE_DECAY as u64)
            .min(u8::MAX as u64) as u8;
        let salience_loss = steps
            .saturating_mul(SEARCH_MEMORY_TIME_SALIENCE_DECAY as u64)
            .min(u8::MAX as u64) as u8;
        let confidence = memory.confidence.saturating_sub(confidence_loss);
        let salience = memory.salience.saturating_sub(salience_loss);
        (confidence > 0 && salience > 0).then_some((confidence, salience))
    }

    fn search_discovery_remembered(
        &self,
        kind: &str,
        location_id: u64,
        subject_id: u64,
        subject_key: &str,
    ) -> bool {
        self.search_memories.values().any(|memory| {
            memory.kind == kind
                && memory.location_id == location_id
                && memory.subject_id == subject_id
                && memory.subject_key == subject_key
                && self.search_memory_active(memory)
        })
    }

    fn search_item_remembered(&self, item_id: u64) -> bool {
        self.search_memories.values().any(|memory| {
            memory.kind == SEARCH_MEMORY_KIND_ITEM
                && memory.subject_id == item_id
                && self.search_memory_active(memory)
        })
    }

    fn search_item_found(&self, item_id: u64) -> bool {
        self.tags
            .get(&search_item_found_tag_id(item_id))
            .map(|tag| tag.active)
            .unwrap_or(false)
    }

    fn forgotten_search_item_at_location(&self, item: CwItem, location_id: u64) -> bool {
        item.holder_actor_id == 0
            && item.location_id == location_id
            && self.search_item_found(item.id)
            && !self.search_item_remembered(item.id)
    }

    fn search_memory_id(actor_id: u64, kind: &str, location_id: u64, subject_key: &str) -> String {
        format!("search_memory:{actor_id}:{kind}:{location_id}:{subject_key}")
    }

    fn search_witness_actor_ids(&self, location_id: u64) -> Vec<u64> {
        let mut actor_ids = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| {
                actor.location_id == location_id && Self::actor_is_active_avatar(*actor)
            })
            .map(|actor| actor.id)
            .collect::<Vec<_>>();
        actor_ids.sort_unstable();
        actor_ids.dedup();
        actor_ids
    }

    fn remember_search_discovery_for_witnesses(
        &mut self,
        location_id: u64,
        kind: &str,
        subject_id: u64,
        subject_key: String,
    ) {
        let actor_ids = self.search_witness_actor_ids(location_id);
        self.remember_search_discovery_for_actor_ids(
            &actor_ids,
            location_id,
            kind,
            subject_id,
            &subject_key,
        );
    }

    fn remember_search_discovery_for_actor_ids(
        &mut self,
        actor_ids: &[u64],
        location_id: u64,
        kind: &str,
        subject_id: u64,
        subject_key: &str,
    ) {
        for actor_id in actor_ids.iter().copied() {
            self.remember_search_discovery(actor_id, location_id, kind, subject_id, &subject_key);
        }
    }

    fn remember_search_discovery(
        &mut self,
        actor_id: u64,
        location_id: u64,
        kind: &str,
        subject_id: u64,
        subject_key: &str,
    ) {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return;
        };
        if !Self::actor_is_active_avatar(actor) {
            return;
        }
        let id = Self::search_memory_id(actor_id, kind, location_id, subject_key);
        let now = self.world.tick;
        match self.search_memories.get_mut(&id) {
            Some(memory) => {
                memory.confidence = memory.confidence.max(SEARCH_MEMORY_CONFIDENCE);
                memory.salience = memory.salience.max(SEARCH_MEMORY_SALIENCE);
                memory.last_used_tick = now;
                memory.use_count = memory.use_count.saturating_add(1);
            }
            None => {
                self.search_memories.insert(
                    id.clone(),
                    SearchMemoryState {
                        id,
                        actor_id,
                        kind: kind.to_string(),
                        location_id,
                        subject_id,
                        subject_key: subject_key.to_string(),
                        confidence: SEARCH_MEMORY_CONFIDENCE,
                        salience: SEARCH_MEMORY_SALIENCE,
                        found_tick: now,
                        last_used_tick: now,
                        use_count: 1,
                    },
                );
            }
        }
    }

    fn decay_search_memories(&mut self) {
        let now = self.world.tick;
        let mut expired = Vec::new();
        for memory in self.search_memories.values_mut() {
            let baseline = memory.last_used_tick.max(memory.found_tick);
            if baseline == 0 {
                memory.last_used_tick = now;
                continue;
            }
            if now <= baseline {
                continue;
            }
            let steps = (now - baseline) / SEARCH_MEMORY_TIME_DECAY_INTERVAL_TICKS;
            if steps == 0 {
                continue;
            }
            let confidence_loss = steps
                .saturating_mul(SEARCH_MEMORY_TIME_CONFIDENCE_DECAY as u64)
                .min(u8::MAX as u64) as u8;
            let salience_loss = steps
                .saturating_mul(SEARCH_MEMORY_TIME_SALIENCE_DECAY as u64)
                .min(u8::MAX as u64) as u8;
            memory.confidence = memory.confidence.saturating_sub(confidence_loss);
            memory.salience = memory.salience.saturating_sub(salience_loss);
            memory.last_used_tick = now;
            if memory.confidence == 0 || memory.salience == 0 {
                expired.push(memory.id.clone());
            }
        }
        for memory_id in expired {
            self.search_memories.remove(&memory_id);
        }
        self.return_forgotten_search_items_to_pool();
    }

    fn reinforce_search_memories_from_events(&mut self, events: &[EventView]) {
        for event in events.iter().filter(|event| event.success) {
            match event.type_name.as_str() {
                "actor.moved" => {
                    let (Some(actor_id), Some(from_location_id), Some(to_location_id)) = (
                        event.actor_id,
                        event.location_id,
                        event.destination_location_id,
                    ) else {
                        continue;
                    };
                    if self
                        .seed_exit_by_locations(from_location_id, to_location_id)
                        .is_some()
                    {
                        self.remember_search_discovery(
                            actor_id,
                            from_location_id,
                            SEARCH_MEMORY_KIND_SEED_EXIT,
                            to_location_id,
                            &seed_exit_search_memory_subject_key(from_location_id, to_location_id),
                        );
                        if self
                            .seed_exit_by_locations(to_location_id, from_location_id)
                            .is_some()
                        {
                            self.remember_search_discovery(
                                actor_id,
                                to_location_id,
                                SEARCH_MEMORY_KIND_SEED_EXIT,
                                from_location_id,
                                &seed_exit_search_memory_subject_key(
                                    to_location_id,
                                    from_location_id,
                                ),
                            );
                        }
                    }
                    if let Some(hidden_exit) =
                        self.hidden_exit_between(from_location_id, to_location_id)
                    {
                        self.remember_search_discovery(
                            actor_id,
                            hidden_exit.from_location_id,
                            SEARCH_MEMORY_KIND_HIDDEN_EXIT,
                            hidden_exit.to_location_id,
                            &hidden_exit.id,
                        );
                    }
                }
                "item.found" | "item.picked_up" | "item.dropped" | "item.used" | "item.given"
                | "item.traded" => {
                    let Some(item_id) = event.item_id else {
                        continue;
                    };
                    if !self.search_item_found(item_id) && event.type_name != "item.found" {
                        continue;
                    }
                    let location_id = event
                        .location_id
                        .or_else(|| {
                            event
                                .actor_id
                                .and_then(|actor_id| self.actor_by_id(actor_id))
                                .map(|actor| actor.location_id)
                        })
                        .unwrap_or(0);
                    if location_id == 0 {
                        continue;
                    }
                    self.remember_search_discovery_for_witnesses(
                        location_id,
                        SEARCH_MEMORY_KIND_ITEM,
                        item_id,
                        item_id.to_string(),
                    );
                }
                _ => {}
            }
        }
    }

    fn return_forgotten_search_items_to_pool(&mut self) {
        let forgotten_item_ids = self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .filter(|item| {
                item.holder_actor_id == 0
                    && item.location_id != 0
                    && self.search_item_found(item.id)
                    && !self.search_item_remembered(item.id)
            })
            .map(|item| item.id)
            .collect::<BTreeSet<_>>();
        if forgotten_item_ids.is_empty() {
            return;
        }
        for item in &mut self.world.items[..self.world.item_count] {
            if forgotten_item_ids.contains(&item.id) {
                item.location_id = 0;
                item.holder_actor_id = 0;
                item.held_since_tick = 0;
            }
        }
    }

    fn avatar_hidden_until_discovered(&self, actor: CwActor) -> bool {
        if !Self::actor_is_active_avatar(actor)
            || !active_content()
                .actors
                .iter()
                .any(|seed_actor| seed_actor.id == actor.id)
        {
            return false;
        }
        let hidden_location = active_content()
            .hidden_exits
            .iter()
            .any(|hidden_exit| hidden_exit.to_location_id == actor.location_id);
        let hidden_rarity = seed_card_rarity_for_subject("actor", actor.id)
            .map(|rarity| search_reveal_chance_percent_for_rarity(rarity) <= 35)
            .unwrap_or(false);
        hidden_location || hidden_rarity
    }

    fn hidden_avatar_candidate_for_search(&self, location_id: u64) -> Option<CwActor> {
        let mut candidates = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| Self::actor_is_active_avatar(*actor))
            .filter(|actor| actor.location_id == location_id)
            .filter(|actor| self.avatar_hidden_until_discovered(*actor))
            .filter(|actor| !self.avatar_discovered(actor.id))
            .collect::<Vec<_>>();
        candidates.sort_by_key(|actor| {
            (
                Reverse(search_reveal_chance_percent_for_subject("actor", actor.id)),
                actor.id,
            )
        });
        candidates.first().copied()
    }

    fn search_reveal_candidates_for_feature(
        &self,
        location_id: u64,
        feature_key: &str,
    ) -> Vec<SearchRevealCandidate> {
        if feature_key == "room" {
            return self.search_reveal_candidates_for_location(location_id);
        }

        let mut candidates = Vec::new();
        if let Some(hidden_exit) = self.hidden_exit_candidate_for_search(location_id, feature_key) {
            candidates.push(SearchRevealCandidate::HiddenExit {
                hidden_exit_id: hidden_exit.id.clone(),
            });
        }
        if self.room_floor_empty(location_id) {
            let hidden_item_id = self.hidden_search_item_for_location(location_id);
            let feature_uses_hidden_item = self
                .room_features(location_id)
                .into_iter()
                .find(|feature| feature.key == feature_key)
                .is_some_and(|feature| {
                    feature
                        .uses
                        .iter()
                        .any(|use_case| Some(use_case.item_id) == hidden_item_id)
                });
            if feature_uses_hidden_item {
                if let Some(item_id) = hidden_item_id {
                    candidates.push(SearchRevealCandidate::Item { item_id });
                }
            }
        }
        candidates.sort_by_key(|candidate| self.search_candidate_sort_key(candidate));
        candidates
    }

    fn search_reveal_candidates_for_location(
        &self,
        location_id: u64,
    ) -> Vec<SearchRevealCandidate> {
        let mut candidates = Vec::new();
        if let Some(exit) = self.seed_exit_candidate_for_search(location_id) {
            candidates.push(SearchRevealCandidate::SeedExit {
                from_location_id: exit.from_location_id,
                to_location_id: exit.to_location_id,
            });
        }
        if let Some(hidden_exit) = self.default_hidden_exit_candidate(location_id) {
            candidates.push(SearchRevealCandidate::HiddenExit {
                hidden_exit_id: hidden_exit.id.clone(),
            });
        }
        if let Some(actor) = self.hidden_avatar_candidate_for_search(location_id) {
            candidates.push(SearchRevealCandidate::Avatar {
                actor_id: actor.id,
                location_id,
            });
        }
        if self.room_floor_empty(location_id) {
            if let Some(item_id) = self.hidden_search_item_for_location(location_id) {
                candidates.push(SearchRevealCandidate::Item { item_id });
            }
        }
        candidates.sort_by_key(|candidate| self.search_candidate_sort_key(candidate));
        candidates
    }

    fn search_candidate_sort_key(
        &self,
        candidate: &SearchRevealCandidate,
    ) -> (u8, Reverse<u8>, u64, u64) {
        match candidate {
            SearchRevealCandidate::SeedExit {
                from_location_id,
                to_location_id,
            } => (
                0,
                Reverse(self.search_candidate_reveal_chance_percent(candidate)),
                *from_location_id,
                *to_location_id,
            ),
            SearchRevealCandidate::HiddenExit { hidden_exit_id } => (
                1,
                Reverse(self.search_candidate_reveal_chance_percent(candidate)),
                stable_hash_u64(&["hidden-exit", hidden_exit_id]),
                0,
            ),
            SearchRevealCandidate::Avatar {
                actor_id,
                location_id,
            } => (
                2,
                Reverse(self.search_candidate_reveal_chance_percent(candidate)),
                *location_id,
                *actor_id,
            ),
            SearchRevealCandidate::Item { item_id } => (
                3,
                Reverse(self.search_candidate_reveal_chance_percent(candidate)),
                *item_id,
                0,
            ),
        }
    }

    fn search_candidate_reveal_chance_percent(&self, candidate: &SearchRevealCandidate) -> u8 {
        match candidate {
            SearchRevealCandidate::SeedExit { to_location_id, .. } => {
                search_reveal_chance_percent_for_subject("location", *to_location_id)
            }
            SearchRevealCandidate::HiddenExit { hidden_exit_id } => self
                .hidden_exit_by_id(hidden_exit_id)
                .map(|hidden_exit| self.hidden_exit_reveal_chance_percent(hidden_exit))
                .unwrap_or(0),
            SearchRevealCandidate::Avatar { actor_id, .. } => {
                search_reveal_chance_percent_for_subject("actor", *actor_id)
            }
            SearchRevealCandidate::Item { item_id } => {
                search_reveal_chance_percent_for_subject("item", *item_id)
            }
        }
    }

    fn search_candidate_stable_key(&self, candidate: &SearchRevealCandidate) -> String {
        match candidate {
            SearchRevealCandidate::SeedExit {
                from_location_id,
                to_location_id,
            } => format!("exit:{from_location_id}:{to_location_id}"),
            SearchRevealCandidate::HiddenExit { hidden_exit_id } => {
                format!("hidden_exit:{hidden_exit_id}")
            }
            SearchRevealCandidate::Avatar {
                actor_id,
                location_id,
            } => format!("avatar:{location_id}:{actor_id}"),
            SearchRevealCandidate::Item { item_id } => format!("item:{item_id}"),
        }
    }

    fn search_candidate_succeeds(
        &self,
        seed: u64,
        actor_id: u64,
        candidate: &SearchRevealCandidate,
    ) -> bool {
        let chance = self.search_candidate_reveal_chance_percent(candidate);
        if chance == 0 {
            return false;
        }
        let actor_id = actor_id.to_string();
        let seed = seed.to_string();
        let candidate_key = self.search_candidate_stable_key(candidate);
        let roll = stable_hash_u64(&["search-reveal", &candidate_key, &actor_id, &seed]) % 100;
        roll < u64::from(chance)
    }

    fn select_search_reveal_candidate(
        &self,
        seed: u64,
        actor_id: u64,
        candidates: &[SearchRevealCandidate],
    ) -> Option<SearchRevealCandidate> {
        candidates
            .iter()
            .find(|candidate| self.search_candidate_succeeds(seed, actor_id, candidate))
            .cloned()
    }

    fn default_search_target(&self, actor_id: u64) -> Option<RoomSearchTarget> {
        let actor = self.actor_by_id(actor_id)?;
        if actor.location_id == COSY_COTTAGE_LOCATION_ID
            && self.listen_attempt_claimed_at(actor_id, actor.location_id)
            && !self.feature_search_claimed(actor_id, actor.location_id, SCARF_BASKET_FEATURE_KEY)
        {
            let feature = self
                .room_features(actor.location_id)
                .into_iter()
                .find(|feature| feature.key == SCARF_BASKET_FEATURE_KEY)?;
            return Some(RoomSearchTarget::feature(feature));
        }
        if self
            .search_reveal_candidates_for_location(actor.location_id)
            .is_empty()
        {
            return None;
        }
        let location_name = self
            .location_name(actor.location_id)
            .unwrap_or_else(|| format!("Location {}", actor.location_id));
        Some(RoomSearchTarget::virtual_room(
            actor.location_id,
            location_name,
        ))
    }

    fn recipe_by_id(&self, recipe_id: u64) -> Option<&'static SeedRecipeContent> {
        active_content()
            .recipes
            .iter()
            .find(|recipe| recipe.id == recipe_id)
    }

    fn craft_action_for_recipe(&self, actor_id: u64, recipe_id: u64) -> Option<CwAction> {
        let actor = self.actor_by_id(actor_id)?;
        if actor.status != CW_ACTOR_ACTIVE {
            return None;
        }
        let recipe = self.recipe_by_id(recipe_id)?;
        let held_items = self.actor_held_items(actor_id);
        let floor_items = self.loose_items_at_location(actor.location_id);
        let held = held_items
            .iter()
            .copied()
            .find(|item| recipe.input_item_ids.contains(&item.id))?;
        let floor = floor_items
            .iter()
            .copied()
            .find(|item| item.id != held.id && recipe.input_item_ids.contains(&item.id))?;
        if recipe
            .input_item_ids
            .iter()
            .any(|item_id| *item_id != held.id && *item_id != floor.id)
        {
            return None;
        }
        let mut action = CwAction {
            kind: CW_ACTION_CRAFT,
            actor_id,
            content_id: recipe.id,
            item_id: held.id,
            target_item_id: floor.id,
            ..CwAction::default()
        };
        if let Some(output) = recipe.output.as_ref() {
            if self.item_by_id(output.item_id).is_some() {
                return None;
            }
            action.output_item_id = output.item_id;
            action.output_target_id = output.target_id;
            action.output_target_kind = placement_target_kind_from_str(&output.target_kind)?;
            action.output_item_kind = seed_item_kind_from_str(&output.kind)?;
            action.output_item_charges = output.charges;
            match action.output_target_kind {
                CW_PLACEMENT_ACTOR_HAND => {
                    let target = self.actor_by_id(output.target_id)?;
                    if target.status != CW_ACTOR_ACTIVE {
                        return None;
                    }
                    if self.actor_inventory_count(output.target_id) != 0 {
                        return None;
                    }
                }
                CW_PLACEMENT_LOCATION_FLOOR => {
                    if !self.room_floor_empty(output.target_id) {
                        return None;
                    }
                }
                _ => return None,
            }
        }
        Some(action)
    }

    fn default_craft_recipe(&self, actor_id: u64) -> Option<&'static SeedRecipeContent> {
        active_content()
            .recipes
            .iter()
            .find(|recipe| self.craft_action_for_recipe(actor_id, recipe.id).is_some())
    }

    fn hide_loose_items_at_location(&mut self, location_id: u64) {
        for item in &mut self.world.items[..self.world.item_count] {
            if item.holder_actor_id == 0 && item.location_id == location_id {
                item.location_id = 0;
                item.held_since_tick = 0;
            }
        }
    }

    fn resident_evolution_item_ids(&self, actor_id: u64) -> Vec<u64> {
        evolution_track_item_ids(actor_id).unwrap_or_default()
    }

    fn resident_evolution_item_ids_for_target_kind(
        &self,
        actor_id: u64,
        target_kind: &str,
    ) -> Vec<u64> {
        active_content()
            .evolution_tracks
            .iter()
            .find(|track| track.actor_id == actor_id)
            .map(|track| {
                track
                    .requirements
                    .iter()
                    .filter(|requirement| requirement.target_kind == target_kind)
                    .map(|requirement| requirement.item_id)
                    .collect()
            })
            .unwrap_or_default()
    }

    fn resident_calling_desired_item_ids(&self, resident: CwActor) -> Vec<u64> {
        if !Self::actor_is_active_avatar(resident) || resident.stats.level >= 2 {
            return Vec::new();
        }
        self.resident_evolution_item_ids(resident.id)
    }

    fn resident_calling_sought_item_ids(&self, resident: CwActor) -> Vec<u64> {
        if !Self::actor_is_active_avatar(resident) || resident.stats.level >= 2 {
            return Vec::new();
        }
        self.resident_evolution_item_ids_for_target_kind(resident.id, "actor_hand")
    }

    fn resident_personal_desires(&self, resident_id: u64) -> Vec<SeedResidentDesireContent> {
        active_content()
            .actors
            .iter()
            .find(|actor| actor.id == resident_id)
            .map(|actor| actor.desires.clone())
            .unwrap_or_default()
    }

    fn resident_personal_desire_for_item(
        &self,
        resident_id: u64,
        item_id: u64,
    ) -> Option<SeedResidentDesireContent> {
        self.resident_personal_desires(resident_id)
            .into_iter()
            .find(|desire| desire.item_id == item_id)
    }

    fn resident_personal_attachments(
        &self,
        resident_id: u64,
    ) -> Vec<SeedResidentAttachmentContent> {
        active_content()
            .actors
            .iter()
            .find(|actor| actor.id == resident_id)
            .map(|actor| actor.attachments.clone())
            .unwrap_or_default()
    }

    fn resident_personal_attachment_for_item(
        &self,
        resident_id: u64,
        item_id: u64,
    ) -> Option<SeedResidentAttachmentContent> {
        self.resident_personal_attachments(resident_id)
            .into_iter()
            .find(|attachment| attachment.item_id == item_id)
    }

    fn resident_attachment_item_ids(&self, resident: CwActor) -> Vec<u64> {
        if !Self::actor_is_active_avatar(resident) {
            return Vec::new();
        }
        self.resident_personal_attachments(resident.id)
            .into_iter()
            .map(|attachment| attachment.item_id)
            .collect()
    }

    fn resident_desired_item_ids(&self, resident: CwActor) -> Vec<u64> {
        if !Self::actor_is_active_avatar(resident) {
            return Vec::new();
        }
        let mut item_ids = self.resident_calling_desired_item_ids(resident);
        for desire in self.resident_personal_desires(resident.id) {
            if !item_ids.contains(&desire.item_id) {
                item_ids.push(desire.item_id);
            }
        }
        item_ids
    }

    fn item_by_id(&self, item_id: u64) -> Option<CwItem> {
        self.world.items[..self.world.item_count]
            .iter()
            .copied()
            .find(|item| item.id == item_id)
    }

    fn resident_healing_target(&self, resident: CwActor) -> Option<CwActor> {
        if !Self::actor_is_active_avatar(resident) {
            return None;
        }
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|target| {
                self.healing_target_is_offerable(&resident, target)
                    && (target.id == resident.id
                        || self.resident_remembers_actor_at(
                            resident.id,
                            target.id,
                            resident.location_id,
                        ))
            })
            .min_by_key(|target| (target.id != resident.id, target.id))
    }

    fn resident_held_healing_item_for_target(
        &self,
        resident: CwActor,
    ) -> Option<(CwItem, CwActor)> {
        let target = self.resident_healing_target(resident)?;
        let item = self
            .actor_held_items(resident.id)
            .into_iter()
            .filter(|item| item.kind == CW_ITEM_POTION && item.charges > 0)
            .min_by_key(|item| (item.held_since_tick, item.id))?;
        Some((item, target))
    }

    fn resident_held_healing_item(&self, resident: CwActor) -> Option<CwItem> {
        self.resident_held_healing_item_for_target(resident)
            .map(|(item, _)| item)
    }

    fn resident_needs_medicine(&self, resident: CwActor) -> bool {
        self.resident_healing_target(resident).is_some()
            && self
                .resident_held_healing_item_for_target(resident)
                .is_none()
    }

    fn resident_feature_use_match_for_item(
        &self,
        resident: CwActor,
        item_id: u64,
    ) -> Option<ResidentFeatureUseCandidate> {
        if !Self::actor_is_active_avatar(resident) {
            return None;
        }
        self.room_features(resident.location_id)
            .into_iter()
            .filter_map(|feature| {
                let use_case = feature
                    .uses
                    .iter()
                    .find(|use_case| use_case.item_id == item_id)?;
                if self.feature_use_claimed(
                    resident.id,
                    resident.location_id,
                    &feature.key,
                    item_id,
                ) {
                    return None;
                }
                Some(ResidentFeatureUseCandidate {
                    actor_id: resident.id,
                    location_id: resident.location_id,
                    feature_key: feature.key.clone(),
                    feature_name: feature.name.clone(),
                    item_id,
                    content: use_case.text.clone(),
                })
            })
            .min_by(|left, right| {
                left.feature_name
                    .cmp(&right.feature_name)
                    .then_with(|| left.feature_key.cmp(&right.feature_key))
            })
    }

    fn resident_local_feature_item_ids(&self, resident: CwActor) -> Vec<u64> {
        if !Self::actor_is_active_avatar(resident) {
            return Vec::new();
        }
        let mut item_ids: Vec<u64> = self
            .room_features(resident.location_id)
            .into_iter()
            .flat_map(|feature| {
                feature.uses.iter().filter_map(|use_case| {
                    (!self.feature_use_claimed(
                        resident.id,
                        resident.location_id,
                        &feature.key,
                        use_case.item_id,
                    ))
                    .then_some(use_case.item_id)
                })
            })
            .collect();
        item_ids.sort_unstable();
        item_ids.dedup();
        item_ids
    }

    fn resident_feature_use_candidate(
        &self,
        resident: CwActor,
    ) -> Option<ResidentFeatureUseCandidate> {
        let mut candidates: Vec<_> = self
            .actor_held_items(resident.id)
            .into_iter()
            .filter_map(|item| self.resident_feature_use_match_for_item(resident, item.id))
            .collect();
        candidates.sort_by_key(|candidate| {
            (
                !evolution_item_matches_resident(candidate.item_id, resident.id),
                candidate.feature_key.clone(),
                candidate.item_id,
            )
        });
        candidates.into_iter().next()
    }

    fn resident_item_is_sought(&self, resident: CwActor, item_id: u64) -> bool {
        let wants_item = self
            .resident_calling_sought_item_ids(resident)
            .into_iter()
            .any(|desired_item_id| desired_item_id == item_id)
            || self
                .resident_personal_desires(resident.id)
                .into_iter()
                .any(|desire| desire.item_id == item_id);
        let already_held = self
            .actor_held_items(resident.id)
            .into_iter()
            .any(|item| item.id == item_id);
        if wants_item && !already_held {
            return true;
        }
        if self
            .resident_attachment_item_ids(resident)
            .into_iter()
            .any(|attachment_item_id| attachment_item_id == item_id)
            && !self
                .actor_held_items(resident.id)
                .into_iter()
                .any(|item| item.id == item_id)
        {
            return true;
        }

        if self.resident_needs_medicine(resident) {
            return self
                .item_by_id(item_id)
                .is_some_and(|item| item.kind == CW_ITEM_POTION && item.charges > 0);
        }
        if !self
            .actor_held_items(resident.id)
            .into_iter()
            .any(|item| item.id == item_id)
            && self
                .resident_feature_use_match_for_item(resident, item_id)
                .is_some()
        {
            return true;
        }
        false
    }

    fn resident_sought_item_ids(&self, resident: CwActor) -> Vec<u64> {
        let held_item_ids: BTreeSet<u64> = self
            .actor_held_items(resident.id)
            .into_iter()
            .map(|item| item.id)
            .collect();

        let mut sought = Vec::new();
        if self.resident_needs_medicine(resident) {
            let mut remembered_potions: Vec<_> = self
                .resident_memories
                .values()
                .filter(|memory| {
                    memory.carrier_actor_id == resident.id
                        && memory.kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                        && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
                        && !held_item_ids.contains(&memory.subject_id)
                })
                .filter_map(|memory| {
                    self.item_by_id(memory.subject_id)
                        .filter(|item| item.kind == CW_ITEM_POTION)
                        .map(|item| {
                            (
                                item.id,
                                std::cmp::Reverse(memory.salience),
                                std::cmp::Reverse(memory.confidence),
                                std::cmp::Reverse(memory.observed_tick),
                            )
                        })
                })
                .collect();
            remembered_potions.sort_by_key(|(_, salience, confidence, observed_tick)| {
                (*salience, *confidence, *observed_tick)
            });
            for (item_id, _, _, _) in remembered_potions {
                if !sought.contains(&item_id) {
                    sought.push(item_id);
                }
            }
        }

        let mut desired_seekable_item_ids = self.resident_calling_sought_item_ids(resident);
        for desire in self.resident_personal_desires(resident.id) {
            if !desired_seekable_item_ids.contains(&desire.item_id) {
                desired_seekable_item_ids.push(desire.item_id);
            }
        }
        for item_id in desired_seekable_item_ids
            .into_iter()
            .filter(|item_id| !held_item_ids.contains(item_id))
        {
            if !sought.contains(&item_id) {
                sought.push(item_id);
            }
        }
        for item_id in self.resident_local_feature_item_ids(resident) {
            if !sought.contains(&item_id) {
                sought.push(item_id);
            }
        }
        for item_id in self
            .resident_attachment_item_ids(resident)
            .into_iter()
            .filter(|item_id| !held_item_ids.contains(item_id))
        {
            if !sought.contains(&item_id) {
                sought.push(item_id);
            }
        }
        sought
    }

    fn resident_memory_seek_target(&self, resident: CwActor) -> Option<ResidentMemoryState> {
        let sought_item_ids: BTreeSet<u64> = self
            .resident_sought_item_ids(resident)
            .into_iter()
            .collect();
        if sought_item_ids.is_empty() {
            return None;
        }

        let mut memories: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == resident.id
                    && memory.kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                    && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
                    && sought_item_ids.contains(&memory.subject_id)
            })
            .cloned()
            .map(|memory| self.resident_item_memory_resolved_by_actor_memory(memory))
            .collect();
        memories.sort_by_key(|memory| {
            let preference = self
                .resident_sought_item_ids(resident)
                .iter()
                .position(|item_id| *item_id == memory.subject_id)
                .unwrap_or(usize::MAX);
            (
                preference,
                std::cmp::Reverse(memory.salience),
                std::cmp::Reverse(memory.confidence),
                std::cmp::Reverse(memory.observed_tick),
                memory.location_id,
                memory.subject_id,
            )
        });
        memories.into_iter().next()
    }

    fn resident_item_memory_resolved_by_actor_memory(
        &self,
        memory: ResidentMemoryState,
    ) -> ResidentMemoryState {
        if memory.kind != RESIDENT_MEMORY_KIND_ITEM_LOCATION {
            return memory;
        }
        let Some(holder_actor_id) = memory.holder_actor_id else {
            return memory;
        };
        let actor_memory_id = Self::resident_memory_id(
            memory.carrier_actor_id,
            RESIDENT_MEMORY_KIND_ACTOR_LOCATION,
            holder_actor_id,
        );
        let Some(actor_memory) = self.resident_memories.get(&actor_memory_id) else {
            return memory;
        };
        if actor_memory.confidence < RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
            || actor_memory.observed_tick < memory.observed_tick
        {
            return memory;
        }

        let mut resolved = memory;
        resolved.location_id = actor_memory.location_id;
        resolved.confidence = resolved.confidence.min(actor_memory.confidence);
        resolved.salience = resolved.salience.min(actor_memory.salience);
        resolved.observed_tick = actor_memory.observed_tick;
        resolved.learned_tick = resolved.learned_tick.max(actor_memory.learned_tick);
        resolved.hops = resolved.hops.max(actor_memory.hops);
        resolved
    }

    fn resident_best_item_memory(
        &self,
        carrier_actor_id: u64,
        item_id: u64,
    ) -> Option<ResidentMemoryState> {
        let mut memories: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == carrier_actor_id
                    && memory.kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                    && memory.subject_id == item_id
                    && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
            })
            .cloned()
            .map(|memory| self.resident_item_memory_resolved_by_actor_memory(memory))
            .collect();
        memories.sort_by_key(|memory| {
            (
                std::cmp::Reverse(memory.salience),
                std::cmp::Reverse(memory.confidence),
                std::cmp::Reverse(memory.observed_tick),
                memory.location_id,
            )
        });
        memories.into_iter().next()
    }

    fn resident_has_fresh_loose_item_observation(
        &self,
        carrier_actor_id: u64,
        item_id: u64,
        location_id: u64,
    ) -> bool {
        let memory_id = Self::resident_memory_id(
            carrier_actor_id,
            RESIDENT_MEMORY_KIND_ITEM_LOCATION,
            item_id,
        );
        self.resident_memories
            .get(&memory_id)
            .is_some_and(|memory| {
                memory.location_id == location_id
                    && memory.holder_actor_id.is_none()
                    && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
                    && memory.observed_tick == self.world.tick
                    && memory.source_actor_id == Some(carrier_actor_id)
            })
    }

    fn resident_actor_location_memory(
        &self,
        carrier_actor_id: u64,
        subject_actor_id: u64,
    ) -> Option<ResidentMemoryState> {
        let memory_id = Self::resident_memory_id(
            carrier_actor_id,
            RESIDENT_MEMORY_KIND_ACTOR_LOCATION,
            subject_actor_id,
        );
        self.resident_memories
            .get(&memory_id)
            .filter(|memory| memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE)
            .cloned()
    }

    fn resident_remembers_actor_at(
        &self,
        carrier_actor_id: u64,
        subject_actor_id: u64,
        location_id: u64,
    ) -> bool {
        self.resident_actor_location_memory(carrier_actor_id, subject_actor_id)
            .is_some_and(|memory| memory.location_id == location_id)
    }

    fn resident_actor_wants_item_memory(
        &self,
        carrier_actor_id: u64,
        target_actor_id: u64,
        item_id: u64,
    ) -> Option<ResidentMemoryState> {
        let memory_id = Self::resident_memory_key(
            carrier_actor_id,
            RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM,
            item_id,
            Some(target_actor_id),
        );
        self.resident_memories
            .get(&memory_id)
            .filter(|memory| memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE)
            .cloned()
    }

    fn resident_remembers_actor_holding_item_at(
        &self,
        carrier_actor_id: u64,
        holder_actor_id: u64,
        item_id: u64,
        location_id: u64,
    ) -> bool {
        self.resident_remembers_actor_at(carrier_actor_id, holder_actor_id, location_id)
            && self
                .resident_best_item_memory(carrier_actor_id, item_id)
                .is_some_and(|memory| {
                    memory.holder_actor_id == Some(holder_actor_id)
                        && memory.location_id == location_id
                })
    }

    #[cfg(test)]
    fn resident_remembers_actor_wants_item(
        &self,
        carrier_actor_id: u64,
        target_actor_id: u64,
        item_id: u64,
    ) -> bool {
        self.resident_actor_wants_item_memory(carrier_actor_id, target_actor_id, item_id)
            .is_some()
    }

    fn resident_item_is_attached(&self, resident_id: u64, item: CwItem) -> bool {
        if self
            .resident_personal_attachment_for_item(resident_id, item.id)
            .is_some()
        {
            return true;
        }
        if evolution_item_matches_resident(item.id, resident_id) {
            return true;
        }
        if evolution_item_belongs_to_another_resident(item.id, resident_id) {
            return false;
        }
        if self.resident_item_has_feature_use_attachment(resident_id, item.id) {
            return true;
        }
        item.holder_actor_id == resident_id
            && item.held_since_tick > 0
            && self.world.tick.saturating_sub(item.held_since_tick) >= 12
    }

    fn resident_item_has_feature_use_attachment(&self, resident_id: u64, item_id: u64) -> bool {
        if evolution_item_belongs_to_another_resident(item_id, resident_id) {
            return false;
        }
        let prefix = format!("actor:{resident_id}:feature_use:");
        let suffix = format!(":{item_id}");
        self.tags.values().any(|tag| {
            tag.active
                && tag.scope == "actor"
                && tag.scope_id == resident_id
                && tag.id.starts_with(&prefix)
                && tag.id.ends_with(&suffix)
        })
    }

    fn resident_attached_item_ids(&self, resident_id: u64) -> Vec<u64> {
        self.actor_held_items(resident_id)
            .into_iter()
            .filter(|item| self.resident_item_is_attached(resident_id, *item))
            .map(|item| item.id)
            .collect()
    }

    fn resident_item_attachment_reason(&self, resident: CwActor, item_id: u64) -> String {
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let item_name = self
            .item_name(item_id)
            .unwrap_or_else(|| format!("Item {item_id}"));
        if evolution_item_matches_resident(item_id, resident.id) {
            format!("{resident_name} is attached to {item_name} because it belongs to their evolution track.")
        } else if self.resident_item_has_feature_use_attachment(resident.id, item_id) {
            format!(
                "{resident_name} is attached to {item_name} because it mattered in a room moment."
            )
        } else if let Some(attachment) =
            self.resident_personal_attachment_for_item(resident.id, item_id)
        {
            format!(
                "{resident_name} is attached to {item_name}: {}",
                attachment.reason.trim_end_matches('.')
            )
        } else {
            format!("{resident_name} is attached to {item_name}.")
        }
    }

    fn resident_item_recovery_reason(&self, resident: CwActor, item_id: u64) -> Option<String> {
        let attachment = self.resident_personal_attachment_for_item(resident.id, item_id)?;
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let item_name = self
            .item_name(item_id)
            .unwrap_or_else(|| format!("Item {item_id}"));
        Some(format!(
            "{resident_name} wants {item_name} back: {}",
            attachment.reason.trim_end_matches('.')
        ))
    }

    fn resident_sought_item_source(&self, resident: CwActor, item_id: u64) -> &'static str {
        if self.resident_needs_medicine(resident)
            && self
                .item_by_id(item_id)
                .is_some_and(|item| item.kind == CW_ITEM_POTION)
        {
            return "medicine";
        }
        if self
            .resident_personal_desire_for_item(resident.id, item_id)
            .is_some()
        {
            return "personal";
        }
        if self
            .resident_calling_desired_item_ids(resident)
            .into_iter()
            .any(|desired_item_id| desired_item_id == item_id)
        {
            return "calling";
        }
        if self
            .resident_personal_attachment_for_item(resident.id, item_id)
            .is_some()
        {
            return "attachment";
        }
        if self
            .resident_feature_use_match_for_item(resident, item_id)
            .is_some()
        {
            return "room_feature";
        }
        "memory"
    }

    fn resident_item_request_reason(&self, resident: CwActor, item_id: u64) -> String {
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let item_name = self
            .item_name(item_id)
            .unwrap_or_else(|| format!("Item {item_id}"));
        let item = self.item_by_id(item_id);
        let healing_target = self.resident_healing_target(resident);
        if let Some(desire) = self.resident_personal_desire_for_item(resident.id, item_id) {
            format!(
                "{resident_name} wants {item_name}: {}.",
                desire.reason.trim_end_matches('.')
            )
        } else if self
            .resident_calling_desired_item_ids(resident)
            .into_iter()
            .any(|desired_item_id| desired_item_id == item_id)
        {
            format!("{resident_name} wants {item_name}.")
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION)
            && healing_target.is_some_and(|target| target.id == resident.id)
        {
            format!("{resident_name} needs {item_name}.")
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION) && healing_target.is_some() {
            let target = healing_target.expect("healing target checked");
            let target_name = self
                .actor_name(target.id)
                .unwrap_or_else(|| format!("Resident {}", target.id));
            format!("{resident_name} wants {item_name} for {target_name}.")
        } else if let Some(reason) = self.resident_item_recovery_reason(resident, item_id) {
            format!("{reason}.")
        } else if let Some(candidate) = self.resident_feature_use_match_for_item(resident, item_id)
        {
            format!(
                "{resident_name} could use {item_name} with {}.",
                candidate.feature_name
            )
        } else if item.is_some_and(|item| item.kind == CW_ITEM_POTION) {
            format!("{resident_name} could use {item_name}.")
        } else {
            format!("{resident_name} values {item_name}.")
        }
    }

    fn resident_waits_for_player_gift(&self, resident: CwActor) -> bool {
        self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| {
                Self::actor_is_active_avatar(*actor)
                    && actor.id != resident.id
                    && actor.location_id == resident.location_id
            })
            .any(|actor| {
                self.resident_request_for_holder(resident, actor.id)
                    .is_some()
            })
    }

    fn resident_economy_prompt_note(
        &self,
        resident: CwActor,
        client_actor_id: Option<u64>,
    ) -> String {
        let Some(economy) = self.resident_economy_view(resident, client_actor_id) else {
            return "Actor economy: no item economy is active.".to_string();
        };

        let mut parts = Vec::new();
        if !economy.motive.trim().is_empty() {
            parts.push(format!("motive: {}", economy.motive.trim()));
        }
        if economy.carrying_capacity_tenths > 0 {
            parts.push(format!(
                "carried deck: {:.1}/{:.1} lb across {} card(s)",
                economy.carried_weight_tenths as f64 / 10.0,
                economy.carrying_capacity_tenths as f64 / 10.0,
                economy.inventory_count
            ));
        }

        let memory_notes = self.resident_memory_prompt_notes(resident.id);
        if !memory_notes.is_empty() {
            parts.push(format!("carried memories: {}", memory_notes.join(" | ")));
        }

        let sought: Vec<_> = economy
            .sought_items
            .iter()
            .take(3)
            .map(|sought| {
                let item_name = self
                    .item_name(sought.item_id)
                    .unwrap_or_else(|| format!("Item {}", sought.item_id));
                let source = sought.source.replace('_', " ");
                let mut text = format!("{item_name} ({source})");
                if let Some(location_name) = sought.memory_location_name.as_deref() {
                    if let Some(holder_name) = sought.holder_actor_name.as_deref() {
                        text.push_str(&format!(
                            " remembered with {holder_name} near {location_name}"
                        ));
                    } else {
                        text.push_str(&format!(" remembered near {location_name}"));
                    }
                }
                let reason = sought.reason.trim_end_matches('.');
                if !reason.is_empty() {
                    text.push_str(&format!("; {reason}"));
                }
                text
            })
            .collect();
        if !sought.is_empty() {
            parts.push(format!("seeks: {}", sought.join(" | ")));
        }

        if let Some(trade) = economy.trade_stance.as_ref() {
            let offered_name = self
                .item_name(trade.offered_item_id)
                .unwrap_or_else(|| format!("Item {}", trade.offered_item_id));
            let requested_name = self
                .item_name(trade.requested_item_id)
                .unwrap_or_else(|| format!("Item {}", trade.requested_item_id));
            let holder_name = client_actor_id
                .and_then(|actor_id| self.actor_name(actor_id))
                .unwrap_or_else(|| "the visitor".to_string());
            let reason = trade.reason.trim_end_matches('.');
            let mut text = format!(
                "{} if {holder_name} offers {offered_name} for {requested_name}",
                trade.willingness
            );
            if !reason.is_empty() {
                text.push_str(&format!("; {reason}"));
            }
            parts.push(format!("trade: {text}"));
        }

        let held: Vec<_> = economy
            .held_items
            .iter()
            .take(4)
            .map(|held| {
                let item_name = self
                    .item_name(held.item_id)
                    .unwrap_or_else(|| format!("Item {}", held.item_id));
                format!("{item_name}: {}", held.disposition)
            })
            .collect();
        if !held.is_empty() {
            parts.push(format!("carrying: {}", held.join(" | ")));
        }

        if parts.is_empty() {
            "Resident economy: open to useful gifts and trades.".to_string()
        } else {
            format!("Resident economy: {}.", parts.join("; "))
        }
    }

    #[cfg(test)]
    fn resident_reply_text_for_committed_action(&self, action: &CwAction) -> Option<(u64, String)> {
        let target = self.actor_by_id(action.target_actor_id)?;
        if !Self::actor_is_active_avatar(target) {
            return None;
        }
        match action.kind {
            CW_ACTION_GIVE_ITEM => {
                let item_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let mut text = format!("I gave you {item_name}.");
                if let Some(reason) = self.resident_action_item_reason(target, action.item_id) {
                    text.push_str(&format!(" {reason}"));
                }
                Some((target.id, text))
            }
            CW_ACTION_TRADE_ITEM => {
                let offered_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let received_name = self
                    .item_name(action.target_item_id)
                    .unwrap_or_else(|| format!("Item {}", action.target_item_id));
                let mut text = format!("I traded you {offered_name} for {received_name}.");
                if let Some(reason) = self.resident_action_item_reason(target, action.item_id) {
                    text.push_str(&format!(" {reason}"));
                }
                Some((target.id, text))
            }
            _ => None,
        }
    }

    fn direct_observation_reply_plan(
        &self,
        observation: &PlayerTickObservation,
    ) -> Option<AvatarReplyPlan> {
        let event = observation.source_events.iter().find(|event| {
            event.success
                && event.actor_id == Some(observation.source_actor_id)
                && matches!(
                    event.type_name.as_str(),
                    "item.given"
                        | "item.traded"
                        | "bond.created"
                        | "bond.revised"
                        | "bond.resolved"
                )
        })?;
        let target_actor_id = event.target_actor_id?;
        let subject = event
            .content
            .clone()
            .or_else(|| event.item_name.clone())
            .unwrap_or_else(|| "what just changed between us".to_string());
        let user_text = match event.type_name.as_str() {
            "item.given" => format!("I gave you {subject}."),
            "item.traded" => format!("We made this trade: {subject}."),
            "bond.created" => format!("I want to remember this friendship: {subject}"),
            "bond.revised" => format!("I see our friendship differently now: {subject}"),
            "bond.resolved" => format!("I want to keep what mattered between us: {subject}"),
            _ => return None,
        };
        self.resident_reply_plan_for_target(
            observation.source_actor_id,
            target_actor_id,
            &user_text,
        )
        .map(|plan| plan.with_observation(observation))
    }

    fn resident_action_item_reason(&self, resident: CwActor, item_id: u64) -> Option<String> {
        let reason = self.resident_item_request_reason(resident, item_id);
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let item_name = self
            .item_name(item_id)
            .unwrap_or_else(|| format!("Item {item_id}"));
        let generic = format!("{resident_name} values {item_name}.");
        (reason != generic).then_some(reason)
    }

    fn resident_local_seek_item_name(
        &self,
        resident: CwActor,
        excluding_item_id: u64,
    ) -> Option<String> {
        let memory = self.resident_memory_seek_target(resident)?;
        if memory.location_id != resident.location_id || memory.subject_id == excluding_item_id {
            return None;
        }
        if !self.item_by_id(memory.subject_id).is_some_and(|item| {
            item.holder_actor_id == 0 && item.location_id == resident.location_id
        }) {
            return None;
        }
        Some(
            self.item_name(memory.subject_id)
                .unwrap_or_else(|| format!("Item {}", memory.subject_id)),
        )
    }

    fn resident_economy_action_reply_plan(&self, action: &CwAction) -> Option<AvatarReplyPlan> {
        let actor = self.actor_by_id(action.actor_id)?;
        if !Self::actor_is_active_avatar(actor) || !self.actor_uses_inference(actor.id) {
            return None;
        }
        let user_text = self.resident_economy_action_reply_seed(actor, action)?;
        let actor_meta = self.actors.get(&actor.id);
        let location_meta = self.location_meta_for(actor.location_id);
        Some(AvatarReplyPlan {
            speaker_actor_id: actor.id,
            speaker_name: self
                .actor_name(actor.id)
                .unwrap_or_else(|| format!("Actor {}", actor.id)),
            speech_mode: actor_meta
                .map(|meta| meta.speech_mode.clone())
                .unwrap_or_else(|| "prose".to_string()),
            resident_continuity: self.resident_continuity_for(actor),
            economy_note: self.resident_economy_prompt_note(actor, None),
            goals: self.narrative_goal_lines(None, actor.location_id),
            location_name: self
                .location_name(actor.location_id)
                .unwrap_or_else(|| "Unknown Location".to_string()),
            location_title: location_meta.title,
            location_description: location_meta.description,
            location_persona: location_meta.persona,
            location_memory: location_meta.memory,
            cast: self.room_cast_names(actor.location_id),
            recent_lines: self.recent_room_lines(actor.location_id, 8),
            recent_activity: self.recent_room_activity(actor.location_id, 10),
            user_text,
            caused_by_event_seq: None,
            source_world_tick: None,
            observed_through_seq: None,
            source_location_id: None,
        })
    }

    fn resident_economy_action_reply_seed(
        &self,
        actor: CwActor,
        action: &CwAction,
    ) -> Option<String> {
        let actor_name = self
            .actor_name(actor.id)
            .unwrap_or_else(|| format!("Resident {}", actor.id));
        match action.kind {
            CW_ACTION_GIVE_ITEM => {
                let item_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let target = self.actor_by_id(action.target_actor_id)?;
                let target_name = self
                    .actor_name(target.id)
                    .unwrap_or_else(|| format!("Resident {}", target.id));
                let mut text = format!("{actor_name} gave {item_name} to {target_name}.");
                if let Some(reason) = self.resident_action_item_reason(target, action.item_id) {
                    text.push_str(&format!(" {reason}"));
                }
                Some(text)
            }
            CW_ACTION_TRADE_ITEM => {
                let offered_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let received_name = self
                    .item_name(action.target_item_id)
                    .unwrap_or_else(|| format!("Item {}", action.target_item_id));
                let target = self.actor_by_id(action.target_actor_id)?;
                let target_name = self
                    .actor_name(target.id)
                    .unwrap_or_else(|| format!("Resident {}", target.id));
                let mut parts = vec![format!(
                    "{actor_name} traded {offered_name} to {target_name} for {received_name}."
                )];
                if let Some(reason) = self.resident_action_item_reason(actor, action.target_item_id)
                {
                    parts.push(reason);
                }
                if let Some(reason) = self.resident_action_item_reason(target, action.item_id) {
                    parts.push(reason);
                }
                Some(parts.join(" "))
            }
            CW_ACTION_USE_ITEM => {
                let item_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let target_name = self
                    .actor_name(action.target_actor_id)
                    .unwrap_or_else(|| actor_name.clone());
                Some(format!(
                    "{actor_name} used {item_name} for {target_name} because it was useful right now."
                ))
            }
            CW_ACTION_PICK_UP_ITEM => {
                let item_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let mut text = format!("{actor_name} picked up {item_name}.");
                if let Some(reason) = self.resident_action_item_reason(actor, action.item_id) {
                    text.push_str(&format!(" {reason}"));
                }
                Some(text)
            }
            CW_ACTION_DROP_ITEM => {
                let item_name = self
                    .item_name(action.item_id)
                    .unwrap_or_else(|| format!("Item {}", action.item_id));
                let target_item_name = self
                    .resident_local_seek_item_name(actor, action.item_id)
                    .unwrap_or_else(|| "something more important".to_string());
                Some(format!(
                    "{actor_name} let go of {item_name} to make room for {target_item_name}."
                ))
            }
            CW_ACTION_MOVE => {
                let destination = self
                    .location_name(action.destination_location_id)
                    .unwrap_or_else(|| format!("Location {}", action.destination_location_id));
                Some(format!("{actor_name} moved toward {destination}."))
            }
            _ => None,
        }
    }

    fn resident_memory_prompt_notes(&self, resident_id: u64) -> Vec<String> {
        let mut memories: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == resident_id
                    && memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
            })
            .cloned()
            .collect();
        memories.sort_by_key(|memory| {
            (
                std::cmp::Reverse(memory.salience),
                std::cmp::Reverse(memory.confidence),
                std::cmp::Reverse(memory.observed_tick),
                memory.hops,
                memory.kind.clone(),
                memory.subject_id,
            )
        });

        let mut notes = Vec::new();
        let mut seen = BTreeSet::new();
        for memory in memories {
            let route = if memory.source_actor_id == Some(resident_id) && memory.hops == 0 {
                "saw"
            } else {
                "heard"
            };
            let location_name = self
                .location_name(memory.location_id)
                .unwrap_or_else(|| format!("Location {}", memory.location_id));
            let note = match memory.kind.as_str() {
                RESIDENT_MEMORY_KIND_ACTOR_LOCATION => {
                    if memory.subject_id == resident_id {
                        continue;
                    }
                    let actor_name = self
                        .actor_name(memory.subject_id)
                        .unwrap_or_else(|| format!("Resident {}", memory.subject_id));
                    format!("{route} {actor_name} near {location_name}")
                }
                RESIDENT_MEMORY_KIND_ITEM_LOCATION => {
                    let item_name = self
                        .item_name(memory.subject_id)
                        .unwrap_or_else(|| format!("Item {}", memory.subject_id));
                    if let Some(holder_name) = memory
                        .holder_actor_id
                        .and_then(|holder_actor_id| self.actor_name(holder_actor_id))
                    {
                        format!("{route} {item_name} with {holder_name} near {location_name}")
                    } else {
                        format!("{route} {item_name} near {location_name}")
                    }
                }
                RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM => {
                    let Some(target_actor_id) = memory.holder_actor_id else {
                        continue;
                    };
                    let target_name = self
                        .actor_name(target_actor_id)
                        .unwrap_or_else(|| format!("Resident {}", target_actor_id));
                    let item_name = self
                        .item_name(memory.subject_id)
                        .unwrap_or_else(|| format!("Item {}", memory.subject_id));
                    format!("{route} {target_name} wanted {item_name} near {location_name}")
                }
                _ => continue,
            };
            if seen.insert(note.clone()) {
                notes.push(note);
            }
            if notes.len() >= 4 {
                break;
            }
        }
        notes
    }

    fn resident_continuity_for(&self, resident: CwActor) -> ResidentContinuityState {
        let identity = self.resident_stable_identity(resident);
        let mut continuity = self
            .resident_continuities
            .get(&resident.id)
            .cloned()
            .unwrap_or_else(|| ResidentContinuityState::empty(resident.id, identity.clone()));
        continuity.stable_identity = identity;
        continuity.relationship_notes_by_actor = self.resident_relationship_notes(resident.id);
        continuity.memory_atoms = self.resident_continuity_atoms(resident.id, 6);
        let (open_obligations, current_intent) =
            self.resident_open_obligations_and_intent(resident);
        continuity.open_obligations = open_obligations;
        if continuity
            .current_intent
            .as_deref()
            .map(|intent| intent.trim().is_empty())
            .unwrap_or(true)
        {
            continuity.current_intent = current_intent;
        }
        continuity.last_observed_event_seq = continuity
            .last_observed_event_seq
            .max(self.latest_observed_event_seq_for_resident(resident));
        continuity
    }

    fn refresh_resident_continuity(&mut self, resident_id: u64) {
        let Some(resident) = self.actor_by_id(resident_id) else {
            self.resident_continuities.remove(&resident_id);
            return;
        };
        if !Self::actor_is_active_avatar(resident) {
            self.resident_continuities.remove(&resident_id);
            return;
        }
        let continuity = self.resident_continuity_for(resident);
        self.resident_continuities.insert(resident_id, continuity);
    }

    fn refresh_all_resident_continuities(&mut self) {
        let resident_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
            .iter()
            .copied()
            .filter(|actor| Self::actor_is_active_avatar(*actor))
            .map(|actor| actor.id)
            .collect();
        for resident_id in resident_ids {
            self.refresh_resident_continuity(resident_id);
        }
    }

    fn ensure_actor_autonomy(&mut self) {
        let actors = self.world.actors[..self.world.actor_count].to_vec();
        let active_ids = actors.iter().map(|actor| actor.id).collect::<BTreeSet<_>>();
        self.actor_autonomy
            .retain(|actor_id, _| active_ids.contains(actor_id));
        for actor in actors {
            let default_mode = seed_actor_default_control_mode(actor.id);
            let desires = self
                .resident_continuities
                .get(&actor.id)
                .map(|continuity| continuity.open_obligations.clone())
                .unwrap_or_default();
            let autonomy =
                self.actor_autonomy
                    .entry(actor.id)
                    .or_insert_with(|| ActorAutonomyState {
                        control_mode: default_mode,
                        ..ActorAutonomyState::default()
                    });
            autonomy.current_desires = desires;
            if autonomy.control_mode.uses_inference() && autonomy.attention_credits == 0 {
                autonomy.attention_credits = 1;
            }
        }
    }

    fn observe_player_tick_for_autonomy(&mut self, observation: &PlayerTickObservation) {
        self.ensure_actor_autonomy();
        let affected_locations = observation
            .ripple_source
            .as_ref()
            .map(|source| {
                source
                    .affected_location_ids
                    .iter()
                    .copied()
                    .collect::<BTreeSet<_>>()
            })
            .unwrap_or_else(|| observation.source_location_id.into_iter().collect());
        for actor in &self.world.actors[..self.world.actor_count] {
            if !Self::actor_is_active_avatar(*actor)
                || !affected_locations.contains(&actor.location_id)
                || !self.actor_uses_inference(actor.id)
            {
                continue;
            }
            if let Some(autonomy) = self.actor_autonomy.get_mut(&actor.id) {
                autonomy.last_observed_tick = observation.source_world_tick;
                autonomy.attention_credits = autonomy.attention_credits.saturating_add(1).min(2);
            }
        }
    }

    fn autonomy_allows_action(
        &self,
        actor_id: u64,
        action_kind: u8,
        source_world_tick: u64,
    ) -> bool {
        let Some(autonomy) = self.actor_autonomy.get(&actor_id) else {
            return false;
        };
        if autonomy.attention_credits == 0 || autonomy.last_acted_tick >= source_world_tick {
            return false;
        }
        match autonomy.control_mode {
            ActorControlMode::DirectInput => false,
            ActorControlMode::ReactiveAi => action_kind == CW_ACTION_SAY,
            ActorControlMode::LocalAi => action_kind != CW_ACTION_FLEE,
            ActorControlMode::RoamingAi | ActorControlMode::DelegatedAi => true,
        }
    }

    fn kernel_offer_allows_action(&self, action: &CwAction) -> bool {
        let required_offer = match action.kind {
            CW_ACTION_NONE | CW_ACTION_SAY | CW_ACTION_CREATE_ACTOR => return true,
            CW_ACTION_MOVE => CW_OFFER_MOVE,
            CW_ACTION_ABILITY_CHECK => CW_OFFER_CHECK,
            CW_ACTION_RULES_SEARCH | CW_ACTION_RULES_STUDY => CW_OFFER_CHECK,
            CW_ACTION_RULES_MAGIC => CW_OFFER_USE_ITEM,
            CW_ACTION_PICK_UP_ITEM => CW_OFFER_PICK_UP,
            CW_ACTION_USE_ITEM => CW_OFFER_USE_ITEM,
            CW_ACTION_ATTACK => CW_OFFER_ATTACK,
            CW_ACTION_DEFEND => CW_OFFER_DEFEND,
            CW_ACTION_GIVE_ITEM => CW_OFFER_GIVE_ITEM,
            CW_ACTION_FLEE => CW_OFFER_FLEE,
            CW_ACTION_DROP_ITEM => CW_OFFER_DROP_ITEM,
            CW_ACTION_TRADE_ITEM => CW_OFFER_TRADE_ITEM,
            CW_ACTION_SEARCH => CW_OFFER_SEARCH,
            CW_ACTION_CRAFT => CW_OFFER_CRAFT,
            _ => return false,
        };
        let mut offers = CwActionOffers::default();
        (unsafe { cw_get_action_offers(&self.world, action.actor_id, &mut offers) }) == CW_OK
            && offers.option_flags & required_offer != 0
    }

    fn record_autonomous_action(&mut self, record: &JournalRecord) {
        if record.origin != JournalOrigin::ActorConsequence || record.source_world_tick.is_none() {
            return;
        }
        let Some(autonomy) = self.actor_autonomy.get_mut(&record.action.actor_id) else {
            return;
        };
        if autonomy.control_mode.is_direct_input() {
            return;
        }
        autonomy.last_acted_tick = record.source_world_tick.unwrap_or(self.world.tick);
        autonomy.attention_credits = autonomy.attention_credits.saturating_sub(1);
        autonomy.pending_intent = None;
    }

    fn player_tick_already_has_autonomous_result(&self, source_world_tick: u64) -> bool {
        self.actor_autonomy.values().any(|autonomy| {
            autonomy.control_mode.uses_inference() && autonomy.last_acted_tick >= source_world_tick
        }) || self.event_log.iter().rev().any(|event| {
            event.success
                && event.type_name == "message.created"
                && event.source_world_tick == Some(source_world_tick)
        })
    }

    fn apply_resident_intent_projection(
        &mut self,
        resident_id: u64,
        proposal: &AvatarIntentProposal,
        reason: &str,
    ) {
        self.refresh_resident_continuity(resident_id);
        let source_event_seq = self
            .actor_by_id(resident_id)
            .map(|resident| self.latest_observed_event_seq_for_resident(resident));
        let Some(continuity) = self.resident_continuities.get_mut(&resident_id) else {
            return;
        };
        if let Some(intent) = sanitize_continuity_note_text(proposal.intent.as_deref()) {
            continuity.current_intent = Some(intent);
        } else if let Some(action) = proposal.proposed_action.as_ref() {
            if let Some(intent) = resident_proposed_action_intent(action) {
                continuity.current_intent = Some(intent);
            }
        }
        if let Some(text) = sanitize_continuity_note_text(proposal.belief.as_deref()) {
            push_resident_continuity_note(
                &mut continuity.beliefs,
                text,
                reason,
                source_event_seq,
                180,
            );
        }
        if let Some(text) = sanitize_continuity_note_text(proposal.desire.as_deref()) {
            push_resident_continuity_note(
                &mut continuity.desires,
                text,
                reason,
                source_event_seq,
                190,
            );
        }
        if let Some(text) = proposal
            .proposed_action
            .as_ref()
            .and_then(|action| action.reason.as_deref())
            .and_then(|reason| sanitize_continuity_note_text(Some(reason)))
        {
            push_resident_continuity_note(
                &mut continuity.desires,
                text,
                reason,
                source_event_seq,
                150,
            );
        }
        if let Some(text) = sanitize_continuity_note_text(proposal.promise.as_deref()) {
            push_resident_continuity_note(
                &mut continuity.promises,
                text,
                reason,
                source_event_seq,
                210,
            );
        }
        if let Some(text) = sanitize_continuity_note_text(proposal.refusal.as_deref()) {
            push_resident_continuity_note(
                &mut continuity.refusals,
                text,
                reason,
                source_event_seq,
                220,
            );
        }
        if reason != "resident_autonomy_intent" {
            continuity.pending_action = proposal.proposed_action.clone();
        }
        if let Some(source_event_seq) = source_event_seq {
            continuity.last_observed_event_seq =
                continuity.last_observed_event_seq.max(source_event_seq);
        }
    }

    fn clear_resident_pending_action(&mut self, resident_id: u64) {
        if let Some(continuity) = self.resident_continuities.get_mut(&resident_id) {
            continuity.pending_action = None;
        }
    }

    fn resident_stable_identity(&self, resident: CwActor) -> String {
        let name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Resident {}", resident.id));
        let meta = self.actors.get(&resident.id);
        let title = meta
            .map(|meta| meta.title.as_str())
            .filter(|title| !title.trim().is_empty())
            .unwrap_or("resident");
        let description = meta
            .map(|meta| meta.description.as_str())
            .filter(|description| !description.trim().is_empty())
            .unwrap_or("A resident of CosyWorld.");
        let speech_mode = meta
            .map(|meta| meta.speech_mode.as_str())
            .filter(|mode| !mode.trim().is_empty())
            .unwrap_or("prose");
        format!("{name} / {title} / speech:{speech_mode} / {description}")
    }

    fn resident_relationship_notes(&self, resident_id: u64) -> BTreeMap<u64, String> {
        let mut notes = BTreeMap::new();
        for bond in self.bonds.values() {
            if bond.status == "resolved" {
                continue;
            }
            let other_id = if bond.actor_id == resident_id {
                bond.target_actor_id
            } else if bond.target_actor_id == resident_id {
                bond.actor_id
            } else {
                continue;
            };
            let other_name = self
                .actor_name(other_id)
                .unwrap_or_else(|| format!("Actor {}", other_id));
            let statement = bond.statement.trim();
            let text = if statement.is_empty() {
                format!("{other_name} matters to them.")
            } else {
                format!("Friendship with {other_name}: {statement}")
            };
            notes.insert(other_id, text);
        }
        notes
    }

    fn resident_continuity_atoms(
        &self,
        resident_id: u64,
        limit: usize,
    ) -> Vec<ResidentContinuityAtom> {
        let mut memories: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| memory.carrier_actor_id == resident_id)
            .cloned()
            .collect();
        memories.sort_by_key(|memory| {
            (
                std::cmp::Reverse(memory.salience),
                std::cmp::Reverse(memory.confidence),
                std::cmp::Reverse(memory.observed_tick),
                memory.hops,
                memory.kind.clone(),
                memory.subject_id,
            )
        });
        memories
            .into_iter()
            .filter_map(|memory| {
                self.resident_memory_atom_text(&memory)
                    .map(|text| ResidentContinuityAtom {
                        kind: memory.kind,
                        subject_id: memory.subject_id,
                        text,
                        confidence: memory.confidence,
                        salience: memory.salience,
                        observed_tick: memory.observed_tick,
                    })
            })
            .take(limit)
            .collect()
    }

    fn resident_memory_atom_text(&self, memory: &ResidentMemoryState) -> Option<String> {
        let route = if memory.source_actor_id == Some(memory.carrier_actor_id) && memory.hops == 0 {
            "saw"
        } else {
            "heard"
        };
        let location_name = self
            .location_name(memory.location_id)
            .unwrap_or_else(|| format!("Location {}", memory.location_id));
        match memory.kind.as_str() {
            RESIDENT_MEMORY_KIND_ACTOR_LOCATION => {
                if memory.subject_id == memory.carrier_actor_id {
                    return None;
                }
                let actor_name = self
                    .actor_name(memory.subject_id)
                    .unwrap_or_else(|| format!("Actor {}", memory.subject_id));
                Some(format!("{route} {actor_name} near {location_name}"))
            }
            RESIDENT_MEMORY_KIND_ITEM_LOCATION => {
                let item_name = self
                    .item_name(memory.subject_id)
                    .unwrap_or_else(|| format!("Item {}", memory.subject_id));
                if let Some(holder_name) = memory
                    .holder_actor_id
                    .and_then(|holder_actor_id| self.actor_name(holder_actor_id))
                {
                    Some(format!(
                        "{route} {item_name} with {holder_name} near {location_name}"
                    ))
                } else {
                    Some(format!("{route} {item_name} near {location_name}"))
                }
            }
            RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM => {
                let target_actor_id = memory.holder_actor_id?;
                let target_name = self
                    .actor_name(target_actor_id)
                    .unwrap_or_else(|| format!("Actor {}", target_actor_id));
                let item_name = self
                    .item_name(memory.subject_id)
                    .unwrap_or_else(|| format!("Item {}", memory.subject_id));
                Some(format!(
                    "{route} {target_name} wanted {item_name} near {location_name}"
                ))
            }
            _ => None,
        }
    }

    fn resident_open_obligations_and_intent(
        &self,
        resident: CwActor,
    ) -> (Vec<String>, Option<String>) {
        let Some(economy) = self.resident_economy_view(resident, None) else {
            return (Vec::new(), None);
        };
        let mut obligations = Vec::new();
        if let Some(request) = economy.request.as_ref() {
            let item_name = self
                .item_name(request.item_id)
                .unwrap_or_else(|| format!("Item {}", request.item_id));
            let holder_name = self
                .actor_name(request.holder_actor_id)
                .unwrap_or_else(|| format!("Actor {}", request.holder_actor_id));
            obligations.push(format!(
                "wants {item_name} from {holder_name}: {}",
                request.reason.trim_end_matches('.')
            ));
        }
        if let Some(offer) = economy.trade_offer.as_ref() {
            let offered_name = self
                .item_name(offer.offered_item_id)
                .unwrap_or_else(|| format!("Item {}", offer.offered_item_id));
            let requested_name = self
                .item_name(offer.requested_item_id)
                .unwrap_or_else(|| format!("Item {}", offer.requested_item_id));
            obligations.push(format!(
                "will trade {offered_name} for {requested_name}: {}",
                offer.reason.trim_end_matches('.')
            ));
        }
        let current_intent = if let Some(item_id) = economy.seeking_item_id {
            let item_name = self
                .item_name(item_id)
                .unwrap_or_else(|| format!("Item {}", item_id));
            let place = economy
                .seeking_location_name
                .as_deref()
                .unwrap_or("somewhere nearby");
            Some(format!("seek {item_name} near {place}"))
        } else if !economy.motive.trim().is_empty() {
            Some(economy.motive.trim_end_matches('.').to_string())
        } else {
            None
        };
        (obligations, current_intent)
    }

    fn latest_observed_event_seq_for_resident(&self, resident: CwActor) -> u64 {
        self.event_log
            .iter()
            .filter(|event| {
                event.actor_id == Some(resident.id)
                    || event.target_actor_id == Some(resident.id)
                    || event.location_id == Some(resident.location_id)
                    || event.destination_location_id == Some(resident.location_id)
            })
            .map(|event| event.seq)
            .max()
            .unwrap_or(0)
    }

    fn item_list_label(&self, item_ids: &[u64]) -> String {
        let names: Vec<_> = item_ids
            .iter()
            .map(|item_id| {
                self.item_name(*item_id)
                    .unwrap_or_else(|| format!("Item {item_id}"))
            })
            .collect();
        match names.as_slice() {
            [] => "nothing in particular".to_string(),
            [one] => one.clone(),
            [first, second] => format!("{first} and {second}"),
            _ => {
                let mut text = names[..names.len() - 1].join(", ");
                text.push_str(", and ");
                text.push_str(&names[names.len() - 1]);
                text
            }
        }
    }

    fn resident_memory_id(carrier_actor_id: u64, kind: &str, subject_id: u64) -> String {
        format!("resident_memory:{carrier_actor_id}:{kind}:{subject_id}")
    }

    fn resident_memory_key(
        carrier_actor_id: u64,
        kind: &str,
        subject_id: u64,
        holder_actor_id: Option<u64>,
    ) -> String {
        if kind == RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM {
            let target_actor_id = holder_actor_id.unwrap_or_default();
            return format!(
                "resident_memory:{carrier_actor_id}:{kind}:{target_actor_id}:{subject_id}"
            );
        }
        Self::resident_memory_id(carrier_actor_id, kind, subject_id)
    }

    fn remember_resident_memory(
        &mut self,
        carrier_actor_id: u64,
        kind: &str,
        subject_id: u64,
        location_id: u64,
        confidence: u8,
        salience: u8,
        source_actor_id: Option<u64>,
    ) {
        self.remember_resident_memory_with_provenance(
            carrier_actor_id,
            kind,
            subject_id,
            location_id,
            confidence,
            salience,
            source_actor_id,
            None,
            self.world.tick,
            self.world.tick,
            0,
        );
    }

    fn remember_resident_memory_with_holder(
        &mut self,
        carrier_actor_id: u64,
        kind: &str,
        subject_id: u64,
        location_id: u64,
        confidence: u8,
        salience: u8,
        source_actor_id: Option<u64>,
        holder_actor_id: Option<u64>,
    ) {
        self.remember_resident_memory_with_provenance(
            carrier_actor_id,
            kind,
            subject_id,
            location_id,
            confidence,
            salience,
            source_actor_id,
            holder_actor_id,
            self.world.tick,
            self.world.tick,
            0,
        );
    }

    fn remember_resident_wants_item_memory(
        &mut self,
        carrier_actor_id: u64,
        wanting_actor_id: u64,
        item_id: u64,
        location_id: u64,
        confidence: u8,
        salience: u8,
        source_actor_id: Option<u64>,
    ) {
        if wanting_actor_id == 0 || item_id == 0 {
            return;
        }
        self.remember_resident_memory_with_holder(
            carrier_actor_id,
            RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM,
            item_id,
            location_id,
            confidence,
            salience,
            source_actor_id,
            Some(wanting_actor_id),
        );
    }

    fn remember_resident_memory_with_provenance(
        &mut self,
        carrier_actor_id: u64,
        kind: &str,
        subject_id: u64,
        location_id: u64,
        confidence: u8,
        salience: u8,
        source_actor_id: Option<u64>,
        holder_actor_id: Option<u64>,
        observed_tick: u64,
        learned_tick: u64,
        hops: u8,
    ) {
        let Some(carrier) = self.actor_by_id(carrier_actor_id) else {
            return;
        };
        if !Self::actor_is_active_avatar(carrier) || location_id == 0 {
            return;
        }

        let id = Self::resident_memory_key(carrier_actor_id, kind, subject_id, holder_actor_id);
        let memory = ResidentMemoryState {
            id: id.clone(),
            carrier_actor_id,
            kind: kind.to_string(),
            subject_id,
            location_id,
            confidence,
            salience,
            observed_tick,
            source_actor_id,
            holder_actor_id: (kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                || kind == RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM)
                .then_some(holder_actor_id)
                .flatten()
                .filter(|holder_id| *holder_id != 0),
            learned_tick,
            hops,
        };
        match self.resident_memories.get_mut(&id) {
            Some(existing) => {
                if memory.observed_tick > existing.observed_tick
                    || (memory.observed_tick == existing.observed_tick
                        && (memory.confidence > existing.confidence
                            || (memory.confidence == existing.confidence
                                && memory.learned_tick >= existing.learned_tick)))
                {
                    *existing = memory;
                } else {
                    existing.salience = existing.salience.max(salience);
                }
            }
            None => {
                self.resident_memories.insert(id, memory);
            }
        }
        self.prune_resident_memories(carrier_actor_id);
    }

    fn prune_resident_memories(&mut self, carrier_actor_id: u64) {
        let mut owned: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| memory.carrier_actor_id == carrier_actor_id)
            .map(|memory| {
                (
                    memory.id.clone(),
                    memory.salience,
                    memory.confidence,
                    memory.observed_tick,
                )
            })
            .collect();
        if owned.len() <= RESIDENT_MEMORY_CAPACITY {
            return;
        }
        owned.sort_by_key(|(_, salience, confidence, observed_tick)| {
            (*salience, *confidence, *observed_tick)
        });
        for (id, _, _, _) in owned
            .into_iter()
            .take(self.resident_memory_overflow_count(carrier_actor_id))
        {
            self.resident_memories.remove(&id);
        }
    }

    fn resident_memory_overflow_count(&self, carrier_actor_id: u64) -> usize {
        self.resident_memories
            .values()
            .filter(|memory| memory.carrier_actor_id == carrier_actor_id)
            .count()
            .saturating_sub(RESIDENT_MEMORY_CAPACITY)
    }

    fn item_is_observable_at_location(&self, item_id: u64, location_id: u64) -> bool {
        let Some(item) = self.item_by_id(item_id) else {
            return false;
        };
        if item.holder_actor_id == 0 {
            return item.location_id == location_id
                && !self.forgotten_search_item_at_location(item, location_id);
        }
        self.actor_by_id(item.holder_actor_id)
            .is_some_and(|holder| {
                holder.location_id == location_id && holder.status != CW_ACTOR_DEAD
            })
    }

    fn item_memory_has_current_holder_location(&self, memory: &ResidentMemoryState) -> bool {
        if memory.kind != RESIDENT_MEMORY_KIND_ITEM_LOCATION {
            return false;
        }
        let Some(holder_actor_id) = memory.holder_actor_id else {
            return false;
        };
        let actor_memory_id = Self::resident_memory_id(
            memory.carrier_actor_id,
            RESIDENT_MEMORY_KIND_ACTOR_LOCATION,
            holder_actor_id,
        );
        self.resident_memories
            .get(&actor_memory_id)
            .is_some_and(|actor_memory| {
                actor_memory.confidence >= RESIDENT_MEMORY_MIN_SEEK_CONFIDENCE
                    && actor_memory.observed_tick >= memory.observed_tick
            })
    }

    fn clear_disproved_item_location_memories(&mut self, resident_id: u64, location_id: u64) {
        let memory_ids: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == resident_id
                    && memory.kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                    && memory.location_id == location_id
                    && !self.item_is_observable_at_location(memory.subject_id, location_id)
                    && !self.item_memory_has_current_holder_location(memory)
            })
            .map(|memory| memory.id.clone())
            .collect();
        for memory_id in memory_ids {
            self.resident_memories.remove(&memory_id);
        }
    }

    fn clear_disproved_actor_location_memories(
        &mut self,
        resident_id: u64,
        location_id: u64,
        observed_actor_ids: &BTreeSet<u64>,
    ) -> BTreeSet<u64> {
        let memory_ids: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == resident_id
                    && memory.kind == RESIDENT_MEMORY_KIND_ACTOR_LOCATION
                    && memory.location_id == location_id
                    && !observed_actor_ids.contains(&memory.subject_id)
            })
            .map(|memory| (memory.id.clone(), memory.subject_id))
            .collect();
        let mut disproved_actor_ids = BTreeSet::new();
        for (memory_id, subject_id) in memory_ids {
            self.resident_memories.remove(&memory_id);
            disproved_actor_ids.insert(subject_id);
        }
        disproved_actor_ids
    }

    fn clear_held_item_memories_for_disproved_holders(
        &mut self,
        resident_id: u64,
        holder_actor_ids: &BTreeSet<u64>,
    ) {
        if holder_actor_ids.is_empty() {
            return;
        }
        let memory_ids: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == resident_id
                    && memory.kind == RESIDENT_MEMORY_KIND_ITEM_LOCATION
                    && memory
                        .holder_actor_id
                        .is_some_and(|holder_actor_id| holder_actor_ids.contains(&holder_actor_id))
            })
            .map(|memory| memory.id.clone())
            .collect();
        for memory_id in memory_ids {
            self.resident_memories.remove(&memory_id);
        }
    }

    fn clear_disproved_actor_wants_item_memories(
        &mut self,
        carrier_actor_id: u64,
        target_actor_id: u64,
        current_item_ids: &BTreeSet<u64>,
    ) {
        let memory_ids: Vec<_> = self
            .resident_memories
            .values()
            .filter(|memory| {
                memory.carrier_actor_id == carrier_actor_id
                    && memory.kind == RESIDENT_MEMORY_KIND_ACTOR_WANTS_ITEM
                    && memory.holder_actor_id == Some(target_actor_id)
                    && !current_item_ids.contains(&memory.subject_id)
            })
            .map(|memory| memory.id.clone())
            .collect();
        for memory_id in memory_ids {
            self.resident_memories.remove(&memory_id);
        }
    }

    fn observe_room_for_resident(&mut self, resident_id: u64, location_id: u64) {
        let Some(resident) = self.actor_by_id(resident_id) else {
            return;
        };
        if !Self::actor_is_active_avatar(resident) || resident.location_id != location_id {
            return;
        }

        let loose_item_ids: Vec<u64> = self.world.items[..self.world.item_count]
            .iter()
            .filter(|item| {
                item.holder_actor_id == 0
                    && item.location_id == location_id
                    && !self.forgotten_search_item_at_location(**item, location_id)
            })
            .map(|item| item.id)
            .collect();
        for item_id in loose_item_ids {
            self.remember_resident_memory(
                resident_id,
                RESIDENT_MEMORY_KIND_ITEM_LOCATION,
                item_id,
                location_id,
                RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                RESIDENT_OBSERVED_MEMORY_SALIENCE,
                Some(resident_id),
            );
        }

        let actor_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| {
                actor.id != resident_id
                    && actor.status == CW_ACTOR_ACTIVE
                    && actor.location_id == location_id
            })
            .map(|actor| actor.id)
            .collect();
        for actor_id in actor_ids.iter().copied() {
            self.remember_resident_memory(
                resident_id,
                RESIDENT_MEMORY_KIND_ACTOR_LOCATION,
                actor_id,
                location_id,
                RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                RESIDENT_OBSERVED_MEMORY_SALIENCE,
                Some(resident_id),
            );
        }
        let observed_actor_ids: BTreeSet<_> = actor_ids.iter().copied().collect();
        let disproved_actor_ids = self.clear_disproved_actor_location_memories(
            resident_id,
            location_id,
            &observed_actor_ids,
        );
        self.clear_held_item_memories_for_disproved_holders(resident_id, &disproved_actor_ids);
        self.clear_disproved_item_location_memories(resident_id, location_id);
        let resident_ids_with_desires: Vec<CwActor> = actor_ids
            .iter()
            .filter_map(|actor_id| self.actor_by_id(*actor_id))
            .filter(|actor| Self::actor_is_active_avatar(*actor))
            .collect();
        for actor in resident_ids_with_desires {
            let sought_item_ids: BTreeSet<_> =
                self.resident_sought_item_ids(actor).into_iter().collect();
            self.clear_disproved_actor_wants_item_memories(resident_id, actor.id, &sought_item_ids);
            for item_id in sought_item_ids {
                self.remember_resident_wants_item_memory(
                    resident_id,
                    actor.id,
                    item_id,
                    location_id,
                    RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                    RESIDENT_OBSERVED_MEMORY_SALIENCE,
                    Some(resident_id),
                );
            }
        }

        let carried_items: Vec<(u64, u64)> = self.world.items[..self.world.item_count]
            .iter()
            .filter(|item| item.holder_actor_id != 0)
            .filter(|item| {
                self.actor_by_id(item.holder_actor_id)
                    .is_some_and(|holder| {
                        holder.id != resident_id
                            && holder.status == CW_ACTOR_ACTIVE
                            && holder.location_id == location_id
                    })
            })
            .map(|item| (item.id, item.holder_actor_id))
            .collect();
        for (item_id, holder_actor_id) in carried_items {
            self.remember_resident_memory_with_holder(
                resident_id,
                RESIDENT_MEMORY_KIND_ITEM_LOCATION,
                item_id,
                location_id,
                RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                RESIDENT_OBSERVED_MEMORY_SALIENCE,
                Some(resident_id),
                Some(holder_actor_id),
            );
        }
    }

    fn observe_room_for_residents(&mut self, location_id: u64) {
        let resident_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| {
                Self::actor_is_active_avatar(**actor) && actor.location_id == location_id
            })
            .map(|actor| actor.id)
            .collect();
        for resident_id in resident_ids {
            self.observe_room_for_resident(resident_id, location_id);
        }
    }

    fn exchange_resident_memories_at(&mut self, location_id: u64) {
        let resident_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
            .iter()
            .filter(|actor| {
                Self::actor_is_active_avatar(**actor) && actor.location_id == location_id
            })
            .map(|actor| actor.id)
            .collect();
        if resident_ids.len() < 2 {
            return;
        }

        let carried: Vec<(u64, Vec<ResidentMemoryState>)> = resident_ids
            .iter()
            .map(|resident_id| {
                let memories = self
                    .resident_memories
                    .values()
                    .filter(|memory| memory.carrier_actor_id == *resident_id)
                    .cloned()
                    .collect();
                (*resident_id, memories)
            })
            .collect();

        for (source_id, memories) in carried {
            for target_id in resident_ids.iter().copied().filter(|id| *id != source_id) {
                for memory in &memories {
                    let confidence = memory
                        .confidence
                        .saturating_sub(RESIDENT_GOSSIP_CONFIDENCE_DECAY);
                    let salience = memory
                        .salience
                        .saturating_sub(RESIDENT_GOSSIP_SALIENCE_DECAY);
                    if confidence == 0 || salience == 0 {
                        continue;
                    }
                    self.remember_resident_memory_with_provenance(
                        target_id,
                        &memory.kind,
                        memory.subject_id,
                        memory.location_id,
                        confidence,
                        salience,
                        Some(source_id),
                        memory.holder_actor_id,
                        memory.observed_tick,
                        self.world.tick,
                        memory.hops.saturating_add(1),
                    );
                }
            }
        }
    }

    fn apply_resident_memory_projection(&mut self, action: &CwAction, events: &[EventView]) {
        let mut locations = BTreeSet::new();
        for event in events.iter().filter(|event| event.success) {
            if let Some(location_id) = event.location_id {
                locations.insert(location_id);
            }
            if let Some(location_id) = event.destination_location_id {
                locations.insert(location_id);
            }
            if event.type_name == "actor.moved" {
                if let (Some(actor_id), Some(from_location_id), Some(to_location_id)) = (
                    event.actor_id,
                    event.location_id,
                    event.destination_location_id,
                ) {
                    let observers: Vec<u64> = self.world.actors[..self.world.actor_count]
                        .iter()
                        .filter(|actor| {
                            actor.id != actor_id
                                && Self::actor_is_active_avatar(**actor)
                                && actor.location_id == from_location_id
                        })
                        .map(|actor| actor.id)
                        .collect();
                    for observer_id in observers.iter().copied() {
                        self.remember_resident_memory(
                            observer_id,
                            RESIDENT_MEMORY_KIND_ACTOR_LOCATION,
                            actor_id,
                            to_location_id,
                            RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                            RESIDENT_OBSERVED_MEMORY_SALIENCE,
                            Some(observer_id),
                        );
                    }
                    let carried_item_ids: Vec<u64> = self
                        .actor_held_items(actor_id)
                        .into_iter()
                        .map(|item| item.id)
                        .collect();
                    for observer_id in observers.iter().copied() {
                        for item_id in &carried_item_ids {
                            self.remember_resident_memory_with_holder(
                                observer_id,
                                RESIDENT_MEMORY_KIND_ITEM_LOCATION,
                                *item_id,
                                to_location_id,
                                RESIDENT_OBSERVED_MEMORY_CONFIDENCE,
                                RESIDENT_OBSERVED_MEMORY_SALIENCE,
                                Some(observer_id),
                                Some(actor_id),
                            );
                        }
                    }
                }
            }
        }

        if let Some(actor) = self.actor_by_id(action.actor_id) {
            if Self::actor_is_active_avatar(actor) {
                locations.insert(actor.location_id);
            }
        }

        for location_id in locations {
            self.observe_room_for_residents(location_id);
            self.exchange_resident_memories_at(location_id);
            let resident_ids: Vec<u64> = self.world.actors[..self.world.actor_count]
                .iter()
                .filter(|actor| {
                    Self::actor_is_active_avatar(**actor) && actor.location_id == location_id
                })
                .map(|actor| actor.id)
                .collect();
            for resident_id in resident_ids {
                self.refresh_resident_continuity(resident_id);
            }
        }
    }

    fn resident_item_offer_score(&self, resident: CwActor, item: CwItem) -> i16 {
        let resident_already_holds_item = self
            .actor_held_items(resident.id)
            .into_iter()
            .any(|held_item| held_item.id == item.id);
        let directly_desired = self
            .resident_desired_item_ids(resident)
            .into_iter()
            .any(|desired_item_id| desired_item_id == item.id)
            || self
                .resident_attachment_item_ids(resident)
                .into_iter()
                .any(|attachment_item_id| attachment_item_id == item.id);
        if directly_desired && !resident_already_holds_item {
            return RESIDENT_DESIRED_ITEM_SCORE;
        }
        if item.kind == CW_ITEM_POTION && self.resident_healing_target(resident).is_some() {
            return RESIDENT_DESIRED_ITEM_SCORE - 10;
        }
        if item.kind == CW_ITEM_POTION {
            return RESIDENT_USEFUL_ITEM_SCORE;
        }
        if self
            .resident_feature_use_match_for_item(resident, item.id)
            .is_some()
        {
            return RESIDENT_DESIRED_ITEM_SCORE - 15;
        }
        RESIDENT_DEFAULT_ITEM_SCORE
    }

    fn resident_item_keep_score(&self, resident: CwActor, item: CwItem) -> i16 {
        if self.resident_item_is_attached(resident.id, item) {
            return RESIDENT_ATTACHED_ITEM_SCORE;
        }
        if item.kind == CW_ITEM_POTION && self.resident_healing_target(resident).is_some() {
            return RESIDENT_DESIRED_ITEM_SCORE - 5;
        }
        if item.kind == CW_ITEM_POTION {
            return RESIDENT_USEFUL_ITEM_SCORE;
        }
        if self
            .resident_feature_use_match_for_item(resident, item.id)
            .is_some()
        {
            return RESIDENT_DESIRED_ITEM_SCORE - 5;
        }
        RESIDENT_DEFAULT_ITEM_SCORE
    }

    #[cfg(test)]
    fn resident_expendable_item_for_pickup(&self, resident: CwActor) -> Option<CwItem> {
        if !Self::actor_is_active_avatar(resident) || !self.actor_inventory_full(resident.id) {
            return None;
        }
        self.resident_exchange_item_for_pickup(resident, None)
    }

    fn resident_exchange_item_for_pickup(
        &self,
        resident: CwActor,
        incoming_item: Option<CwItem>,
    ) -> Option<CwItem> {
        if !Self::actor_is_active_avatar(resident) {
            return None;
        }
        let mut candidates: Vec<_> = self
            .actor_held_items(resident.id)
            .into_iter()
            .filter(|item| !self.resident_item_is_attached(resident.id, *item))
            .filter(|item| {
                incoming_item.is_none_or(|incoming| {
                    self.actor_can_exchange_items(resident.id, Some(*item), incoming)
                })
            })
            .collect();
        candidates.sort_by_key(|item| {
            (
                self.resident_item_keep_score(resident, *item),
                item.held_since_tick,
                item.id,
            )
        });
        candidates.into_iter().next()
    }

    fn resident_trade_preference(
        &self,
        resident_id: u64,
        offered_item: CwItem,
        requested_item: CwItem,
    ) -> ResidentTradePreference {
        let Some(resident) = self.actor_by_id(resident_id) else {
            return ResidentTradePreference {
                accepted: false,
                score: i16::MIN,
                willingness: "refuses",
                reason: "That avatar is not here.".to_string(),
            };
        };
        let offered_score = self.resident_item_offer_score(resident, offered_item);
        let requested_score = self.resident_item_keep_score(resident, requested_item);
        let score = offered_score.saturating_sub(requested_score);
        let resident_name = self
            .actor_name(resident.id)
            .unwrap_or_else(|| format!("Avatar {}", resident.id));
        let offered_name = self
            .item_name(offered_item.id)
            .unwrap_or_else(|| format!("Item {}", offered_item.id));
        let requested_name = self
            .item_name(requested_item.id)
            .unwrap_or_else(|| format!("Item {}", requested_item.id));
        let wants_offered = self.resident_item_is_sought(resident, offered_item.id);
        let protects_requested = self.resident_item_is_attached(resident.id, requested_item);
        let accepted = offered_score > requested_score;
        let (willingness, reason) = if accepted && wants_offered {
            let offered_reason = self
                .resident_item_request_reason(resident, offered_item.id)
                .trim_end_matches('.')
                .to_string();
            (
                "eager",
                format!("{offered_reason}; {resident_name} will trade {requested_name}."),
            )
        } else if accepted {
            (
                "willing",
                format!("{resident_name} values {offered_name} more than {requested_name}."),
            )
        } else if protects_requested {
            (
                "refuses",
                self.resident_item_attachment_reason(resident, requested_item.id),
            )
        } else {
            (
                "refuses",
                format!("{resident_name} is not seeking {offered_name} right now."),
            )
        };
        ResidentTradePreference {
            accepted,
            score,
            willingness,
            reason,
        }
    }

    fn actor_base_carrying_capacity_tenths(&self, actor_id: u64) -> Option<u32> {
        self.actor_by_id(actor_id)
            .map(actor_base_carrying_capacity_tenths)
    }

    fn actor_inventory_count(&self, actor_id: u64) -> usize {
        self.world.items[..self.world.item_count]
            .iter()
            .filter(|item| item.holder_actor_id == actor_id)
            .count()
    }

    fn actor_carried_weight_tenths(&self, actor_id: u64) -> u32 {
        self.actor_held_items(actor_id)
            .into_iter()
            .map(|item| u32::from(effective_item_weight_tenths(item)))
            .sum()
    }

    fn actor_container_capacity_tenths(&self, actor_id: u64) -> u32 {
        self.actor_held_items(actor_id)
            .into_iter()
            .filter(|item| {
                item.role == CW_ITEM_ROLE_CONTAINER
                    && item.zone == CW_CARD_ZONE_EQUIPPED
                    && item.container_item_id == 0
            })
            .map(|item| u32::from(item.container_capacity_tenths))
            .sum()
    }

    fn actor_carrying_capacity_tenths(&self, actor_id: u64) -> Option<u32> {
        self.actor_base_carrying_capacity_tenths(actor_id)
            .map(|base| base + self.actor_container_capacity_tenths(actor_id))
    }

    fn actor_inventory_full(&self, actor_id: u64) -> bool {
        self.actor_carrying_capacity_tenths(actor_id)
            .map(|capacity| self.actor_carried_weight_tenths(actor_id) >= capacity)
            .unwrap_or(false)
    }

    fn actor_can_receive_item(&self, target: CwActor, offered_item_id: u64) -> bool {
        let Some(item) = self.item_by_id(offered_item_id) else {
            return false;
        };
        self.actor_can_exchange_items(target.id, None, item)
    }

    fn actor_can_exchange_items(
        &self,
        actor_id: u64,
        removed_item: Option<CwItem>,
        added_item: CwItem,
    ) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        let mut weight = 0u32;
        let mut capacity = actor_base_carrying_capacity_tenths(actor);
        for item in self.actor_held_items(actor_id) {
            if removed_item.is_some_and(|removed| removed.id == item.id) {
                continue;
            }
            weight += u32::from(effective_item_weight_tenths(item));
            if item.role == CW_ITEM_ROLE_CONTAINER
                && item.zone == CW_CARD_ZONE_EQUIPPED
                && item.container_item_id == 0
            {
                capacity += u32::from(item.container_capacity_tenths);
            }
        }
        weight += u32::from(effective_item_weight_tenths(added_item));
        weight <= capacity
    }

    fn resident_player_gift_return_item(
        &self,
        target: CwActor,
        offered_item: CwItem,
    ) -> Option<CwItem> {
        if !Self::actor_is_active_avatar(target)
            || self.actor_can_receive_item(target, offered_item.id)
        {
            return None;
        }
        let return_item = self.resident_exchange_item_for_pickup(target, Some(offered_item))?;
        (self.resident_item_offer_score(target, offered_item)
            > self.resident_item_keep_score(target, return_item))
        .then_some(return_item)
    }

    fn resident_can_accept_player_gift(&self, target: CwActor, offered_item: CwItem) -> bool {
        self.actor_can_receive_item(target, offered_item.id)
            || self
                .resident_player_gift_return_item(target, offered_item)
                .is_some()
    }

    fn exit_direction(&self, from_location_id: u64, to_location_id: u64) -> Option<String> {
        if let Some(direction) = active_content()
            .exits
            .iter()
            .find(|exit| {
                exit.from_location_id == from_location_id && exit.to_location_id == to_location_id
            })
            .and_then(|exit| exit.direction.as_deref())
            .and_then(canonical_direction)
        {
            return Some(direction.to_string());
        }
        active_content()
            .hidden_exits
            .iter()
            .filter(|hidden_exit| self.hidden_exit_discovered(hidden_exit))
            .find_map(|hidden_exit| {
                if hidden_exit.from_location_id == from_location_id
                    && hidden_exit.to_location_id == to_location_id
                {
                    canonical_direction(&hidden_exit.direction)
                } else if hidden_exit.to_location_id == from_location_id
                    && hidden_exit.from_location_id == to_location_id
                {
                    canonical_direction(&hidden_exit.return_direction)
                } else {
                    None
                }
            })
            .map(ToString::to_string)
    }

    fn next_unlocked_step_toward(
        &self,
        from_location_id: u64,
        target_location_id: u64,
    ) -> Option<u64> {
        if from_location_id == target_location_id {
            return None;
        }

        let mut visited = BTreeSet::from([from_location_id]);
        let mut queue = VecDeque::from([(from_location_id, None)]);
        while let Some((location_id, first_step)) = queue.pop_front() {
            let exits: Vec<_> = self.world.exits[..self.world.exit_count]
                .iter()
                .copied()
                .filter(|exit| exit.from_location_id == location_id)
                .filter(|exit| exit.flags & CW_EXIT_LOCKED == 0)
                .collect();
            for exit in exits {
                if !visited.insert(exit.to_location_id) {
                    continue;
                }
                let next_step = first_step.unwrap_or(exit.to_location_id);
                if exit.to_location_id == target_location_id {
                    return Some(next_step);
                }
                queue.push_back((exit.to_location_id, Some(next_step)));
            }
        }
        None
    }

    fn listen_reward_claimable(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        if actor.status != CW_ACTOR_ACTIVE {
            return false;
        }
        let claim_key = ability_check_success_claim_key(
            actor_id,
            actor.location_id,
            LISTEN_ABILITY,
            i16::try_from(LISTEN_DC).unwrap_or(i16::MAX),
        );
        !self.orb_reward_claims.contains(&claim_key)
    }

    fn listen_attempted_here(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        if actor.status != CW_ACTOR_ACTIVE {
            return false;
        }
        self.listen_attempt_claimed_at(actor_id, actor.location_id)
    }

    fn first_tale_trace_event_seq(&self, actor_id: u64) -> Option<u64> {
        let prefix = first_tale_trace_claim_prefix(actor_id);
        self.rpg_claims
            .iter()
            .filter_map(|claim| claim.strip_prefix(&prefix)?.parse::<u64>().ok())
            .min()
    }

    fn listen_cost_orbs(&self, _actor_id: u64) -> i32 {
        0
    }

    fn listen_affordable(&self, actor_id: u64) -> bool {
        let cost = self.listen_cost_orbs(actor_id);
        cost <= 0 || self.orb_balance(actor_id) >= cost
    }

    fn listen_offerable(&self, actor_id: u64) -> bool {
        if self.unbanked_visit_ledger_count(actor_id) > 0 {
            return true;
        }
        self.listen_affordable(actor_id)
            && (!self.listen_attempted_here(actor_id)
                || self
                    .actor_by_id(actor_id)
                    .is_some_and(|actor| self.location_is_frontier(actor.location_id)))
    }

    fn rest_available(&self, actor_id: u64) -> bool {
        self.tired_tag_active(actor_id)
            && self.frontier_travel_since_rest_count(actor_id)
                >= self.frontier_travel_since_rest_required(actor_id)
    }

    fn frontier_travel_since_rest_required(&self, actor_id: u64) -> usize {
        self.actor_by_id(actor_id)
            .map(|actor| usize::from(actor.stats.level.clamp(1, 4)))
            .unwrap_or(1)
    }

    fn frontier_travel_since_rest_count(&self, actor_id: u64) -> usize {
        let prefix = frontier_travel_since_rest_tag_prefix(actor_id);
        self.tags
            .values()
            .filter(|tag| {
                tag.active
                    && tag.scope == "actor"
                    && tag.scope_id == actor_id
                    && tag.id.starts_with(&prefix)
            })
            .count()
    }

    fn frontier_travel_since_rest_tag_ids(&self, actor_id: u64) -> Vec<String> {
        let prefix = frontier_travel_since_rest_tag_prefix(actor_id);
        let mut tag_ids: Vec<_> = self
            .tags
            .values()
            .filter(|tag| {
                tag.active
                    && tag.scope == "actor"
                    && tag.scope_id == actor_id
                    && tag.id.starts_with(&prefix)
            })
            .map(|tag| tag.id.clone())
            .collect();
        tag_ids.sort();
        tag_ids
    }

    fn tired_tag_active(&self, actor_id: u64) -> bool {
        self.tags
            .get(&tired_tag_id(actor_id))
            .map(|tag| tag.active)
            .unwrap_or(false)
    }

    fn trained_since_rest_tag_active(&self, actor_id: u64) -> bool {
        self.tags
            .get(&trained_since_rest_tag_id(actor_id))
            .map(|tag| tag.active)
            .unwrap_or(false)
    }

    fn clock_is_frontier(&self, clock_id: &str) -> bool {
        self.clocks
            .get(clock_id)
            .map(|clock| clock_zone(clock) == ZONE_FRONTIER)
            .unwrap_or(false)
    }

    fn location_is_frontier(&self, location_id: u64) -> bool {
        if let Some(pathway) = self.generated_pathway_for_location(location_id) {
            return !pathway.familiar;
        }
        self.room_sheets
            .get(&location_id)
            .map(|sheet| room_sheet_zone(sheet) == ZONE_FRONTIER)
            .unwrap_or_else(|| default_zone_for_scope("room", location_id) == ZONE_FRONTIER)
    }

    fn hearth_tonic_warmth_guards_rest(&self, location_id: u64) -> bool {
        location_id == MOONLIT_TRAIL_LOCATION_ID
            && self
                .tags
                .get(HEARTH_TONIC_WARMTH_TAG_ID)
                .map(|tag| tag.active)
                .unwrap_or(false)
    }

    fn prepare_available(&self, actor_id: u64) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        let Some(clock_id) = self.active_progress_clock_id_for_location(actor.location_id) else {
            return false;
        };
        actor.status == CW_ACTOR_ACTIVE
            && !self.prepared_tag_active(actor_id, actor.location_id)
            && !self.project_preparation_spent_for_clock(actor_id, actor.location_id, &clock_id)
            && !self.tired_tag_active(actor_id)
    }

    fn work_available(&self, actor_id: u64) -> bool {
        self.job_contribution_intent(actor_id, "work", None, None, None)
            .is_some()
    }

    fn help_available(&self, actor_id: u64) -> bool {
        self.job_contribution_intent(actor_id, "help", None, None, None)
            .is_some()
    }

    fn active_progress_clock_id_for_location(&self, location_id: u64) -> Option<String> {
        let has_location_job = self.location_has_job(location_id);
        self.active_job_for_location(location_id)
            .map(|job| job.progress_clock_id.clone())
            .or_else(|| {
                if has_location_job {
                    return None;
                }
                listen_progress_clock_id_for_location(location_id).and_then(|clock_id| {
                    self.clocks
                        .get(clock_id)
                        .filter(|clock| clock.filled < clock.segments)
                        .map(|_| clock_id.to_string())
                })
            })
    }

    fn location_has_job(&self, location_id: u64) -> bool {
        self.jobs
            .values()
            .any(|job| job.delivery.is_none() && job.location_ids.contains(&location_id))
    }

    fn active_job_for_location(&self, location_id: u64) -> Option<&JobState> {
        self.jobs
            .values()
            .filter(|job| job.delivery.is_none())
            .filter(|job| job.location_ids.contains(&location_id))
            .filter(|job| self.job_status(job) == "active")
            .filter_map(|job| {
                self.clocks
                    .get(&job.progress_clock_id)
                    .map(|clock| (job, clock))
            })
            .filter(|(_, clock)| clock.filled < clock.segments)
            .min_by(|(left, _), (right, _)| self.compare_job_presentation(left, right))
            .map(|(job, _)| job)
    }

    fn compare_job_presentation(&self, left: &JobState, right: &JobState) -> std::cmp::Ordering {
        let presentation_for = |job: &JobState| {
            self.clocks
                .get(&job.progress_clock_id)
                .map(|clock| &clock.presentation)
        };
        let left_presentation = presentation_for(left);
        let right_presentation = presentation_for(right);
        right_presentation
            .map(|presentation| presentation.priority)
            .unwrap_or_default()
            .cmp(
                &left_presentation
                    .map(|presentation| presentation.priority)
                    .unwrap_or_default(),
            )
            .then_with(|| {
                clock_attention_rank(
                    right_presentation
                        .map(|presentation| presentation.attention.as_str())
                        .unwrap_or_default(),
                )
                .cmp(&clock_attention_rank(
                    left_presentation
                        .map(|presentation| presentation.attention.as_str())
                        .unwrap_or_default(),
                ))
            })
            .then_with(|| left.id.cmp(&right.id))
    }

    fn contribution_strategy_binding_is_active(&self, strategy: &JobContributionStrategy) -> bool {
        let Some(binding) = resolved_action_binding(&strategy.action_kind) else {
            return false;
        };
        let pack_matches = active_content()
            .manifest
            .packs
            .iter()
            .any(|pack| pack.id == strategy.pack_id && pack.version == strategy.pack_version);
        strategy.version == JOB_CONTRIBUTION_SCHEMA_VERSION
            && strategy.rules_profile == active_content().manifest.rules_profile
            && strategy.rules_action == binding.rules_action
            && strategy.operation == binding.operation
            && strategy.rules_pack_id == binding.pack_id
            && strategy.rules_pack_version == binding.pack_version
            && pack_matches
    }

    fn contribution_requirement_met(
        &self,
        actor_id: u64,
        requirement: &ContributionRequirement,
    ) -> bool {
        let Some(actor) = self.actor_by_id(actor_id) else {
            return false;
        };
        match requirement {
            ContributionRequirement::AtLocation { location_id } => {
                actor.location_id == *location_id
            }
            ContributionRequirement::HeldItem { item_id } => self
                .item_by_id(*item_id)
                .is_some_and(|item| item.holder_actor_id == actor_id),
            ContributionRequirement::ActiveTag { tag_id } => {
                self.tags.get(tag_id).is_some_and(|tag| tag.active)
            }
            ContributionRequirement::RoomFeature {
                location_id,
                feature_key,
            } => {
                actor.location_id == *location_id
                    && active_content().room_features.iter().any(|feature| {
                        feature.location_id == *location_id && feature.key == *feature_key
                    })
            }
        }
    }

    fn resolve_contribution_target(
        &self,
        actor_id: u64,
        job: &JobState,
        strategy: &JobContributionStrategy,
        target_hint: Option<(&str, &str)>,
    ) -> Option<ResolvedContributionTarget> {
        let actor = self.actor_by_id(actor_id)?;
        let descriptor = &strategy.target;
        if let Some(id) = descriptor.id.as_deref() {
            if target_hint
                .is_some_and(|(kind, target_id)| kind != descriptor.kind || target_id != id)
            {
                return None;
            }
            let available = match descriptor.kind.as_str() {
                "job" => id == job.id,
                "room" => id
                    .parse::<u64>()
                    .ok()
                    .is_some_and(|location_id| actor.location_id == location_id),
                "feature" => job.location_ids.contains(&actor.location_id),
                "actor" => id.parse::<u64>().ok().is_some_and(|target_actor_id| {
                    target_actor_id != actor_id
                        && self.actor_by_id(target_actor_id).is_some_and(|target| {
                            Self::actor_is_active_avatar(target)
                                && target.location_id == actor.location_id
                                && self.actor_visible_in_projection(target, Some(actor_id), None)
                                && !self.actors_blocked(actor_id, target_actor_id)
                        })
                }),
                "item" => id.parse::<u64>().ok().is_some_and(|item_id| {
                    self.item_by_id(item_id).is_some_and(|item| {
                        item.holder_actor_id == actor_id || item.location_id == actor.location_id
                    })
                }),
                _ => false,
            };
            return available.then(|| ResolvedContributionTarget {
                kind: descriptor.kind.clone(),
                id: id.to_string(),
                label: descriptor.label.clone(),
            });
        }

        match descriptor.predicate.as_deref()? {
            "current_room" => Some(ResolvedContributionTarget {
                kind: "room".to_string(),
                id: actor.location_id.to_string(),
                label: self
                    .location_name(actor.location_id)
                    .unwrap_or_else(|| descriptor.label.clone()),
            }),
            "job_participant_here" => job
                .participant_ids
                .iter()
                .filter_map(|target_actor_id| self.actor_by_id(*target_actor_id))
                .find(|target| {
                    target.id != actor_id
                        && Self::actor_is_active_avatar(*target)
                        && target.location_id == actor.location_id
                        && self.actor_visible_in_projection(*target, Some(actor_id), None)
                        && !self.actors_blocked(actor_id, target.id)
                })
                .map(|target| ResolvedContributionTarget {
                    kind: "actor".to_string(),
                    id: target.id.to_string(),
                    label: self
                        .actor_name(target.id)
                        .unwrap_or_else(|| descriptor.label.clone()),
                }),
            "co_present_avatar" => self.world.actors[..self.world.actor_count]
                .iter()
                .find(|target| {
                    target.id != actor_id
                        && Self::actor_is_active_avatar(**target)
                        && target.location_id == actor.location_id
                        && self.actor_visible_in_projection(**target, Some(actor_id), None)
                        && !self.actors_blocked(actor_id, target.id)
                })
                .map(|target| ResolvedContributionTarget {
                    kind: "actor".to_string(),
                    id: target.id.to_string(),
                    label: self
                        .actor_name(target.id)
                        .unwrap_or_else(|| descriptor.label.clone()),
                }),
            _ => None,
        }
    }

    fn job_contribution_intent(
        &self,
        actor_id: u64,
        action_kind: &str,
        requested_job_id: Option<&str>,
        requested_strategy_id: Option<&str>,
        target_hint: Option<(&str, &str)>,
    ) -> Option<JobContributionIntent> {
        let actor = self.actor_by_id(actor_id)?;
        if !Self::actor_is_active_avatar(actor) || self.tired_tag_active(actor_id) {
            return None;
        }
        self.jobs
            .values()
            .filter(|job| job.delivery.is_none())
            .filter(|job| {
                requested_job_id.is_none_or(|requested| job.id == requested)
                    && job.location_ids.contains(&actor.location_id)
                    && self.job_status(job) == "active"
                    && job.contribution_schema_version == JOB_CONTRIBUTION_SCHEMA_VERSION
            })
            .flat_map(|job| {
                job.contribution_strategies
                    .iter()
                    .map(move |strategy| (job, strategy))
            })
            .filter(|(_, strategy)| {
                strategy.action_kind == action_kind
                    && requested_strategy_id.is_none_or(|requested| strategy.id == requested)
                    && self.contribution_strategy_binding_is_active(strategy)
                    && strategy
                        .requirements
                        .iter()
                        .all(|requirement| self.contribution_requirement_met(actor_id, requirement))
                    && self
                        .clocks
                        .get(&strategy.clock_id)
                        .is_some_and(|clock| clock.filled < clock.segments)
            })
            .filter_map(|(job, strategy)| {
                let target =
                    self.resolve_contribution_target(actor_id, job, strategy, target_hint)?;
                let claim_key = Self::contribution_claim_key(actor_id, &job.id, strategy, &target);
                if claim_key
                    .as_ref()
                    .is_some_and(|claim_key| self.rpg_claims.contains(claim_key))
                {
                    return None;
                }
                Some(JobContributionIntent {
                    job_id: job.id.clone(),
                    strategy: strategy.clone(),
                    target,
                })
            })
            .min_by(|left, right| {
                let job_order = self
                    .jobs
                    .get(&left.job_id)
                    .zip(self.jobs.get(&right.job_id))
                    .map(|(left, right)| self.compare_job_presentation(left, right))
                    .unwrap_or_else(|| left.job_id.cmp(&right.job_id));
                job_order
                    .then_with(|| left.strategy.id.cmp(&right.strategy.id))
                    .then_with(|| left.target.id.cmp(&right.target.id))
            })
    }

    fn contribution_progress_amount(&self, actor_id: u64, intent: &JobContributionIntent) -> u8 {
        let prepared = self
            .actor_by_id(actor_id)
            .is_some_and(|actor| self.prepared_tag_active(actor_id, actor.location_id));
        intent
            .strategy
            .baseline_progress
            .saturating_add(intent.strategy.success_progress)
            .saturating_add(if prepared {
                intent.strategy.prepared_bonus_progress
            } else {
                0
            })
    }

    fn ensure_delivery_need_job(
        &mut self,
        pulse: &WorldPulse,
        source_location_id: Option<u64>,
        caused_by_event_seq: Option<u64>,
    ) -> Option<EventView> {
        let trade = &pulse.trade;
        let existing_id = self.jobs.values().find_map(|job| {
            let delivery = job.delivery.as_ref()?;
            (self.job_status(job) == "active"
                && delivery.origin_location_id == trade.from_location_id
                && delivery.destination_location_id == trade.to_location_id
                && delivery.resource == trade.resource)
                .then(|| job.id.clone())
        });
        if let Some(job_id) = existing_id {
            let destination_name = self
                .location_name(trade.to_location_id)
                .unwrap_or_else(|| format!("Location {}", trade.to_location_id));
            if let Some(job) = self.jobs.get_mut(&job_id) {
                if let Some(delivery) = job.delivery.as_mut() {
                    delivery.updated_world_tick = pulse.source_world_tick;
                }
                job.stakes = format!(
                    "{destination_name} needs a represented item, carried there by an actor."
                );
            }
            return None;
        }

        let origin_name = self
            .location_name(trade.from_location_id)
            .unwrap_or_else(|| format!("Location {}", trade.from_location_id));
        let destination_name = self
            .location_name(trade.to_location_id)
            .unwrap_or_else(|| format!("Location {}", trade.to_location_id));
        let resource_key = trade
            .resource
            .chars()
            .map(|character| {
                if character.is_ascii_alphanumeric() {
                    character.to_ascii_lowercase()
                } else {
                    '-'
                }
            })
            .collect::<String>();
        let job_id = format!(
            "world-delivery:{}:{}:{}:{}",
            trade.from_location_id, trade.to_location_id, resource_key, pulse.pulse_index
        );
        let progress_clock_id = format!("{job_id}:arrived");
        let danger_clock_id = format!("{job_id}:waiting");
        let zone = if self.location_is_frontier(trade.to_location_id) {
            ZONE_FRONTIER
        } else {
            ZONE_SANCTUARY
        };
        self.clocks.insert(
            progress_clock_id.clone(),
            ClockState {
                id: progress_clock_id.clone(),
                scope: "room".to_string(),
                scope_id: trade.to_location_id,
                kind: "progress".to_string(),
                zone: zone.to_string(),
                label: format!("Bring {} from {origin_name}", trade.resource),
                segments: 1,
                filled: 0,
                visible_to_players: true,
                status: "active".to_string(),
                presentation: ClockPresentation {
                    version: CLOCK_PRESENTATION_SCHEMA_VERSION,
                    question: format!(
                        "Can someone carry {} from {origin_name} to {destination_name}?",
                        trade.resource
                    ),
                    rhythm: "immediate".to_string(),
                    attention: "local".to_string(),
                    priority: 70,
                    situation: format!(
                        "{destination_name} is waiting for a represented {} to arrive.",
                        trade.resource
                    ),
                    stakes: format!(
                        "The need is answered only when an avatar physically carries the item from {origin_name}."
                    ),
                    outcome: format!(
                        "{destination_name} receives the {} and remembers who delivered it.",
                        trade.resource
                    ),
                    completion_memory: format!(
                        "A traveler carried {} from {origin_name} to {destination_name}.",
                        trade.resource
                    ),
                },
                on_fill: Vec::new(),
                recent_contributions: Vec::new(),
                completion: None,
                created_event_seq: None,
                updated_event_seq: None,
            },
        );
        self.clocks.insert(
            danger_clock_id.clone(),
            ClockState {
                id: danger_clock_id.clone(),
                scope: "room".to_string(),
                scope_id: trade.to_location_id,
                kind: "danger".to_string(),
                zone: zone.to_string(),
                label: format!("{destination_name} goes without"),
                segments: 4,
                filled: 0,
                visible_to_players: true,
                status: "active".to_string(),
                presentation: ClockPresentation {
                    version: CLOCK_PRESENTATION_SCHEMA_VERSION,
                    question: format!(
                        "How long can {destination_name} wait for {}?",
                        trade.resource
                    ),
                    rhythm: "multi_session".to_string(),
                    attention: "background".to_string(),
                    priority: 15,
                    situation: format!(
                        "{destination_name} is beginning to feel the missing {}.",
                        trade.resource
                    ),
                    stakes: format!(
                        "If nobody makes the journey, {destination_name} continues to go without."
                    ),
                    outcome: format!(
                        "{destination_name} has gone too long without {}.",
                        trade.resource
                    ),
                    completion_memory: format!(
                        "{destination_name} waited in vain for {} from {origin_name}.",
                        trade.resource
                    ),
                },
                on_fill: Vec::new(),
                recent_contributions: Vec::new(),
                completion: None,
                created_event_seq: None,
                updated_event_seq: None,
            },
        );
        self.jobs.insert(
            job_id.clone(),
            JobState {
                pack_id: String::new(),
                id: job_id,
                premise: format!(
                    "Bring a physical {} from {origin_name} to {destination_name}.",
                    trade.resource
                ),
                stakes: format!(
                    "{destination_name} needs an actor to carry a represented item there."
                ),
                location_ids: vec![trade.from_location_id, trade.to_location_id],
                participant_ids: Vec::new(),
                progress_clock_id,
                danger_clock_id,
                status: "active".to_string(),
                reward: JobReward::Label(format!(
                    "{destination_name} remembers who answered the need."
                )),
                consequence: format!("{destination_name} continues to go without."),
                memory_summary: format!(
                    "A physical delivery connected {origin_name} and {destination_name}."
                ),
                action_copy: JobActionCopy {
                    label: format!("Carry {} to {destination_name}", trade.resource),
                    summary: format!(
                        "Pick up a physical item at {origin_name}, travel with it, then give, drop, or use it at {destination_name}."
                    ),
                },
                contribution_schema_version: 0,
                contribution_strategies: Vec::new(),
                narrated_thresholds: Vec::new(),
                delivery: Some(DeliveryJobSpec {
                    resource: trade.resource.clone(),
                    origin_location_id: trade.from_location_id,
                    destination_location_id: trade.to_location_id,
                    created_world_tick: pulse.source_world_tick,
                    updated_world_tick: pulse.source_world_tick,
                }),
            },
        );
        Some(self.append_world_history_event(
            "world.delivery.needed",
            trade.from_location_id,
            Some(trade.to_location_id),
            format!(
                "{destination_name} is running short of {}. A physical item picked up at {origin_name} can be carried there.",
                trade.resource
            ),
            pulse.source_world_tick,
            source_location_id,
            caused_by_event_seq,
        ))
    }

    fn world_stakes_consent(
        &self,
        actor_id: u64,
        events: &[EventView],
    ) -> Option<(WorldStakesConsent, u64, String)> {
        events
            .iter()
            .filter(|event| event.success && event.actor_id == Some(actor_id))
            .filter_map(|event| {
                let (location_id, danger_clock_id) = match event.type_name.as_str() {
                    "clock.updated" if event.clock_kind.as_deref() == Some("progress") => {
                        let location_id = event.location_id?;
                        let progress_clock_id = event.clock_id.as_deref()?;
                        let danger_clock_id = self
                            .jobs
                            .values()
                            .filter(|job| job.location_ids.contains(&location_id))
                            .filter(|job| job.progress_clock_id == progress_clock_id)
                            .filter(|job| self.job_status(job) == "active")
                            .find_map(|job| {
                                self.clocks
                                    .get(&job.danger_clock_id)
                                    .filter(|clock| clock.filled < clock.segments)
                                    .map(|_| job.danger_clock_id.clone())
                            })?;
                        (location_id, danger_clock_id)
                    }
                    "combat.attack.attempt" | "combat.dodge" => {
                        let location_id = event.location_id?;
                        let danger_clock_id = event
                            .content_id
                            .and_then(|encounter_id| self.combat_job_id_for_encounter(encounter_id))
                            .and_then(|job_id| self.jobs.get(&job_id))
                            .filter(|job| self.job_status(job) == "active")
                            .map(|job| job.danger_clock_id.clone())
                            .or_else(|| self.active_danger_clock_id_for_location(location_id))?;
                        (location_id, danger_clock_id)
                    }
                    "combat.defend" => {
                        let location_id = event.location_id?;
                        (
                            location_id,
                            self.active_danger_clock_id_for_location(location_id)?,
                        )
                    }
                    "actor.moved" => {
                        let location_id = event.destination_location_id?;
                        (
                            location_id,
                            self.active_danger_clock_id_for_location(location_id)?,
                        )
                    }
                    _ => return None,
                };
                self.location_is_frontier(location_id).then_some((
                    WorldStakesConsent { location_id },
                    event.seq,
                    danger_clock_id,
                ))
            })
            .next_back()
    }

    fn apply_played_time_world_simulation(
        &mut self,
        action: &CwAction,
        entropy: u64,
        source_events: &[EventView],
        allow_public_beat: bool,
    ) -> Vec<EventView> {
        let Some(actor) = self.actor_by_id(action.actor_id) else {
            return Vec::new();
        };
        if !Self::actor_is_active_avatar(actor)
            || !source_events
                .iter()
                .any(|event| event.actor_id == Some(action.actor_id))
        {
            return Vec::new();
        }

        let source_location_id = Some(actor.location_id);
        let caused_by_event_seq = source_events
            .iter()
            .filter(|event| event.actor_id == Some(action.actor_id))
            .map(|event| event.seq)
            .max();
        let stakes_consent = self.world_stakes_consent(action.actor_id, source_events);
        let seed = self.world_simulation_seed();
        let Some(pulse) = self.world_simulation.advance_if_due(
            &seed,
            self.world.tick,
            entropy,
            source_location_id,
            stakes_consent.as_ref().map(|(consent, _, _)| *consent),
        ) else {
            return Vec::new();
        };

        let mut events = Vec::new();
        if allow_public_beat {
            match pulse.public_beat {
                Some(PulseBeatKind::Weather) if pulse.weather.notable => {
                    let weather_location = self
                        .location_name(pulse.weather.location_id)
                        .unwrap_or_else(|| format!("Location {}", pulse.weather.location_id));
                    events.push(self.append_world_history_event(
                        "world.weather.shifted",
                        pulse.weather.location_id,
                        None,
                        format!(
                            "At {weather_location}, {} gives way to {}. Travelers there may need to change their plans.",
                            pulse.weather.before, pulse.weather.after
                        ),
                        pulse.source_world_tick,
                        source_location_id,
                        caused_by_event_seq,
                    ));
                }
                Some(PulseBeatKind::DeliveryNeed) if pulse.trade.needs_delivery => {
                    if let Some(event) = self.ensure_delivery_need_job(
                        &pulse,
                        source_location_id,
                        caused_by_event_seq,
                    ) {
                        events.push(event);
                    }
                }
                Some(PulseBeatKind::Faction) => {
                    if let Some(faction) = pulse.faction.as_ref() {
                        let from_name = self
                            .location_name(faction.from_location_id)
                            .unwrap_or_else(|| format!("Location {}", faction.from_location_id));
                        let to_name = self
                            .location_name(faction.to_location_id)
                            .unwrap_or_else(|| format!("Location {}", faction.to_location_id));
                        events.push(self.append_world_history_event(
                            "world.faction.influence_shifted",
                            faction.from_location_id,
                            Some(faction.to_location_id),
                            format!(
                                "{} carries its promises from {from_name} toward {to_name}. People at {to_name} now have a new claim to answer.",
                                faction.faction_name
                            ),
                            pulse.source_world_tick,
                            source_location_id,
                            caused_by_event_seq,
                        ));
                    }
                }
                Some(PulseBeatKind::Conflict)
                    if pulse.conflict.after != pulse.conflict.before
                        || pulse.conflict.escalated =>
                {
                    let conflict_location = self
                        .location_name(pulse.conflict.location_id)
                        .unwrap_or_else(|| format!("Location {}", pulse.conflict.location_id));
                    let event_type = if pulse.conflict.escalated {
                        "world.conflict.escalated"
                    } else if pulse.conflict.after > pulse.conflict.before {
                        "world.conflict.pressure_grew"
                    } else {
                        "world.conflict.pressure_eased"
                    };
                    let conflict_cause = if pulse.conflict.class == PulseEffectClass::Stakes {
                        stakes_consent.as_ref().map(|(_, event_seq, _)| *event_seq)
                    } else {
                        caused_by_event_seq
                    };
                    events.push(self.append_world_history_event(
                        event_type,
                        pulse.conflict.location_id,
                        None,
                        if pulse.conflict.escalated {
                            format!(
                                "In {conflict_location}, old strains meet and the air hardens."
                            )
                        } else if pulse.conflict.after > pulse.conflict.before {
                            format!(
                                "The air in {conflict_location} draws taut around an unanswered strain."
                            )
                        } else {
                            format!("Whatever pressed on {conflict_location} loosens, for now.")
                        },
                        pulse.source_world_tick,
                        source_location_id,
                        conflict_cause,
                    ));
                }
                _ => {}
            }
        }

        if pulse.conflict.escalated && pulse.conflict.class == PulseEffectClass::Stakes {
            if let Some((consent, stakes_event_seq, clock_id)) = stakes_consent
                .as_ref()
                .filter(|(consent, _, _)| consent.location_id == pulse.conflict.location_id)
            {
                let mut clock_events =
                    self.advance_clock(clock_id, 1, action.actor_id, "consented_world_stakes");
                for event in &mut clock_events {
                    event.caused_by_event_seq = Some(*stakes_event_seq);
                    event.source_world_tick = Some(pulse.source_world_tick);
                    event.source_location_id = Some(consent.location_id);
                    if let Some(logged) = self
                        .event_log
                        .iter_mut()
                        .rev()
                        .find(|logged| logged.seq == event.seq)
                    {
                        *logged = event.clone();
                    }
                }
                events.extend(clock_events);
            }
        }
        events
    }

    fn apply_player_tick_frontier_resets(
        &mut self,
        action: &CwAction,
        events: &[EventView],
    ) -> Vec<EventView> {
        if !self
            .actor_by_id(action.actor_id)
            .is_some_and(Self::actor_is_active_avatar)
        {
            return Vec::new();
        }
        if !events
            .iter()
            .any(|event| event.success && event.actor_id == Some(action.actor_id))
        {
            return Vec::new();
        }

        let mut frontier_locations = BTreeSet::new();
        if let Some(actor) = self.actor_by_id(action.actor_id) {
            if self.location_is_frontier(actor.location_id) {
                frontier_locations.insert(actor.location_id);
            }
        }
        for event in events {
            for location_id in [event.location_id, event.destination_location_id]
                .into_iter()
                .flatten()
            {
                if self.location_is_frontier(location_id) {
                    frontier_locations.insert(location_id);
                }
            }
        }

        let mut projected = Vec::new();
        for location_id in frontier_locations {
            projected
                .extend(self.reset_ready_frontier_jobs_at_location(action.actor_id, location_id));
        }
        projected
    }

    fn reset_ready_frontier_jobs_at_location(
        &mut self,
        actor_id: u64,
        location_id: u64,
    ) -> Vec<EventView> {
        if !self.location_is_frontier(location_id) {
            return Vec::new();
        }
        let current_seq = self.world.next_event_seq;
        let job_ids: Vec<String> = self
            .jobs
            .values()
            .filter(|job| job.location_ids.contains(&location_id))
            .filter(|job| self.frontier_job_ready_for_reset(job, current_seq))
            .map(|job| job.id.clone())
            .collect();

        let mut events = Vec::new();
        for job_id in job_ids {
            events.extend(self.reset_frontier_job(actor_id, &job_id, location_id));
        }
        events
    }

    fn frontier_job_ready_for_reset(&self, job: &JobState, current_seq: u64) -> bool {
        if !job
            .location_ids
            .iter()
            .any(|id| self.location_is_frontier(*id))
        {
            return false;
        }
        if self.job_status(job) == "active" {
            return false;
        }
        self.latest_job_resolution_seq(job)
            .map(|seq| current_seq.saturating_sub(seq) >= ENCOUNTER_RESET_PLAYER_TICKS)
            .unwrap_or(false)
    }

    fn latest_job_resolution_seq(&self, job: &JobState) -> Option<u64> {
        let progress_segments = self
            .clocks
            .get(&job.progress_clock_id)
            .map(|clock| clock.segments);
        let danger_segments = self
            .clocks
            .get(&job.danger_clock_id)
            .map(|clock| clock.segments);
        self.event_log.iter().rev().find_map(|event| {
            if event.type_name == "job.updated" {
                if let Some(content) = event.content.as_deref() {
                    let completed = format!("{}:completed:", job.id);
                    let failed = format!("{}:failed:", job.id);
                    if content.starts_with(&completed) || content.starts_with(&failed) {
                        return Some(event.seq);
                    }
                }
            }
            if event.type_name == "clock.updated" {
                if event.clock_id.as_deref() == Some(job.progress_clock_id.as_str())
                    && progress_segments
                        .zip(event.clock_filled)
                        .map(|(segments, filled)| filled >= segments)
                        .unwrap_or(false)
                {
                    return Some(event.seq);
                }
                if event.clock_id.as_deref() == Some(job.danger_clock_id.as_str())
                    && danger_segments
                        .zip(event.clock_filled)
                        .map(|(segments, filled)| filled >= segments)
                        .unwrap_or(false)
                {
                    return Some(event.seq);
                }
            }
            None
        })
    }

    fn reset_frontier_job(
        &mut self,
        actor_id: u64,
        job_id: &str,
        location_id: u64,
    ) -> Vec<EventView> {
        let Some(job) = self.jobs.get(job_id).cloned() else {
            return Vec::new();
        };
        let mut events = Vec::new();
        events.extend(self.reset_clock_to_zero(
            &job.progress_clock_id,
            actor_id,
            "encounter_reset",
        ));
        events.extend(self.reset_clock_to_zero(&job.danger_clock_id, actor_id, "encounter_reset"));

        for tag_id in self.resolved_tag_ids_for_job(&job) {
            if let Some(event) = self.clear_rpg_tag(&tag_id, actor_id, "encounter_reset") {
                events.push(event);
            }
        }

        if let Some(job_state) = self.jobs.get_mut(job_id) {
            job_state.status = "active".to_string();
            let job_state = job_state.clone();
            events.push(self.append_job_event(
                "job.updated",
                actor_id,
                &job_state,
                "encounter_reset",
            ));
        }

        let mut target_actor_id = None;
        let mut current_hp = None;
        let actor_count = self.world.actor_count;
        for participant_id in &job.participant_ids {
            if let Some(actor) = self.world.actors[..actor_count]
                .iter_mut()
                .find(|actor| actor.id == *participant_id)
            {
                actor.status = CW_ACTOR_ACTIVE;
                actor.damage = 0;
                target_actor_id.get_or_insert(actor.id);
                current_hp.get_or_insert(actor.stats.hp_base);
            }
        }

        events.push(self.append_encounter_reset_event(
            actor_id,
            &job,
            target_actor_id,
            current_hp,
            location_id,
        ));
        events
    }

    fn reset_clock_to_zero(
        &mut self,
        clock_id: &str,
        actor_id: u64,
        reason: &str,
    ) -> Vec<EventView> {
        let Some(clock) = self.clocks.get_mut(clock_id) else {
            return Vec::new();
        };
        let before = clock.filled;
        if before == 0 && clock.status == "active" {
            return Vec::new();
        }
        clock.filled = 0;
        clock.status = "active".to_string();
        clock.updated_event_seq = Some(self.world.next_event_seq);
        let clock = clock.clone();
        vec![self.append_clock_event(
            "clock.updated",
            actor_id,
            &clock,
            -i16::from(before),
            reason,
        )]
    }

    fn resolved_tag_ids_for_job(&self, job: &JobState) -> Vec<String> {
        let mut tag_ids = BTreeSet::new();
        for clock_id in [&job.progress_clock_id, &job.danger_clock_id] {
            if let Some(clock) = self.clocks.get(clock_id) {
                for effect in &clock.on_fill {
                    if let EffectDescriptor::SetTag { tag_id, .. } = effect {
                        tag_ids.insert(tag_id.clone());
                    }
                }
            }
        }
        for tag in self.tags.values() {
            if !tag.active {
                continue;
            }
            if tag.scope == "room"
                && job.location_ids.contains(&tag.scope_id)
                && (tag.label == job.reward.label() || tag.label == job.consequence)
            {
                tag_ids.insert(tag.id.clone());
            }
        }
        tag_ids.into_iter().collect()
    }

    fn append_encounter_reset_event(
        &mut self,
        actor_id: u64,
        job: &JobState,
        target_actor_id: Option<u64>,
        current_hp: Option<i16>,
        location_id: u64,
    ) -> EventView {
        let event = EventView {
            world_id: official_world_id(),
            world_epoch: official_world_epoch(),
            seq: self.world.next_event_seq,
            type_name: "encounter.reset".to_string(),
            success: true,
            reason: 0,
            actor_id: Some(actor_id),
            actor_name: self.actor_name(actor_id),
            target_actor_id,
            target_actor_name: target_actor_id.and_then(|id| self.actor_name(id)),
            location_id: Some(location_id),
            location_name: self.location_name(location_id),
            destination_location_id: None,
            destination_location_name: None,
            content_id: None,
            content: Some(format!("{}:player_tick", job.id)),
            item_id: None,
            item_name: None,
            target_item_id: None,
            target_item_name: None,
            raw_roll: None,
            modifier: None,
            total: None,
            dc: None,
            damage: None,
            current_hp,
            clock_id: None,
            clock_scope: None,
            clock_scope_id: None,
            clock_kind: None,
            clock_label: None,
            clock_filled: None,
            clock_segments: None,
            clock_delta: None,
            tag_id: None,
            tag_scope: None,
            tag_scope_id: None,
            tag_kind: None,
            tag_label: None,
            caused_by_event_seq: None,
            source_world_tick: None,
            observed_through_seq: None,
            source_location_id: None,
            content_context: ContentReferenceContext::default(),
        };
        self.world.next_event_seq += 1;
        self.push_projected_event(event.clone());
        event
    }

