async fn ability_check(
    ConnectInfo(client_addr): ConnectInfo<SocketAddr>,
    State(state): State<AppState>,
    Json(payload): Json<CheckRequest>,
) -> Json<ActionResponse> {
    if !allow_actor_mutation(
        &state,
        client_addr,
        payload.actor_id,
        "action-actor",
        GENERAL_ACTION_LIMIT,
    ) {
        return action_rate_limited_response();
    }
    if ability_from_string(&payload.ability) != LISTEN_ABILITY
        || payload.dc.is_some_and(|dc| dc != LISTEN_DC)
    {
        return Json(ActionResponse {
            ok: false,
            status: 400,
            events: Vec::new(),
        });
    }
    let contribution_mutations = {
        let runtime = state.inner.lock().await;
        runtime
            .job_contribution_intent(payload.actor_id, "check", None, None, None)
            .map(|intent| ProjectionMutation::ResolveJobContribution { intent })
            .into_iter()
            .collect()
    };
    apply_and_broadcast_with_mutations(
        state,
        CwAction {
            kind: CW_ACTION_RULES_SEARCH,
            actor_id: payload.actor_id,
            ability: LISTEN_ABILITY,
            dc: LISTEN_DC,
            ..CwAction::default()
        },
        payload.actor_session.as_deref(),
        contribution_mutations,
    )
    .await
}

