fn generated_pathway_contribution_strategies(
    job_id: &str,
    progress_clock_id: &str,
) -> Vec<JobContributionStrategy> {
    let pack_id = "cosyworld.core";
    let pack_version = active_content()
        .manifest
        .packs
        .iter()
        .find(|pack| pack.id == pack_id)
        .map(|pack| pack.version.clone())
        .unwrap_or_default();
    ["work", "help"]
        .into_iter()
        .filter_map(|action_kind| {
            let binding = resolved_action_binding(action_kind)?;
            let (target, baseline_progress, prepared_bonus_progress, strategy_label) =
                if action_kind == "work" {
                    (
                        ContributionTargetDescriptor {
                            kind: "job".to_string(),
                            id: Some(job_id.to_string()),
                            predicate: None,
                            label: "the newly found way".to_string(),
                        },
                        2,
                        1,
                        "Mark and steady the route",
                    )
                } else {
                    (
                        ContributionTargetDescriptor {
                            kind: "actor".to_string(),
                            id: None,
                            predicate: Some("co_present_avatar".to_string()),
                            label: "a nearby traveler".to_string(),
                        },
                        1,
                        1,
                        "Work beside another traveler",
                    )
                };
            Some(JobContributionStrategy {
                version: JOB_CONTRIBUTION_SCHEMA_VERSION,
                id: format!("pathway-{action_kind}"),
                action_kind: action_kind.to_string(),
                rules_action: binding.rules_action,
                operation: binding.operation,
                target,
                requirements: Vec::new(),
                resolution: ContributionResolutionPolicy::Certain,
                clock_id: progress_clock_id.to_string(),
                baseline_progress,
                success_progress: 0,
                prepared_bonus_progress,
                on_success: Vec::new(),
                on_failure: Vec::new(),
                claim_policy: ContributionClaimPolicy::Repeatable,
                strategy_label: strategy_label.to_string(),
                narration_key: format!("pathway.familiarity.{action_kind}"),
                rules_profile: active_content().manifest.rules_profile.clone(),
                rules_pack_id: binding.pack_id,
                rules_pack_version: binding.pack_version,
                pack_id: pack_id.to_string(),
                pack_version: pack_version.clone(),
            })
        })
        .collect()
}

fn pathway_edge_key(left: u64, right: u64) -> String {
    let (origin, destination) = canonical_pathway_anchors(left, right);
    format!("{origin}:{destination}")
}

fn parse_pathway_edge_key(value: &str) -> Option<(u64, u64)> {
    let (left, right) = value.split_once(':')?;
    Some((left.parse().ok()?, right.parse().ok()?))
}

fn stable_pathway_hash(value: &str) -> u64 {
    value.bytes().fold(0xcbf2_9ce4_8422_2325, |hash, byte| {
        (hash ^ u64::from(byte)).wrapping_mul(0x1000_0000_01b3)
    })
}

fn materialized_item_id(receipt_id: &str) -> u64 {
    const MATERIALIZED_ITEM_ID_BASE: u64 = 8_000_000_000;
    const MATERIALIZED_ITEM_ID_RANGE: u64 = 1_000_000_000;
    MATERIALIZED_ITEM_ID_BASE + stable_pathway_hash(receipt_id) % MATERIALIZED_ITEM_ID_RANGE
}

fn generated_pathway_location_id(pathway_id: &str, index: usize) -> u64 {
    GENERATED_PATHWAY_LOCATION_ID_BASE
        + (stable_pathway_hash(pathway_id) % 10_000) * 16
        + index as u64
}

fn interpolated_pathway_terrain(
    origin: &LocationMeta,
    destination: &LocationMeta,
    index: usize,
    count: usize,
) -> Vec<String> {
    let origin_terrain = if origin.terrain.is_empty() {
        vec![origin.biome.clone()]
    } else {
        origin.terrain.clone()
    };
    let destination_terrain = if destination.terrain.is_empty() {
        vec![destination.biome.clone()]
    } else {
        destination.terrain.clone()
    };
    let progress = index + 1;
    let mut terrain = Vec::new();
    if progress * 2 <= count + 1 {
        terrain.extend(origin_terrain.into_iter().take(2));
        terrain.extend(destination_terrain.into_iter().take(1));
    } else {
        terrain.extend(destination_terrain.into_iter().take(2));
        terrain.extend(origin_terrain.into_iter().take(1));
    }
    terrain.retain(|value| !value.trim().is_empty());
    terrain.sort();
    terrain.dedup();
    terrain
}

fn normalize_skill_id(value: &str) -> Option<&'static str> {
    let normalized = compact_whitespace(&value.replace(['_', '-'], " ")).to_ascii_lowercase();
    match normalized.as_str() {
        "lift" | "lifting" | "might" | "str" | "strength" => Some("lifting"),
        "nimble" | "nimble hands" | "hands" | "dex" | "dexterity" => Some("nimble_hands"),
        "steady" | "steadiness" | "endurance" | "con" | "constitution" => Some("steadiness"),
        "lore" | "lorecraft" | "study" | "int" | "intelligence" => Some("lorecraft"),
        "listen" | "listening" | "notice" | "noticing" | "wis" | "wisdom" => Some("listening"),
        "kind" | "kindness" | "heart" | "cha" | "charisma" | "charm" => Some("kindness"),
        _ => None,
    }
}

