fn record_economy_reconciliation(
    path: &Path,
    external: &OwnershipIndex,
    source: &str,
) -> io::Result<EconomyReconciliationView> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let mut box_owners = BTreeMap::<String, BTreeSet<String>>::new();
    let mut pack_owners = BTreeMap::<String, BTreeSet<String>>::new();
    for wallet in &external.wallets {
        for asset_id in &wallet.box_ids {
            box_owners
                .entry(asset_id.clone())
                .or_default()
                .insert(wallet.wallet_address.clone());
        }
        for asset_id in &wallet.pack_ids {
            pack_owners
                .entry(asset_id.clone())
                .or_default()
                .insert(wallet.wallet_address.clone());
        }
    }

    let local_receipts = {
        let mut stmt = conn
            .prepare(
                "SELECT box_asset_address, owner_wallet_address
                 FROM wooden_box_receipts",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map([], |row| {
                Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?))
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<BTreeMap<_, _>, _>>()
            .map_err(sqlite_error)?
    };
    let local_openings = {
        let mut stmt = conn
            .prepare(
                "SELECT pack_id, owner_wallet_address
                 FROM avatar_pack_openings",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map([], |row| {
                Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?))
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<BTreeMap<_, _>, _>>()
            .map_err(sqlite_error)?
    };

    let mut anomalies = Vec::new();
    for (asset_id, owners) in &box_owners {
        if owners.len() > 1 {
            anomalies.push(EconomyReconciliationAnomaly {
                kind: "box_multiple_external_owners".to_string(),
                asset_id: asset_id.clone(),
                external_wallet_address: owners.iter().cloned().collect::<Vec<_>>().join(","),
                local_wallet_address: None,
                detail: "The trusted snapshot reports one Box under multiple wallets.".to_string(),
            });
        }
        if let Some(local_owner) = local_receipts.get(asset_id) {
            anomalies.push(EconomyReconciliationAnomaly {
                kind: "burned_box_reported_active".to_string(),
                asset_id: asset_id.clone(),
                external_wallet_address: owners.iter().next().cloned().unwrap_or_default(),
                local_wallet_address: Some(local_owner.clone()),
                detail:
                    "A Box with a durable burn receipt is still active in the trusted snapshot."
                        .to_string(),
            });
        }
    }
    for (asset_id, owners) in &pack_owners {
        if owners.len() > 1 {
            anomalies.push(EconomyReconciliationAnomaly {
                kind: "pack_multiple_external_owners".to_string(),
                asset_id: asset_id.clone(),
                external_wallet_address: owners.iter().cloned().collect::<Vec<_>>().join(","),
                local_wallet_address: None,
                detail: "The trusted snapshot reports one unopened avatar bundle under multiple wallets."
                    .to_string(),
            });
        }
        if let Some(local_owner) = local_openings.get(asset_id) {
            anomalies.push(EconomyReconciliationAnomaly {
                kind: "opened_pack_reported_unopened".to_string(),
                asset_id: asset_id.clone(),
                external_wallet_address: owners.iter().next().cloned().unwrap_or_default(),
                local_wallet_address: Some(local_owner.clone()),
                detail:
                    "An avatar bundle with a durable opening record is still unopened in the trusted snapshot."
                        .to_string(),
            });
        }
    }
    anomalies.sort_by(|a, b| a.kind.cmp(&b.kind).then(a.asset_id.cmp(&b.asset_id)));

    let source = match source {
        "startup" => "startup",
        _ => "refresh",
    };
    let created_at_ms = now_millis();
    let status = if anomalies.is_empty() {
        "clear"
    } else {
        "open"
    };
    let anomalies_json = serde_json::to_string(&anomalies).map_err(io::Error::other)?;
    conn.execute(
        "INSERT INTO economy_reconciliation_runs
         (source, wallet_count, active_box_count, unopened_pack_count,
          anomaly_count, anomalies_json, status, created_at_ms)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)",
        params![
            source,
            external.wallet_count() as i64,
            box_owners.len() as i64,
            pack_owners.len() as i64,
            anomalies.len() as i64,
            anomalies_json,
            status,
            created_at_ms as i64,
        ],
    )
    .map_err(sqlite_error)?;

    Ok(EconomyReconciliationView {
        run_id: conn.last_insert_rowid().max(0) as u64,
        source: source.to_string(),
        wallet_count: external.wallet_count(),
        active_box_count: box_owners.len(),
        unopened_pack_count: pack_owners.len(),
        anomaly_count: anomalies.len(),
        anomalies,
        status: status.to_string(),
        created_at_ms,
        resolved_at_ms: None,
        resolved_by: None,
        resolution_note: None,
    })
}

fn economy_reconciliation_from_row(
    row: &rusqlite::Row<'_>,
) -> rusqlite::Result<EconomyReconciliationView> {
    let anomalies_json: String = row.get(6)?;
    let anomalies = serde_json::from_str(&anomalies_json).unwrap_or_default();
    Ok(EconomyReconciliationView {
        run_id: row.get::<_, i64>(0)?.max(0) as u64,
        source: row.get(1)?,
        wallet_count: row.get::<_, i64>(2)?.max(0) as usize,
        active_box_count: row.get::<_, i64>(3)?.max(0) as usize,
        unopened_pack_count: row.get::<_, i64>(4)?.max(0) as usize,
        anomaly_count: row.get::<_, i64>(5)?.max(0) as usize,
        anomalies,
        status: row.get(7)?,
        created_at_ms: row.get::<_, i64>(8)?.max(0) as u64,
        resolved_at_ms: row
            .get::<_, Option<i64>>(9)?
            .map(|value| value.max(0) as u64),
        resolved_by: row.get(10)?,
        resolution_note: row.get(11)?,
    })
}

fn economy_reconciliation_by_id(
    conn: &Connection,
    run_id: u64,
) -> io::Result<Option<EconomyReconciliationView>> {
    conn.query_row(
        "SELECT run_id, source, wallet_count, active_box_count,
                unopened_pack_count, anomaly_count, anomalies_json, status, created_at_ms,
                resolved_at_ms, resolved_by, resolution_note
         FROM economy_reconciliation_runs
         WHERE run_id = ?1",
        params![run_id as i64],
        economy_reconciliation_from_row,
    )
    .optional()
    .map_err(sqlite_error)
}

fn resolve_economy_reconciliation(
    path: &Path,
    run_id: u64,
    moderator: &str,
    note: Option<&str>,
) -> io::Result<Option<EconomyReconciliationView>> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let Some(current) = economy_reconciliation_by_id(&conn, run_id)? else {
        return Ok(None);
    };
    if current.status != "open" || current.anomaly_count == 0 {
        return Ok(Some(current));
    }
    conn.execute(
        "UPDATE economy_reconciliation_runs
         SET status = 'resolved', resolved_at_ms = ?2, resolved_by = ?3, resolution_note = ?4
         WHERE run_id = ?1 AND status = 'open' AND anomaly_count > 0",
        params![run_id as i64, now_millis() as i64, moderator, note],
    )
    .map_err(sqlite_error)?;
    economy_reconciliation_by_id(&conn, run_id)
}

fn read_economy_audit(path: &Path, limit: usize) -> io::Result<ModerationEconomyResponse> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let limit = limit.min(MAX_EVENT_STORE_SCAN) as i64;

    let orb_ledger = {
        let mut stmt = conn
            .prepare(
                "SELECT idempotency_key, actor_id, delta, reason, source_event_id,
                        balance_after, metadata_json, created_at_ms
                 FROM orb_ledger
                 ORDER BY created_at_ms DESC, idempotency_key DESC
                 LIMIT ?1",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map(params![limit], |row| {
                Ok(OrbLedgerAuditView {
                    idempotency_key: row.get(0)?,
                    actor_id: row.get::<_, i64>(1)?.max(0) as u64,
                    delta: row.get::<_, i64>(2)? as i32,
                    reason: row.get(3)?,
                    source_event_id: row.get::<_, Option<i64>>(4)?.map(|seq| seq.max(0) as u64),
                    balance_after: row.get::<_, i64>(5)? as i32,
                    metadata_json: row.get(6)?,
                    created_at_ms: row.get::<_, i64>(7)?.max(0) as u64,
                })
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<Vec<_>, _>>().map_err(sqlite_error)?
    };

    let ai_usage_ledger = {
        let mut stmt = conn
            .prepare(
                "SELECT idempotency_key, actor_id, feature, payer_mode, provider,
                        model, status, source_event_id, orb_delta, error_code,
                        latency_ms, created_at_ms
                 FROM ai_usage_ledger
                 ORDER BY created_at_ms DESC, idempotency_key DESC
                 LIMIT ?1",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map(params![limit], |row| {
                Ok(AiUsageLedgerAuditView {
                    idempotency_key: row.get(0)?,
                    actor_id: row
                        .get::<_, Option<i64>>(1)?
                        .map(|actor_id| actor_id.max(0) as u64),
                    feature: row.get(2)?,
                    payer_mode: row.get(3)?,
                    provider: row.get(4)?,
                    model: row.get(5)?,
                    status: row.get(6)?,
                    source_event_id: row.get::<_, Option<i64>>(7)?.map(|seq| seq.max(0) as u64),
                    orb_delta: row.get::<_, i64>(8)? as i32,
                    error_code: row.get(9)?,
                    latency_ms: row.get::<_, i64>(10)?.max(0) as u64,
                    created_at_ms: row.get::<_, i64>(11)?.max(0) as u64,
                })
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<Vec<_>, _>>().map_err(sqlite_error)?
    };

    let wooden_box_receipts = {
        let mut stmt = conn
            .prepare(
                "SELECT box_asset_address, owner_wallet_address, status, burn_signature,
                        verification_status, pack_id, created_at_ms, updated_at_ms
                 FROM wooden_box_receipts
                 ORDER BY updated_at_ms DESC, box_asset_address DESC
                 LIMIT ?1",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map(params![limit], |row| {
                Ok(WoodenBoxReceiptView {
                    box_asset_address: row.get(0)?,
                    owner_wallet_address: row.get(1)?,
                    status: row.get(2)?,
                    burn_signature: row.get(3)?,
                    verification_status: row.get(4)?,
                    pack_id: row.get(5)?,
                    created_at_ms: row.get::<_, i64>(6)?.max(0) as u64,
                    updated_at_ms: row.get::<_, i64>(7)?.max(0) as u64,
                })
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<Vec<_>, _>>().map_err(sqlite_error)?
    };

    let avatar_pack_openings = {
        let mut stmt = conn
            .prepare(
                "SELECT idempotency_key, owner_wallet_address, box_asset_address, pack_id,
                        reveal_seed, catalog_hash, card_ids_json, provenance_json, created_at_ms
                 FROM avatar_pack_openings
                 ORDER BY created_at_ms DESC, pack_id DESC
                 LIMIT ?1",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map(params![limit], |row| {
                let card_ids_json: String = row.get(6)?;
                let card_ids = serde_json::from_str(&card_ids_json).unwrap_or_default();
                Ok(AvatarPackOpeningView {
                    idempotency_key: row.get(0)?,
                    owner_wallet_address: row.get(1)?,
                    box_asset_address: row.get(2)?,
                    pack_id: row.get(3)?,
                    reveal_seed: row.get(4)?,
                    catalog_hash: row.get(5)?,
                    card_ids,
                    provenance_json: row.get(7)?,
                    created_at_ms: row.get::<_, i64>(8)?.max(0) as u64,
                })
            })
            .map_err(sqlite_error)?;
        rows.collect::<Result<Vec<_>, _>>().map_err(sqlite_error)?
    };

    let economy_reconciliations = {
        let mut stmt = conn
            .prepare(
                "SELECT run_id, source, wallet_count, active_box_count,
                        unopened_pack_count, anomaly_count, anomalies_json, status, created_at_ms,
                        resolved_at_ms, resolved_by, resolution_note
                 FROM economy_reconciliation_runs
                 ORDER BY created_at_ms DESC, run_id DESC
                 LIMIT ?1",
            )
            .map_err(sqlite_error)?;
        let rows = stmt
            .query_map(params![limit], economy_reconciliation_from_row)
            .map_err(sqlite_error)?;
        rows.collect::<Result<Vec<_>, _>>().map_err(sqlite_error)?
    };

    Ok(ModerationEconomyResponse {
        ok: true,
        status: 200,
        orb_ledger,
        ai_usage_ledger,
        wooden_box_receipts,
        avatar_pack_openings,
        economy_reconciliations,
        error: None,
    })
}

fn open_event_store(path: &Path) -> io::Result<Connection> {
    let conn = Connection::open(path).map_err(sqlite_error)?;
    conn.busy_timeout(Duration::from_secs(5))
        .map_err(sqlite_error)?;
    Ok(conn)
}

fn canonical_command_receipt_key(world_id: &str, intent_id: &str) -> String {
    format!("{world_id}\u{0}{intent_id}")
}

fn read_canonical_command_response(
    path: &Path,
    world_id: &str,
    intent_id: &str,
) -> io::Result<Option<StoredCommandResponse>> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    conn.query_row(
        "SELECT request_hash, response_json
         FROM canonical_command_receipts
         WHERE world_id = ?1 AND intent_id = ?2 AND finalized = 1",
        params![world_id, intent_id],
        |row| {
            Ok(StoredCommandResponse {
                request_hash: row.get(0)?,
                response_json: row.get(1)?,
            })
        },
    )
    .optional()
    .map_err(sqlite_error)
}

fn write_canonical_command_response(
    path: &Path,
    world_id: &str,
    intent_id: &str,
    stored: &StoredCommandResponse,
) -> io::Result<bool> {
    init_event_store(path)?;
    let conn = open_event_store(path)?;
    let inserted = conn
        .execute(
            "INSERT OR IGNORE INTO canonical_command_receipts
             (world_id, intent_id, request_hash, response_json, created_at_ms)
             VALUES (?1, ?2, ?3, ?4, ?5)",
            params![
                world_id,
                intent_id,
                stored.request_hash,
                stored.response_json,
                now_millis() as i64
            ],
        )
        .map_err(sqlite_error)?;
    Ok(inserted == 1)
}

fn snapshot_error(message: impl Into<String>) -> io::Error {
    io::Error::new(io::ErrorKind::InvalidData, message.into())
}

fn sqlite_error(error: rusqlite::Error) -> io::Error {
    io::Error::other(error)
}

fn event_store_error_code(error: &io::Error) -> &'static str {
    match error.kind() {
        io::ErrorKind::NotFound => "not_found",
        io::ErrorKind::PermissionDenied => "permission_denied",
        io::ErrorKind::OutOfMemory => "out_of_memory",
        io::ErrorKind::InvalidData => "invalid_data",
        io::ErrorKind::StorageFull => "storage_full",
        io::ErrorKind::ReadOnlyFilesystem => "read_only_filesystem",
        _ => "sqlite_io_error",
    }
}

fn event_type_name(type_: u8) -> String {
    unsafe {
        let ptr = cw_event_type_name(type_);
        if ptr.is_null() {
            "unknown".to_string()
        } else {
            CStr::from_ptr(ptr).to_string_lossy().into_owned()
        }
    }
}

fn ability_from_string(value: &str) -> u8 {
    match value.to_lowercase().as_str() {
        "str" | "strength" => 0,
        "dex" | "dexterity" => 1,
        "con" | "constitution" => 2,
        "int" | "intelligence" => 3,
        "wis" | "wisdom" => 4,
        "cha" | "charisma" => 5,
        _ => 5,
    }
}

fn actor_kind(kind: u8) -> &'static str {
    match kind {
        CW_ACTOR_HUMAN => "human",
        CW_ACTOR_NPC => "npc",
        _ => "unknown",
    }
}

fn actor_status(status: u8) -> &'static str {
    match status {
        CW_ACTOR_ACTIVE => "active",
        CW_ACTOR_KNOCKED_OUT => "knocked_out",
        CW_ACTOR_DEAD => "dead",
        _ => "unknown",
    }
}

fn item_kind(kind: u8) -> &'static str {
    match kind {
        CW_ITEM_POTION => "potion",
        CW_ITEM_EVOLUTION => "evolution",
        CW_ITEM_KEEPSAKE => "keepsake",
        _ => "unknown",
    }
}

fn item_role(role: u8) -> &'static str {
    match role {
        CW_ITEM_ROLE_CONSUMABLE => "consumable",
        CW_ITEM_ROLE_WEAPON => "weapon",
        CW_ITEM_ROLE_SKILL_CHARM => "skill_charm",
        CW_ITEM_ROLE_SPELL => "spell",
        CW_ITEM_ROLE_CONTAINER => "container",
        CW_ITEM_ROLE_TOOL => "tool",
        CW_ITEM_ROLE_RELIC => "relic",
        _ => "generic",
    }
}

fn card_zone(zone: u8, holder_actor_id: u64, location_id: u64) -> &'static str {
    match zone {
        CW_CARD_ZONE_WORLD => "world",
        CW_CARD_ZONE_CARRIED => "carried",
        CW_CARD_ZONE_EQUIPPED => "equipped",
        CW_CARD_ZONE_SPELL_DECK => "spell_deck",
        CW_CARD_ZONE_EXHAUSTED => "exhausted",
        CW_CARD_ZONE_CONTAINED => "contained",
        CW_CARD_ZONE_ESCROW => "escrow",
        _ if holder_actor_id != 0 => "carried",
        _ if location_id != 0 => "world",
        _ => "collection",
    }
}

fn item_size(size_class: u8) -> &'static str {
    match size_class {
        CW_ITEM_SIZE_TINY => "tiny",
        CW_ITEM_SIZE_MEDIUM => "medium",
        CW_ITEM_SIZE_LARGE => "large",
        _ => "small",
    }
}

fn effective_item_weight_tenths(item: CwItem) -> u16 {
    if item.weight_tenths == 0 {
        CW_ITEM_DEFAULT_WEIGHT_TENTHS
    } else {
        item.weight_tenths
    }
}

fn actor_base_carrying_capacity_tenths(actor: CwActor) -> u32 {
    u32::from(actor.stats.strength.max(1) as u8) * 150
}

fn opt_id(value: u64) -> Option<u64> {
    if value == 0 {
        None
    } else {
        Some(value)
    }
}

fn opt_i16(value: i16) -> Option<i16> {
    if value == 0 {
        None
    } else {
        Some(value)
    }
}

fn event_current_hp(event: &CwEvent) -> Option<i16> {
    match event.type_ {
        CW_EVENT_ACTOR_CREATED
        | CW_EVENT_ITEM_USED
        | CW_EVENT_COMBAT_ATTACK_HIT
        | CW_EVENT_COMBAT_KNOCKOUT
        | CW_EVENT_AVATAR_EVOLVED => Some(event.current_hp),
        _ => opt_i16(event.current_hp),
    }
}

fn now_seed() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_nanos() as u64)
        .unwrap_or(0xC051_0002)
}

fn now_millis() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis() as u64)
        .unwrap_or(0)
}

