    fn create_test_human(runtime: &mut RuntimeWorld, actor_id: u64, location_id: u64, name: &str) {
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = actor_id;
        create.location_id = location_id;
        let mut record = JournalRecord::new(create, 70_000 + actor_id);
        record.actor_meta_upserts.insert(
            actor_id,
            ActorMeta {
                name: name.to_string(),
                speech_mode: "prose".to_string(),
                title: "Relay Test Avatar".to_string(),
                description: "A test avatar controlled through the narrative move relay."
                    .to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);
    }

    fn quest_projection_signature(runtime: &RuntimeWorld) -> serde_json::Value {
        serde_json::json!({
            "progress": runtime.clocks.get(MOONLIT_PROGRESS_CLOCK_ID),
            "danger": runtime.clocks.get(MOONLIT_DANGER_CLOCK_ID),
            "claims": runtime.rpg_claims,
            "events": runtime.event_log.iter().filter(|event| matches!(
                event.type_name.as_str(),
                "ability_check.rolled"
                    | "job.contribution.resolved"
                    | "clock.updated"
                    | "clock.threshold"
                    | "tag.applied"
                    | "tag.cleared"
                    | "job.updated"
            )).collect::<Vec<_>>(),
        })
    }

    fn arrange_test_transfer_items(runtime: &mut RuntimeWorld) {
        for item in &mut runtime.world.items[..runtime.world.item_count] {
            match item.id {
                STORY_BUTTON_ITEM_ID => {
                    item.location_id = 0;
                    item.holder_actor_id = 5000;
                }
                DEWBRIGHT_BUTTON_ITEM_ID => {
                    item.location_id = 0;
                    item.holder_actor_id = 5001;
                }
                _ => {}
            }
        }
    }

    #[tokio::test]
    async fn direct_avatar_gift_requires_consent_and_acceptance_is_idempotent() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(&mut runtime, 5000, COSY_COTTAGE_LOCATION_ID, "Gift Giver");
        create_test_human(
            &mut runtime,
            5001,
            COSY_COTTAGE_LOCATION_ID,
            "Gift Receiver",
        );
        arrange_test_transfer_items(&mut runtime);
        let state = test_app_state(runtime, None);
        let giver_session = issue_actor_session(&state, 5000).0;
        let receiver_session = issue_actor_session(&state, 5001).0;

        let offered = give_item(
            ConnectInfo("127.0.0.1:46001".parse().unwrap()),
            State(state.clone()),
            Json(ItemRequest {
                actor_id: 5000,
                actor_session: Some(giver_session),
                item_id: STORY_BUTTON_ITEM_ID,
                target_item_id: None,
                target_actor_id: Some(5001),
            }),
        )
        .await
        .0;
        assert!(offered.ok);
        assert!(offered
            .events
            .iter()
            .any(|event| event.type_name == "transfer.offer_created"));
        let offer_id = {
            let runtime = state.inner.lock().await;
            assert_eq!(
                runtime
                    .item_by_id(STORY_BUTTON_ITEM_ID)
                    .unwrap()
                    .holder_actor_id,
                5000
            );
            runtime.transfer_offers.keys().next().unwrap().clone()
        };

        let accepted = resolve_transfer_offer(
            ConnectInfo("127.0.0.1:46002".parse().unwrap()),
            State(state.clone()),
            Json(TransferOfferActionRequest {
                actor_id: 5001,
                actor_session: Some(receiver_session.clone()),
                offer_id: offer_id.clone(),
                decision: "accept".to_string(),
            }),
        )
        .await
        .0;
        assert!(accepted.ok);
        assert!(accepted
            .events
            .iter()
            .any(|event| event.type_name == "item.given"));
        {
            let runtime = state.inner.lock().await;
            assert_eq!(
                runtime
                    .item_by_id(STORY_BUTTON_ITEM_ID)
                    .unwrap()
                    .holder_actor_id,
                5001
            );
            assert_eq!(
                runtime.transfer_offers[&offer_id].status,
                TransferOfferStatus::Accepted
            );
        }

        let retry = resolve_transfer_offer(
            ConnectInfo("127.0.0.1:46002".parse().unwrap()),
            State(state.clone()),
            Json(TransferOfferActionRequest {
                actor_id: 5001,
                actor_session: Some(receiver_session.clone()),
                offer_id: offer_id.clone(),
                decision: "accept".to_string(),
            }),
        )
        .await
        .0;
        assert!(retry.ok);
        assert!(retry
            .events
            .iter()
            .any(|event| event.type_name == "transfer.offer_unchanged"));
        assert_eq!(
            state
                .inner
                .lock()
                .await
                .item_by_id(STORY_BUTTON_ITEM_ID)
                .unwrap()
                .holder_actor_id,
            5001
        );
    }

    #[tokio::test]
    async fn explicit_item_request_auto_accepts_that_gift_exactly_once() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Requested Giver",
        );
        create_test_human(
            &mut runtime,
            5001,
            COSY_COTTAGE_LOCATION_ID,
            "Requesting Receiver",
        );
        arrange_test_transfer_items(&mut runtime);
        let state = test_app_state(runtime, None);
        let giver_session = issue_actor_session(&state, 5000).0;
        let receiver_session = issue_actor_session(&state, 5001).0;
        let request = request_gift_auto_accept(
            ConnectInfo("127.0.0.1:46009".parse().unwrap()),
            State(state.clone()),
            Json(GiftAutoAcceptRequest {
                actor_id: 5001,
                actor_session: Some(receiver_session),
                offered_by_actor_id: 5000,
                item_id: STORY_BUTTON_ITEM_ID,
            }),
        )
        .await
        .0;
        assert!(request.ok);

        let accepted = give_item(
            ConnectInfo("127.0.0.1:46010".parse().unwrap()),
            State(state.clone()),
            Json(ItemRequest {
                actor_id: 5000,
                actor_session: Some(giver_session.clone()),
                item_id: STORY_BUTTON_ITEM_ID,
                target_item_id: None,
                target_actor_id: Some(5001),
            }),
        )
        .await
        .0;
        assert!(accepted.ok);
        assert!(accepted
            .events
            .iter()
            .any(|event| event.type_name == "item.given"));
        {
            let mut runtime = state.inner.lock().await;
            assert!(runtime
                .gift_auto_accepts
                .values()
                .all(|policy| policy.consumed));
            runtime
                .world
                .items
                .iter_mut()
                .find(|item| item.id == STORY_BUTTON_ITEM_ID)
                .unwrap()
                .holder_actor_id = 5000;
        }

        let second = give_item(
            ConnectInfo("127.0.0.1:46010".parse().unwrap()),
            State(state.clone()),
            Json(ItemRequest {
                actor_id: 5000,
                actor_session: Some(giver_session),
                item_id: STORY_BUTTON_ITEM_ID,
                target_item_id: None,
                target_actor_id: Some(5001),
            }),
        )
        .await
        .0;
        assert!(second.ok);
        assert!(second
            .events
            .iter()
            .any(|event| event.type_name == "transfer.offer_created"));
        assert_eq!(
            state
                .inner
                .lock()
                .await
                .item_by_id(STORY_BUTTON_ITEM_ID)
                .unwrap()
                .holder_actor_id,
            5000
        );
    }

