    #[tokio::test]
    async fn canonical_journal_commits_privacy_safe_story_metrics_atomically() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-story-journal-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(&mut runtime, 5000, COSY_COTTAGE_LOCATION_ID, "Private Name");
        let state = test_app_state(runtime, Some(path.clone()));
        let _ = issue_actor_session(&state, 5000);

        let events = {
            let mut runtime = state.inner.lock().await;
            let content_id = runtime.next_content_id;
            runtime.next_content_id = runtime.next_content_id.saturating_add(1);
            let mut record = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_SAY,
                    actor_id: 5000,
                    content_id,
                    ..CwAction::default()
                },
                runtime.next_seed_value(),
            );
            record
                .content_upserts
                .insert(content_id, "private prose is not analytics".to_string());
            let (status, events) = commit_journal_record(&state, &mut runtime, record).unwrap();
            assert_eq!(status, CW_OK);
            events
        };
        assert!(events
            .iter()
            .any(|event| event.type_name == "message.created"));

        let conn = open_event_store(&path).unwrap();
        let metrics = read_recent_story_metrics(&conn, 20).unwrap();
        assert!(metrics
            .iter()
            .any(|event| event.event_kind == "meaningful_action_completed"));
        assert!(metrics
            .iter()
            .any(|event| event.event_kind == "public_trace_created"));
        let serialized = serde_json::to_string(&metrics).unwrap();
        assert!(!serialized.contains("Private Name"));
        assert!(!serialized.contains("private prose"));
        assert!(serialized.contains(&story_player_ref(5000)));

        let _ = fs::remove_file(path);
    }

    #[tokio::test]
    async fn hosted_party_entry_is_server_verified_restricted_and_evacuated_on_revocation() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-hosted-party-route-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(&mut runtime, 5000, COSY_COTTAGE_LOCATION_ID, "Host");
        create_test_human(&mut runtime, 5001, COSY_COTTAGE_LOCATION_ID, "Guest");
        let mut state = test_app_state(runtime, Some(path.clone()));
        state.hosted_access_config = Arc::new(HostedAccessConfig {
            grace_ms: 0,
            ..HostedAccessConfig::default()
        });
        let (host_session, _) = issue_actor_session(&state, 5000);
        let (guest_session, _) = issue_actor_session(&state, 5001);
        assert_eq!(
            actor_for_session(&state.actor_sessions, &host_session),
            Some(5000)
        );
        assert_eq!(
            actor_for_session(&state.actor_sessions, &guest_session),
            Some(5001)
        );

        let gate = active_content()
            .access_gates
            .first()
            .expect("official world has a gated location")
            .clone();
        let (host_ref, guest_ref, public_ref, gated_ref) = {
            let runtime = state.inner.lock().await;
            (
                runtime.canonical_ref("actor", 5000).unwrap().to_string(),
                runtime.canonical_ref("actor", 5001).unwrap().to_string(),
                runtime
                    .canonical_ref("location", COSY_COTTAGE_LOCATION_ID)
                    .unwrap()
                    .to_string(),
                runtime
                    .canonical_ref("location", gate.location_id)
                    .unwrap()
                    .to_string(),
            )
        };
        let denied_without_party = {
            let runtime = state.inner.lock().await;
            resolve_movement_access(
                &state,
                &runtime,
                &OwnershipIndex::default(),
                5001,
                gate.location_id,
                &AccessContext::default(),
                now_millis(),
            )
        };
        assert_eq!(denied_without_party.view.mode, "denied");
        record_movement_access_outcome(&state, &denied_without_party, "denied");

        join_hosted_party(
            &path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            "party-hosted-test",
            &host_ref,
            &guest_ref,
            &public_ref,
            now_millis(),
            now_millis() + 60_000,
            &state.hosted_access_config,
        )
        .expect("form party in public room");
        state
            .wallet_actor_links
            .lock()
            .unwrap()
            .insert("wallet-host".to_string(), 5000);
        let ownership = OwnershipIndex::parse(&format!(
            r#"{{"wallets":[{{"walletAddress":"wallet-host","grantIds":["{}"]}}]}}"#,
            gate.required_grant_id
        ));
        *state.ownership_index.write().await = ownership.clone();
        {
            let mut runtime = state.inner.lock().await;
            runtime.place_actor_location(5000, gate.location_id, false);
        }
        let missing_provider = {
            let runtime = state.inner.lock().await;
            resolve_movement_access(
                &state,
                &runtime,
                &OwnershipIndex::default(),
                5001,
                gate.location_id,
                &AccessContext::default(),
                now_millis(),
            )
        };
        assert_eq!(missing_provider.view.mode, "denied");
        assert_eq!(missing_provider.reason_code, "host_entitlement_missing");
        let hosted = {
            let runtime = state.inner.lock().await;
            resolve_movement_access(
                &state,
                &runtime,
                &ownership,
                5001,
                gate.location_id,
                &AccessContext::default(),
                now_millis(),
            )
        };
        assert_eq!(hosted.view.mode, "hosted_guest");
        assert_eq!(hosted.view.party_id.as_deref(), Some("party-hosted-test"));
        {
            let mut runtime = state.inner.lock().await;
            let mut entry = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_NONE,
                    actor_id: 5001,
                    destination_location_id: gate.location_id,
                    ..CwAction::default()
                },
                runtime.next_seed_value(),
            )
            .into_player_card();
            entry.source_location_id = Some(COSY_COTTAGE_LOCATION_ID);
            entry.hosted_access_grant = hosted.hosted_journal_grant();
            entry
                .projection_mutations
                .push(ProjectionMutation::RendezvousActor {
                    actor_id: 5001,
                    location_id: gate.location_id,
                    invite_id: "party-hosted-test".to_string(),
                });
            let (status, events) = commit_journal_record(&state, &mut runtime, entry).unwrap();
            assert_eq!(status, CW_OK);
            assert!(events.iter().any(|event| {
                event.type_name == "actor.moved"
                    && event.actor_id == Some(5001)
                    && event.destination_location_id == Some(gate.location_id)
            }));
            assert!(hosted_guest_action_restricted(
                &state,
                &runtime,
                5001,
                CW_ACTION_PICK_UP_ITEM
            ));
            assert!(!hosted_guest_action_restricted(
                &state,
                &runtime,
                5001,
                CW_ACTION_SAY
            ));
            let mut progression = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_NONE,
                    actor_id: 5001,
                    ..CwAction::default()
                },
                runtime.next_seed_value(),
            )
            .into_player_card();
            progression
                .projection_mutations
                .push(ProjectionMutation::BankVisitLedger {
                    reason: "hosted_access_test".to_string(),
                });
            let (status, events) =
                commit_journal_record(&state, &mut runtime, progression).unwrap();
            assert_eq!(status, CW_ERR_RULE);
            assert!(events.is_empty());
        }
        assert!(actor_has_active_hosted_entry(
            &path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &guest_ref,
            &gated_ref,
        )
        .unwrap());

        *state.ownership_index.write().await = OwnershipIndex::default();
        let events = reconcile_hosted_access(&state).await;
        assert!(events.iter().any(|event| {
            event.type_name == "actor.moved"
                && event.actor_id == Some(5001)
                && event.destination_location_id == Some(COSY_COTTAGE_LOCATION_ID)
        }));
        assert_eq!(
            state
                .inner
                .lock()
                .await
                .actor_by_id(5001)
                .unwrap()
                .location_id,
            COSY_COTTAGE_LOCATION_ID
        );
        let conn = open_event_store(&path).unwrap();
        assert_eq!(
            conn.query_row(
                "SELECT COUNT(*) FROM canonical_hosted_access_events
                 WHERE access_mode = 'hosted_guest' AND outcome = 'allowed'",
                [],
                |row| row.get::<_, i64>(0),
            )
            .unwrap(),
            1
        );
        assert_eq!(
            conn.query_row(
                "SELECT COUNT(*) FROM canonical_hosted_access_events
                 WHERE access_mode = 'hosted_guest' AND outcome = 'evacuated'",
                [],
                |row| row.get::<_, i64>(0),
            )
            .unwrap(),
            1
        );
        let story_metrics = read_recent_story_metrics(&conn, 100).unwrap();
        assert!(story_metrics
            .iter()
            .any(|event| event.event_kind == "entitlement_denial"));
        assert!(story_metrics
            .iter()
            .any(|event| event.event_kind == "hosted_guest_entry"));
        drop(conn);
        fs::remove_file(path).unwrap();
    }

    #[tokio::test]
    async fn world_beat_exposure_endpoint_validates_delivery_and_state_reads_do_not_count() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-world-beat-exposure-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Visible Reader",
        );
        let state = test_app_state(runtime, Some(path.clone()));
        let actor_session = issue_actor_session(&state, 5000).0;
        let (visible_beat, visible_revision) = {
            let mut runtime = state.inner.lock().await;
            let world_tick = runtime.world.tick;
            let event = runtime.append_world_history_event(
                "world.weather.shifted",
                COSY_COTTAGE_LOCATION_ID,
                None,
                "Rain thins into a pearly mist around the cottage windows.".to_string(),
                world_tick,
                Some(COSY_COTTAGE_LOCATION_ID),
                None,
            );
            let revision = runtime.world.next_event_seq.saturating_sub(1);
            (event, revision)
        };

        let seen_count = || {
            let conn = open_event_store(&path).expect("open exposure test store");
            conn.query_row(
                "SELECT COUNT(*) FROM story_metric_events
                 WHERE schema_version = ?1 AND event_kind = 'world_beat_seen'",
                params![STORY_METRICS_SCHEMA_VERSION],
                |row| row.get::<_, i64>(0),
            )
            .unwrap()
        };
        assert_eq!(seen_count(), 0);
        let _ = state_view(
            State(state.clone()),
            Query(StateQuery {
                actor_id: Some(5000),
                actor_session: Some(actor_session.clone()),
                wallet_address: None,
                wallet: None,
                wallet_session: None,
                owned_card_ids: None,
                cards: None,
                openrouter_connected: None,
            }),
        )
        .await;
        assert_eq!(seen_count(), 0, "GET /state must not imply exposure");

        let valid_receipt = WorldBeatExposureReceiptRequest {
            actor_id: 5000,
            actor_session: actor_session.clone(),
            exposure_id: world_beat_exposure_id(visible_beat.seq),
            transport: "browser".to_string(),
            state_revision: visible_revision,
        };
        let first =
            acknowledge_world_beat_exposure(State(state.clone()), Json(valid_receipt.clone()))
                .await
                .0;
        assert!(first.ok && first.recorded);
        let duplicate =
            acknowledge_world_beat_exposure(State(state.clone()), Json(valid_receipt.clone()))
                .await
                .0;
        assert!(duplicate.ok && !duplicate.recorded);
        assert_eq!(seen_count(), 1);

        let unauthorized = acknowledge_world_beat_exposure(
            State(state.clone()),
            Json(WorldBeatExposureReceiptRequest {
                actor_session: "not-a-session".to_string(),
                ..valid_receipt.clone()
            }),
        )
        .await
        .0;
        assert!(!unauthorized.ok && unauthorized.status == 403);

        let (raw_event, inaccessible_event, gap_seq, current_revision) = {
            let mut runtime = state.inner.lock().await;
            let world_tick = runtime.world.tick;
            let raw = runtime.append_world_history_event(
                "world.bootstrapped",
                COSY_COTTAGE_LOCATION_ID,
                None,
                "internal boot state".to_string(),
                world_tick,
                Some(COSY_COTTAGE_LOCATION_ID),
                None,
            );
            let inaccessible = runtime.append_world_history_event(
                "world.trade.flowed",
                11,
                None,
                "A parcel finds its way through Homeroom.".to_string(),
                world_tick,
                Some(11),
                None,
            );
            let gap = runtime.world.next_event_seq;
            runtime.world.next_event_seq = runtime.world.next_event_seq.saturating_add(1);
            let revision = runtime.world.next_event_seq.saturating_sub(1);
            (raw, inaccessible, gap, revision)
        };
        let receipt_for = |seq| WorldBeatExposureReceiptRequest {
            actor_id: 5000,
            actor_session: actor_session.clone(),
            exposure_id: world_beat_exposure_id(seq),
            transport: "browser".to_string(),
            state_revision: current_revision,
        };
        let raw =
            acknowledge_world_beat_exposure(State(state.clone()), Json(receipt_for(raw_event.seq)))
                .await
                .0;
        assert!(!raw.ok && raw.status == 422);
        let inaccessible = acknowledge_world_beat_exposure(
            State(state.clone()),
            Json(receipt_for(inaccessible_event.seq)),
        )
        .await
        .0;
        assert!(!inaccessible.ok && inaccessible.status == 403);
        let unknown =
            acknowledge_world_beat_exposure(State(state.clone()), Json(receipt_for(gap_seq)))
                .await
                .0;
        assert!(!unknown.ok && unknown.status == 404);
        assert_eq!(seen_count(), 1);

        fs::remove_file(path).unwrap();
    }

    #[tokio::test]
    async fn shared_question_exposure_requires_visible_client_confirmation() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-shared-question-exposure-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            MOONLIT_TRAIL_LOCATION_ID,
            "Visible Question Reader",
        );
        let state = test_app_state(runtime, Some(path.clone()));
        let actor_session = issue_actor_session(&state, 5000).0;
        let seen_count = || {
            let conn = open_event_store(&path).expect("open shared-question exposure store");
            conn.query_row(
                "SELECT COUNT(*) FROM story_metric_events
                 WHERE schema_version = ?1 AND event_kind = 'shared_question_seen'",
                params![STORY_METRICS_SCHEMA_VERSION],
                |row| row.get::<_, i64>(0),
            )
            .unwrap()
        };

        assert_eq!(seen_count(), 0);
        let _ = state_view(
            State(state.clone()),
            Query(StateQuery {
                actor_id: Some(5000),
                actor_session: Some(actor_session.clone()),
                wallet_address: None,
                wallet: None,
                wallet_session: None,
                owned_card_ids: None,
                cards: None,
                openrouter_connected: None,
            }),
        )
        .await;
        assert_eq!(
            seen_count(),
            0,
            "reading canonical state cannot imply presentation"
        );

        let revision = state
            .inner
            .lock()
            .await
            .world
            .next_event_seq
            .saturating_sub(1);
        let valid_receipt = ClockPresentationReceiptRequest {
            actor_id: 5000,
            actor_session: actor_session.clone(),
            exposure_id: clock_presentation_exposure_id(
                MOONLIT_PROGRESS_CLOCK_ID,
                "promoted_seen",
                revision,
            ),
            clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
            interaction: "promoted_seen".to_string(),
            transport: "browser".to_string(),
            state_revision: revision,
        };
        let first =
            acknowledge_clock_presentation(State(state.clone()), Json(valid_receipt.clone()))
                .await
                .0;
        assert!(first.ok && first.recorded);
        let duplicate =
            acknowledge_clock_presentation(State(state.clone()), Json(valid_receipt.clone()))
                .await
                .0;
        assert!(duplicate.ok && !duplicate.recorded);
        assert_eq!(seen_count(), 1);

        let unauthorized = acknowledge_clock_presentation(
            State(state.clone()),
            Json(ClockPresentationReceiptRequest {
                actor_session: "not-a-session".to_string(),
                ..valid_receipt.clone()
            }),
        )
        .await
        .0;
        assert!(!unauthorized.ok && unauthorized.status == 403);
        let quiet_danger = acknowledge_clock_presentation(
            State(state.clone()),
            Json(ClockPresentationReceiptRequest {
                exposure_id: clock_presentation_exposure_id(
                    MOONLIT_DANGER_CLOCK_ID,
                    "promoted_seen",
                    revision,
                ),
                clock_id: MOONLIT_DANGER_CLOCK_ID.to_string(),
                ..valid_receipt.clone()
            }),
        )
        .await
        .0;
        assert!(!quiet_danger.ok && quiet_danger.status == 403);
        assert_eq!(seen_count(), 1);

        let comprehension = acknowledge_clock_presentation(
            State(state.clone()),
            Json(ClockPresentationReceiptRequest {
                exposure_id: clock_presentation_exposure_id(
                    MOONLIT_PROGRESS_CLOCK_ID,
                    "comprehension_confirmed",
                    revision,
                ),
                interaction: "comprehension_confirmed".to_string(),
                ..valid_receipt
            }),
        )
        .await
        .0;
        assert!(comprehension.ok && comprehension.recorded);

        let conn = open_event_store(&path).expect("inspect shared-question metrics");
        let metrics = read_recent_story_metrics(&conn, 10).unwrap();
        let metric = metrics
            .iter()
            .find(|metric| metric.event_kind == "shared_question_seen")
            .expect("client receipt writes one privacy-safe metric");
        let encoded = serde_json::to_string(metric).unwrap();
        assert!(!encoded.contains("Will the trail's echoes"));
        assert!(!encoded.contains("Visible Question Reader"));
        assert!(metrics
            .iter()
            .any(|metric| metric.event_kind == "shared_question_comprehension_confirmed"));
        drop(conn);
        fs::remove_file(path).unwrap();
    }

    fn canonical_test_command_request(
        runtime: &RuntimeWorld,
        actor_id: u64,
        actor_session: &str,
        intent_id: &str,
        command: &str,
    ) -> CommandRequest {
        let actor = runtime.actor_by_id(actor_id).expect("canonical test actor");
        let actor_ref = runtime
            .canonical_ref("actor", actor_id)
            .expect("canonical actor ref")
            .to_string();
        let location_ref = runtime
            .canonical_ref("location", actor.location_id)
            .expect("canonical location ref");
        CommandRequest {
            actor_id,
            actor_session: Some(actor_session.to_string()),
            command: command.to_string(),
            wallet_address: None,
            wallet: None,
            wallet_session: None,
            owned_card_ids: None,
            cards: None,
            envelope: Some(CanonicalCommandEnvelope {
                world_id: OFFICIAL_WORLD_ID.to_string(),
                intent_id: intent_id.to_string(),
                actor_ref: actor_ref.clone(),
                observed: CanonicalObservedVersions {
                    actor_version: Some(runtime.entity_version(&actor_ref)),
                    location_version: Some(runtime.entity_version(location_ref)),
                    entities: BTreeMap::new(),
                },
                last_world_seq: runtime.world.next_event_seq.saturating_sub(1),
            }),
        }
    }

    #[test]
    fn snapshot_canonical_refs_ignore_capacity_process_names() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Process Neutral",
        );
        let expected_ref = runtime
            .canonical_ref("actor", 5000)
            .expect("runtime actor ref")
            .to_string();
        let path = std::env::temp_dir().join(format!(
            "cosyworld-canonical-process-neutral-{}.json",
            random_hex(8)
        ));
        runtime
            .save_snapshot(&path)
            .expect("save canonical snapshot");

        let west = DeploymentConfig {
            profile: DeploymentProfile::Local,
            world_id: OFFICIAL_WORLD_ID.to_string(),
            process_id: "api-west".to_string(),
        };
        let east = DeploymentConfig {
            profile: DeploymentProfile::Local,
            world_id: OFFICIAL_WORLD_ID.to_string(),
            process_id: "api-east".to_string(),
        };
        let west_runtime = RuntimeWorld::load_snapshot(&path).expect("west snapshot replay");
        let east_runtime = RuntimeWorld::load_snapshot(&path).expect("east snapshot replay");
        fs::remove_file(&path).expect("remove canonical snapshot fixture");

        assert_ne!(west.process_id, east.process_id);
        assert_eq!(west.world_id, east.world_id);
        assert_eq!(
            west_runtime.canonical_ref("actor", 5000),
            Some(expected_ref.as_str())
        );
        assert_eq!(
            east_runtime.canonical_ref("actor", 5000),
            Some(expected_ref.as_str())
        );
    }

    #[test]
    fn canonical_routing_requires_a_safe_origin_and_paired_secret() {
        assert!(!canonical_routing_config(None, None).unwrap().enabled());
        assert!(
            canonical_routing_config(Some("https://capacity.example".to_string()), None,).is_err()
        );
        assert!(canonical_routing_config(
            Some("https://capacity.example/internal".to_string()),
            Some("0123456789abcdef".to_string()),
        )
        .is_err());
        assert!(canonical_routing_config(
            Some("https://capacity.example".to_string()),
            Some("too-short".to_string()),
        )
        .is_err());

        let config = canonical_routing_config(
            Some("https://capacity.example".to_string()),
            Some("0123456789abcdef".to_string()),
        )
        .unwrap();
        assert!(config.enabled());
        assert_eq!(config.base_url.as_deref(), Some("https://capacity.example"));
    }

