    #[test]
    fn durable_process_fanout_is_ordered_and_exactly_once() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Fanout Neighbour",
        );
        let event = runtime
            .event_log
            .iter()
            .find(|event| event.seq > 0 && event.type_name != "action.receipt")
            .cloned()
            .expect("durable actor event");
        let mut delayed = event.clone();
        delayed.seq = event.seq + 1;
        delayed.type_name = "test.delayed".to_string();
        let state = test_app_state(runtime, None);
        state
            .canonical_fanout_seq
            .store(event.seq.saturating_sub(1), AtomicOrdering::Release);
        let mut receiver = state.tx.subscribe();

        broadcast_events(&state, &[delayed.clone()]);
        assert!(receiver.try_recv().is_err(), "a durable gap must wait");
        broadcast_events(&state, &[event.clone(), delayed.clone()]);
        assert_eq!(receiver.try_recv().unwrap().seq, event.seq);
        assert_eq!(receiver.try_recv().unwrap().seq, delayed.seq);
        broadcast_events(&state, &[event, delayed]);
        assert!(receiver.try_recv().is_err(), "a durable retry must dedupe");
    }

    #[tokio::test]
    async fn duplicate_canonical_intent_returns_the_same_receipt_and_one_effect() {
        let actor_id = 5000;
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            actor_id,
            COSY_COTTAGE_LOCATION_ID,
            "Idempotent Neighbour",
        );
        let state = test_app_state(runtime, None);
        let actor_session = create_actor_session(&state.actor_sessions, actor_id).0;
        let request = {
            let runtime = state.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_id,
                &actor_session,
                "test:same-intent",
                "say one warm hello",
            )
        };
        let client = ConnectInfo("127.0.0.1:45129".parse().expect("client address"));

        let first = command(client, State(state.clone()), Json(request.clone()))
            .await
            .0;
        let second = command(client, State(state.clone()), Json(request)).await.0;

        assert!(first.ok, "{first:?}");
        assert!(!first.events.is_empty());
        assert!(first.events.iter().all(|event| {
            event.world_id == OFFICIAL_WORLD_ID
                && event.world_epoch == OFFICIAL_WORLD_EPOCH
                && (event.seq > 0 || event.type_name == "actor.presence")
        }));
        assert!(first
            .events
            .iter()
            .filter(|event| event.type_name == "actor.presence")
            .all(|event| event.seq == 0));
        assert_eq!(first.receipt, second.receipt);
        assert_eq!(
            serde_json::to_value(&first).unwrap(),
            serde_json::to_value(&second).unwrap()
        );
        let runtime = state.inner.lock().await;
        assert_eq!(
            runtime
                .event_log
                .iter()
                .filter(|event| {
                    event.type_name == "message.created"
                        && event.actor_id == Some(actor_id)
                        && event.content.as_deref() == Some("one warm hello")
                })
                .count(),
            1
        );
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 4)]
    async fn divergent_capacity_processes_converge_without_affinity() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-capacity-convergence-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        init_event_store(&path).expect("initialize convergence store");

        let listener_a = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind process A");
        let listener_b = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind process B");
        let addr_a = listener_a.local_addr().expect("process A address");
        let addr_b = listener_b.local_addr().expect("process B address");
        let url_a = format!("http://{addr_a}");
        let url_b = format!("http://{addr_b}");
        let router_token = "capacity-test-router-token";
        let lease_ttl = Duration::from_secs(1);

        let state_a = configure_capacity_test_state(
            test_app_state(RuntimeWorld::seeded(), Some(path.clone())),
            "process-a",
            "process-a:boot-a",
            &url_a,
            router_token,
            lease_ttl,
        );
        let actor_a = 5000;
        let actor_b = 5001;
        let session_a =
            commit_capacity_test_human(&state_a, actor_a, COSY_COTTAGE_LOCATION_ID, "Pinned A")
                .await;
        let session_b =
            commit_capacity_test_human(&state_a, actor_b, RAIN_SOFT_GARDEN_LOCATION_ID, "Pinned B")
                .await;
        let baseline_seq = current_world_seq(
            &open_event_store(&path).expect("baseline store"),
            OFFICIAL_WORLD_ID,
        )
        .expect("baseline cursor");

        let mut runtime_b = RuntimeWorld::from_action_journal(&path).expect("replay process B");
        advance_runtime_next_event_seq_from_store(&mut runtime_b, &path)
            .expect("advance process B cursor");
        let state_b = configure_capacity_test_state(
            test_app_state(runtime_b, Some(path.clone())),
            "process-b",
            "process-b:boot-b",
            &url_b,
            router_token,
            lease_ttl,
        );

        let app_a = routes::app_router(state_a.clone());
        let app_b = routes::app_router(state_b.clone());
        let server_a = tokio::spawn(async move {
            axum::serve(
                listener_a,
                app_a.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve process A");
        });
        let server_b = tokio::spawn(async move {
            axum::serve(
                listener_b,
                app_b.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve process B");
        });
        let convergence_a =
            start_canonical_capacity_scheduler(state_a.clone()).expect("process A convergence");
        let convergence_b =
            start_canonical_capacity_scheduler(state_b.clone()).expect("process B convergence");
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(5))
            .build()
            .expect("capacity test client");

        // Presence crosses the real process routes but stays outside durable history.
        let mut presence_rx_b = state_b.tx.subscribe();
        let ping: serde_json::Value = client
            .post(format!("{url_a}/presence/ping"))
            .json(&serde_json::json!({
                "actor_id": actor_a,
                "actor_session": session_a,
            }))
            .send()
            .await
            .expect("ping through process A")
            .json()
            .await
            .expect("presence response");
        assert_eq!(ping["ok"], true);
        let relayed_presence = tokio::time::timeout(Duration::from_secs(2), async {
            loop {
                let event = presence_rx_b
                    .recv()
                    .await
                    .expect("process B presence event");
                if event.type_name == "actor.presence" && event.actor_id == Some(actor_a) {
                    break event;
                }
            }
        })
        .await
        .expect("presence fan-out timeout");
        assert_eq!(relayed_presence.seq, 0);
        assert_eq!(relayed_presence.content.as_deref(), Some("active"));
        assert_eq!(
            current_world_seq(
                &open_event_store(&path).expect("presence cursor store"),
                OFFICIAL_WORLD_ID,
            )
            .expect("presence cursor"),
            baseline_seq,
            "presence must not advance canonical history"
        );

        // Refresh process A's room lease immediately before B follows the invite.
        let warmup_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_a,
                &session_a,
                "test:capacity-warmup",
                "say the same hearth is ready",
            )
        };
        let warmup: CommandResponse = client
            .post(format!("{url_a}/commands"))
            .json(&warmup_request)
            .send()
            .await
            .expect("warmup command")
            .json()
            .await
            .expect("warmup response");
        assert!(warmup.ok, "{warmup:?}");

        let invite: CanonicalInviteResponse = client
            .post(format!("{url_a}/invites"))
            .json(&CreateCanonicalInviteRequest {
                actor_id: actor_a,
                actor_session: session_a.clone(),
            })
            .send()
            .await
            .expect("create invite through A")
            .json()
            .await
            .expect("invite response");
        assert!(invite.ok, "{invite:?}");
        assert_eq!(invite.process_id, "process-a");
        let invite = invite.invite.expect("canonical invite");
        assert!(invite.hosted_access.eligible);
        let resolved_on_b: CanonicalInviteResponse = client
            .get(format!("{url_b}/invites/{}", invite.invite_id))
            .send()
            .await
            .expect("resolve invite through B")
            .json()
            .await
            .expect("resolved invite response");
        assert!(resolved_on_b.ok, "{resolved_on_b:?}");
        assert_eq!(resolved_on_b.process_id, "process-b");
        assert_eq!(
            resolved_on_b
                .invite
                .as_ref()
                .map(|view| view.inviter.actor_ref.as_str()),
            Some(invite.inviter.actor_ref.as_str())
        );

        let followed: CanonicalInviteFollowResponse = client
            .post(format!("{url_b}/invites/{}/follow", invite.invite_id))
            .json(&FollowCanonicalInviteRequest {
                actor_id: actor_b,
                actor_session: session_b.clone(),
            })
            .send()
            .await
            .expect("follow invite through B")
            .json()
            .await
            .expect("follow response");
        assert!(followed.ok, "{followed:?}");
        assert!(followed.party.is_some());
        assert_eq!(
            followed.rendezvous_location_ref.as_deref(),
            Some(invite.inviter.location_ref.as_str())
        );
        assert!(followed.events.iter().any(|event| {
            event.type_name == "actor.moved"
                && event.actor_id == Some(actor_b)
                && event.destination_location_id == Some(COSY_COTTAGE_LOCATION_ID)
        }));

        let actor_b_ref = followed.actor_ref.clone().expect("actor B canonical ref");
        let profile_a: CanonicalProfileResponse = client
            .get(format!("{url_a}/profiles"))
            .query(&[("actor_ref", actor_b_ref.as_str())])
            .send()
            .await
            .expect("profile through A")
            .json()
            .await
            .expect("profile A response");
        let profile_b: CanonicalProfileResponse = client
            .get(format!("{url_b}/profiles"))
            .query(&[("actor_ref", actor_b_ref.as_str())])
            .send()
            .await
            .expect("profile through B")
            .json()
            .await
            .expect("profile B response");
        assert_eq!(profile_a.profile, profile_b.profile);
        assert_eq!(
            profile_b.profile.as_ref().map(|view| view.location_id),
            Some(COSY_COTTAGE_LOCATION_ID)
        );

        // One intent enters through both processes concurrently and commits once.
        let retry_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_a,
                &session_a,
                "test:cross-process-retry",
                "say this arrives exactly once",
            )
        };
        let request_a = client
            .post(format!("{url_a}/commands"))
            .json(&retry_request)
            .send();
        let request_b = client
            .post(format!("{url_b}/commands"))
            .json(&retry_request)
            .send();
        let (response_a, response_b) = tokio::join!(request_a, request_b);
        let response_a: CommandResponse = response_a
            .expect("retry through A")
            .json()
            .await
            .expect("retry A response");
        let response_b: CommandResponse = response_b
            .expect("retry through B")
            .json()
            .await
            .expect("retry B response");
        assert!(response_a.ok, "{response_a:?}");
        assert!(response_b.ok, "{response_b:?}");
        assert_eq!(response_a.receipt, response_b.receipt);
        assert_eq!(
            serde_json::to_value(&response_a).unwrap(),
            serde_json::to_value(&response_b).unwrap()
        );
        let receipt_count = open_event_store(&path)
            .expect("receipt store")
            .query_row(
                "SELECT COUNT(*) FROM canonical_command_receipts
                 WHERE world_id = ?1 AND intent_id = ?2",
                params![OFFICIAL_WORLD_ID, "test:cross-process-retry"],
                |row| row.get::<_, i64>(0),
            )
            .expect("receipt count");
        assert_eq!(receipt_count, 1);
        for state in [&state_a, &state_b] {
            converge_capacity_for_read(state, None).await;
            assert_eq!(
                state
                    .inner
                    .lock()
                    .await
                    .event_log
                    .iter()
                    .filter(|event| {
                        event.type_name == "message.created"
                            && event.actor_id == Some(actor_a)
                            && event.content.as_deref() == Some("this arrives exactly once")
                    })
                    .count(),
                1
            );
        }

        // A command entering through B mutates the item once on A's fenced room.
        let (loose_item_id, loose_item_name) = {
            let runtime = state_a.inner.lock().await;
            let item = runtime.world.items[..runtime.world.item_count]
                .iter()
                .find(|item| {
                    item.location_id == COSY_COTTAGE_LOCATION_ID && item.holder_actor_id == 0
                })
                .copied()
                .expect("loose cottage item");
            (
                item.id,
                runtime.item_name(item.id).expect("loose item name"),
            )
        };
        let take_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_a,
                &session_a,
                "test:cross-process-item",
                &format!("take {loose_item_name}"),
            )
        };
        let take: CommandResponse = client
            .post(format!("{url_b}/commands"))
            .json(&take_request)
            .send()
            .await
            .expect("take through B")
            .json()
            .await
            .expect("take response");
        assert!(take.ok, "{take:?}");
        for state in [&state_a, &state_b] {
            converge_capacity_for_read(state, None).await;
            assert_eq!(
                state
                    .inner
                    .lock()
                    .await
                    .item_by_id(loose_item_id)
                    .map(|item| item.holder_actor_id),
                Some(actor_a)
            );
        }

        let state_url = |base: &str| format!("{base}/state");
        let state_a_view: serde_json::Value = client
            .get(state_url(&url_a))
            .query(&[
                ("actor_id", actor_b.to_string()),
                ("actor_session", session_b.clone()),
            ])
            .send()
            .await
            .expect("state through A")
            .json()
            .await
            .expect("state A json");
        let state_b_view: serde_json::Value = client
            .get(state_url(&url_b))
            .query(&[
                ("actor_id", actor_b.to_string()),
                ("actor_session", session_b.clone()),
            ])
            .send()
            .await
            .expect("state through B")
            .json()
            .await
            .expect("state B json");
        for field in ["location", "actors", "items", "action_hand"] {
            assert_eq!(
                state_a_view[field], state_b_view[field],
                "pinned clients diverged at {field}"
            );
        }

        let events_a: EventsResponse = client
            .get(format!("{url_a}/events"))
            .query(&[
                ("after", baseline_seq.to_string()),
                ("limit", "500".to_string()),
                ("actor_id", actor_b.to_string()),
                ("actor_session", session_b.clone()),
            ])
            .send()
            .await
            .expect("events through A")
            .json()
            .await
            .expect("events A response");
        let events_b: EventsResponse = client
            .get(format!("{url_b}/events"))
            .query(&[
                ("after", baseline_seq.to_string()),
                ("limit", "500".to_string()),
                ("actor_id", actor_b.to_string()),
                ("actor_session", session_b.clone()),
            ])
            .send()
            .await
            .expect("events through B")
            .json()
            .await
            .expect("events B response");
        assert_eq!(
            serde_json::to_value(&events_a.events).unwrap(),
            serde_json::to_value(&events_b.events).unwrap()
        );
        assert!(events_a.caught_up && events_b.caught_up);
        assert!(events_a
            .events
            .windows(2)
            .all(|events| events[0].seq + 1 == events[1].seq));

        // Kill the owner entrance. B waits for lease expiry, takes a higher fence,
        // and continues from the same actor identity and committed prefix.
        convergence_a.abort();
        server_a.abort();
        tokio::time::sleep(lease_ttl + Duration::from_millis(250)).await;
        converge_capacity_for_read(&state_b, Some(&session_a)).await;
        let failover_request = {
            let runtime = state_b.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_a,
                &session_a,
                "test:owner-process-loss",
                "say history stayed with us",
            )
        };
        let failover: CommandResponse = client
            .post(format!("{url_b}/commands"))
            .json(&failover_request)
            .send()
            .await
            .expect("command after owner loss")
            .json()
            .await
            .expect("failover response");
        assert!(failover.ok, "{failover:?}");
        assert!(
            failover
                .receipt
                .as_ref()
                .map(|receipt| receipt.owner_fencing_epoch)
                > response_a
                    .receipt
                    .as_ref()
                    .map(|receipt| receipt.owner_fencing_epoch)
        );
        let profile_after_loss: CanonicalProfileResponse = client
            .get(format!("{url_b}/profiles"))
            .query(&[("actor_ref", invite.inviter.actor_ref.as_str())])
            .send()
            .await
            .expect("profile after owner loss")
            .json()
            .await
            .expect("profile after loss response");
        assert_eq!(
            profile_after_loss
                .profile
                .as_ref()
                .map(|profile| profile.actor_ref.as_str()),
            Some(invite.inviter.actor_ref.as_str())
        );
        assert!(state_b.inner.lock().await.event_log.iter().any(|event| {
            event.type_name == "message.created"
                && event.content.as_deref() == Some("this arrives exactly once")
        }));

        convergence_b.abort();
        server_b.abort();
        drop(client);
        let _ = fs::remove_file(path);
    }

    #[test]
    fn hot_room_and_regional_chaos_preserve_one_committed_world() {
        std::thread::Builder::new()
            .name("hot-room-regional-chaos".to_string())
            .stack_size(16 * 1024 * 1024)
            .spawn(|| {
                tokio::runtime::Builder::new_multi_thread()
                    .worker_threads(2)
                    .enable_all()
                    .build()
                    .expect("build hot-room regional chaos runtime")
                    .block_on(run_hot_room_and_regional_chaos());
            })
            .expect("spawn hot-room regional chaos thread")
            .join()
            .expect("hot-room regional chaos thread");
    }

    async fn run_hot_room_and_regional_chaos() {
        let primary_path = std::env::temp_dir().join(format!(
            "cosyworld-hot-room-primary-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let recovery_path = std::env::temp_dir().join(format!(
            "cosyworld-hot-room-recovery-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let quarantine_path = primary_path.with_extension("isolated.sqlite");
        for path in [&primary_path, &recovery_path, &quarantine_path] {
            let _ = fs::remove_file(path);
        }

        let listener_a = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind hot-room process A");
        let listener_b = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind hot-room process B");
        let addr_a = listener_a.local_addr().expect("hot-room process A address");
        let addr_b = listener_b.local_addr().expect("hot-room process B address");
        let url_a = format!("http://{addr_a}");
        let url_b = format!("http://{addr_b}");
        let router_token = "hot-room-regional-router-token";
        let lease_ttl = Duration::from_millis(1_500);
        let actor_hot = 5100;
        let actor_cold = 5101;

        let state_a = configure_capacity_test_state(
            test_app_state(RuntimeWorld::seeded(), Some(primary_path.clone())),
            "hot-a",
            "hot-a:boot-a",
            &url_a,
            router_token,
            lease_ttl,
        );
        let session_hot = commit_capacity_test_human(
            &state_a,
            actor_hot,
            COSY_COTTAGE_LOCATION_ID,
            "Hot Room Neighbour",
        )
        .await;
        let session_cold = commit_capacity_test_human(
            &state_a,
            actor_cold,
            RAIN_SOFT_GARDEN_LOCATION_ID,
            "Cold Room Neighbour",
        )
        .await;
        let baseline_seq = current_world_seq(
            &open_event_store(&primary_path).expect("hot-room baseline store"),
            OFFICIAL_WORLD_ID,
        )
        .expect("hot-room baseline cursor");

        let mut runtime_b =
            RuntimeWorld::from_action_journal(&primary_path).expect("replay hot-room process B");
        advance_runtime_next_event_seq_from_store(&mut runtime_b, &primary_path)
            .expect("advance hot-room process B cursor");
        let state_b = configure_capacity_test_state(
            test_app_state(runtime_b, Some(primary_path.clone())),
            "hot-b",
            "hot-b:boot-b",
            &url_b,
            router_token,
            lease_ttl,
        );
        let store_id = state_a.canonical_store_id.as_ref().clone();
        assert_eq!(state_b.canonical_store_id.as_str(), store_id);

        let app_a = routes::app_router(state_a.clone());
        let app_b = routes::app_router(state_b.clone());
        let server_a = tokio::spawn(async move {
            axum::serve(
                listener_a,
                app_a.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve hot-room process A");
        });
        let server_b = tokio::spawn(async move {
            axum::serve(
                listener_b,
                app_b.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve hot-room process B");
        });
        let convergence_a =
            start_canonical_capacity_scheduler(state_a.clone()).expect("hot-room convergence A");
        let convergence_b =
            start_canonical_capacity_scheduler(state_b.clone()).expect("hot-room convergence B");
        let client = reqwest::Client::builder()
            .timeout(Duration::from_secs(5))
            .build()
            .expect("hot-room client");

        let (actor_ref, hot_partition, cold_partition) = {
            let runtime = state_a.inner.lock().await;
            let actor_ref = runtime
                .canonical_ref("actor", actor_hot)
                .expect("hot actor ref")
                .to_string();
            let hot_location_ref = runtime
                .canonical_ref("location", COSY_COTTAGE_LOCATION_ID)
                .expect("hot location ref");
            let cold_location_ref = runtime
                .canonical_ref("location", RAIN_SOFT_GARDEN_LOCATION_ID)
                .expect("cold location ref");
            (
                actor_ref,
                canonical_room_partition_key(hot_location_ref),
                canonical_room_partition_key(cold_location_ref),
            )
        };

        // Hot-room load may enter through either edge, but one fenced owner
        // serializes every effect and entity versions only move forward.
        let mut actor_versions = Vec::new();
        let mut hot_messages = Vec::new();
        for index in 0..16_u64 {
            converge_capacity_for_read(&state_a, Some(&session_hot)).await;
            let content = format!("hot-room-load-{index}");
            let request = {
                let runtime = state_a.inner.lock().await;
                canonical_test_command_request(
                    &runtime,
                    actor_hot,
                    &session_hot,
                    &format!("test:hot-room-load:{index}"),
                    &format!("say {content}"),
                )
            };
            let base = if index % 2 == 0 { &url_a } else { &url_b };
            let response: CommandResponse = client
                .post(format!("{base}/commands"))
                .json(&request)
                .send()
                .await
                .expect("hot-room load command")
                .json()
                .await
                .expect("hot-room load response");
            assert!(response.ok, "{response:?}");
            converge_capacity_for_read(&state_a, Some(&session_hot)).await;
            let version = state_a.inner.lock().await.entity_version(&actor_ref);
            actor_versions.push(version);
            hot_messages.push(content);
        }
        assert!(actor_versions.windows(2).all(|pair| pair[1] > pair[0]));

        let source_hot_lease = current_partition_lease(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &hot_partition,
            now_millis(),
        )
        .expect("read hot-room source lease")
        .expect("hot-room source owner");
        assert_eq!(source_hot_lease.owner_id, "hot-a:boot-a");
        let handoff_seq = current_world_seq(
            &open_event_store(&primary_path).expect("handoff store"),
            OFFICIAL_WORLD_ID,
        )
        .expect("handoff cursor");
        let handoff = handoff_partition_leases(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &store_id,
            DEFAULT_CANONICAL_REGION_ID,
            &BTreeMap::from([(
                hot_partition.clone(),
                CanonicalOwnershipTransfer {
                    source: source_hot_lease.clone(),
                    target_owner_id: "hot-b:boot-b".to_string(),
                },
            )]),
            handoff_seq,
            "hot-room load rebalance",
            now_millis(),
            authority_lease_ttl_ms(&state_a),
        )
        .expect("commit hot-room handoff");
        let target_hot_lease = handoff
            .leases
            .get(&hot_partition)
            .expect("target hot-room lease")
            .clone();
        assert_eq!(handoff.world_seq, handoff_seq);
        assert_eq!(target_hot_lease.owner_id, "hot-b:boot-b");
        assert_eq!(
            target_hot_lease.fencing_epoch,
            source_hot_lease.fencing_epoch + 1
        );

        let stale_rejected = {
            let mut conn = open_event_store(&primary_path).expect("stale handoff store");
            let tx = conn
                .transaction_with_behavior(rusqlite::TransactionBehavior::Immediate)
                .expect("stale handoff transaction");
            let result = validate_and_renew_partition_lease(
                &tx,
                &source_hot_lease,
                now_millis(),
                authority_lease_ttl_ms(&state_a),
            );
            tx.rollback().expect("rollback stale handoff probe");
            result
        };
        assert_eq!(
            stale_rejected
                .expect_err("stale pre-handoff owner must fail")
                .kind(),
            io::ErrorKind::PermissionDenied
        );

        let post_handoff_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_hot,
                &session_hot,
                "test:after-hot-room-handoff",
                "say handoff stayed contiguous",
            )
        };
        let post_handoff: CommandResponse = client
            .post(format!("{url_a}/commands"))
            .json(&post_handoff_request)
            .send()
            .await
            .expect("post-handoff command through stale edge")
            .json()
            .await
            .expect("post-handoff response");
        assert!(post_handoff.ok, "{post_handoff:?}");
        assert!(post_handoff
            .receipt
            .as_ref()
            .is_some_and(|receipt| receipt.owner_fencing_epoch >= target_hot_lease.fencing_epoch));

        // Refresh the cold room, then checkpoint two independently owned
        // ranges at one exact global sequence boundary.
        converge_capacity_for_read(&state_a, Some(&session_cold)).await;
        let cold_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_cold,
                &session_cold,
                "test:cold-range-checkpoint",
                "say cold range is ready",
            )
        };
        let cold_response: CommandResponse = client
            .post(format!("{url_a}/commands"))
            .json(&cold_request)
            .send()
            .await
            .expect("cold range command")
            .json()
            .await
            .expect("cold range response");
        assert!(cold_response.ok, "{cold_response:?}");
        let split_now = now_millis();
        let hot_before_split = current_partition_lease(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &hot_partition,
            split_now,
        )
        .unwrap()
        .expect("hot owner before split");
        let cold_before_split = current_partition_lease(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &cold_partition,
            split_now,
        )
        .unwrap()
        .expect("cold owner before split");
        assert_ne!(hot_before_split.owner_id, cold_before_split.owner_id);
        let split_seq =
            current_world_seq(&open_event_store(&primary_path).unwrap(), OFFICIAL_WORLD_ID)
                .unwrap();
        let split = handoff_partition_leases(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &store_id,
            DEFAULT_CANONICAL_REGION_ID,
            &BTreeMap::from([
                (
                    hot_partition.clone(),
                    CanonicalOwnershipTransfer {
                        target_owner_id: hot_before_split.owner_id.clone(),
                        source: hot_before_split,
                    },
                ),
                (
                    cold_partition.clone(),
                    CanonicalOwnershipTransfer {
                        target_owner_id: cold_before_split.owner_id.clone(),
                        source: cold_before_split,
                    },
                ),
            ]),
            split_seq,
            "split hot and cold ownership ranges",
            split_now,
            authority_lease_ttl_ms(&state_a),
        )
        .expect("commit ownership split checkpoint");
        assert_eq!(split.world_seq, split_seq);
        assert_eq!(split.leases.len(), 2);
        assert_ne!(
            split.leases[&hot_partition].owner_id,
            split.leases[&cold_partition].owner_id
        );

        // A cross-range mutation cannot partially apply while the children
        // have different owners.
        converge_capacity_for_read(&state_b, Some(&session_hot)).await;
        let before_cross_seq = latest_action_journal_seq(&primary_path).unwrap();
        let before_cross_location = state_b
            .inner
            .lock()
            .await
            .actor_by_id(actor_hot)
            .unwrap()
            .location_id;
        let cross_result = {
            let mut runtime = state_b.inner.lock().await;
            let mut record = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_NONE,
                    actor_id: actor_hot,
                    destination_location_id: RAIN_SOFT_GARDEN_LOCATION_ID,
                    ..CwAction::default()
                },
                runtime.next_seed_value(),
            );
            record.source_location_id = Some(COSY_COTTAGE_LOCATION_ID);
            record
                .projection_mutations
                .push(ProjectionMutation::RendezvousActor {
                    actor_id: actor_hot,
                    location_id: RAIN_SOFT_GARDEN_LOCATION_ID,
                    invite_id: "test:split-range".to_string(),
                });
            commit_journal_record(&state_b, &mut runtime, record)
        };
        assert_eq!(
            cross_result
                .expect_err("cross-owner mutation must fail closed")
                .kind(),
            io::ErrorKind::WouldBlock
        );
        assert_eq!(
            latest_action_journal_seq(&primary_path).unwrap(),
            before_cross_seq
        );
        assert_eq!(
            state_b
                .inner
                .lock()
                .await
                .actor_by_id(actor_hot)
                .unwrap()
                .location_id,
            before_cross_location
        );

        // Network isolation cannot bootstrap a second world at the same path:
        // a fresh file has no pinned store identity and every mutation rejects.
        convergence_a.abort();
        convergence_b.abort();
        fs::rename(&primary_path, &quarantine_path).expect("isolate primary store");
        let isolated_request = {
            let runtime = state_b.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_hot,
                &session_hot,
                "test:network-isolation",
                "say this must not fork",
            )
        };
        let isolated: CommandResponse = client
            .post(format!("{url_b}/commands"))
            .json(&isolated_request)
            .send()
            .await
            .expect("isolated command response")
            .json()
            .await
            .expect("isolated command json");
        assert!(!isolated.ok);
        assert_eq!(isolated.status, 503);
        let isolated_conn = open_event_store(&primary_path).expect("fresh isolated store");
        let isolated_actions: i64 = isolated_conn
            .query_row("SELECT COUNT(*) FROM action_journal", [], |row| row.get(0))
            .unwrap();
        let isolated_identity: i64 = isolated_conn
            .query_row("SELECT COUNT(*) FROM canonical_store_identity", [], |row| {
                row.get(0)
            })
            .unwrap();
        assert_eq!((isolated_actions, isolated_identity), (0, 0));
        drop(isolated_conn);
        fs::remove_file(&primary_path).expect("remove isolated empty store");
        fs::rename(&quarantine_path, &primary_path).expect("restore primary store");
        let convergence_a =
            start_canonical_capacity_scheduler(state_a.clone()).expect("restart convergence A");
        let convergence_b =
            start_canonical_capacity_scheduler(state_b.clone()).expect("restart convergence B");
        converge_capacity_for_read(&state_a, Some(&session_hot)).await;

        // Kill the hot-room owner. The surviving process takes the expired
        // range at a higher fence without changing actor identity or history.
        convergence_b.abort();
        server_b.abort();
        tokio::time::sleep(lease_ttl + Duration::from_millis(250)).await;
        let process_loss_request = {
            let runtime = state_a.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_hot,
                &session_hot,
                "test:hot-owner-loss",
                "say process loss kept one history",
            )
        };
        let process_loss: CommandResponse = client
            .post(format!("{url_a}/commands"))
            .json(&process_loss_request)
            .send()
            .await
            .expect("command after hot owner loss")
            .json()
            .await
            .expect("process loss response");
        assert!(process_loss.ok, "{process_loss:?}");
        let process_loss_fence = process_loss
            .receipt
            .as_ref()
            .expect("process loss receipt")
            .owner_fencing_epoch;
        assert!(process_loss_fence > split.leases[&hot_partition].fencing_epoch);

        // Replicate one exact committed prefix, lose the source region, and
        // promote only the verified copy under a higher regional epoch/fence.
        let source_authority =
            current_region_authority(&primary_path, OFFICIAL_WORLD_ID, OFFICIAL_WORLD_EPOCH)
                .expect("source region authority");
        assert_eq!(
            source_authority.active_region_id,
            DEFAULT_CANONICAL_REGION_ID
        );
        let pre_promotion_lease = current_partition_lease(
            &primary_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &hot_partition,
            now_millis(),
        )
        .unwrap()
        .expect("pre-promotion hot lease");
        let checkpoint = replicate_canonical_store(
            &primary_path,
            &recovery_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            "recovery",
            now_millis(),
        )
        .expect("replicate recovery prefix");
        assert_eq!(
            checkpoint.durable_world_seq,
            current_world_seq(&open_event_store(&primary_path).unwrap(), OFFICIAL_WORLD_ID)
                .unwrap()
        );
        assert!(checkpoint.prefix_hash.starts_with("sha256:"));
        convergence_a.abort();
        server_a.abort();
        let promotion = promote_recovery_region(
            &recovery_path,
            OFFICIAL_WORLD_ID,
            OFFICIAL_WORLD_EPOCH,
            &store_id,
            DEFAULT_CANONICAL_REGION_ID,
            "recovery",
            source_authority.promotion_epoch,
            &checkpoint,
            now_millis(),
        )
        .expect("promote recovery region");
        assert_eq!(
            promotion.promotion_epoch,
            source_authority.promotion_epoch + 1
        );
        assert_eq!(promotion.durable_world_seq, checkpoint.durable_world_seq);
        assert_eq!(promotion.prefix_hash, checkpoint.prefix_hash);
        let promoted_authority =
            current_region_authority(&recovery_path, OFFICIAL_WORLD_ID, OFFICIAL_WORLD_EPOCH)
                .unwrap();
        assert_eq!(promoted_authority.active_region_id, "recovery");
        let stale_region_rejected = {
            let mut conn = open_event_store(&recovery_path).unwrap();
            let tx = conn
                .transaction_with_behavior(rusqlite::TransactionBehavior::Immediate)
                .unwrap();
            let result = validate_and_renew_partition_lease(
                &tx,
                &pre_promotion_lease,
                now_millis(),
                authority_lease_ttl_ms(&state_a),
            );
            tx.rollback().unwrap();
            result
        };
        assert_eq!(
            stale_region_rejected
                .expect_err("pre-promotion owner must be fenced")
                .kind(),
            io::ErrorKind::PermissionDenied
        );

        let listener_recovery = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind recovery writer");
        let recovery_addr = listener_recovery.local_addr().unwrap();
        let recovery_url = format!("http://{recovery_addr}");
        let mut recovery_runtime =
            RuntimeWorld::from_action_journal(&recovery_path).expect("replay recovery writer");
        advance_runtime_next_event_seq_from_store(&mut recovery_runtime, &recovery_path).unwrap();
        let mut recovery_state = test_app_state(recovery_runtime, Some(recovery_path.clone()));
        recovery_state.canonical_region_id = Arc::new("recovery".to_string());
        let recovery_state = configure_capacity_test_state(
            recovery_state,
            "recovery-writer",
            "recovery-writer:boot-r",
            &recovery_url,
            router_token,
            lease_ttl,
        );
        let recovery_app = routes::app_router(recovery_state.clone());
        let recovery_server = tokio::spawn(async move {
            axum::serve(
                listener_recovery,
                recovery_app.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve recovery writer");
        });
        let recovery_convergence = start_canonical_capacity_scheduler(recovery_state.clone())
            .expect("recovery convergence");
        converge_capacity_for_read(&recovery_state, Some(&session_hot)).await;
        let recovery_request = {
            let runtime = recovery_state.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_hot,
                &session_hot,
                "test:regional-promotion",
                "say recovery kept the committed prefix",
            )
        };
        let recovery_response: CommandResponse = client
            .post(format!("{recovery_url}/commands"))
            .json(&recovery_request)
            .send()
            .await
            .expect("recovery region command")
            .json()
            .await
            .expect("recovery command response");
        assert!(recovery_response.ok, "{recovery_response:?}");
        assert!(
            recovery_response.receipt.as_ref().is_some_and(
                |receipt| receipt.owner_fencing_epoch > pre_promotion_lease.fencing_epoch
            )
        );

        // A client reconnecting through the former region reads the promoted
        // prefix and forwards writes to the active recovery owner.
        let listener_reconnect = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind reconnect edge");
        let reconnect_addr = listener_reconnect.local_addr().unwrap();
        let reconnect_url = format!("http://{reconnect_addr}");
        let mut reconnect_runtime =
            RuntimeWorld::from_action_journal(&recovery_path).expect("replay reconnect edge");
        advance_runtime_next_event_seq_from_store(&mut reconnect_runtime, &recovery_path).unwrap();
        let reconnect_state = configure_capacity_test_state(
            test_app_state(reconnect_runtime, Some(recovery_path.clone())),
            "former-region-edge",
            "former-region-edge:boot-e",
            &reconnect_url,
            router_token,
            lease_ttl,
        );
        let reconnect_app = routes::app_router(reconnect_state.clone());
        let reconnect_server = tokio::spawn(async move {
            axum::serve(
                listener_reconnect,
                reconnect_app.into_make_service_with_connect_info::<SocketAddr>(),
            )
            .await
            .expect("serve reconnect edge");
        });
        let reconnect_convergence = start_canonical_capacity_scheduler(reconnect_state.clone())
            .expect("reconnect convergence");
        converge_capacity_for_read(&reconnect_state, Some(&session_hot)).await;
        let reconnect_request = {
            let runtime = reconnect_state.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_hot,
                &session_hot,
                "test:cross-region-reconnect",
                "say both regions rejoined one world",
            )
        };
        let reconnect_response: CommandResponse = client
            .post(format!("{reconnect_url}/commands"))
            .json(&reconnect_request)
            .send()
            .await
            .expect("reconnected region command")
            .json()
            .await
            .expect("reconnected command response");
        assert!(reconnect_response.ok, "{reconnect_response:?}");
        converge_capacity_for_read(&recovery_state, Some(&session_hot)).await;
        converge_capacity_for_read(&reconnect_state, Some(&session_hot)).await;

        let recovery_view: serde_json::Value = client
            .get(format!("{recovery_url}/state"))
            .query(&[
                ("actor_id", actor_hot.to_string()),
                ("actor_session", session_hot.clone()),
            ])
            .send()
            .await
            .unwrap()
            .json()
            .await
            .unwrap();
        let reconnect_view: serde_json::Value = client
            .get(format!("{reconnect_url}/state"))
            .query(&[
                ("actor_id", actor_hot.to_string()),
                ("actor_session", session_hot.clone()),
            ])
            .send()
            .await
            .unwrap()
            .json()
            .await
            .unwrap();
        for field in ["world_seq", "location", "actors", "items", "action_hand"] {
            assert_eq!(
                recovery_view[field], reconnect_view[field],
                "regional reconnect diverged at {field}"
            );
        }

        let final_seq = current_world_seq(
            &open_event_store(&recovery_path).unwrap(),
            OFFICIAL_WORLD_ID,
        )
        .unwrap();
        let suffix = read_event_store_forward_between(
            &recovery_path,
            baseline_seq,
            final_seq,
            MAX_EVENT_STORE_SCAN,
        )
        .expect("read regional recovery suffix");
        assert!(suffix.windows(2).all(|pair| pair[1].seq == pair[0].seq + 1));
        assert_eq!(
            suffix
                .iter()
                .map(|event| event.seq)
                .collect::<BTreeSet<_>>()
                .len(),
            suffix.len(),
            "regional suffix contains duplicate event ids"
        );
        for content in hot_messages.iter().map(String::as_str).chain([
            "handoff stayed contiguous",
            "process loss kept one history",
            "recovery kept the committed prefix",
            "both regions rejoined one world",
        ]) {
            assert_eq!(
                suffix
                    .iter()
                    .filter(|event| {
                        event.type_name == "message.created"
                            && event.content.as_deref() == Some(content)
                    })
                    .count(),
                1,
                "message {content:?} was lost or duplicated"
            );
        }
        assert!(!suffix.iter().any(|event| {
            event.type_name == "message.created"
                && event.content.as_deref() == Some("this must not fork")
        }));

        recovery_convergence.abort();
        reconnect_convergence.abort();
        recovery_server.abort();
        reconnect_server.abort();
        drop(client);
        for path in [&primary_path, &recovery_path, &quarantine_path] {
            let _ = fs::remove_file(path);
        }
    }

    #[tokio::test]
    async fn committed_command_survives_response_loss_and_replays_once() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-canonical-command-restart-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let actor_id = 5000;
        let state = test_app_state(RuntimeWorld::seeded(), Some(path.clone()));
        {
            let mut runtime = state.inner.lock().await;
            let mut create = JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_CREATE_ACTOR,
                    actor_id,
                    location_id: COSY_COTTAGE_LOCATION_ID,
                    ..CwAction::default()
                },
                71_000,
            );
            create.actor_meta_upserts.insert(
                actor_id,
                ActorMeta {
                    name: "Restart Neighbour".to_string(),
                    speech_mode: "prose".to_string(),
                    title: "Receipt Witness".to_string(),
                    description: "A test avatar surviving response loss.".to_string(),
                },
            );
            assert_eq!(
                commit_journal_record(&state, &mut runtime, create)
                    .expect("commit restart actor")
                    .0,
                CW_OK
            );
        }
        let actor_session = create_actor_session(&state.actor_sessions, actor_id).0;
        let request = {
            let runtime = state.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_id,
                &actor_session,
                "test:response-loss",
                "say this lands exactly once",
            )
        };
        let client = ConnectInfo("127.0.0.1:45131".parse().unwrap());
        let first = command(client, State(state.clone()), Json(request.clone()))
            .await
            .0;
        assert!(first.ok, "{first:?}");

        let (journal_after_first, events_after_first, receipt_finalized, committed_seq) = {
            let conn = open_event_store(&path).expect("inspect committed command");
            let journal = conn
                .query_row("SELECT COUNT(*) FROM action_journal", [], |row| {
                    row.get::<_, i64>(0)
                })
                .unwrap();
            let events = conn
                .query_row("SELECT COUNT(*) FROM world_events", [], |row| {
                    row.get::<_, i64>(0)
                })
                .unwrap();
            let finalized = conn
                .query_row(
                    "SELECT finalized FROM canonical_command_receipts
                     WHERE world_id = ?1 AND intent_id = ?2",
                    params![OFFICIAL_WORLD_ID, "test:response-loss"],
                    |row| row.get::<_, i64>(0),
                )
                .unwrap();
            let committed_seq = current_world_seq(&conn, OFFICIAL_WORLD_ID).unwrap();
            (journal, events, finalized, committed_seq)
        };
        assert_eq!(receipt_finalized, 1);
        assert_eq!(
            first.receipt.as_ref().map(|receipt| receipt.world_seq),
            Some(committed_seq)
        );

        state.inner.lock().await.command_receipts.clear();
        let second = command(client, State(state), Json(request)).await.0;
        assert_eq!(
            serde_json::to_value(&first).unwrap(),
            serde_json::to_value(&second).unwrap()
        );

        let conn = open_event_store(&path).expect("inspect idempotent replay");
        assert_eq!(
            conn.query_row("SELECT COUNT(*) FROM action_journal", [], |row| row
                .get::<_, i64>(0))
                .unwrap(),
            journal_after_first
        );
        assert_eq!(
            conn.query_row("SELECT COUNT(*) FROM world_events", [], |row| row
                .get::<_, i64>(0))
                .unwrap(),
            events_after_first
        );
        assert_eq!(
            conn.query_row(
                "SELECT COUNT(*) FROM canonical_command_receipts",
                [],
                |row| row.get::<_, i64>(0)
            )
            .unwrap(),
            1
        );
        drop(conn);
        let _ = fs::remove_file(path);
    }

    #[tokio::test]
    async fn stale_canonical_entity_versions_fail_closed() {
        let actor_id = 5000;
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            actor_id,
            COSY_COTTAGE_LOCATION_ID,
            "Versioned Neighbour",
        );
        let state = test_app_state(runtime, None);
        let actor_session = create_actor_session(&state.actor_sessions, actor_id).0;
        let first_request = {
            let runtime = state.inner.lock().await;
            canonical_test_command_request(
                &runtime,
                actor_id,
                &actor_session,
                "test:advance-version",
                "say versions move forward",
            )
        };
        let mut stale_request = first_request.clone();
        stale_request.command = "say stale history must not land".to_string();
        stale_request
            .envelope
            .as_mut()
            .expect("canonical envelope")
            .intent_id = "test:stale-version".to_string();
        let client = ConnectInfo("127.0.0.1:45130".parse().expect("client address"));

        let first = command(client, State(state.clone()), Json(first_request))
            .await
            .0;
        assert!(first.ok, "{first:?}");
        let stale = command(client, State(state.clone()), Json(stale_request))
            .await
            .0;

        assert!(!stale.ok);
        assert_eq!(stale.status, 409);
        assert!(stale
            .output
            .as_deref()
            .is_some_and(|output| output.contains("Stale actor version")));
        let runtime = state.inner.lock().await;
        assert!(!runtime.event_log.iter().any(|event| {
            event.type_name == "message.created"
                && event.content.as_deref() == Some("stale history must not land")
        }));
    }

    fn discover_seed_exit_for_test(
        runtime: &mut RuntimeWorld,
        from_location_id: u64,
        to_location_id: u64,
    ) {
        let destination = runtime
            .location_name(to_location_id)
            .unwrap_or_else(|| format!("Location {to_location_id}"));
        let id = seed_exit_discovered_tag_id(from_location_id, to_location_id);
        runtime.tags.insert(
            id.clone(),
            RpgTagState {
                id,
                scope: "room".to_string(),
                scope_id: from_location_id,
                label: format!("path to {destination}"),
                kind: "discovery".to_string(),
                active: true,
                source_event_seq: None,
                expires: None,
            },
        );
        runtime.remember_search_discovery(
            RATI_ACTOR_ID,
            from_location_id,
            SEARCH_MEMORY_KIND_SEED_EXIT,
            to_location_id,
            &seed_exit_search_memory_subject_key(from_location_id, to_location_id),
        );
    }

    fn discover_seed_exit_pair_for_test(
        runtime: &mut RuntimeWorld,
        from_location_id: u64,
        to_location_id: u64,
    ) {
        discover_seed_exit_for_test(runtime, from_location_id, to_location_id);
        discover_seed_exit_for_test(runtime, to_location_id, from_location_id);
    }

    fn discover_all_seed_exits_for_test(runtime: &mut RuntimeWorld) {
        for exit in &active_content().exits {
            discover_seed_exit_for_test(runtime, exit.from_location_id, exit.to_location_id);
        }
    }

    fn move_test_actor(
        runtime: &mut RuntimeWorld,
        actor_id: u64,
        destination_location_id: u64,
        seed: u64,
    ) {
        let mut action = CwAction::default();
        action.kind = CW_ACTION_MOVE;
        action.actor_id = actor_id;
        action.destination_location_id = destination_location_id;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(action, seed))
                .0,
            CW_OK
        );
    }

    fn signed_narrative_move(
        signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        session_id: &str,
        character_id: u64,
        command: &str,
        nonce: &str,
        issued_at_unix: u64,
    ) -> SignedNarrativeMove {
        use ed25519_dalek::Signer;

        let command = normalize_command_text(command);
        let message = narrative_move_signature_message(
            wallet_address,
            session_id,
            character_id,
            &command,
            nonce,
            issued_at_unix,
        );
        SignedNarrativeMove {
            wallet_address: wallet_address.to_string(),
            command,
            nonce: nonce.to_string(),
            issued_at_unix,
            signature: WalletSignatureInput::Bytes(
                signing_key.sign(message.as_bytes()).to_bytes().to_vec(),
            ),
            delegation: None,
        }
    }

    fn signed_narrative_move_delegation(
        owner_signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        delegate_address: &str,
        session_id: &str,
        character_id: u64,
        issued_at_unix: u64,
        expires_at_unix: u64,
    ) -> NarrativeMoveDelegation {
        use ed25519_dalek::Signer;

        let message = narrative_move_delegation_message(
            wallet_address,
            delegate_address,
            session_id,
            character_id,
            issued_at_unix,
            expires_at_unix,
        );
        NarrativeMoveDelegation {
            delegate_address: delegate_address.to_string(),
            issued_at_unix,
            expires_at_unix,
            signature: WalletSignatureInput::Bytes(
                owner_signing_key
                    .sign(message.as_bytes())
                    .to_bytes()
                    .to_vec(),
            ),
        }
    }

    fn delegated_narrative_move(
        delegate_signing_key: &ed25519_dalek::SigningKey,
        wallet_address: &str,
        delegate_address: &str,
        session_id: &str,
        character_id: u64,
        command: &str,
        nonce: &str,
        issued_at_unix: u64,
        delegation: NarrativeMoveDelegation,
    ) -> SignedNarrativeMove {
        use ed25519_dalek::Signer;

        let command = normalize_command_text(command);
        let message = delegated_narrative_move_signature_message(
            wallet_address,
            delegate_address,
            session_id,
            character_id,
            &command,
            nonce,
            issued_at_unix,
        );
        SignedNarrativeMove {
            wallet_address: wallet_address.to_string(),
            command,
            nonce: nonce.to_string(),
            issued_at_unix,
            signature: WalletSignatureInput::Bytes(
                delegate_signing_key
                    .sign(message.as_bytes())
                    .to_bytes()
                    .to_vec(),
            ),
            delegation: Some(delegation),
        }
    }

    #[test]
    fn action_backed_command_failures_include_visible_output() {
        let resolved = ResolvedCommand {
            command: "attack Coach".to_string(),
            verb: "attack".to_string(),
            action: Some(command_action("attack", "Attack", "attack Coach")),
            dispatch: CommandDispatch::Attack {
                target_actor_id: 1004,
            },
        };
        let lost = command_action_failure_output(&resolved, 500);
        let reconnect = command_action_failure_output(&resolved, 403);
        let hurried = command_action_failure_output(&resolved, RATE_LIMITED_STATUS);

        let Json(response) = command_action_response_with_events(
            resolved,
            ActionResponse {
                ok: false,
                status: 409,
                events: Vec::new(),
            },
            Vec::new(),
        );

        assert!(!response.ok);
        assert_eq!(
            response.output.as_deref(),
            Some("There is no need to fight here now.")
        );
        assert_eq!(
            lost,
            "That choice got lost before the room could answer. Try once more."
        );
        assert_eq!(
            reconnect,
            "Your avatar slipped out of reach. Begin again or reconnect your account."
        );
        assert_eq!(hurried, "The room needs a breath. Try again in a moment.");
        assert!(![lost, reconnect, hurried].iter().any(|copy| {
            let lowered = copy.to_lowercase();
            lowered.contains("committed")
                || lowered.contains("session")
                || lowered.contains("status")
        }));
    }

