    fn hide_seed_items(runtime: &mut RuntimeWorld) {
        for item in &mut runtime.world.items[..runtime.world.item_count] {
            if (2001..=2010).contains(&item.id) {
                item.location_id = 0;
                item.holder_actor_id = 0;
                item.held_since_tick = 0;
            }
        }
    }

    fn insert_wallet_session(state: &AppState, token: &str, wallet_address: &str) {
        state
            .wallet_sessions
            .lock()
            .expect("wallet sessions")
            .sessions
            .insert(
                token.to_string(),
                WalletSession {
                    wallet_address: wallet_address.to_string(),
                    linked_wallet_addresses: Vec::new(),
                    expires_at: Instant::now() + Duration::from_secs(3600),
                },
            );
    }

