    #[test]
    fn legacy_single_writer_store_migrates_in_place_to_canonical_journal() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-canonical-migration-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let legacy_event = EventView {
            seq: 42,
            type_name: "world.legacy_checkpoint".to_string(),
            success: true,
            location_id: Some(COSY_COTTAGE_LOCATION_ID),
            ..EventView::default()
        };
        let conn = Connection::open(&path).unwrap();
        conn.execute_batch(
            "CREATE TABLE world_events (
                seq INTEGER PRIMARY KEY,
                event_type TEXT NOT NULL,
                payload_json TEXT NOT NULL,
                created_at_ms INTEGER NOT NULL
             );",
        )
        .unwrap();
        conn.execute(
            "INSERT INTO world_events (seq, event_type, payload_json, created_at_ms)
             VALUES (?1, ?2, ?3, 1)",
            params![
                legacy_event.seq as i64,
                legacy_event.type_name,
                serde_json::to_string(&legacy_event).unwrap()
            ],
        )
        .unwrap();
        drop(conn);

        init_event_store(&path).expect("migrate legacy single-writer store");
        let conn = open_event_store(&path).unwrap();
        let event_columns = conn
            .prepare("PRAGMA table_info(world_events)")
            .unwrap()
            .query_map([], |row| row.get::<_, String>(1))
            .unwrap()
            .collect::<Result<BTreeSet<_>, _>>()
            .unwrap();
        assert!(event_columns.contains("world_id"));
        assert!(event_columns.contains("world_epoch"));
        assert_eq!(current_world_seq(&conn, OFFICIAL_WORLD_ID).unwrap(), 42);
        assert_eq!(
            conn.query_row(
                "SELECT world_id, world_epoch FROM world_events WHERE seq = 42",
                [],
                |row| Ok((row.get::<_, String>(0)?, row.get::<_, i64>(1)?))
            )
            .unwrap(),
            (OFFICIAL_WORLD_ID.to_string(), OFFICIAL_WORLD_EPOCH as i64)
        );
        for table in [
            "canonical_world_state",
            "canonical_partition_leases",
            "canonical_entity_versions",
            "canonical_claims",
            "canonical_commits",
        ] {
            let exists = conn
                .query_row(
                    "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = ?1",
                    params![table],
                    |row| row.get::<_, i64>(0),
                )
                .unwrap();
            assert_eq!(exists, 1, "{table} should be migrated in place");
        }
        drop(conn);

        append_event_store(
            &path,
            &[EventView {
                seq: 43,
                type_name: "world.after_migration".to_string(),
                success: true,
                ..EventView::default()
            }],
        )
        .expect("append after canonical migration");
        assert_eq!(
            read_event_store(&path, Some(42), 10)
                .unwrap()
                .iter()
                .map(|event| event.seq)
                .collect::<Vec<_>>(),
            vec![43]
        );
        let _ = fs::remove_file(path);
    }

    #[test]
    fn event_store_appends_and_reads_after_seq() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-events-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);

        let events = vec![
            EventView {
                seq: 1,
                type_name: "world.bootstrapped".to_string(),
                success: true,
                reason: 0,
                actor_id: None,
                actor_name: None,
                target_actor_id: None,
                target_actor_name: None,
                location_id: Some(1),
                location_name: Some("The Cosy Cottage".to_string()),
                destination_location_id: None,
                destination_location_name: None,
                content_id: None,
                content: None,
                item_id: None,
                item_name: None,
                raw_roll: None,
                modifier: None,
                total: None,
                dc: None,
                damage: None,
                current_hp: None,
                ..EventView::default()
            },
            EventView {
                seq: 2,
                type_name: "message.created".to_string(),
                success: true,
                reason: 0,
                actor_id: Some(5000),
                actor_name: Some("Mira".to_string()),
                target_actor_id: None,
                target_actor_name: None,
                location_id: Some(1),
                location_name: Some("The Cosy Cottage".to_string()),
                destination_location_id: None,
                destination_location_name: None,
                content_id: Some(9001),
                content: Some("hello".to_string()),
                item_id: None,
                item_name: None,
                raw_roll: None,
                modifier: None,
                total: None,
                dc: None,
                damage: None,
                current_hp: None,
                ..EventView::default()
            },
        ];

        append_event_store(&path, &events).expect("append events");
        append_event_store(&path, &events).expect("idempotent append");

        let loaded = read_event_store(&path, Some(1), MAX_EVENT_STORE_SCAN).expect("read events");
        assert_eq!(loaded.len(), 1);
        assert_eq!(loaded[0].seq, 2);
        assert_eq!(loaded[0].content.as_deref(), Some("hello"));
        assert_eq!(loaded[0].content_context.mapping_version, 1);
        assert!(loaded[0]
            .content_context
            .references
            .iter()
            .any(|reference| reference.canonical_ref == "pack://cosyworld.core/location/1"));

        let _ = fs::remove_file(path);
    }

    #[test]
    fn room_memory_chapters_persist_prior_days_in_order() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-room-memory-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);

        upsert_room_memory_chapter(
            &path,
            COSY_COTTAGE_LOCATION_ID,
            20_600,
            12,
            "The cottage learned that Moss Lantern carried rain on their sleeve.",
            "llm",
        )
        .expect("persist first chapter");
        upsert_room_memory_chapter(
            &path,
            COSY_COTTAGE_LOCATION_ID,
            20_601,
            18,
            "Rati listened as the room turned toward Moonwool Thread.",
            "fallback",
        )
        .expect("persist second chapter");
        upsert_room_memory_chapter(
            &path,
            RAIN_SOFT_GARDEN_LOCATION_ID,
            20_601,
            19,
            "The garden kept its own rain-bright discovery.",
            "llm",
        )
        .expect("persist other room chapter");

        let prior = load_room_memory_prior_chapters(&path, COSY_COTTAGE_LOCATION_ID, 20_602, 8)
            .expect("load prior chapters");
        assert_eq!(
            prior
                .iter()
                .map(|chapter| chapter.day_index)
                .collect::<Vec<_>>(),
            vec![20_600, 20_601]
        );
        assert_eq!(prior[0].source, "llm");
        assert!(prior[1].summary.contains("Moonwool Thread"));

        let before_second =
            load_room_memory_prior_chapters(&path, COSY_COTTAGE_LOCATION_ID, 20_601, 8)
                .expect("load before second day");
        assert_eq!(before_second.len(), 1);
        assert_eq!(before_second[0].day_index, 20_600);

        let _ = fs::remove_file(path);
    }

