    #[tokio::test]
    async fn moderation_suspend_broadcasts_presence_leave_and_blocks_session() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 17635);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Suspended Presence".to_string(),
                speech_mode: "prose".to_string(),
                title: "Moderation Tester".to_string(),
                description: "A test avatar checking suspension fanout.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        let mut state = test_app_state(runtime, None);
        state.moderation_token = Some(Arc::new("audit-secret".to_string()));
        let (actor_session, _) = issue_actor_session(&state, 5000);
        assert_eq!(
            ping_actor_session_for_actor(&state.actor_sessions, 5000, &actor_session),
            Some(false)
        );
        assert!(active_actor_ids_for_state(&state).contains(&5000));
        let mut rx = state.tx.subscribe();
        let mut headers = HeaderMap::new();
        headers.insert(
            header::AUTHORIZATION,
            "Bearer audit-secret".parse().unwrap(),
        );

        let denied_suspend = moderation_suspend_actor(
            HeaderMap::new(),
            State(state.clone()),
            AxumPath(5000),
            Json(ModerationSuspendRequest {
                reason: Some("ignored".to_string()),
            }),
        )
        .await
        .0;
        assert!(!denied_suspend.ok);
        assert_eq!(denied_suspend.status, 403);
        assert_eq!(
            denied_suspend.error.as_deref(),
            Some("moderation bearer token required")
        );

        let denied_unsuspend =
            moderation_unsuspend_actor(HeaderMap::new(), State(state.clone()), AxumPath(5000))
                .await
                .0;
        assert!(!denied_unsuspend.ok);
        assert_eq!(denied_unsuspend.status, 403);
        assert_eq!(
            denied_unsuspend.error.as_deref(),
            Some("moderation bearer token required")
        );

        let inference_controlled_suspend = moderation_suspend_actor(
            headers.clone(),
            State(state.clone()),
            AxumPath(1001),
            Json(ModerationSuspendRequest {
                reason: Some("not a player avatar".to_string()),
            }),
        )
        .await
        .0;
        assert!(!inference_controlled_suspend.ok);
        assert_eq!(inference_controlled_suspend.status, 404);
        assert_eq!(
            inference_controlled_suspend.error.as_deref(),
            Some("actor was not found or is not directly controlled")
        );

        let suspended = moderation_suspend_actor(
            headers,
            State(state.clone()),
            AxumPath(5000),
            Json(ModerationSuspendRequest {
                reason: Some(" room safety ".to_string()),
            }),
        )
        .await
        .0;

        assert!(suspended.ok);
        assert_eq!(suspended.status, 200);
        assert!(suspended.suspended);
        assert_eq!(suspended.reason.as_deref(), Some("room safety"));
        assert!(suspended.error.is_none());
        assert!(!active_actor_ids_for_state(&state).contains(&5000));
        let broadcast = rx.try_recv().expect("suspension presence broadcast");
        assert_eq!(broadcast.type_name, "actor.presence");
        assert_eq!(broadcast.actor_id, Some(5000));
        assert_eq!(broadcast.content.as_deref(), Some("inactive"));

        let denied_speech = say(
            ConnectInfo("127.0.0.1:0".parse().unwrap()),
            State(state.clone()),
            Json(SayRequest {
                actor_id: 5000,
                actor_session: Some(actor_session),
                content: "still here?".to_string(),
            }),
        )
        .await
        .0;
        assert!(!denied_speech.ok);
        assert_eq!(denied_speech.status, 403);
        assert!(denied_speech.events.is_empty());
    }

    #[test]
    fn action_journal_replays_runtime_state() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-journal-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);

        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;

        let mut create_record = JournalRecord::new(create, 12345);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Replay".to_string(),
                speech_mode: "prose".to_string(),
                title: "Replay Traveler".to_string(),
                description: "A journal replay fixture.".to_string(),
            },
        );

        let mut say = CwAction::default();
        say.kind = CW_ACTION_SAY;
        say.actor_id = 5000;
        say.content_id = 9001;

        let mut say_record = JournalRecord::new(say, 12346);
        say_record
            .content_upserts
            .insert(9001, "hello from the journal".to_string());

        append_action_journal(&path, &create_record).expect("append create");
        append_action_journal(&path, &say_record).expect("append say");

        assert!(action_journal_has_records(&path).expect("has records"));
        let records = read_action_journal(&path).expect("read records");
        assert_eq!(records.len(), 2);
        assert_eq!(records[0].version, 6);
        assert_eq!(records[0].content_context.mapping_version, 1);
        let location_reference = records[0]
            .content_context
            .references
            .iter()
            .find(|reference| reference.canonical_ref == "pack://cosyworld.core/location/1")
            .expect("journal persists its canonical location reference");
        assert_eq!(location_reference.pack_version, "1.3.6");
        assert_eq!(location_reference.legacy_runtime_id, Some(1));

        let replayed = RuntimeWorld::from_action_journal(&path).expect("replay runtime");
        assert_eq!(replayed.actor_name(5000).as_deref(), Some("Replay"));
        assert_eq!(
            replayed.content.get(&9001).map(String::as_str),
            Some("hello from the journal")
        );
        assert!(replayed.actor_by_id(5000).is_some());
        assert!(replayed
            .event_log
            .iter()
            .any(|event| event.type_name == "message.created" && event.content_id == Some(9001)));

        let _ = fs::remove_file(path);
    }

    #[test]
    fn action_journal_replays_declared_worldpack_epochs_in_order() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-migrated-journal-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let compatible_hashes = &active_content()
            .manifest
            .persistence_compatibility
            .replay_compatible_bundle_hashes;

        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = COSY_COTTAGE_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 9911);
        create_record.worldpack_bundle_hash = compatible_hashes[0].clone();
        for reference in &mut create_record.content_context.references {
            if reference.pack_id == "cosyworld.core" {
                reference.pack_version = "1.0.0".to_string();
            }
        }
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Migrated Traveler".to_string(),
                speech_mode: "prose".to_string(),
                title: "Epoch Walker".to_string(),
                description: "A continuity migration fixture.".to_string(),
            },
        );

        let mut say = CwAction::default();
        say.kind = CW_ACTION_SAY;
        say.actor_id = 5000;
        say.content_id = 9001;
        let mut say_record = JournalRecord::new(say, 9912);
        say_record.worldpack_bundle_hash = compatible_hashes[1].clone();
        say_record.content_context = ContentReferenceContext::default();
        say_record
            .content_upserts
            .insert(9001, "hello across worldpack epochs".to_string());

        append_action_journal(&path, &create_record).expect("append migrated create");
        append_action_journal(&path, &say_record).expect("append migrated speech");
        for (index, bundle_hash) in compatible_hashes.iter().enumerate().skip(2) {
            let content_id = 9000 + index as u64;
            let mut say = CwAction::default();
            say.kind = CW_ACTION_SAY;
            say.actor_id = 5000;
            say.content_id = content_id;
            let mut epoch_record = JournalRecord::new(say, 9912 + index as u64);
            epoch_record.worldpack_bundle_hash = bundle_hash.clone();
            epoch_record.content_context = ContentReferenceContext::default();
            epoch_record.content_upserts.insert(
                content_id,
                format!("hello from declared worldpack epoch {index}"),
            );
            append_action_journal(&path, &epoch_record).expect("append declared worldpack epoch");
        }

        let replay_hashes = read_action_journal(&path)
            .expect("read migrated journal")
            .into_iter()
            .map(|record| record.worldpack_bundle_hash)
            .collect::<Vec<_>>();
        assert_eq!(replay_hashes, *compatible_hashes);

        let replayed = RuntimeWorld::from_action_journal(&path)
            .expect("declared journal epochs replay against current content");
        assert_eq!(
            replayed.actor_name(5000).as_deref(),
            Some("Migrated Traveler")
        );
        assert_eq!(
            replayed.content.get(&9001).map(String::as_str),
            Some("hello across worldpack epochs")
        );
        assert!(replayed.actor_by_id(5000).is_some());

        let _ = fs::remove_file(path);
    }

    #[test]
    fn unavailable_pack_journal_is_inspectable_but_not_replayable() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-missing-pack-journal-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let mut record = JournalRecord::new(CwAction::default(), 44);
        record
            .content_context
            .references
            .push(ContentReferenceEntry {
                canonical_ref: "pack://unavailable.pack/creature/goblin".to_string(),
                pack_id: "unavailable.pack".to_string(),
                pack_version: "1.0.0".to_string(),
                kind: "creature".to_string(),
                local_id: "goblin".to_string(),
                runtime_handle: 1_000_000_000_001,
                legacy_runtime_id: None,
            });
        append_action_journal(&path, &record).expect("journal remains writable for inspection");

        let records = read_action_journal(&path).expect("missing-pack journal remains readable");
        assert_eq!(records.len(), 1);
        let unavailable = records[0]
            .content_context
            .references
            .iter()
            .find(|reference| reference.pack_id == "unavailable.pack")
            .expect("self-contained missing-pack identity survives");
        assert_eq!(unavailable.local_id, "goblin");
        assert_eq!(
            content_registry().inspect_content_reference(unavailable),
            ContentReferenceStatus::MissingPack
        );
        let error = RuntimeWorld::from_action_journal(&path).unwrap_err();
        assert!(error.to_string().contains("MissingPack"));

        let _ = fs::remove_file(path);
    }

