    #[tokio::test]
    async fn scarce_item_race_has_one_winner_and_a_causal_losing_result() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(&mut runtime, 5000, 2, "First Picker");
        create_test_human(&mut runtime, 5001, 2, "Second Picker");
        let item = runtime
            .world
            .items
            .iter_mut()
            .take(runtime.world.item_count)
            .find(|item| item.id == 2002)
            .expect("scarce test item");
        item.location_id = 2;
        item.holder_actor_id = 0;
        let replay_base = RuntimeSnapshot::from_runtime(&runtime);
        let path = std::env::temp_dir().join(format!(
            "cosyworld-target-race-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        let state = test_app_state(runtime, Some(path.clone()));
        let (first_session, _) = issue_actor_session(&state, 5000);
        let (second_session, _) = issue_actor_session(&state, 5001);

        let first = pick_up_item(
            ConnectInfo("127.0.0.1:43130".parse().unwrap()),
            State(state.clone()),
            Json(ItemRequest {
                actor_id: 5000,
                actor_session: Some(first_session),
                item_id: 2002,
                target_item_id: None,
                target_actor_id: None,
            }),
        )
        .await
        .0;
        assert!(first.ok);

        let second = pick_up_item(
            ConnectInfo("127.0.0.1:43131".parse().unwrap()),
            State(state.clone()),
            Json(ItemRequest {
                actor_id: 5001,
                actor_session: Some(second_session),
                item_id: 2002,
                target_item_id: None,
                target_actor_id: None,
            }),
        )
        .await
        .0;
        assert!(!second.ok);
        let conflict = second
            .events
            .iter()
            .find(|event| event.type_name == "action.conflict")
            .expect("losing write explains its target conflict");
        assert!(conflict
            .content
            .as_deref()
            .is_some_and(|content| content.contains("Nothing was duplicated")));

        let runtime = state.inner.lock().await;
        assert_eq!(
            runtime
                .world
                .items
                .iter()
                .take(runtime.world.item_count)
                .find(|item| item.id == 2002)
                .map(|item| item.holder_actor_id),
            Some(5000)
        );
        drop(runtime);
        let journal = read_action_journal(&path).expect("race journal");
        let mut replayed = replay_base
            .into_runtime()
            .expect("race checkpoint restores");
        let replay_statuses = journal
            .iter()
            .map(|record| replayed.apply_journal_record(record).0)
            .collect::<Vec<_>>();
        assert_eq!(replay_statuses.first().copied(), Some(CW_OK));
        assert!(replay_statuses
            .last()
            .is_some_and(|status| *status != CW_OK));
        assert_eq!(
            replayed
                .world
                .items
                .iter()
                .take(replayed.world.item_count)
                .find(|item| item.id == 2002)
                .map(|item| item.holder_actor_id),
            Some(5000)
        );
        let _ = fs::remove_file(path);
    }

    #[tokio::test]
    async fn bracelet_growth_returns_authoritative_state_and_cannot_repeat_without_advancement() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Bracelet Tester",
        );
        grant_test_advancement(&mut runtime, 5000, "test:bracelet-receipt");
        let wolfprint = runtime
            .world
            .items
            .iter_mut()
            .take(runtime.world.item_count)
            .find(|item| item.id == 2003)
            .expect("Wolfprint Charm exists");
        wolfprint.location_id = 0;
        wolfprint.holder_actor_id = 5000;
        wolfprint.zone = CW_CARD_ZONE_CARRIED;
        assert!(!runtime
            .set_charm_equipped(5000, 2003, true, "test")
            .is_empty());
        give_test_skill_charm(&mut runtime, 5000, 2900, "Thimble Charm");
        let deck_before = runtime.deck_view(Some(5000));
        let carried_count = deck_before.carried_cards.len();
        let expansion = deck_before
            .charm_slot_expansion
            .expect("a full bracelet and an unworn charm expose concrete demand");
        assert_eq!(expansion.label, "Make room for Thimble Charm");
        assert!(expansion.explanation.contains("Your Journal holds 1"));
        let state = test_app_state(runtime, None);
        let (actor_session, _) = issue_actor_session(&state, 5000);

        let response = unlock_charm_slot(
            ConnectInfo("127.0.0.1:43010".parse().expect("client address")),
            State(state.clone()),
            Json(ActorRequest {
                actor_id: 5000,
                actor_session: Some(actor_session.clone()),
            }),
        )
        .await
        .0;

        assert!(response.ok);
        assert_eq!(response.status, CW_OK);
        assert!(response
            .events
            .iter()
            .any(|event| event.type_name == "advancement.spent"));
        assert!(response.events.iter().any(|event| {
            event.type_name == "charm_slot.unlocked" && event.item_id == Some(2900)
        }));
        let receipt = response
            .events
            .iter()
            .find(|event| event.type_name == "action.receipt")
            .and_then(|event| event.content.as_deref())
            .and_then(|content| serde_json::from_str::<serde_json::Value>(content).ok())
            .expect("bracelet growth returns its updated authoritative state");
        assert_eq!(receipt["state"]["deck"]["bracelet_slots"], 2);
        assert_eq!(receipt["state"]["ledger"]["spent_count"], 1);
        assert_eq!(receipt["state"]["ledger"]["advancement_points"], 0);
        assert_eq!(
            receipt["state"]["deck"]["carried_cards"]
                .as_array()
                .map(Vec::len),
            Some(carried_count)
        );
        assert_eq!(
            receipt["state"]["deck"]["equipped_charms"]
                .as_array()
                .map(Vec::len),
            Some(1)
        );
        assert!(receipt["state"]["primary_action"]["options"]
            .as_array()
            .is_some_and(|options| options
                .iter()
                .all(|option| option["kind"] != "unlock_charm_slot")));

        let repeat = unlock_charm_slot(
            ConnectInfo("127.0.0.1:43010".parse().expect("client address")),
            State(state),
            Json(ActorRequest {
                actor_id: 5000,
                actor_session: Some(actor_session),
            }),
        )
        .await
        .0;
        assert!(!repeat.ok);
        assert_eq!(repeat.status, 409);
        assert!(repeat.events.is_empty());
    }

