    #[tokio::test]
    async fn inactive_inventory_cleanup_skips_stale_canonical_versions() {
        let actor_id = 5000;
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            actor_id,
            COSY_COTTAGE_LOCATION_ID,
            "Versioned Collector",
        );
        let held_since_tick = runtime.world.tick;
        let story = runtime
            .world
            .items
            .iter_mut()
            .find(|item| item.id == STORY_BUTTON_ITEM_ID)
            .expect("Story Button exists");
        story.holder_actor_id = actor_id;
        story.location_id = 0;
        story.held_since_tick = held_since_tick;
        let expected_versions = [
            ("actor", actor_id),
            ("journal", actor_id),
            ("location", COSY_COTTAGE_LOCATION_ID),
            ("item", STORY_BUTTON_ITEM_ID),
        ]
        .into_iter()
        .filter_map(|(kind, handle)| {
            runtime
                .canonical_ref(kind, handle)
                .map(|entity_ref| (entity_ref.to_string(), runtime.entity_version(entity_ref)))
        })
        .collect::<BTreeMap<_, _>>();
        let item_ref = runtime
            .canonical_ref("item", STORY_BUTTON_ITEM_ID)
            .expect("Story Button canonical ref")
            .to_string();
        let path = std::env::temp_dir().join(format!(
            "cosyworld-stale-inactive-inventory-{}.sqlite",
            random_hex(8)
        ));
        let state = test_app_state(runtime, Some(path.clone()));
        let conn = open_event_store(&path).expect("open canonical test store");
        for (entity_ref, version) in &expected_versions {
            let stored_version = if entity_ref == &item_ref {
                version.saturating_add(1)
            } else {
                *version
            };
            conn.execute(
                "INSERT INTO canonical_entity_versions
                    (world_id, entity_ref, entity_version, updated_at_ms)
                 VALUES (?1, ?2, ?3, ?4)",
                params![
                    OFFICIAL_WORLD_ID,
                    entity_ref,
                    stored_version as i64,
                    now_millis() as i64
                ],
            )
            .expect("seed canonical entity version");
        }
        drop(conn);

        let mut runtime = state.inner.lock().await;
        let events = release_inactive_direct_inventory_locked(&state, &mut runtime);

        assert!(events.is_empty());
        assert!(runtime.world.items[..runtime.world.item_count]
            .iter()
            .any(|item| {
                item.id == STORY_BUTTON_ITEM_ID
                    && item.holder_actor_id == actor_id
                    && item.location_id == 0
            }));
        drop(runtime);
        assert_eq!(
            state
                .event_store_health
                .lock()
                .expect("event store health")
                .consecutive_append_failures,
            0
        );
        assert!(state
            .inactive_inventory_release_conflicts
            .lock()
            .expect("inactive inventory conflicts")
            .contains(&(actor_id, STORY_BUTTON_ITEM_ID)));
        let _ = fs::remove_file(path);
    }

    #[test]
    fn explicit_leave_marks_actor_session_inactive_until_reused() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 17600);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Presence Guest".to_string(),
                speech_mode: "prose".to_string(),
                title: "Presence Tester".to_string(),
                description: "A test avatar checking explicit leave presence.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        let actor_sessions = StdMutex::new(ActorSessions::default());
        let (session_token, _) = create_actor_session(&actor_sessions, 5000);
        assert!(!active_actor_ids(&actor_sessions).contains(&5000));
        assert_eq!(
            ping_actor_session_for_actor(&actor_sessions, 5000, &session_token),
            Some(false)
        );
        assert!(active_actor_ids(&actor_sessions).contains(&5000));
        assert!(!mark_actor_session_inactive(
            &actor_sessions,
            5001,
            &session_token
        ));
        assert!(active_actor_ids(&actor_sessions).contains(&5000));
        assert!(mark_actor_session_inactive(
            &actor_sessions,
            5000,
            &session_token
        ));
        assert!(!active_actor_ids(&actor_sessions).contains(&5000));
        assert_eq!(
            ping_actor_session_for_actor(&actor_sessions, 5000, &session_token),
            None
        );
        assert!(!active_actor_ids(&actor_sessions).contains(&5000));
        assert!(client_actor_authorized(
            &runtime,
            &actor_sessions,
            5000,
            Some(&session_token)
        ));
        assert!(active_actor_ids(&actor_sessions).contains(&5000));
    }

