    #[test]
    fn srd_action_replay_golden_is_byte_stable_and_offline() {
        let fixture: serde_json::Value = serde_json::from_str(include_str!(
            "../tests/fixtures/srd-action-replay-golden-v2.json"
        ))
        .expect("golden replay fixture is valid JSON");
        assert_eq!(
            fixture.get("schema").and_then(serde_json::Value::as_str),
            Some("cosyworld.replay-golden/2")
        );
        let records: Vec<JournalRecord> = serde_json::from_value(
            fixture
                .get("records")
                .cloned()
                .expect("golden fixture has journal records"),
        )
        .expect("golden journal records deserialize without migration or network access");
        assert!(records.iter().any(|record| {
            record.version == 1 && record.action.kind == CW_ACTION_ABILITY_CHECK
        }));
        assert!(records
            .iter()
            .any(|record| { record.version == 1 && record.action.kind == CW_ACTION_ATTACK }));
        assert!(records
            .iter()
            .any(|record| { record.version == 1 && record.action.kind == CW_ACTION_COMBAT_START }));
        assert!(records
            .iter()
            .any(|record| { record.rules_action.as_deref() == Some("srd5.2.1:search") }));
        assert!(records
            .iter()
            .any(|record| { record.rules_action.as_deref() == Some("srd5.2.1:study") }));
        assert!(records
            .iter()
            .any(|record| !record.projection_mutations.is_empty()));

        let mut direct_replay = RuntimeWorld::seeded();
        for record in &records {
            let (status, events) = direct_replay.apply_journal_record(record);
            assert_eq!(
                status, CW_OK,
                "golden record kind {} must remain replayable",
                record.action.kind
            );
            if record.action.kind == CW_ACTION_RULES_STUDY {
                assert!(events
                    .iter()
                    .any(|event| event.type_name == "study.resolved"));
            }
        }

        let path = std::env::temp_dir().join(format!(
            "cosyworld-srd-replay-golden-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        for record in &records {
            append_action_journal(&path, record).expect("append golden journal record");
        }
        let replayed = RuntimeWorld::from_action_journal(&path)
            .expect("golden journal replays under its declared profile");
        let _ = fs::remove_file(path);

        let relevant_types = BTreeSet::from([
            "actor.created",
            "actor.entered_location",
            "combat.attack.attempt",
            "combat.attack.hit",
            "combat.attack.miss",
            "ability_check.rolled",
            "clock.updated",
            "ledger.marked",
            "study.resolved",
            "combat.encounter.started",
            "combat.initiative.rolled",
            "combat.turn.started",
            "tag.applied",
            "job.updated",
        ]);
        let events = replayed
            .event_log
            .iter()
            .filter(|event| relevant_types.contains(event.type_name.as_str()))
            .map(|event| {
                serde_json::json!([
                    event.seq,
                    event.type_name,
                    event.success,
                    event.actor_id,
                    event.target_actor_id,
                    event.raw_roll,
                    event.modifier,
                    event.total,
                    event.dc,
                    event.damage,
                    event.current_hp,
                    event.clock_id,
                    event.clock_filled,
                    event.clock_delta,
                    event.content
                ])
            })
            .collect::<Vec<_>>();
        let actor = replayed.actor_by_id(5000).expect("golden actor exists");
        let echo = replayed
            .actor_by_id(1004)
            .expect("golden combat target exists");
        let encounter = replayed
            .combat_encounter(9003)
            .expect("combat/3 encounter start remains replayable");
        let actual = serde_json::json!({
            "rules_profile": active_content().manifest.rules_profile,
            "kernel_version": replayed.world.version,
            "world_tick": replayed.world.tick,
            "next_event_seq": replayed.world.next_event_seq,
            "actor": {
                "id": actor.id,
                "location_id": actor.location_id,
                "status": actor.status,
                "damage": actor.damage
            },
            "echo": {
                "id": echo.id,
                "status": echo.status,
                "damage": echo.damage,
                "current_hp": unsafe { cw_actor_current_hp(&echo) }
            },
            "project_clock": replayed.clocks.get(MOONLIT_PROGRESS_CLOCK_ID).map(|clock| clock.filled),
            "encounter": {
                "id": encounter.id,
                "status": encounter.status,
                "round": encounter.round,
                "participant_count": encounter.participant_count
            },
            "events": events
        });
        assert_eq!(
            actual,
            fixture
                .get("expected")
                .cloned()
                .expect("golden expected result exists"),
            "authoritative replay output changed; preserve legacy meaning or version the fixture intentionally"
        );
    }

    #[test]
    fn player_card_commit_atomically_persists_events_and_a_recoverable_actor_job() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-actor-outbox-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);
        init_event_store(&path).expect("initialize actor outbox");
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Outbox Player",
        );
        let state = test_app_state(runtime, Some(path.clone()));
        let mut runtime = state.inner.blocking_lock();
        let before_tick = runtime.world.tick;
        let mut record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            17632,
        )
        .into_player_card();
        record
            .projection_mutations
            .push(ProjectionMutation::SetTag {
                tag: RpgTagState {
                    id: "test:outbox:prepared".to_string(),
                    scope: "actor".to_string(),
                    scope_id: 5000,
                    label: "prepared".to_string(),
                    kind: "aspect".to_string(),
                    active: true,
                    source_event_seq: None,
                    expires: Some("after_work".to_string()),
                },
                reason: "actor_outbox_test".to_string(),
            });

        let (status, events) =
            commit_journal_record(&state, &mut runtime, record).expect("commit player card");
        assert_eq!(status, CW_OK);
        assert_eq!(runtime.world.tick, before_tick + 1);
        assert!(!events.is_empty());
        drop(runtime);

        let conn = open_event_store(&path).expect("open actor outbox");
        let journal_count: i64 = conn
            .query_row("SELECT COUNT(*) FROM action_journal", [], |row| row.get(0))
            .expect("journal count");
        let event_count: i64 = conn
            .query_row("SELECT COUNT(*) FROM world_events", [], |row| row.get(0))
            .expect("event count");
        let job_count: i64 = conn
            .query_row("SELECT COUNT(*) FROM actor_jobs", [], |row| row.get(0))
            .expect("job count");
        assert_eq!(journal_count, 1);
        assert_eq!(event_count, events.len() as i64);
        assert_eq!(job_count, 1);
        drop(conn);

        assert!(
            claim_next_actor_job(&path)
                .expect("inspect heartbeat delay")
                .is_none(),
            "the resident heartbeat should not fire immediately"
        );
        release_pending_actor_jobs(&path, ACTOR_JOB_KIND_PLAYER_TICK)
            .expect("release heartbeat for deterministic test");
        let first = claim_next_actor_job(&path)
            .expect("claim actor job")
            .expect("pending actor job");
        let observation = match &first.payload {
            ActorJobPayload::PlayerTick(observation) => observation,
            _ => panic!("player card queued the wrong actor payload"),
        };
        assert_eq!(observation.source_world_tick, before_tick + 1);
        assert_eq!(
            observation.caused_by_event_seq,
            events.last().map(|event| event.seq)
        );
        assert!(!append_actor_job(&path, observation).expect("dedupe actor job"));

        let conn = open_event_store(&path).expect("expire actor lease");
        conn.execute(
            "UPDATE actor_jobs SET lease_until_ms = 0 WHERE id = ?1",
            params![first.id],
        )
        .expect("expire actor lease");
        drop(conn);
        let recovered = claim_next_actor_job(&path)
            .expect("recover actor job")
            .expect("expired actor job");
        assert_eq!(recovered.id, first.id);
        assert_eq!(recovered.attempts, 2);
        complete_actor_job(&path, recovered.id).expect("complete actor job");
        assert!(claim_next_actor_job(&path)
            .expect("inspect drained outbox")
            .is_none());
        let _ = fs::remove_file(path);
    }

