            check.ability = LISTEN_ABILITY;
            check.dc = LISTEN_DC;
            let (status, events) =
                commit_journal_record(&state, &mut runtime, JournalRecord::new(check, seed))
                    .expect("commit repeated check");
            assert_eq!(status, CW_OK);
