    #[test]
    fn two_avatars_can_choose_different_strategies_but_targetless_work_cannot_advance() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            MOONLIT_TRAIL_LOCATION_ID,
            "Signs Reader",
        );
        create_test_human(
            &mut runtime,
            5001,
            MOONLIT_TRAIL_LOCATION_ID,
            "Trail Tender",
        );
        let study_intent = runtime
            .job_contribution_intent(5000, "study", None, None, None)
            .expect("first avatar can Study");
        let work_intent = runtime
            .job_contribution_intent(5001, "work", None, None, None)
            .expect("second avatar can Work");
        assert_ne!(study_intent.strategy.id, work_intent.strategy.id);
        assert_eq!(study_intent.job_id, work_intent.job_id);

        let mut study_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_RULES_STUDY,
                actor_id: 5000,
                ability: 3,
                dc: LISTEN_DC,
                ..CwAction::default()
            },
            82_201,
        )
        .into_player_card();
        study_record
            .projection_mutations
            .push(ProjectionMutation::ResolveJobContribution {
                intent: study_intent,
            });
        let mut work_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5001,
                ..CwAction::default()
            },
            82_202,
        )
        .into_player_card();
        work_record
            .projection_mutations
            .push(ProjectionMutation::ResolveJobContribution {
                intent: work_intent,
            });
        let (_, study_events) = runtime.apply_journal_record(&study_record);
        let (_, work_events) = runtime.apply_journal_record(&work_record);
        let traces = study_events
            .iter()
            .chain(work_events.iter())
            .filter(|event| event.type_name == "job.contribution.resolved")
            .map(|event| {
                serde_json::from_str::<JobContributionTrace>(
                    event.content.as_deref().expect("trace content"),
                )
                .expect("trace schema")
            })
            .collect::<Vec<_>>();
        assert_eq!(traces.len(), 2);
        assert_eq!(traces[0].job_id, MOONLIT_JOB_ID);
        assert_eq!(traces[1].job_id, MOONLIT_JOB_ID);
        assert_ne!(traces[0].strategy_id, traces[1].strategy_id);

        let mut targetless = RuntimeWorld::seeded();
        create_test_human(
            &mut targetless,
            5002,
            MOONLIT_TRAIL_LOCATION_ID,
            "Targetless Worker",
        );
        assert!(targetless
            .active_progress_clock_id_for_location(MOONLIT_TRAIL_LOCATION_ID)
            .is_some());
        targetless
            .jobs
            .get_mut(MOONLIT_JOB_ID)
            .expect("Moonlit job")
            .contribution_strategies
            .clear();
        assert!(!targetless.work_available(5002));
        assert!(!targetless.help_available(5002));
        let before = targetless.clocks[MOONLIT_PROGRESS_CLOCK_ID].filled;
        let generic = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5002,
                ..CwAction::default()
            },
            82_203,
        )
        .into_player_card();
        let (_, generic_events) = targetless.apply_journal_record(&generic);
        assert!(!generic_events
            .iter()
            .any(|event| event.type_name == "clock.updated"));
        assert_eq!(targetless.clocks[MOONLIT_PROGRESS_CLOCK_ID].filled, before);
    }

    #[tokio::test]
    async fn project_help_trades_speed_for_safe_bond_progress() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = MOONLIT_TRAIL_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7143);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Careful Helper".to_string(),
                speech_mode: "prose".to_string(),
                title: "Project Companion".to_string(),
                description: "A test avatar helping a resident instead of forcing progress."
                    .to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);
        let initial = runtime.state_response(Some(5000), &AccessContext::default());
        let help_offer = initial
            .action_offers
            .iter()
            .find(|offer| offer.kind == "help")
            .expect("help offer is exposed in the resident project room");
        assert!(help_offer.risk.is_none());
        assert_eq!(
            help_offer.target.as_ref().and_then(|target| target.id),
            Some(1004)
        );
        assert!(help_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("first help brings you closer")));
        assert!(help_offer
            .claim_key
            .as_deref()
            .is_some_and(|claim_key| claim_key == "bond_help:5000:1004"));

        let state = test_app_state(runtime, None);
        let (actor_session, _) = issue_actor_session(&state, 5000);
        assert_eq!(
            ping_actor_session_for_actor(&state.actor_sessions, 5000, &actor_session),
            Some(false)
        );
        let response = help_room(
            ConnectInfo("127.0.0.1:43111".parse().expect("client address")),
            State(state.clone()),
            Json(JobContributionRequest {
                actor_id: 5000,
                actor_session: Some(actor_session.clone()),
                job_id: None,
                strategy_id: None,
            }),
        )
        .await
        .0;
        assert!(response.ok);
        assert_eq!(response.status, CW_OK);
        assert!(response.events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_PROGRESS_CLOCK_ID)
                && event.clock_delta == Some(1)
                && event.content.as_deref()
                    == Some("job_contribution:moonlit-trail:quiet-the-echo:steady-beside-traveler")
        }));
        assert!(response.events.iter().any(|event| {
            event.type_name == "bond.deepened"
                && event.actor_id == Some(5000)
                && event.target_actor_id == Some(1004)
        }));
        assert!(!response
            .events
            .iter()
            .any(|event| event.type_name == "tag.applied"
                && event.tag_label.as_deref() == Some("tired")));

        let runtime = state.inner.lock().await;
        assert!(!runtime.tired_tag_active(5000));
        assert_eq!(
            runtime
                .clocks
                .get(MOONLIT_PROGRESS_CLOCK_ID)
                .map(|clock| clock.filled),
            Some(1)
        );
        let bond = runtime
            .bonds
            .get(&bond_id(5000, 1004))
            .expect("project help deepens a bond with the helped resident");
        assert_eq!(bond.strength, 1);
        let helped_state = runtime.state_response(Some(5000), &AccessContext::default());
        let repeat_help_offer = helped_state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "help")
            .expect("help stays available after safe contribution");
        assert!(repeat_help_offer.claim_key.is_none());
        assert!(repeat_help_offer
            .risk
            .as_deref()
            .is_some_and(|risk| risk.contains("helping again may tire you")));
        assert!(!repeat_help_offer
            .effect
            .as_deref()
            .unwrap_or_default()
            .contains("first help brings you closer"));
        drop(runtime);

        let repeat_response = help_room(
            ConnectInfo("127.0.0.1:43112".parse().expect("client address")),
            State(state.clone()),
            Json(JobContributionRequest {
                actor_id: 5000,
                actor_session: Some(actor_session),
                job_id: None,
                strategy_id: None,
            }),
        )
        .await
        .0;
        assert!(repeat_response.ok);
        assert_eq!(repeat_response.status, CW_OK);
        assert!(repeat_response.events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_PROGRESS_CLOCK_ID)
                && event.clock_delta == Some(1)
                && event.content.as_deref()
                    == Some("job_contribution:moonlit-trail:quiet-the-echo:steady-beside-traveler")
        }));
        assert!(repeat_response.events.iter().any(|event| {
            event.type_name == "tag.applied" && event.tag_label.as_deref() == Some("tired")
        }));
        let runtime = state.inner.lock().await;
        assert!(runtime.tired_tag_active(5000));
        assert!(!runtime.help_available(5000));
    }

