    #[test]
    fn defend_sets_up_active_room_project() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = MOONLIT_TRAIL_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7160);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Guard Worker".to_string(),
                speech_mode: "prose".to_string(),
                title: "Shielded Helper".to_string(),
                description: "A test avatar turning defense into project preparation.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);

        let initial = runtime.state_response(Some(5000), &AccessContext::default());
        let defend_offer = initial
            .action_offers
            .iter()
            .find(|offer| offer.kind == "defend")
            .expect("defend offer is exposed in combat project room");
        assert_eq!(defend_offer.progress, Some(2));
        assert_eq!(
            defend_offer.effect.as_deref(),
            Some("guards carefully and makes the next try count")
        );
        for offer in &initial.action_offers {
            let player_copy = format!(
                "{} {}",
                offer.effect.as_deref().unwrap_or_default(),
                offer.risk.as_deref().unwrap_or_default()
            )
            .to_ascii_lowercase();
            for forbidden in ["progress", "clock", "ledger", "tag", "projection", "kernel"] {
                assert!(
                    !player_copy.contains(forbidden),
                    "{} offer leaked {forbidden}: {player_copy}",
                    offer.kind
                );
            }
            assert!(
                !player_copy.contains(" +"),
                "{} offer leaked arithmetic: {player_copy}",
                offer.kind
            );
        }
        assert_eq!(
            runtime.project_progress_amount(5000, MOONLIT_TRAIL_LOCATION_ID),
            1
        );

        let mut defend_action = CwAction::default();
        defend_action.kind = CW_ACTION_DEFEND;
        defend_action.actor_id = 5000;
        let (status, events) =
            runtime.apply_journal_record(&JournalRecord::new(defend_action, 7161));
        assert_eq!(status, CW_OK);
        assert!(events.iter().any(|event| {
            event.type_name == "combat.defend"
                && event.actor_id == Some(5000)
                && event.location_id == Some(MOONLIT_TRAIL_LOCATION_ID)
        }));
        assert!(events.iter().any(|event| {
            event.type_name == "tag.applied"
                && event.tag_id.as_deref()
                    == Some(prepared_tag_id(5000, MOONLIT_TRAIL_LOCATION_ID).as_str())
                && event.tag_label.as_deref() == Some("prepared")
                && event.content.as_deref() == Some("defend_prepare")
        }));
        assert!(runtime.prepared_tag_active(5000, MOONLIT_TRAIL_LOCATION_ID));
        assert_eq!(
            runtime.project_progress_amount(5000, MOONLIT_TRAIL_LOCATION_ID),
            2
        );

        let prepared = runtime.state_response(Some(5000), &AccessContext::default());
        assert!(prepared
            .action_offers
            .iter()
            .find(|offer| offer.kind == "defend")
            .and_then(|offer| offer.effect.as_deref())
            .is_some_and(|effect| effect.contains("careful guard")));
    }

    #[test]
    fn attack_advances_active_frontier_project_danger() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = MOONLIT_TRAIL_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7170);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Risk Attacker".to_string(),
                speech_mode: "prose".to_string(),
                title: "Echo Striker".to_string(),
                description: "A test avatar checking attack danger pressure.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);

        let initial = runtime.state_response(Some(5000), &AccessContext::default());
        let attack_offer = initial
            .action_offers
            .iter()
            .find(|offer| offer.kind == "attack")
            .expect("attack offer is exposed in combat project room");
        assert!(attack_offer.risk.as_deref().is_some_and(|risk| risk
            .contains("scuffle grows more dangerous")
            && risk.contains("fall quiet")));

        let mut attack = CwAction::default();
        attack.kind = CW_ACTION_ATTACK;
        attack.actor_id = 5000;
        attack.target_actor_id = 1004;
        let (status, events) = runtime.apply_journal_record(&JournalRecord::new(attack, 7171));
        assert_eq!(status, CW_OK);
        assert!(events
            .iter()
            .any(|event| event.type_name == "combat.attack.attempt"));
        assert!(events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_DANGER_CLOCK_ID)
                && event.clock_delta == Some(1)
                && event.content.as_deref() == Some("attack")
        }));
        assert_eq!(
            runtime
                .clocks
                .get(MOONLIT_DANGER_CLOCK_ID)
                .map(|clock| clock.filled),
            Some(1)
        );

        runtime
            .clocks
            .get_mut(MOONLIT_DANGER_CLOCK_ID)
            .expect("moonlit danger clock exists")
            .filled = 3;
        if let Some(echo) = runtime
            .world
            .actors
            .iter_mut()
            .find(|actor| actor.id == 1004)
        {
            echo.status = CW_ACTOR_ACTIVE;
            echo.damage = 0;
        }
        let (status, fill_events) = runtime.apply_journal_record(&JournalRecord::new(attack, 7172));
        assert_eq!(status, CW_OK);
        assert!(fill_events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_DANGER_CLOCK_ID)
                && event.clock_filled == Some(4)
                && event.content.as_deref() == Some("attack")
        }));
        assert!(fill_events.iter().any(|event| {
            event.type_name == "tag.applied"
                && event.tag_id.as_deref()
                    == Some(echo_fractured_tag_id(MOONLIT_TRAIL_LOCATION_ID).as_str())
        }));
        assert!(fill_events.iter().any(|event| {
            event.type_name == "job.updated"
                && event
                    .content
                    .as_deref()
                    .is_some_and(|content| content.contains("failed"))
        }));
        let failed = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(failed.jobs[0].status, "failed");
        assert!(!failed
            .primary_action
            .options
            .iter()
            .any(|option| matches!(option.kind.as_str(), "prepare" | "work" | "help")));
    }

    #[test]
    fn combat_jobs_target_inference_controllers_and_fail_closed_for_players_and_blocks() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            MOONLIT_TRAIL_LOCATION_ID,
            "Consent Checker",
        );
        assert_eq!(
            runtime.combat_job_for_actor(5000, Some(1004)),
            Some((MOONLIT_JOB_ID.to_string(), 1004)),
            "the authored inference-controlled encounter remains playable"
        );

        runtime
            .actor_autonomy
            .get_mut(&1004)
            .expect("encounter target has controller provenance")
            .control_mode = ActorControlMode::DirectInput;
        assert!(
            runtime.combat_job_for_actor(5000, Some(1004)).is_none(),
            "a directly controlled avatar is not implicit combat consent"
        );

        runtime
            .actor_autonomy
            .get_mut(&1004)
            .expect("encounter target retains controller provenance")
            .control_mode = ActorControlMode::LocalAi;
        runtime
            .actor_safety
            .entry(5000)
            .or_default()
            .blocked_actor_ids
            .insert(1004);
        assert!(
            runtime.combat_job_for_actor(5000, Some(1004)).is_none(),
            "a block in either direction removes the combat target"
        );
    }

    #[test]
    fn combat_v3_state_snapshot_and_projection_gate_follow_encounter_turns() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            MOONLIT_TRAIL_LOCATION_ID,
            "Encounter Snapshotter",
        );
        let encounter_id = combat_encounter_id(MOONLIT_JOB_ID);
        let start = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_COMBAT_START,
                actor_id: 5000,
                target_actor_id: 1004,
                content_id: encounter_id,
                ..CwAction::default()
            },
            71_731,
        )
        .into_system();
        let (status, events) = runtime.apply_journal_record(&start);
        assert_eq!(status, CW_OK);
        assert!(events
            .iter()
            .any(|event| event.type_name == "combat.encounter.started"));

        let state = runtime.state_response(Some(5000), &AccessContext::default());
        let combat = state
            .combat
            .as_ref()
            .expect("active encounter is public state");
        assert_eq!(combat.protocol, "cosyworld.combat/4");
        assert_eq!(combat.encounter_id, encounter_id);
        assert_eq!(combat.round, 1);
        assert_eq!(combat.participants.len(), 2);
        assert!(combat
            .participants
            .iter()
            .any(|participant| participant.actor_id == 5000 && participant.side == 1));
        assert!(combat
            .participants
            .iter()
            .any(|participant| participant.actor_id == 1004 && participant.side == 2));
        if combat.is_current_actor {
            assert!(combat.available_actions.contains(&"attack"));
            assert!(combat.available_actions.contains(&"dodge"));
            assert!(state
                .primary_action
                .options
                .iter()
                .all(|option| matches!(option.kind.as_str(), "attack" | "defend" | "flee")));
        } else {
            assert_eq!(state.primary_action.kind, "wait");
            assert!(state.primary_action.disabled);
        }

        let progress_before = runtime
            .clocks
            .get(MOONLIT_PROGRESS_CLOCK_ID)
            .map(|clock| clock.filled)
            .expect("moonlit progress clock");
        let mut blocked = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            71_732,
        )
        .into_player_card();
        blocked
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
                amount: 1,
                reason: "combat_bypass_attempt".to_string(),
            });
        let (status, blocked_events) = runtime.apply_journal_record(&blocked);
        assert_ne!(status, CW_OK);
        assert!(blocked_events
            .iter()
            .any(|event| event.type_name == "rule.rejected" && event.reason == 20));
        assert_eq!(
            runtime
                .clocks
                .get(MOONLIT_PROGRESS_CLOCK_ID)
                .map(|clock| clock.filled),
            Some(progress_before)
        );

        let restored = RuntimeSnapshot::from_runtime(&runtime)
            .into_runtime()
            .expect("active combat survives a snapshot round trip");
        let restored_encounter = restored
            .active_combat_encounter(encounter_id)
            .expect("restored encounter remains active");
        assert_eq!(restored_encounter.round, 1);
        assert_eq!(restored_encounter.participant_count, 2);
        assert_eq!(restored.world.version, CW_KERNEL_VERSION);

        let mut invalid_snapshot = RuntimeSnapshot::from_runtime(&runtime);
        invalid_snapshot.world_combat_encounters[0].participant_count =
            CW_MAX_COMBAT_PARTICIPANTS + 1;
        assert!(invalid_snapshot.into_runtime().is_err());
    }

    #[tokio::test]
    async fn combat_v3_route_filters_targets_and_drives_npc_turns_to_resolution() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            MOONLIT_TRAIL_LOCATION_ID,
            "Encounter Router",
        );
        let human = runtime
            .world
            .actors
            .iter_mut()
            .find(|actor| actor.id == 5000)
            .expect("test human exists");
        human.stats.strength = 1;
        human.stats.dexterity = 100;
        human.stats.hp_base = 100;
        human.damage = 0;
        let echo = runtime
            .world
            .actors
            .iter_mut()
            .find(|actor| actor.id == 1004)
            .expect("Moonlit encounter target exists");
        echo.stats.strength = 1;
        echo.stats.dexterity = 50;
        echo.stats.hp_base = 100;
        echo.damage = 0;
        let unrelated = runtime
            .world
            .actors
            .iter_mut()
            .find(|actor| actor.id == 1003)
            .expect("unrelated resident exists");
        unrelated.location_id = MOONLIT_TRAIL_LOCATION_ID;
        unrelated.status = CW_ACTOR_ACTIVE;

        let starting_orbs = runtime.orb_balance(5000);
        let state = test_app_state(runtime, None);
        let (actor_session, _) = issue_actor_session(&state, 5000);
        let rejected = apply_combat_choice(
            state.clone(),
            5000,
            CombatChoice::Attack {
                target_actor_id: 1003,
            },
            Some(&actor_session),
        )
        .await
        .0;
        assert!(!rejected.ok);
        assert_eq!(rejected.status, 409);
        assert!(rejected.events.is_empty());

        let mut all_events = Vec::new();
        for _ in 0..5 {
            let response = apply_combat_choice(
                state.clone(),
                5000,
                CombatChoice::Attack {
                    target_actor_id: 1004,
                },
                Some(&actor_session),
            )
            .await
            .0;
            assert!(response.ok, "combat attack failed with {}", response.status);
            all_events.extend(response.events);
            let resolved = state
                .inner
                .lock()
                .await
                .combat_encounter(combat_encounter_id(MOONLIT_JOB_ID))
                .is_some_and(|encounter| encounter.status == CW_COMBAT_ENCOUNTER_RESOLVED);
            if resolved {
                break;
            }
        }

        assert!(all_events
            .iter()
            .any(|event| event.type_name == "combat.encounter.started"));
        assert!(all_events
            .iter()
            .any(|event| event.type_name == "combat.initiative.rolled"));
        assert!(all_events.iter().any(|event| {
            event.type_name == "combat.attack.attempt" && event.actor_id == Some(1004)
        }));
        assert!(all_events
            .iter()
            .any(|event| event.type_name == "combat.encounter.resolved" && event.total == Some(1)));
        assert!(all_events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_PROGRESS_CLOCK_ID)
                && event.content.as_deref() == Some("combat_resolved")
        }));

        let runtime = state.inner.lock().await;
        let encounter = runtime
            .combat_encounter(combat_encounter_id(MOONLIT_JOB_ID))
            .expect("resolved encounter is retained for replay");
        assert_eq!(encounter.status, CW_COMBAT_ENCOUNTER_RESOLVED);
        let echo = runtime.actor_by_id(1004).expect("target remains in world");
        assert_eq!(echo.status, CW_ACTOR_KNOCKED_OUT);
        assert_eq!(unsafe { cw_actor_current_hp(&echo) }, 1);
        assert_eq!(
            runtime.job_status(&runtime.jobs[MOONLIT_JOB_ID]),
            "completed"
        );
        assert!(runtime.orb_balance(5000) >= starting_orbs + COMBAT_OUTCOME_ORB_REWARD);
        let state_view = runtime.state_response(Some(5000), &AccessContext::default());
        assert!(state_view.combat.is_none());
    }

    #[test]
    fn completed_combat_project_clears_combat_actions() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = MOONLIT_TRAIL_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7180);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Calm Resolver".to_string(),
                speech_mode: "prose".to_string(),
                title: "Echo Peacemaker".to_string(),
                description: "A test avatar checking combat affordances after project resolution."
                    .to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);

        discover_seed_exit_pair_for_test(&mut runtime, MOONLIT_TRAIL_LOCATION_ID, 2);
        let active = runtime.state_response(Some(5000), &AccessContext::default());
        assert!(active
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "attack"));
        assert!(active
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "defend"));
        assert!(active
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "flee"));

        let mut complete_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            7181,
        );
        complete_record
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
                amount: 4,
                reason: "test_complete".to_string(),
            });
        assert_eq!(runtime.apply_journal_record(&complete_record).0, CW_OK);

        let completed = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(
            completed
                .jobs
                .iter()
                .find(|job| job.id == "moonlit-trail:quiet-the-echo")
                .map(|job| job.status.as_str()),
            Some("completed")
        );
        assert!(!completed
            .primary_action
            .options
            .iter()
            .any(|option| matches!(option.kind.as_str(), "attack" | "defend" | "flee")));
        assert!(!completed
            .action_offers
            .iter()
            .any(|offer| matches!(offer.kind.as_str(), "attack" | "defend" | "flee")));

        let item_count = runtime.world.item_count;
        let tonic = runtime.world.items[..item_count]
            .iter_mut()
            .find(|item| item.id == 2001)
            .expect("Hearth Tonic exists");
        tonic.holder_actor_id = 5000;
        tonic.location_id = 0;
        tonic.charges = 1;
        let actor_count = runtime.world.actor_count;
        runtime.world.actors[..actor_count]
            .iter_mut()
            .find(|actor| actor.id == 1004)
            .expect("Coach exists")
            .damage = 3;
        let wounded_quieted = runtime.state_response(Some(5000), &AccessContext::default());
        assert!(wounded_quieted
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "use_item"));

        for command in ["attack Coach", "defend", "flee"] {
            let resolved = runtime
                .resolve_command(&command_request(5000, command), &AccessContext::default())
                .expect("combat command still resolves to a disabled action");
            assert!(
                matches!(
                    resolved.dispatch,
                    CommandDispatch::Disabled { status: 409, .. }
                ),
                "{command} should be disabled after the combat project resolves"
            );
        }
    }

    #[test]
    fn resolved_frontier_encounter_resets_on_later_player_tick() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = RAIN_SOFT_GARDEN_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7185);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Late Arrival".to_string(),
                speech_mode: "prose".to_string(),
                title: "Frontier Returner".to_string(),
                description: "A test avatar checking seasonal frontier reset.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);

        let mut complete_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            7186,
        );
        complete_record
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
                amount: 4,
                reason: "test_complete_before_late_arrival".to_string(),
            });
        let (status, completion_events) = runtime.apply_journal_record(&complete_record);
        assert_eq!(status, CW_OK);
        assert!(completion_events
            .iter()
            .any(|event| event.type_name == "job.updated"
                && event
                    .content
                    .as_deref()
                    .is_some_and(|content| content.contains("completed"))));
        assert!(!completion_events
            .iter()
            .any(|event| event.type_name == "encounter.reset"));

        if let Some(echo) = runtime
            .world
            .actors
            .iter_mut()
            .take(runtime.world.actor_count)
            .find(|actor| actor.id == MOONLIT_ECHO_ACTOR_ID)
        {
            echo.status = CW_ACTOR_KNOCKED_OUT;
            echo.damage = echo.stats.hp_base;
        }

        let mut enter_too_soon = CwAction::default();
        enter_too_soon.kind = CW_ACTION_MOVE;
        enter_too_soon.actor_id = 5000;
        enter_too_soon.destination_location_id = MOONLIT_TRAIL_LOCATION_ID;
        let (status, early_events) =
            runtime.apply_journal_record(&JournalRecord::new(enter_too_soon, 7187));
        assert_eq!(status, CW_OK);
        assert!(!early_events
            .iter()
            .any(|event| event.type_name == "encounter.reset"));
        let early_state = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(
            early_state
                .jobs
                .iter()
                .find(|job| job.id == MOONLIT_JOB_ID)
                .map(|job| job.status.as_str()),
            Some("completed")
        );
        assert!(!early_state
            .primary_action
            .options
            .iter()
            .any(|option| matches!(option.kind.as_str(), "attack" | "defend" | "flee")));

        let mut leave_trail = CwAction::default();
        leave_trail.kind = CW_ACTION_MOVE;
        leave_trail.actor_id = 5000;
        leave_trail.destination_location_id = RAIN_SOFT_GARDEN_LOCATION_ID;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(leave_trail, 7188))
                .0,
            CW_OK
        );
        runtime.world.next_event_seq = runtime
            .world
            .next_event_seq
            .saturating_add(ENCOUNTER_RESET_PLAYER_TICKS);

        let mut enter_after_season = CwAction::default();
        enter_after_season.kind = CW_ACTION_MOVE;
        enter_after_season.actor_id = 5000;
        enter_after_season.destination_location_id = MOONLIT_TRAIL_LOCATION_ID;
        let (status, reset_events) =
            runtime.apply_journal_record(&JournalRecord::new(enter_after_season, 7189));
        assert_eq!(status, CW_OK);
        assert!(reset_events
            .iter()
            .any(|event| event.type_name == "encounter.reset"
                && event.target_actor_id == Some(MOONLIT_ECHO_ACTOR_ID)
                && event.location_id == Some(MOONLIT_TRAIL_LOCATION_ID)));
        assert!(reset_events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.clock_id.as_deref() == Some(MOONLIT_PROGRESS_CLOCK_ID)
                && event.clock_delta == Some(-4)
                && event.clock_filled == Some(0)
        }));
        assert!(reset_events.iter().any(|event| {
            event.type_name == "tag.cleared"
                && event.tag_id.as_deref()
                    == Some(quieted_moonlight_tag_id(MOONLIT_TRAIL_LOCATION_ID).as_str())
        }));

        let reset_state = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(
            reset_state
                .jobs
                .iter()
                .find(|job| job.id == MOONLIT_JOB_ID)
                .map(|job| job.status.as_str()),
            Some("active")
        );
        assert!(reset_state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "attack"));
        let echo = runtime
            .world
            .actors
            .iter()
            .take(runtime.world.actor_count)
            .find(|actor| actor.id == MOONLIT_ECHO_ACTOR_ID)
            .expect("Coach exists");
        assert_eq!(echo.status, CW_ACTOR_ACTIVE);
        assert_eq!(echo.damage, 0);

        let before_second_completion = runtime.orb_balance(5000);
        let mut complete_again = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            7190,
        );
        complete_again
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
                amount: 4,
                reason: "test_complete_after_reset".to_string(),
            });
        let (status, second_completion_events) = runtime.apply_journal_record(&complete_again);
        assert_eq!(status, CW_OK);
        assert!(second_completion_events.iter().any(|event| {
            event.type_name == "job.updated"
                && event
                    .content
                    .as_deref()
                    .is_some_and(|content| content.contains("completed"))
        }));
        assert_eq!(runtime.orb_balance(5000), before_second_completion + 2);
    }

    #[test]
    fn danger_clock_on_fill_fails_seed_job() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = MOONLIT_TRAIL_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 7094);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Danger Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "Echo Witness".to_string(),
                description: "A test avatar checking danger resolution.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&create_record).0, CW_OK);

        let mut danger_action = CwAction::default();
        danger_action.kind = CW_ACTION_NONE;
        danger_action.actor_id = 5000;
        let mut danger_record = JournalRecord::new(danger_action, 7095);
        danger_record
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_DANGER_CLOCK_ID.to_string(),
                amount: 4,
                reason: "test_danger_fill".to_string(),
            });
        let (status, events) = runtime.apply_journal_record(&danger_record);
        assert_eq!(status, CW_OK);
        let echo_tag_id = echo_fractured_tag_id(MOONLIT_TRAIL_LOCATION_ID);
        assert!(events.iter().any(|event| {
            event.type_name == "tag.applied"
                && event.tag_id.as_deref() == Some(echo_tag_id.as_str())
        }));
        assert!(events.iter().any(|event| {
            event.type_name == "job.updated"
                && event
                    .content
                    .as_deref()
                    .is_some_and(|content| content.contains("failed"))
        }));

        let failed = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(failed.jobs[0].status, "failed");
        assert!(failed
            .tags
            .iter()
            .any(|tag| tag.label == "echo-fractured trail"));

        let mut progress_record = JournalRecord::new(danger_action, 7096);
        progress_record
            .projection_mutations
            .push(ProjectionMutation::AdvanceClock {
                clock_id: MOONLIT_PROGRESS_CLOCK_ID.to_string(),
                amount: 4,
                reason: "late_progress_fill".to_string(),
            });
        let (status, events) = runtime.apply_journal_record(&progress_record);
        assert_eq!(status, CW_OK);
        assert!(events
            .iter()
            .any(|event| event.type_name == "clock.fill_effect_rejected"));
        let still_failed = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(still_failed.jobs[0].status, "failed");
        assert!(!still_failed
            .tags
            .iter()
            .any(|tag| tag.label == "quieted moonlight"));
    }

