    #[test]
    fn search_found_items_return_to_hidden_pool_when_forgotten() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Pocket Finder",
        );
        for item in &mut runtime.world.items[..runtime.world.item_count] {
            if item.id == HEARTH_TONIC_ITEM_ID {
                item.location_id = 0;
                item.holder_actor_id = 5000;
            } else if item.id == STORY_BUTTON_ITEM_ID {
                item.location_id = 0;
                item.holder_actor_id = 0;
            }
        }
        assert!(!runtime.world.items[..runtime.world.item_count]
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID
                && item.location_id == COSY_COTTAGE_LOCATION_ID));
        assert_eq!(
            runtime.hidden_search_item_for_location(COSY_COTTAGE_LOCATION_ID),
            Some(STORY_BUTTON_ITEM_ID)
        );

        let mut record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_SEARCH,
                actor_id: 5000,
                location_id: COSY_COTTAGE_LOCATION_ID,
                content_id: 91_003,
                item_id: STORY_BUTTON_ITEM_ID,
                ..CwAction::default()
            },
            91_003,
        );
        record.content_upserts.insert(
            91_003,
            "Scarf Basket: a warm wooden button turns up.".to_string(),
        );
        record
            .projection_mutations
            .push(ProjectionMutation::RememberSearchItem {
                item_id: STORY_BUTTON_ITEM_ID,
                location_id: COSY_COTTAGE_LOCATION_ID,
                reason: "search_feature".to_string(),
            });
        let (status, events) = runtime.apply_journal_record(&record);
        assert_eq!(status, CW_OK);
        assert!(events
            .iter()
            .any(|event| event.type_name == "item.found"
                && event.item_id == Some(STORY_BUTTON_ITEM_ID)));
        assert!(runtime.search_item_remembered(STORY_BUTTON_ITEM_ID));
        assert!(runtime
            .state_response(Some(5000), &AccessContext::default())
            .items
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID));

        runtime.world.tick = runtime
            .world
            .tick
            .saturating_add(SEARCH_MEMORY_TIME_DECAY_INTERVAL_TICKS * 64);
        runtime.decay_search_memories();

        assert!(!runtime.search_item_remembered(STORY_BUTTON_ITEM_ID));
        assert_eq!(
            runtime
                .item_by_id(STORY_BUTTON_ITEM_ID)
                .map(|item| item.location_id),
            Some(0)
        );
        assert_eq!(
            runtime.hidden_search_item_for_location(COSY_COTTAGE_LOCATION_ID),
            Some(STORY_BUTTON_ITEM_ID)
        );
        assert!(!runtime
            .state_response(Some(5000), &AccessContext::default())
            .items
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID));
    }

    #[tokio::test]
    async fn lonely_forest_source_characters_are_seeded_with_png_cards() {
        const CHARACTER_ASSET_PREFIX: &str = "/assets/lonely-forest/characters/";
        let content = active_content();
        let runtime = RuntimeWorld::seeded();

        let placed_seed_actors: Vec<&SeedActorContent> = content
            .actors
            .iter()
            .filter(|actor| actor.location_id.is_some())
            .collect();
        assert_eq!(placed_seed_actors.len(), 56);
        for actor in placed_seed_actors {
            let world_actor = runtime.actor_by_id(actor.id).expect("placed seed actor");
            assert_eq!(world_actor.location_id, actor.location_id.unwrap());
            assert_eq!(world_actor.kind, CW_ACTOR_NPC);
            assert_eq!(world_actor.stats.hp_base, seed_actor_stats(actor).hp_base);
        }

        let lonely_forest_actor_cards: Vec<&SeedCardContent> = content
            .cards
            .iter()
            .filter(|card| {
                card.subject_kind == "actor"
                    && card
                        .image_url
                        .as_deref()
                        .is_some_and(|url| url.starts_with(CHARACTER_ASSET_PREFIX))
            })
            .collect();
        assert_eq!(lonely_forest_actor_cards.len(), 25);
        for card in lonely_forest_actor_cards {
            let image_url = card.image_url.as_deref().expect("Lonely Forest image URL");
            let asset_file = image_url
                .strip_prefix(CHARACTER_ASSET_PREFIX)
                .expect("Lonely Forest asset prefix");
            let (mount, relative_path) = content_registry()
                .public_asset_mount(image_url)
                .expect("card asset resolves through its pack provider");
            assert_eq!(relative_path, asset_file);
            assert!(seed_asset_mount_path(mount, relative_path).is_some_and(|path| path.exists()));

            let projected = card_for_actor(card.subject_id, &card.display_name, &card.title, "", 1);
            assert_eq!(projected.image_url.as_deref(), Some(image_url));
            assert_eq!(projected.asset_status, "source_art");
        }

        let response =
            serve_public_asset_path("/assets/lonely-forest/characters/10-woodland-bear.png");
        assert_eq!(response.status(), StatusCode::OK);
        assert_eq!(
            response
                .headers()
                .get(header::CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("image/png")
        );

        let invalid =
            serve_public_asset_path("/assets/lonely-forest/characters/../10-woodland-bear.png");
        assert_eq!(invalid.status(), StatusCode::BAD_REQUEST);

        let generated = generated_seed_card_asset(AxumPath("cosy-whiskerwind.webp".to_string()))
            .await
            .into_response();
        assert_eq!(generated.status(), StatusCode::OK);
        assert_eq!(
            generated
                .headers()
                .get(header::CONTENT_TYPE)
                .and_then(|value| value.to_str().ok()),
            Some("image/webp")
        );

        let missing_generated =
            generated_seed_card_asset(AxumPath("../cosy-whiskerwind.webp".to_string()))
                .await
                .into_response();
        assert_eq!(missing_generated.status(), StatusCode::NOT_FOUND);
    }

