    #[test]
    fn ranked_action_offers_and_inspector_explain_room_state() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 7840);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Inspector Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "Room Auditor".to_string(),
                description: "A test avatar checking offer and inspector metadata.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        for (destination, seed) in [(2, 7841), (MOONLIT_TRAIL_LOCATION_ID, 7842)] {
            let mut move_action = CwAction::default();
            move_action.kind = CW_ACTION_MOVE;
            move_action.actor_id = 5000;
            move_action.destination_location_id = destination;
            assert_eq!(
                runtime
                    .apply_journal_record(&JournalRecord::new(move_action, seed))
                    .0,
                CW_OK
            );
        }

        discover_seed_exit_pair_for_test(&mut runtime, MOONLIT_TRAIL_LOCATION_ID, 2);
        let state = runtime.state_response(Some(5000), &AccessContext::default());
        assert_eq!(state.primary_action.kind, "pick_up");
        assert_eq!(state.primary_action.label, "Take");
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "check" && option.command == "listen"));
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "prepare" && option.command == "prepare"));
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "help" && option.command == "assist"));
        let listen_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "check")
            .expect("listen offer is exposed");
        assert_eq!(listen_offer.category, "discovery");
        assert_eq!(listen_offer.intention, "notice");
        assert_eq!(listen_offer.verb, "Notice");
        assert_eq!(listen_offer.label, "Notice");
        assert_eq!(listen_offer.accessible_label, "Notice at Moonlit Trail");
        assert!(listen_offer.target.as_ref().is_some_and(|target| {
            target.kind == "location"
                && target.id == Some(MOONLIT_TRAIL_LOCATION_ID)
                && target.label.as_deref() == Some("Moonlit Trail")
        }));
        assert_eq!(listen_offer.zone, ZONE_FRONTIER);
        assert!(listen_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("one useful clue")
                && effect.contains("shared work")
                && !effect.contains(MOONLIT_PROGRESS_CLOCK_ID)));
        assert_eq!(listen_offer.progress, Some(1));
        assert!(listen_offer
            .risk
            .as_deref()
            .is_some_and(|risk| risk.contains("out here may tire you")));
        assert!(state
            .action_offers
            .windows(2)
            .all(|pair| pair[0].rank <= pair[1].rank));
        let help_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "help")
            .expect("help offer is exposed");
        assert_eq!(help_offer.category, "social");
        assert_eq!(help_offer.intention, "contribute");
        assert_eq!(help_offer.verb, "Help");
        assert_eq!(help_offer.command, "assist");
        assert!(help_offer.risk.is_none());
        assert!(help_offer
            .effect
            .as_deref()
            .is_some_and(|effect| effect.contains("first help brings you closer")));
        assert_eq!(help_offer.progress, Some(1));
        assert!(help_offer.project.as_ref().is_some_and(|project| {
            project.id == MOONLIT_JOB_ID
                && project.verb == "Contribute"
                && project.label == "Quiet the echo"
                && project.progress_clock_id == MOONLIT_PROGRESS_CLOCK_ID
        }));
        assert!(help_offer.accessible_label.contains("with Quiet the echo"));
        let work_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "work")
            .expect("work offer is exposed");
        assert_eq!(work_offer.category, "project");
        assert_eq!(work_offer.intention, "contribute");
        assert_eq!(work_offer.verb, "Push");
        assert_eq!(work_offer.accessible_label, "Push Quiet the echo");
        assert_eq!(work_offer.effect.as_deref(), Some("makes good headway"));
        assert_eq!(work_offer.progress, Some(2));
        assert!(work_offer
            .risk
            .as_deref()
            .is_some_and(|risk| risk.contains("rushing in may tire you")));
        assert!(
            !state
                .action_offers
                .iter()
                .any(|offer| matches!(offer.kind.as_str(), "chat" | "create_bond")),
            "Chat is not an ordinary room offer without available advancement"
        );
        let move_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "move")
            .expect("move offer is exposed");
        assert_eq!(move_offer.category, "travel");
        assert_eq!(move_offer.intention, "travel");
        assert_eq!(move_offer.verb, "Travel");
        assert!(move_offer.accessible_label.starts_with("Travel to "));

        let inspector = state.inspector;
        assert_eq!(inspector.location_id, MOONLIT_TRAIL_LOCATION_ID);
        let suggested = inspector
            .suggested_action
            .as_ref()
            .expect("inspector exposes a suggested action");
        assert_eq!(suggested.kind, "pick_up");
        assert_eq!(suggested.category, "inventory");
        assert_eq!(suggested.zone, ZONE_FRONTIER);
        assert_eq!(suggested.source, "kernel_flags+rpg_projection");
        assert_eq!(suggested.rank, action_offer_rank("pick_up"));
        assert!(!suggested.disabled);
        assert!(state.action_offers.iter().any(|offer| {
            offer.kind == "prepare"
                && offer.progress == Some(2)
                && offer.effect.as_deref() == Some("makes the next try count")
        }));
        assert!(inspector
            .fronts
            .iter()
            .any(|front| front.id == "moonlit-trail:echo-front"
                && front
                    .stakes_questions
                    .iter()
                    .any(|question| question.contains("quiet again"))));
        assert!(inspector
            .room
            .listen_reason
            .as_deref()
            .is_some_and(|reason| reason.contains("one useful clue")
                && reason.contains("shared work")
                && !reason.contains(MOONLIT_PROGRESS_CLOCK_ID)));
        assert!(
            inspector
                .jobs
                .iter()
                .any(|job| job.id == MOONLIT_JOB_ID
                    && job.needs.iter().any(|need| need.contains("4")))
        );
        assert!(inspector.clocks.iter().any(|clock| {
            clock.id == MOONLIT_PROGRESS_CLOCK_ID
                && clock
                    .on_fill_effect
                    .as_deref()
                    .is_some_and(|effect| effect.contains("quieted moonlight"))
        }));
        assert!(inspector.lifecycle_hooks.iter().any(|hook| {
            hook.hook == "on_listen"
                && hook.target_kind == "room"
                && hook
                    .effect
                    .as_deref()
                    .is_some_and(|effect| effect.contains(MOONLIT_PROGRESS_CLOCK_ID))
        }));
    }

    #[test]
    fn ruby_high_first_bell_live_catalog_projects_card_metadata() {
        assert_eq!(external_card_catalog().len(), 24);

        let ids: BTreeSet<&str> = external_card_catalog()
            .iter()
            .map(|spec| spec.card_id.as_str())
            .collect();
        for card_id in [
            "lyra",
            "sami",
            "ravi",
            "indra",
            "mika",
            "noor",
            "ruby",
            "sally-science",
            "professor-edward",
            "eliza",
            "rati",
            "captain-null",
            "item-hall-pass",
            "item-flashcards",
            "item-library-card",
            "item-lab-flask",
            "item-lunch-tray",
            "item-notebook",
            "location-homeroom",
            "location-science-lab",
            "location-library",
            "location-cafeteria",
            "location-greenhouse",
            "location-courtyard",
        ] {
            assert!(ids.contains(card_id), "missing First Bell card {card_id}");
            let card = external_card_by_id(card_id).expect("card projects");
            assert_eq!(card.card_id, card_id);
            assert_eq!(card.source, "ruby_high_first_bell");
            assert_eq!(card.asset_status, "on_chain");
            assert!(card
                .set_number
                .as_deref()
                .is_some_and(|value| value.starts_with("FB-")));
            let expected_image_url = format!("/assets/cards/{card_id}.png");
            assert_eq!(card.image_url.as_deref(), Some(expected_image_url.as_str()));
            assert!(card
                .chain_image_uri
                .as_deref()
                .is_some_and(|value| value.starts_with("https://gateway.irys.xyz/")));
        }

        assert_eq!(
            external_card_by_id("item-lab-flask").unwrap().aspect,
            "square"
        );
        assert_eq!(
            external_card_by_id("location-library").unwrap().aspect,
            "wide"
        );
        assert_eq!(external_card_by_id("rati").unwrap().aspect, "tall");
    }

    #[test]
    fn compiled_worldpack_asset_index_resolves_pack_mounts_safely() {
        assert!(content_registry().asset_mounts().len() >= 4);
        assert!(content_registry()
            .asset_mounts()
            .iter()
            .any(|mount| { mount.pack_id == "ruby-high.first-bell" && mount.mount == "cards" }));
        for mount in content_registry().asset_mounts() {
            assert!(valid_sha256_digest(&mount.content_hash));
            assert!(mount.cache_key("example.png").contains(&mount.pack_version));
            assert!(mount.cache_key("example.png").contains(&mount.content_hash));
        }
        let core_cards = content_registry()
            .asset_mounts()
            .iter()
            .find(|mount| mount.pack_id == "cosyworld.core" && mount.mount == "generated/cards")
            .expect("core card mount exists");
        let card_path = seed_asset_mount_path(core_cards, "cosy-hearth-tonic.webp")
            .expect("core card mount resolves");
        assert!(card_path.ends_with("core/assets/generated/cards/cosy-hearth-tonic.webp"));
        assert!(card_path.exists());
        assert!(seed_asset_mount_path(core_cards, "../pack.json").is_none());
        assert!(content_registry()
            .asset_mounts()
            .iter()
            .all(|mount| mount.pack_id != "missing.pack"));
    }

