    #[test]
    fn non_track_resident_uses_attached_item_with_room_feature() {
        let mut runtime = RuntimeWorld::seeded();
        runtime.world.tick = 0;
        runtime.resident_memories.clear();
        for item in &mut runtime.world.items[..runtime.world.item_count] {
            if item.id == STORY_BUTTON_ITEM_ID {
                item.location_id = 40;
                item.holder_actor_id = 0;
                item.held_since_tick = 0;
            }
        }

        assert_eq!(evolution_track_item_ids(OLD_OAK_TREE_ACTOR_ID), None);
        let old_oak = runtime
            .prepare_resident_local_memories(OLD_OAK_TREE_ACTOR_ID)
            .expect("Old Oak observes the local room item");
        assert!(runtime
            .resident_sought_item_ids(old_oak)
            .contains(&STORY_BUTTON_ITEM_ID));
        let sought = runtime.resident_sought_item_view(old_oak, STORY_BUTTON_ITEM_ID);
        assert_eq!(sought.source, "attachment");
        assert!(sought.reason.contains("wants Story Button back"));
        assert!(sought.reason.contains("Hollow"));
        let memory = runtime
            .resident_best_item_memory(OLD_OAK_TREE_ACTOR_ID, STORY_BUTTON_ITEM_ID)
            .expect("Old Oak carries a memory of the local item");
        assert_eq!(memory.location_id, 40);
        assert_eq!(memory.source_actor_id, Some(OLD_OAK_TREE_ACTOR_ID));

        let pickup = runtime
            .resident_economy_autonomy_action(old_oak)
            .expect("Old Oak acts on the remembered room item");
        assert_eq!(pickup.kind, CW_ACTION_PICK_UP_ITEM);
        assert_eq!(pickup.actor_id, OLD_OAK_TREE_ACTOR_ID);
        assert_eq!(pickup.item_id, STORY_BUTTON_ITEM_ID);
        let (status, events) = runtime.apply_journal_record(&JournalRecord::new(pickup, 7837));
        assert_eq!(status, CW_OK);
        assert!(events.iter().any(|event| {
            event.type_name == "item.picked_up"
                && event.actor_id == Some(OLD_OAK_TREE_ACTOR_ID)
                && event.item_id == Some(STORY_BUTTON_ITEM_ID)
        }));
        let pickup_event = events
            .iter()
            .find(|event| {
                event.type_name == "item.picked_up"
                    && event.actor_id == Some(OLD_OAK_TREE_ACTOR_ID)
                    && event.item_id == Some(STORY_BUTTON_ITEM_ID)
            })
            .expect("Old Oak pickup event");
        assert!(pickup_event
            .content
            .as_deref()
            .is_some_and(
                |content| content.contains("wants Story Button back") && content.contains("Hollow")
            ));

        let old_oak = runtime
            .actor_by_id(OLD_OAK_TREE_ACTOR_ID)
            .expect("Old Oak remains present");
        let record = runtime
            .resident_economy_autonomy_record(old_oak, 7838)
            .expect("Old Oak can use the held room item");
        assert_eq!(record.action.kind, CW_ACTION_NONE);
        assert_eq!(record.action.actor_id, OLD_OAK_TREE_ACTOR_ID);
        match record.projection_mutations.as_slice() {
            [ProjectionMutation::UseFeature {
                item_id,
                location_id,
                feature_key,
                reason,
                ..
            }, ProjectionMutation::UpdateResidentContinuity {
                resident_id,
                reason: continuity_reason,
                ..
            }] => {
                assert_eq!(*item_id, STORY_BUTTON_ITEM_ID);
                assert_eq!(*location_id, 40);
                assert_eq!(feature_key, "hollow_voice");
                assert_eq!(reason, "resident_feature_use");
                assert_eq!(*resident_id, OLD_OAK_TREE_ACTOR_ID);
                assert_eq!(continuity_reason, "resident_autonomy_intent");
            }
            other => panic!("expected Old Oak room feature use, got {other:?}"),
        }

        let (status, events) = runtime.apply_journal_record(&record);
        assert_eq!(status, CW_OK);
        assert!(events.iter().any(|event| {
            event.type_name == "item.used"
                && event.actor_id == Some(OLD_OAK_TREE_ACTOR_ID)
                && event.item_id == Some(STORY_BUTTON_ITEM_ID)
                && event.location_id == Some(40)
        }));
        assert!(runtime.feature_use_claimed(
            OLD_OAK_TREE_ACTOR_ID,
            40,
            "hollow_voice",
            STORY_BUTTON_ITEM_ID,
        ));
        let story_button = runtime
            .item_by_id(STORY_BUTTON_ITEM_ID)
            .expect("Story Button exists");
        assert!(runtime.resident_item_is_attached(OLD_OAK_TREE_ACTOR_ID, story_button));
        let old_oak = runtime
            .actor_by_id(OLD_OAK_TREE_ACTOR_ID)
            .expect("Old Oak remains present");
        let held_story = runtime.resident_held_item_view(old_oak, story_button);
        assert_eq!(held_story.disposition, "attached");
        assert!(held_story.reason.contains("protects Story Button"));
        assert!(held_story.reason.contains("Hollow"));
    }

    #[test]
    fn pickup_adds_to_weight_based_carried_deck_without_auto_dropping() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = COSY_COTTAGE_LOCATION_ID;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(create, 7831))
                .0,
            CW_OK
        );

        for item in &mut runtime.world.items[..runtime.world.item_count] {
            match item.id {
                2001 => {
                    item.location_id = 0;
                    item.holder_actor_id = 5000;
                    item.held_since_tick = 10;
                }
                STORY_BUTTON_ITEM_ID => {
                    item.location_id = COSY_COTTAGE_LOCATION_ID;
                    item.holder_actor_id = 0;
                    item.held_since_tick = 0;
                }
                _ => {}
            }
        }

        let access = AccessContext::default();
        let deck_state = runtime.state_response(Some(5000), &access);
        assert!(deck_state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "pick_up")
            .and_then(|offer| offer.effect.as_deref())
            .is_some_and(|effect| effect.contains("carried deck")));

        let pickup = CwAction {
            kind: CW_ACTION_PICK_UP_ITEM,
            actor_id: 5000,
            item_id: STORY_BUTTON_ITEM_ID,
            ..CwAction::default()
        };
        let (status, events) = runtime.apply_journal_record(&JournalRecord::new(pickup, 7832));
        assert_eq!(status, CW_OK);
        assert!(events.iter().any(|event| {
            event.type_name == "item.picked_up" && event.item_id == Some(STORY_BUTTON_ITEM_ID)
        }));
        assert!(command_response_output(None, &events)
            .is_some_and(|output| output.starts_with("You take Story Button.")));
        assert!(runtime.world.items[..runtime.world.item_count]
            .iter()
            .any(|item| item.id == 2001 && item.holder_actor_id == 5000));
        assert!(runtime.world.items[..runtime.world.item_count]
            .iter()
            .any(|item| item.id == STORY_BUTTON_ITEM_ID && item.holder_actor_id == 5000));

        let inventory = runtime
            .resolve_command(&command_request(5000, "inventory"), &access)
            .expect("inventory resolves");
        match inventory.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("You carry Hearth Tonic, Story Button"));
                assert!(output.contains("0.6/"));
                assert!(output.contains("Hearth Tonic"));
            }
            other => panic!("inventory should be read-only, got {other:?}"),
        }
    }

    #[test]
    fn state_projects_card_transactions_and_location_search() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = COSY_COTTAGE_LOCATION_ID;
        let mut record = JournalRecord::new(create, 18620);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Card Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "Transaction Reader".to_string(),
                description: "A test avatar reading the world as card transactions.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);
        discover_seed_exit_pair_for_test(
            &mut runtime,
            COSY_COTTAGE_LOCATION_ID,
            RAIN_SOFT_GARDEN_LOCATION_ID,
        );
        runtime.hide_loose_items_at_location(COSY_COTTAGE_LOCATION_ID);

        let access = AccessContext::default();
        let state = runtime.state_response(Some(5000), &access);
        assert!(state.room_features.is_empty());
        assert!(state.search_available);
        assert!(state.card_transactions.iter().any(|transaction| {
            transaction.subject.display_name == "The Cosy Cottage"
                && transaction.predicate == "connected_to"
                && transaction.object.display_name == "Rain-Soft Garden"
        }));
        assert!(state.card_transactions.iter().any(|transaction| {
            transaction.subject.display_name == "Card Tester"
                && transaction.predicate == "in"
                && transaction.object.display_name == "The Cosy Cottage"
        }));

        let search = runtime
            .resolve_command(&command_request(5000, "search"), &access)
            .expect("location search resolves");
        match search.dispatch {
            CommandDispatch::SearchFeature {
                location_id,
                feature_key,
                feature_name,
                output,
            } => {
                assert_eq!(location_id, COSY_COTTAGE_LOCATION_ID);
                assert_eq!(feature_key, "room");
                assert_eq!(feature_name, "The Cosy Cottage");
                assert_eq!(output, "You look closely around The Cosy Cottage.");
            }
            other => panic!("search should target the location card, got {other:?}"),
        }

        let mut search_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                location_id: COSY_COTTAGE_LOCATION_ID,
                ..CwAction::default()
            },
            18621,
        );
        search_record
            .projection_mutations
            .push(ProjectionMutation::SearchLocation {
                location_id: COSY_COTTAGE_LOCATION_ID,
                content: "You look closely around The Cosy Cottage.".to_string(),
                reason: "search_location".to_string(),
            });
        let (status, events) = runtime.apply_journal_record(&search_record);
        assert_eq!(status, CW_OK);
        assert!(events.iter().any(|event| {
            event.type_name == "location.searched" && event.actor_id == Some(5000)
        }));
        assert!(events.iter().any(|event| {
            event.type_name == "tag.applied"
                && event.tag_id.as_deref()
                    == Some(location_search_tag_id(5000, COSY_COTTAGE_LOCATION_ID).as_str())
        }));
    }

    #[test]
    fn first_cottage_clue_turns_search_into_a_scarf_basket_follow_up() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = COSY_COTTAGE_LOCATION_ID;
        let mut record = JournalRecord::new(create, 18630);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Clue Follower".to_string(),
                speech_mode: "prose".to_string(),
                title: "Basket Noticer".to_string(),
                description: "A test avatar following a cosy clue to its next card.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);
        runtime.hide_loose_items_at_location(COSY_COTTAGE_LOCATION_ID);
        runtime
            .listen_attempt_claims
            .insert(listen_attempt_claim_key(5000, COSY_COTTAGE_LOCATION_ID));

        let waiting_target = runtime
            .default_search_target(5000)
            .expect("the listened clue stays actionable while another keepsake waits");
        assert_eq!(waiting_target.key, SCARF_BASKET_FEATURE_KEY);
        assert!(runtime
            .search_reveal_candidates_for_feature(
                COSY_COTTAGE_LOCATION_ID,
                SCARF_BASKET_FEATURE_KEY,
            )
            .is_empty());

        if let Some(tonic) = runtime.world.items[..runtime.world.item_count]
            .iter_mut()
            .find(|item| item.id == HEARTH_TONIC_ITEM_ID)
        {
            tonic.holder_actor_id = RATI_ACTOR_ID;
        }

        let target = runtime
            .default_search_target(5000)
            .expect("the listened clue has a follow-up search");
        assert_eq!(target.key, SCARF_BASKET_FEATURE_KEY);
        assert_eq!(target.name, "Scarf Basket");
        assert!(target.output.contains("round notch"));

        let candidates =
            runtime.search_reveal_candidates_for_feature(COSY_COTTAGE_LOCATION_ID, &target.key);
        assert!(matches!(
            candidates.as_slice(),
            [SearchRevealCandidate::Item {
                item_id: STORY_BUTTON_ITEM_ID
            }]
        ));

        let access = AccessContext::default();
        let state = runtime.state_response(Some(5000), &access);
        let search_offer = state
            .action_offers
            .iter()
            .find(|offer| offer.kind == "search")
            .expect("search offer");
        assert_eq!(search_offer.intention, "inspect");
        assert_eq!(search_offer.verb, "Inspect");
        assert_eq!(search_offer.label, "Inspect Scarf Basket");
        assert_eq!(search_offer.accessible_label, "Inspect Scarf Basket");
        assert_eq!(search_offer.command, "search Scarf Basket");
        assert_eq!(
            search_offer
                .target
                .as_ref()
                .and_then(|target| target.label.as_deref()),
            Some("Scarf Basket")
        );

        let search = runtime
            .resolve_command(&command_request(5000, "search Scarf Basket"), &access)
            .expect("clue-led search resolves");
        match search.dispatch {
            CommandDispatch::SearchFeature {
                location_id,
                feature_key,
                feature_name,
                output,
            } => {
                assert_eq!(location_id, COSY_COTTAGE_LOCATION_ID);
                assert_eq!(feature_key, SCARF_BASKET_FEATURE_KEY);
                assert_eq!(feature_name, "Scarf Basket");
                assert!(output.contains("warm wooden button"));
            }
            other => panic!("the clue should lead to the scarf basket, got {other:?}"),
        }
    }

    #[test]
    fn mud_commands_resolve_to_world_actions_and_feature_use_events() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 7830);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Command Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "MUD Verb Tester".to_string(),
                description: "A test avatar checking the command grammar.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        discover_seed_exit_pair_for_test(&mut runtime, 1, 2);
        discover_seed_exit_pair_for_test(&mut runtime, 1, 11);
        let access = AccessContext::default();
        let state = runtime.state_response(Some(5000), &access);
        assert!(state.room_features.is_empty());
        let cottage_features = runtime.room_feature_views(1, Some(5000));
        assert!(cottage_features
            .iter()
            .any(|feature| feature.key == "hearth"));
        assert!(cottage_features
            .iter()
            .any(|feature| feature.uses.iter().any(|use_case| use_case.item_id == 2005)));
        assert!(state.exits.iter().any(|exit| {
            exit.destination_location_id == 2 && exit.direction.as_deref() == Some("east")
        }));

        let look = runtime
            .resolve_command(&command_request(5000, "look"), &access)
            .expect("look resolves");
        match look.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("The Cosy Cottage"));
                assert!(output.contains("Ways onward:"));
                assert!(output.contains("east: Rain-Soft Garden"));
                assert!(!output.contains("Features:"));
            }
            other => panic!("look should be read-only, got {other:?}"),
        }

        assert_eq!(canonical_command_verb("more"), "shuffle");
        assert_eq!(canonical_command_verb("practice"), "skill");
        assert_eq!(canonical_command_verb("purpose"), "calling");
        assert_eq!(canonical_command_verb("friendship"), "bond");

        let help = runtime
            .resolve_command(&command_request(5000, "help"), &access)
            .expect("help resolves");
        match help.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("emote <action>"));
                assert!(output.contains("report <actor>: <reason>"));
                assert!(output.contains("drop <item>"));
                assert!(output.contains("more"));
                assert!(output.contains("deck"));
                assert!(!output.contains("bracelet unlock"));
                assert!(!output.contains(", grow,"));
                assert!(output.contains("wear <skill charm>"));
                assert!(output.contains("remove <skill charm>"));
                assert!(!output.contains("practice <knack>"));
                assert!(output.contains("purpose <what draws you in>"));
                assert!(output.contains("friendship <avatar>"));
                assert!(output.contains("remember <avatar>"));
                assert!(output.contains("pass"));
                assert!(output.contains("need time"));
                assert!(!output.contains("skill <name>"));
                assert!(!output.contains("calling <new drive>"));
                assert!(!output.contains("bond <avatar>"));
                assert!(!output.contains("settle <avatar>"));
                assert!(!output.contains("resolve bond"));
            }
            other => panic!("help should be read-only, got {other:?}"),
        }

        let shuffle = runtime
            .resolve_command(&command_request(5000, "shuffle"), &access)
            .expect("shuffle resolves");
        match shuffle.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("A fresh hand appears"));
                assert!(output.contains("Nothing in the room changes"));
            }
            other => panic!("shuffle should be a free hand redeal hint, got {other:?}"),
        }

        runtime.hide_loose_items_at_location(1);
        let search = runtime
            .resolve_command(&command_request(5000, "search scarf"), &access)
            .expect("search resolves");
        match search.dispatch {
            CommandDispatch::SearchFeature {
                location_id,
                feature_key,
                feature_name,
                output,
            } => {
                assert_eq!(location_id, 1);
                assert_eq!(feature_key, "room");
                assert_eq!(feature_name, "The Cosy Cottage");
                assert_eq!(output, "You look closely around The Cosy Cottage.");
                let found_item_id = STORY_BUTTON_ITEM_ID;
                assert!(runtime.world.items[..runtime.world.item_count]
                    .iter()
                    .any(|item| {
                        item.id == found_item_id
                            && item.location_id == 0
                            && item.holder_actor_id == 0
                    }));
                let mut search_record = JournalRecord::new(
                    CwAction {
                        kind: CW_ACTION_SEARCH,
                        actor_id: 5000,
                        location_id,
                        item_id: found_item_id,
                        ..CwAction::default()
                    },
                    7829,
                );
                search_record
                    .projection_mutations
                    .push(ProjectionMutation::SearchLocation {
                        location_id,
                        content: output.clone(),
                        reason: "search_location".to_string(),
                    });
                let (status, events) = runtime.apply_journal_record(&search_record);
                assert_eq!(status, CW_OK);
                assert!(events.iter().any(|event| {
                    event.type_name == "location.searched"
                        && event.actor_id == Some(5000)
                        && event.location_id == Some(1)
                }));
                assert!(events.iter().any(|event| {
                    event.type_name == "tag.applied"
                        && event.tag_id.as_deref() == Some(location_search_tag_id(5000, 1).as_str())
                }));
                assert!(events
                    .iter()
                    .any(|event| event.type_name == "ledger.marked"));
                let output = command_response_output(Some(output), &events)
                    .expect("location search has command output");
                assert!(output.contains("You look closely around The Cosy Cottage."));
            }
            other => panic!("search should map to a projected feature search, got {other:?}"),
        }

        let look_east = runtime
            .resolve_command(&command_request(5000, "look east"), &access)
            .expect("look direction resolves");
        match look_east.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("Rain-Soft Garden"));
                assert!(output.contains("Rain-Pearled Annex"));
            }
            other => panic!("look direction should be read-only, got {other:?}"),
        }

        let go = runtime
            .resolve_command(&command_request(5000, "go garden"), &access)
            .expect("go resolves");
        assert_eq!(
            go.action.as_ref().map(|action| action.command.as_str()),
            Some("go Rain-Soft Garden")
        );
        match go.dispatch {
            CommandDispatch::Move {
                destination_location_id,
            } => assert_eq!(destination_location_id, 2),
            other => panic!("go should map to movement, got {other:?}"),
        }

        let go_east = runtime
            .resolve_command(&command_request(5000, "east"), &access)
            .expect("direction command resolves");
        match go_east.dispatch {
            CommandDispatch::Move {
                destination_location_id,
            } => assert_eq!(destination_location_id, 2),
            other => panic!("direction should map to movement, got {other:?}"),
        }

        let go_east_alias = runtime
            .resolve_command(&command_request(5000, "go e"), &access)
            .expect("direction alias resolves");
        match go_east_alias.dispatch {
            CommandDispatch::Move {
                destination_location_id,
            } => assert_eq!(destination_location_id, 2),
            other => panic!("direction alias should map to movement, got {other:?}"),
        }

        let mut move_action = CwAction::default();
        move_action.kind = CW_ACTION_MOVE;
        move_action.actor_id = 5000;
        move_action.destination_location_id = 2;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(move_action, 7831))
                .0,
            CW_OK
        );

        let take = runtime
            .resolve_command(&command_request(5000, "take dewbright"), &access)
            .expect("take resolves");
        match take.dispatch {
            CommandDispatch::PickUp { item_id } => assert_eq!(item_id, 2002),
            other => panic!("take should map to pick-up, got {other:?}"),
        }

        let mut pickup = CwAction::default();
        pickup.kind = CW_ACTION_PICK_UP_ITEM;
        pickup.actor_id = 5000;
        pickup.item_id = 2002;
        let (status, pickup_events) =
            runtime.apply_journal_record(&JournalRecord::new(pickup, 7832));
        assert_eq!(status, CW_OK);
        assert!(command_response_output(None, &pickup_events)
            .is_some_and(|output| output.starts_with("You take Dewbright Button.")));

        let inventory = runtime
            .resolve_command(&command_request(5000, "inventory"), &access)
            .expect("inventory resolves");
        match inventory.dispatch {
            CommandDispatch::Read { output } => assert!(output.contains("Dewbright Button")),
            other => panic!("inventory should be read-only, got {other:?}"),
        }

        let off_room_give = runtime
            .resolve_command(&command_request(5000, "give dewbright to gust"), &access)
            .expect_err("off-room give explains where the resident is");
        assert_eq!(off_room_give.status, 404);
        assert!(off_room_give.output.contains("Gust"));
        assert!(off_room_give.output.contains("The Cosy Cottage"));
        assert!(off_room_give.output.contains("Rain-Soft Garden"));

        let drop = runtime
            .resolve_command(&command_request(5000, "drop dewbright"), &access)
            .expect("drop resolves");
        match drop.dispatch {
            CommandDispatch::Drop { item_id } => {
                assert_eq!(item_id, 2002);
                let mut drop_action = CwAction::default();
                drop_action.kind = CW_ACTION_DROP_ITEM;
                drop_action.actor_id = 5000;
                drop_action.item_id = item_id;
                let (status, drop_events) =
                    runtime.apply_journal_record(&JournalRecord::new(drop_action, 7833));
                assert_eq!(status, CW_OK);
                assert_eq!(
                    command_response_output(None, &drop_events).as_deref(),
                    Some("You drop Dewbright Button.")
                );
                assert!(runtime.world.items[..runtime.world.item_count]
                    .iter()
                    .any(|item| {
                        item.id == 2002 && item.location_id == 2 && item.holder_actor_id == 0
                    }));
            }
            other => panic!("drop should map to item drop, got {other:?}"),
        }

        let inventory = runtime
            .resolve_command(&command_request(5000, "inventory"), &access)
            .expect("inventory resolves after drop");
        match inventory.dispatch {
            CommandDispatch::Read { output } => assert!(!output.contains("Dewbright Button")),
            other => panic!("inventory should be read-only, got {other:?}"),
        }

        let take_again = runtime
            .resolve_command(&command_request(5000, "take dewbright"), &access)
            .expect("retake resolves");
        match take_again.dispatch {
            CommandDispatch::PickUp { item_id } => assert_eq!(item_id, 2002),
            other => panic!("retake should map to pick-up, got {other:?}"),
        }
        pickup.item_id = 2002;
        let (status, pickup_events) =
            runtime.apply_journal_record(&JournalRecord::new(pickup, 7834));
        assert_eq!(status, CW_OK);
        assert!(pickup_events
            .iter()
            .any(|event| event.type_name == "item.picked_up" && event.item_id == Some(2002)));

        move_action.destination_location_id = 1;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(move_action, 7835))
                .0,
            CW_OK
        );

        pickup.item_id = 2005;
        assert_eq!(
            runtime
                .apply_journal_record(&JournalRecord::new(pickup, 7836))
                .0,
            CW_OK
        );
        let use_feature = runtime
            .resolve_command(
                &command_request(5000, "use Story Button on scarf basket"),
                &access,
            )
            .expect("use feature resolves");
        assert_eq!(
            use_feature
                .action
                .as_ref()
                .map(|action| action.kind.as_str()),
            Some("use_feature")
        );
        match use_feature.dispatch {
            CommandDispatch::UseFeature {
                item_id,
                location_id,
                feature_key,
                output,
            } => {
                assert_eq!(item_id, 2005);
                assert_eq!(location_id, 1);
                assert_eq!(feature_key, "scarf_basket");
                assert!(output.contains("Story Button"));
                assert!(output.contains("fits the notch"));
                let mut feature_record = JournalRecord::new(
                    CwAction {
                        kind: CW_ACTION_NONE,
                        actor_id: 5000,
                        ..CwAction::default()
                    },
                    7837,
                );
                feature_record
                    .projection_mutations
                    .push(ProjectionMutation::UseFeature {
                        item_id,
                        location_id,
                        feature_key: feature_key.clone(),
                        content: output.clone(),
                        reason: "use_feature".to_string(),
                    });
                let (status, events) = runtime.apply_journal_record(&feature_record);
                assert_eq!(status, CW_OK);
                assert!(events.iter().any(|event| {
                    event.type_name == "item.used"
                        && event.actor_id == Some(5000)
                        && event.item_id == Some(2005)
                }));
                assert!(events.iter().any(|event| {
                    event.type_name == "bond.deepened"
                        && event.actor_id == Some(5000)
                        && event.target_actor_id == Some(RATI_ACTOR_ID)
                        && event
                            .content
                            .as_deref()
                            .map(|content| content.contains("story_button_scarf"))
                            .unwrap_or(false)
                }));
                assert!(events.iter().any(|event| {
                    event.type_name == "tag.applied"
                        && event.tag_id.as_deref()
                            == Some(feature_use_tag_id(5000, 1, &feature_key, 2005).as_str())
                }));
                assert!(events
                    .iter()
                    .any(|event| event.type_name == "ledger.marked"));
                let feature_views = runtime.room_feature_views(1, Some(5000));
                assert!(feature_views
                    .iter()
                    .flat_map(|feature| feature.uses.iter())
                    .any(|use_case| use_case.item_id == 2005 && use_case.used));
                assert!(feature_views
                    .iter()
                    .flat_map(|feature| feature.uses.iter())
                    .any(|use_case| use_case.item_id == 2005
                        && use_case.effect.as_deref() == Some("friendship with Rati grows")));
                let feature_state = runtime.state_response(Some(5000), &access);
                let rati_bond = feature_state
                    .bonds
                    .iter()
                    .find(|bond| bond.target_actor_id == RATI_ACTOR_ID)
                    .expect("Story Button feature use deepens Rati bond");
                assert_eq!(rati_bond.strength, 1);
                let output = command_response_output(Some(output.clone()), &events)
                    .expect("feature use has command output");
                assert!(output.contains("fits the notch"));
            }
            other => panic!("feature use should map to projected item use, got {other:?}"),
        }

        let carried = runtime
            .resolve_command(&command_request(5000, "inventory"), &access)
            .expect("multi-card carried deck resolves");
        match carried.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("Dewbright Button"));
                assert!(output.contains("Story Button"));
            }
            other => panic!("inventory should show both carried cards, got {other:?}"),
        }

        let give = runtime
            .resolve_command(&command_request(5000, "give dewbright to gust"), &access)
            .expect("give resolves");
        assert_eq!(
            give.action.as_ref().map(|action| action.command.as_str()),
            Some("give Dewbright Button to Gust")
        );
        match give.dispatch {
            CommandDispatch::GiveItem {
                item_id,
                target_actor_id,
            } => {
                assert_eq!(item_id, 2002);
                assert_eq!(target_actor_id, 1002);
            }
            other => panic!("give should map to give-item, got {other:?}"),
        }

        let chat = runtime
            .resolve_command(&command_request(5000, "talk rati"), &access)
            .expect("chat resolves");
        match chat.dispatch {
            CommandDispatch::Disabled { status, output } => {
                assert_eq!(status, 409);
                assert!(output.contains("already share a friendship"));
            }
            other => panic!("Chat should not create a duplicate friendship, got {other:?}"),
        }

        let report = runtime
            .resolve_command(
                &command_request(5000, "report rati: repeated room spam"),
                &access,
            )
            .expect("report resolves");
        match report.dispatch {
            CommandDispatch::Report {
                target_actor_id,
                reason,
            } => {
                assert_eq!(target_actor_id, 1001);
                assert_eq!(reason, "repeated room spam");
                assert_eq!(report.command, "report Rati: repeated room spam");
            }
            other => panic!("report should map to moderation report, got {other:?}"),
        }

        let say = runtime
            .resolve_command(&command_request(5000, "say hello room"), &access)
            .expect("say resolves");
        match say.dispatch {
            CommandDispatch::Say { content } => {
                assert_eq!(content, "hello room");
                let content_id = 9101;
                let mut record = JournalRecord::new(
                    CwAction {
                        kind: CW_ACTION_SAY,
                        actor_id: 5000,
                        content_id,
                        ..CwAction::default()
                    },
                    7838,
                );
                record.content_upserts.insert(content_id, content);
                let (status, events) = runtime.apply_journal_record(&record);
                assert_eq!(status, CW_OK);
                assert!(events.iter().any(|event| {
                    event.type_name == "message.created"
                        && event.actor_id == Some(5000)
                        && event.location_id == Some(1)
                        && event.content.as_deref() == Some("hello room")
                }));
                assert_eq!(
                    command_response_output(None, &events).as_deref(),
                    Some("hello room")
                );
            }
            other => panic!("say should map to room speech, got {other:?}"),
        }

        let emote = runtime
            .resolve_command(&command_request(5000, "/me waves by the hearth"), &access)
            .expect("emote resolves");
        match emote.dispatch {
            CommandDispatch::Emote { content } => {
                assert_eq!(emote.command, "emote waves by the hearth.");
                assert_eq!(content, "waves by the hearth.");
                let content_id = 9102;
                let mut record = JournalRecord::new(
                    CwAction {
                        kind: CW_ACTION_SAY,
                        actor_id: 5000,
                        content_id,
                        ..CwAction::default()
                    },
                    7839,
                );
                record.content_upserts.insert(content_id, content);
                let (status, events) = runtime.apply_journal_record(&record);
                assert_eq!(status, CW_OK);
                assert!(events.iter().any(|event| {
                    event.type_name == "message.created"
                        && event.actor_id == Some(5000)
                        && event.location_id == Some(1)
                        && event.content.as_deref() == Some("waves by the hearth.")
                }));
                assert_eq!(
                    command_response_output(None, &events).as_deref(),
                    Some("waves by the hearth.")
                );
            }
            other => panic!("emote should map to room narration, got {other:?}"),
        }

        let unsafe_emote = runtime
            .resolve_command(
                &command_request(5000, "emote points toward https://spam.example"),
                &access,
            )
            .expect("unsafe emote resolves to disabled output");
        match unsafe_emote.dispatch {
            CommandDispatch::Disabled { status, output } => {
                assert_eq!(status, 400);
                assert!(output.contains("Keep it cozy"));
            }
            other => panic!("unsafe emote should be rejected before commit, got {other:?}"),
        }

        let unsafe_say = runtime
            .resolve_command(
                &command_request(5000, "say visit https://spam.example now"),
                &access,
            )
            .expect("unsafe say resolves to disabled output");
        match unsafe_say.dispatch {
            CommandDispatch::Disabled { status, output } => {
                assert_eq!(status, 400);
                assert!(output.contains("Keep it cozy"));
            }
            other => panic!("unsafe say should be rejected before commit, got {other:?}"),
        }
    }

    #[test]
    fn mud_look_reports_rpg_room_state() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 7836);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Look Tester".to_string(),
                speech_mode: "prose".to_string(),
                title: "State Reader".to_string(),
                description: "A test avatar checking typed room state.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        for (destination, seed) in [(2, 7837), (MOONLIT_TRAIL_LOCATION_ID, 7838)] {
            let mut move_action = CwAction::default();
            move_action.kind = CW_ACTION_MOVE;
            move_action.actor_id = 5000;
            move_action.destination_location_id = destination;
            assert_eq!(
                runtime
                    .apply_journal_record(&JournalRecord::new(move_action, seed))
                    .0,
                CW_OK
            );
        }
        assert!(runtime
            .mark_visit_ledger(
                5000,
                "listening",
                "The trail taught you to listen for echoes.",
                7839,
                "test:look",
            )
            .is_some());

        let look = runtime
            .resolve_command(&command_request(5000, "look"), &AccessContext::default())
            .expect("look resolves");
        match look.dispatch {
            CommandDispatch::Read { output } => {
                assert!(output.contains("Moonlit Trail"));
                assert!(output.contains("This place feels a little wild around the edges"));
                assert!(output.contains("Shared questions:"));
                assert!(output.contains(
                    "Can travelers quiet the Moonlit Trail before its echoes turn every step against them?"
                ));
                assert!(output.contains("Progress: 0/4."));
                assert!(output.contains("Trouble: 0/4."));
                assert!(
                    output.contains("What finishing changes: Footsteps sound like travelers again")
                );
                assert!(output.contains("Try:"));
                assert!(!output.contains("Quiet the Moonlit Trail —"));
                assert!(!output.contains("Echo Shatters the Trail —"));
                assert!(output.contains("What lingers:"));
                assert!(output.contains("moonlit threshold crossed"));
                assert!(output.contains(
                    "Your journal holds an older unsettled memory. Your next successful discovery will settle it automatically."
                ));
                assert!(!output.contains("frontier"));
                assert!(!output.contains("growth left"));
                assert!(!output.contains("Memory:"));
            }
            other => panic!("look should be read-only, got {other:?}"),
        }
    }

    #[test]
    fn normal_play_primary_action_prefers_concrete_room_verbs() {
        let mut runtime = RuntimeWorld::seeded();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = 1;
        let mut record = JournalRecord::new(create, 7051);
        record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "Chat Guest".to_string(),
                speech_mode: "prose".to_string(),
                title: "Chat Tester".to_string(),
                description: "A test avatar checking the main verb.".to_string(),
            },
        );
        assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);

        let access = AccessContext::default();
        let state = runtime.state_response(Some(5000), &access);
        assert_eq!(state.primary_action.kind, "pick_up");
        assert_eq!(state.primary_action.label, "Take");
        assert_eq!(state.primary_action.command, "take");
        assert!(!state
            .primary_action
            .options
            .iter()
            .any(|option| matches!(option.kind.as_str(), "chat" | "create_bond")));
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "search" && option.command.starts_with("search ")));
        assert!(!state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "move"));
        assert!(state.exits.is_empty());
        assert!(!state
            .exits
            .iter()
            .any(|exit| exit.destination_location_id == 10));

        let mut tired_record = JournalRecord::new(
            CwAction {
                kind: CW_ACTION_NONE,
                actor_id: 5000,
                ..CwAction::default()
            },
            7052,
        );
        tired_record
            .projection_mutations
            .push(ProjectionMutation::SetTag {
                tag: RpgTagState {
                    id: tired_tag_id(5000),
                    scope: "actor".to_string(),
                    scope_id: 5000,
                    label: "tired".to_string(),
                    kind: "condition".to_string(),
                    active: true,
                    source_event_seq: None,
                    expires: Some("after_rest".to_string()),
                },
                reason: "test_tired".to_string(),
            });
        assert_eq!(runtime.apply_journal_record(&tired_record).0, CW_OK);
        let tired_cottage = runtime.state_response(Some(5000), &access);
        assert_eq!(tired_cottage.primary_action.kind, "pick_up");
        assert!(!tired_cottage
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "rest"));
        let take_offer = tired_cottage
            .action_offers
            .iter()
            .find(|offer| offer.kind == "pick_up")
            .expect("take offer remains visible while tired in the cottage");
        assert!(take_offer.rank > 0);
        assert!(!tired_cottage
            .action_offers
            .iter()
            .any(|offer| offer.kind == "rest"));

        let ownership = OwnershipIndex::parse("wallet-1:location-homeroom,location-science-lab");
        let access = AccessContext::from_parts(Some("wallet-1"), [None], &ownership);
        discover_seed_exit_pair_for_test(&mut runtime, 1, 11);
        discover_seed_exit_pair_for_test(&mut runtime, 11, 10);
        let state = runtime.state_response(Some(5000), &access);
        assert_eq!(state.primary_action.kind, "pick_up");
        assert!(state
            .primary_action
            .options
            .iter()
            .any(|option| option.kind == "move"));
        assert!(state
            .exits
            .iter()
            .any(|exit| exit.destination_location_id == 11 && exit.accessible));
        let world = runtime.world_response(Some(5000), &access);
        let homeroom = world
            .locations
            .iter()
            .find(|location| location.id == 11)
            .expect("Homeroom exists in world map");
        assert!(homeroom
            .exits
            .iter()
            .any(|exit| exit.destination_location_id == 10 && exit.accessible));
    }

