        assert_eq!(memory.subject_id, STORY_BUTTON_ITEM_ID);
        assert_eq!(memory.holder_actor_id, Some(5000));
        assert_eq!(memory.location_id, RAIN_SOFT_GARDEN_LOCATION_ID);
