    #[test]
    fn free_world_locations_are_public_with_optional_card_ownership() {
        let mut runtime = RuntimeWorld::seeded();
        discover_seed_exit_pair_for_test(&mut runtime, 1, 2);
        discover_seed_exit_pair_for_test(&mut runtime, 1, 11);
        discover_all_seed_exits_for_test(&mut runtime);
        let no_wallet = AccessContext::default();
        let state = runtime.state_response(None, &no_wallet);
        let cottage_exits: BTreeSet<u64> = state
            .exits
            .iter()
            .map(|exit| exit.destination_location_id)
            .collect();
        assert!(cottage_exits.contains(&2));
        assert!(cottage_exits.contains(&11));
        assert!(state.cards.locations[&2].accessible);
        assert!(!state.cards.locations[&11].accessible);
        assert_eq!(
            state.cards.locations[&11].access_reason.as_deref(),
            Some("Ruby High: First Bell location pass required.")
        );

        let world = runtime.world_response(None, &no_wallet);
        for (location_id, card_id) in [
            (2, "cosy-rain-soft-garden"),
            (30, "location-the-heavens"),
            (34, "location-goblin-cave"),
            (50, "location-great-library"),
            (63, "location-digital-realm"),
        ] {
            let location = world
                .locations
                .iter()
                .find(|location| location.id == location_id)
                .expect("free world location exists");
            assert!(location.accessible);
            assert!(location.card.accessible);
            assert!(!location.card.owned);
            assert!(!world.access.locked_card_ids.contains(&card_id.to_string()));
        }

        for (location_id, card_id) in [
            (10, "location-science-lab"),
            (11, "location-homeroom"),
            (12, "location-library"),
            (13, "location-cafeteria"),
            (14, "location-greenhouse"),
            (15, "location-courtyard"),
        ] {
            let location = world
                .locations
                .iter()
                .find(|location| location.id == location_id)
                .expect("discovered Ruby High location exists");
            assert!(!location.accessible);
            assert!(!location.card.accessible);
            assert!(world.access.locked_card_ids.contains(&card_id.to_string()));
        }

        let ownership = OwnershipIndex::parse(
            "wallet-1:cosy-rain-soft-garden,location-homeroom,location-library,location-greenhouse",
        );
        let with_location_cards = AccessContext::from_parts(Some("wallet-1"), [None], &ownership);
        let state = runtime.state_response(None, &with_location_cards);
        assert!(state.cards.locations[&2].accessible);
        assert!(state.cards.locations[&2].owned);
        assert!(state.cards.locations[&11].accessible);
        assert!(state.cards.locations[&11].owned);

        let world = runtime.world_response(None, &with_location_cards);
        let library = world
            .locations
            .iter()
            .find(|location| location.id == 12)
            .expect("Library location exists");
        assert!(library.card.accessible);
        assert!(library.card.owned);
        let greenhouse = world
            .locations
            .iter()
            .find(|location| location.id == 14)
            .expect("Greenhouse location exists");
        assert!(greenhouse.card.accessible);
        assert!(greenhouse.card.owned);
        let science = world
            .locations
            .iter()
            .find(|location| location.id == 10)
            .expect("discovered Science Class exists");
        assert!(!science.accessible);
        assert!(!science.card.accessible);
        assert_eq!(library.card.set_number.as_deref(), Some("FB-021"));
        assert_eq!(
            greenhouse.card.profile_id.as_deref(),
            Some("location-greenhouse")
        );
    }

    #[test]
    fn client_card_claims_are_ignored_without_dev_trust() {
        let query = StateQuery {
            actor_id: None,
            actor_session: None,
            wallet_address: Some("wallet-1".to_string()),
            wallet: None,
            wallet_session: None,
            owned_card_ids: Some("location-science-lab".to_string()),
            cards: None,
            openrouter_connected: None,
        };
        let empty_ownership = OwnershipIndex::default();
        let wallet_sessions = StdMutex::new(WalletSessions::default());
        let untrusted =
            AccessContext::from_query(&query, &empty_ownership, false, &wallet_sessions, false);
        assert!(!untrusted.owns_card("location-science-lab"));
        assert!(untrusted.owner_wallet_address.is_none());

        let trusted_cards =
            AccessContext::from_query(&query, &empty_ownership, true, &wallet_sessions, false);
        assert!(trusted_cards.owns_card("location-science-lab"));
        assert!(trusted_cards.owner_wallet_address.is_none());

        let trusted_wallet =
            AccessContext::from_query(&query, &empty_ownership, false, &wallet_sessions, true);
        assert_eq!(
            trusted_wallet.owner_wallet_address.as_deref(),
            Some("wallet-1")
        );
        assert!(trusted_wallet.unsigned_wallet_claim);
    }

    #[test]
    fn signed_wallet_session_verifies_solana_challenge() {
        use ed25519_dalek::{Signer, SigningKey};

        let signing_key = SigningKey::from_bytes(&[7_u8; 32]);
        let wallet_address = bs58::encode(signing_key.verifying_key().to_bytes()).into_string();
        let message = wallet_challenge_message(&wallet_address, "nonce-1", 1_234);
        let signature = signing_key.sign(message.as_bytes()).to_bytes();

        assert!(verify_solana_wallet_signature(
            &wallet_address,
            &message,
            &signature
        ));
        assert!(!verify_solana_wallet_signature(
            &wallet_address,
            "tampered",
            &signature
        ));
    }

    #[test]
    fn moderation_bearer_token_is_required_for_audit_replay() {
        let mut headers = HeaderMap::new();
        assert!(!moderation_authorized_token(Some("secret"), &headers));

        headers.insert(header::AUTHORIZATION, "Bearer wrong".parse().unwrap());
        assert!(!moderation_authorized_token(Some("secret"), &headers));

        headers.insert(header::AUTHORIZATION, "Bearer secret".parse().unwrap());
        assert!(moderation_authorized_token(Some("secret"), &headers));
        assert!(!moderation_authorized_token(None, &headers));
    }

    #[tokio::test]
    async fn player_reports_require_session_and_feed_moderation_queue() {
        let path = std::env::temp_dir().join(format!(
            "cosyworld-v2-report-audit-{}-{}.sqlite",
            std::process::id(),
            now_seed()
        ));
        let _ = fs::remove_file(&path);

        let mut runtime = RuntimeWorld::seeded();
        for (actor_id, name) in [(5000, "Report Tester"), (5001, "Closed Tab Guest")] {
            let mut create = CwAction::default();
            create.kind = CW_ACTION_CREATE_ACTOR;
            create.actor_id = actor_id;
            create.location_id = 1;
            let mut record = JournalRecord::new(create, 7741 + actor_id);
            record.actor_meta_upserts.insert(
                actor_id,
                ActorMeta {
                    name: name.to_string(),
                    speech_mode: "prose".to_string(),
                    title: "Moderation Tester".to_string(),
                    description: "A test avatar checking player reports.".to_string(),
                },
            );
            assert_eq!(runtime.apply_journal_record(&record).0, CW_OK);
        }

        let mut state = test_app_state(runtime, Some(path.clone()));
        state.moderation_token = Some(Arc::new("audit-secret".to_string()));
        let (actor_session, _) = issue_actor_session(&state, 5000);
        let client_addr: SocketAddr = "127.0.0.1:0".parse().unwrap();

        let denied = report_actor(
            ConnectInfo(client_addr),
            State(state.clone()),
            Json(ReportRequest {
                actor_id: 5000,
                actor_session: None,
                target_actor_id: 1001,
                reason: "missing session".to_string(),
            }),
        )
        .await
        .0;
        assert!(!denied.ok);
        assert_eq!(denied.status, 403);

        let stale_target = report_actor(
            ConnectInfo(client_addr),
            State(state.clone()),
            Json(ReportRequest {
                actor_id: 5000,
                actor_session: Some(actor_session.clone()),
                target_actor_id: 5001,
                reason: "closed tab human".to_string(),
            }),
        )
        .await
        .0;
        assert!(!stale_target.ok);
        assert_eq!(stale_target.status, 404);
        assert_eq!(
            stale_target.error.as_deref(),
            Some("Reported actor must be nearby.")
        );

        let submitted = report_actor(
            ConnectInfo(client_addr),
            State(state.clone()),
            Json(ReportRequest {
                actor_id: 5000,
                actor_session: Some(actor_session),
                target_actor_id: 1001,
                reason: "  repeated   room spam  ".to_string(),
            }),
        )
        .await
        .0;
        assert!(submitted.ok);
        assert_eq!(submitted.status, 200);
        let report = submitted.report.expect("report response");
        assert!(report.report_id > 0);
        assert_eq!(report.reporter_actor_id, 5000);
        assert_eq!(report.reporter_actor_name, "Report Tester");
        assert_eq!(report.reporter_actor_kind, "human");
        assert!(!report.reporter_suspended);
        assert_eq!(report.target_actor_id, 1001);
        assert_eq!(report.target_actor_name, "Rati");
        assert_eq!(report.target_actor_kind, "npc");
        assert!(!report.target_suspended);
        assert_eq!(report.location_name, "The Cosy Cottage");
        assert_eq!(report.reason, "repeated room spam");
        assert_eq!(report.status, "open");
        assert_eq!(report.resolved_at_ms, None);
        state.actor_suspensions.lock().unwrap().insert(
            5000,
            ActorSuspension {
                reason: "queue annotation probe".to_string(),
                created_at_unix: now_unix_secs(),
            },
        );

        let denied_queue = moderation_reports_view(
            HeaderMap::new(),
            State(state.clone()),
            Query(ModerationReportsQuery {
                after: None,
                limit: Some(10),
                status: None,
            }),
        )
        .await
        .0;
        assert!(!denied_queue.ok);
        assert_eq!(denied_queue.status, 403);

        let mut headers = HeaderMap::new();
        headers.insert(
            header::AUTHORIZATION,
            "Bearer audit-secret".parse().unwrap(),
        );
        let queue = moderation_reports_view(
            headers.clone(),
            State(state.clone()),
            Query(ModerationReportsQuery {
                after: None,
                limit: Some(10),
                status: None,
            }),
        )
        .await
        .0;
        assert!(queue.ok);
        assert_eq!(queue.status, 200);
        assert_eq!(queue.reports.len(), 1);
        assert_eq!(queue.reports[0].reason, "repeated room spam");
        assert!(queue.reports[0].reporter_suspended);
        assert!(!queue.reports[0].target_suspended);

        let denied_delete_open = moderation_delete_report(
            headers.clone(),
            State(state.clone()),
            AxumPath(report.report_id),
        )
        .await
        .0;
        assert!(!denied_delete_open.ok);
        assert_eq!(denied_delete_open.status, 409);
        assert_eq!(
            denied_delete_open
                .report
                .as_ref()
                .map(|report| report.status.as_str()),
            Some("open")
        );

        let denied_resolution = moderation_resolve_report(
            HeaderMap::new(),
            State(state.clone()),
            AxumPath(report.report_id),
            Json(ResolveReportRequest {
                moderator: Some("Smoke Mod".to_string()),
                note: Some("reviewed".to_string()),
            }),
        )
        .await
        .0;
        assert!(!denied_resolution.ok);
        assert_eq!(denied_resolution.status, 403);

        let resolved = moderation_resolve_report(
            headers.clone(),
            State(state.clone()),
            AxumPath(report.report_id),
            Json(ResolveReportRequest {
                moderator: Some(" Smoke   Mod ".to_string()),
                note: Some(" handled after review ".to_string()),
            }),
        )
        .await
        .0;
        assert!(resolved.ok);
        assert_eq!(resolved.status, 200);
        let resolved_report = resolved.report.expect("resolved report");
        assert_eq!(resolved_report.report_id, report.report_id);
        assert_eq!(resolved_report.status, "resolved");
        assert_eq!(resolved_report.resolved_by.as_deref(), Some("Smoke Mod"));
        assert_eq!(
            resolved_report.resolution_note.as_deref(),
            Some("handled after review")
        );
        assert!(resolved_report.resolved_at_ms.is_some());

        let open_queue = moderation_reports_view(
            headers.clone(),
            State(state.clone()),
            Query(ModerationReportsQuery {
                after: None,
                limit: Some(10),
                status: None,
            }),
        )
        .await
        .0;
        assert!(open_queue.ok);
        assert!(open_queue.reports.is_empty());

        let resolved_queue = moderation_reports_view(
            headers.clone(),
            State(state.clone()),
            Query(ModerationReportsQuery {
                after: None,
                limit: Some(10),
                status: Some("resolved".to_string()),
            }),
        )
        .await
        .0;
        assert!(resolved_queue.ok);
        assert_eq!(resolved_queue.reports.len(), 1);
        assert_eq!(resolved_queue.reports[0].report_id, report.report_id);

        let deleted = moderation_delete_report(
            headers.clone(),
            State(state.clone()),
            AxumPath(report.report_id),
        )
        .await
        .0;
        assert!(deleted.ok);
        assert_eq!(deleted.status, 200);
        assert_eq!(
            deleted.report.as_ref().map(|report| report.status.as_str()),
            Some("resolved")
        );

        let all_queue = moderation_reports_view(
            headers,
            State(state),
            Query(ModerationReportsQuery {
                after: None,
                limit: Some(10),
                status: Some("all".to_string()),
            }),
        )
        .await
        .0;
        assert!(all_queue.ok);
        assert!(all_queue.reports.is_empty());

        let _ = fs::remove_file(path);
    }

    #[test]
