    #[test]
    fn played_time_pulse_can_maintain_distant_state_without_public_fiction() {
        let mut runtime = RuntimeWorld::seeded();
        create_test_human(
            &mut runtime,
            5000,
            COSY_COTTAGE_LOCATION_ID,
            "Distant Witness",
        );

        let ticks_until_pulse =
            WORLD_PULSE_INTERVAL_TICKS - (runtime.world.tick % WORLD_PULSE_INTERVAL_TICKS);
        let mut pulse_events = Vec::new();
        for offset in 0..ticks_until_pulse {
            let action = CwAction {
                kind: CW_ACTION_ABILITY_CHECK,
                actor_id: 5000,
                ability: LISTEN_ABILITY,
                dc: LISTEN_DC,
                ..CwAction::default()
            };
            let (status, events) =
                runtime.apply_journal_record(&JournalRecord::new(action, 80_001 + offset));
            assert_eq!(status, CW_OK);
            if runtime.world.tick % WORLD_PULSE_INTERVAL_TICKS == 0 {
                pulse_events = events;
            }
        }

        assert_eq!(runtime.world.tick % WORLD_PULSE_INTERVAL_TICKS, 0);
        assert_eq!(runtime.world_simulation.pulse_index, 1);
        assert_eq!(
            runtime.world_simulation.last_advanced_tick,
            runtime.world.tick
        );
        assert!(
            pulse_events
                .iter()
                .filter(|event| event.type_name.starts_with("world."))
                .count()
                <= 1
        );
        assert!(!pulse_events.iter().any(|event| matches!(
            event.type_name.as_str(),
            "world.trade.flowed" | "world.trade.disrupted" | "world.logistics.completed"
        )));
        assert!(pulse_events.iter().all(|event| {
            let content = event.content.as_deref().unwrap_or_default().to_lowercase();
            !["caravan", "courier", "shipment"]
                .iter()
                .any(|claim| content.contains(claim))
        }));
        assert!(!pulse_events
            .iter()
            .any(|event| event.type_name == "world.conflict.escalated"));
        assert!(!pulse_events.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.content.as_deref() == Some("consented_world_stakes")
        }));
        assert!(pulse_events
            .iter()
            .filter(|event| event.type_name.starts_with("world."))
            .all(|event| {
                event.location_id != Some(COSY_COTTAGE_LOCATION_ID)
                    && event.destination_location_id != Some(COSY_COTTAGE_LOCATION_ID)
                    && event.source_location_id == Some(COSY_COTTAGE_LOCATION_ID)
                    && event.source_world_tick == Some(runtime.world.tick)
            }));

        let world = runtime.world_response(Some(5000), &AccessContext::default());
        assert_eq!(world.simulation.pulse_index, 1);
        assert!(world.simulation.recent_history.windows(2).all(|pair| {
            pair[0].source_world_tick > pair[1].source_world_tick
                || (pair[0].source_world_tick == pair[1].source_world_tick
                    && pair[0].seq < pair[1].seq)
        }));
        assert!(runtime
            .world_simulation
            .locations
            .values()
            .any(|location| location.last_pulse_tick > 0));
    }

    #[test]
    fn world_simulation_survives_snapshot_and_journal_style_replay() {
        let mut records = Vec::new();
        let mut create = CwAction::default();
        create.kind = CW_ACTION_CREATE_ACTOR;
        create.actor_id = 5000;
        create.location_id = COSY_COTTAGE_LOCATION_ID;
        let mut create_record = JournalRecord::new(create, 81_000);
        create_record.actor_meta_upserts.insert(
            5000,
            ActorMeta {
                name: "History Keeper".to_string(),
                speech_mode: "prose".to_string(),
                title: "Replay Witness".to_string(),
                description: "A test avatar watching the far world move.".to_string(),
            },
        );
        records.push(create_record);
        for seed in 81_001..=81_011 {
            records.push(JournalRecord::new(
                CwAction {
                    kind: CW_ACTION_ABILITY_CHECK,
                    actor_id: 5000,
                    ability: LISTEN_ABILITY,
                    dc: LISTEN_DC,
                    ..CwAction::default()
                },
                seed,
            ));
        }

        let mut first = RuntimeWorld::seeded();
        let mut replay = RuntimeWorld::seeded();
        for record in &records {
            assert_eq!(first.apply_journal_record(record).0, CW_OK);
            assert_eq!(replay.apply_journal_record(record).0, CW_OK);
        }
        assert_eq!(first.world_simulation, replay.world_simulation);
        let first_history = first
            .event_log
            .iter()
            .filter(|event| event.type_name.starts_with("world."))
            .map(|event| (event.type_name.clone(), event.content.clone()))
            .collect::<Vec<_>>();
        let replay_history = replay
            .event_log
            .iter()
            .filter(|event| event.type_name.starts_with("world."))
            .map(|event| (event.type_name.clone(), event.content.clone()))
            .collect::<Vec<_>>();
        assert_eq!(first_history, replay_history);

        let snapshot = RuntimeSnapshot::from_runtime(&first);
        let restored = snapshot
            .into_runtime()
            .expect("simulation snapshot restores");
        assert_eq!(restored.world_simulation, first.world_simulation);
        assert_eq!(
            restored.world_simulation_view().recent_history.len(),
            first.world_simulation_view().recent_history.len()
        );
    }

    #[test]
    fn aggregate_scarcity_creates_a_physical_delivery_job_without_claiming_completion() {
        let mut runtime = RuntimeWorld::seeded();
        let pulse = WorldPulse {
            pulse_index: 4,
            source_world_tick: 24,
            weather: WeatherShift {
                class: PulseEffectClass::Ambient,
                location_id: MOONLIT_TRAIL_LOCATION_ID,
                before: "settled".to_string(),
                after: "settled".to_string(),
                intensity: 0,
                changed: false,
                notable: false,
            },
            trade: TradeOutcome {
                class: PulseEffectClass::Opportunity,
                from_location_id: MOONLIT_TRAIL_LOCATION_ID,
                to_location_id: COSY_COTTAGE_LOCATION_ID,
                resource: "herbs".to_string(),
                moved: false,
                amount: 0,
                reason: "useful stores are running thin".to_string(),
                needs_delivery: true,
            },
            faction: None,
            conflict: ConflictOutcome {
                class: PulseEffectClass::Opportunity,
                location_id: MOONLIT_TRAIL_LOCATION_ID,
                before: 0,
                after: 0,
                escalated: false,
                front_ids: Vec::new(),
                faction_ids: Vec::new(),
                reason: "quiet".to_string(),
            },
            public_beat: Some(PulseBeatKind::DeliveryNeed),
        };
        let event = runtime
            .ensure_delivery_need_job(&pulse, Some(1), Some(77))
            .expect("a new need creates one public opportunity");
        assert_eq!(event.type_name, "world.delivery.needed");
        assert_eq!(event.location_id, Some(MOONLIT_TRAIL_LOCATION_ID));
        assert_eq!(
            event.destination_location_id,
            Some(COSY_COTTAGE_LOCATION_ID)
        );
        assert_eq!(event.caused_by_event_seq, Some(77));
        assert!(!runtime
            .event_log
            .iter()
            .any(|event| event.type_name == "world.logistics.completed"));
        let job = runtime
            .jobs
            .values()
            .find(|job| job.delivery.is_some())
            .expect("the opportunity has a concrete job");
        assert_eq!(runtime.job_status(job), "active");
        let progress_clock = &runtime.clocks[&job.progress_clock_id];
        assert_eq!(progress_clock.segments, 1);
        assert_eq!(progress_clock.presentation.rhythm, "immediate");
        assert!(job.premise.contains("physical"));
        assert!(job.action_copy.summary.contains("Pick up a physical item"));
        assert!(
            runtime
                .active_progress_clock_id_for_location(COSY_COTTAGE_LOCATION_ID)
                .is_none(),
            "generic Work cannot abstractly complete a physical delivery"
        );
        assert!(
            runtime
                .ensure_delivery_need_job(&pulse, Some(1), Some(78))
                .is_none(),
            "the same active need updates silently instead of duplicating public news"
        );
    }

    #[test]
    fn causal_delivery_evidence_completes_the_matching_delivery_job() {
        let mut runtime = RuntimeWorld::seeded();
        let pulse = WorldPulse {
            pulse_index: 5,
            source_world_tick: 30,
            weather: WeatherShift {
                class: PulseEffectClass::Ambient,
                location_id: MOONLIT_TRAIL_LOCATION_ID,
                before: "settled".to_string(),
                after: "settled".to_string(),
                intensity: 0,
                changed: false,
                notable: false,
            },
            trade: TradeOutcome {
                class: PulseEffectClass::Opportunity,
                from_location_id: MOONLIT_TRAIL_LOCATION_ID,
                to_location_id: RAIN_SOFT_GARDEN_LOCATION_ID,
                resource: "herbs".to_string(),
                moved: false,
                amount: 0,
                reason: "useful stores are running thin".to_string(),
                needs_delivery: true,
            },
            faction: None,
            conflict: ConflictOutcome {
                class: PulseEffectClass::Opportunity,
                location_id: MOONLIT_TRAIL_LOCATION_ID,
                before: 0,
                after: 0,
                escalated: false,
                front_ids: Vec::new(),
                faction_ids: Vec::new(),
                reason: "quiet".to_string(),
            },
            public_beat: Some(PulseBeatKind::DeliveryNeed),
        };
        runtime
            .ensure_delivery_need_job(&pulse, Some(COSY_COTTAGE_LOCATION_ID), Some(77))
            .expect("delivery need");
        let job_id = runtime
            .jobs
            .values()
            .find(|job| job.delivery.is_some())
            .map(|job| job.id.clone())
            .expect("delivery job");

        let projected = runtime.apply_actor_causal_logistics(vec![DeliveryEvidence {
            actor_id: RATI_ACTOR_ID,
            item_id: DEWBRIGHT_BUTTON_ITEM_ID,
            origin_location_id: MOONLIT_TRAIL_LOCATION_ID,
            destination_location_id: RAIN_SOFT_GARDEN_LOCATION_ID,
            acquisition_event_seq: 80,
            movement_event_seqs: vec![81],
            delivery_event_seq: 82,
        }]);

        assert_eq!(runtime.job_status(&runtime.jobs[&job_id]), "completed");
        assert!(projected.iter().any(|event| {
            event.type_name == "clock.updated"
                && event.caused_by_event_seq == Some(82)
                && event.clock_delta == Some(1)
        }));
        assert!(projected
            .iter()
            .any(|event| event.type_name == "job.updated"));
        assert_eq!(
            projected
                .iter()
                .filter(|event| event.type_name == "world.logistics.completed")
                .count(),
            1
        );
        let receipt = command_response_output(None, &projected)
            .expect("physical delivery returns one causal receipt");
        assert!(receipt.contains("The need is answered (1/1)"));
        assert!(receipt.contains("contribution is remembered here"));
        assert!(!receipt.contains("The work is done."));
        let completed = runtime
            .shared_question_views(RAIN_SOFT_GARDEN_LOCATION_ID, Some(RATI_ACTOR_ID))
            .into_iter()
            .find(|question| question.id == job_id)
            .expect("the completed delivery remains legible at its destination");
        assert_eq!(completed.presentation_state, "completed_memory");
        assert!(completed.completion_memory.is_some());
        assert_eq!(completed.recent_contributions.len(), 1);
        assert_eq!(completed.recent_contributions[0].actor_id, RATI_ACTOR_ID);
        assert_eq!(completed.recent_contributions[0].event_seq, 82);
    }

